-- Catálogo textual de 1.324 exercícios de hasaneyldrm/exercises-dataset (MIT).
-- A mídia da Gym Visual não é importada: requer licença própria.
alter table public.exercises drop constraint exercises_source_check;
alter table public.exercises add constraint exercises_source_check check (source in ('wger', 'custom', 'hasaneyldrm'));

insert into public.exercises (id, org_id, name, movement_pattern, primary_muscles, secondary_muscles, load_type, unilateral, instructions, media_url, source, external_id) values
  ('b1d7a80a-0000-4000-8000-000000000001'::uuid, null, '3/4 abdominais', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0001.gif', 'hasaneyldrm', '0001'),
  ('b1d7a80a-0000-4000-8000-000000000002'::uuid, null, 'Curvatura lateral de 45°', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos ao lado do corpo. Mantendo as costas retas e o núcleo engajado, dobre lentamente o tronco para o lado, abaixando a mão em direção ao joelho. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0002.gif', 'hasaneyldrm', '0002'),
  ('b1d7a80a-0000-4000-8000-000000000003'::uuid, null, 'bicicleta aérea', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com as mãos colocadas atrás da cabeça. Levante as pernas do chão e dobre os joelhos em um ângulo de 90 graus. Traga o cotovelo direito em direção ao joelho esquerdo e, ao mesmo tempo, estique a perna direita. Volte à posição inicial e repita o movimento no lado oposto, aproximando o cotovelo esquerdo do joelho direito enquanto estica a perna esquerda. Continue alternando os lados em um movimento de pedalada pelo número desejado de repetições.', '/exercise-media/bstrainer/0003.gif', 'hasaneyldrm', '0003'),
  ('b1d7a80a-0000-4000-8000-000000001512'::uuid, null, 'alongamento do pelotão de quatro', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Comece de quatro, com as mãos diretamente sob os ombros e os joelhos diretamente sob os quadris. Estenda uma perna para trás, mantendo o joelho dobrado e o pé flexionado. Abaixe lentamente os quadris em direção ao chão, sentindo um alongamento nos quadríceps. Mantenha esta posição por 20 a 30 segundos. Troque as pernas e repita o alongamento do outro lado.', '/exercise-media/bstrainer/1512.gif', 'hasaneyldrm', '1512'),
  ('b1d7a80a-0000-4000-8000-000000000006'::uuid, null, 'tocadores de calcanhar alternados', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', true, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Estenda os braços para os lados, paralelos ao chão. Envolvendo os abdominais, levante os ombros do chão e estenda a mão direita em direção ao calcanhar direito. Volte à posição inicial e repita no lado esquerdo, estendendo a mão esquerda em direção ao calcanhar esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0006.gif', 'hasaneyldrm', '0006'),
  ('b1d7a80a-0000-4000-8000-000000000007'::uuid, null, 'pulldown lateral alternativo', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids']::text[], 'cable', true, 'Sente-se na máquina de cabo com as costas retas e os pés apoiados no chão. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Incline-se ligeiramente para trás e puxe as alças em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0007.gif', 'hasaneyldrm', '0007'),
  ('b1d7a80a-0000-4000-8000-000000001368'::uuid, null, 'círculos no tornozelo', 'isolation', ARRAY['calves', 'ankle stabilizers']::text[], ARRAY['ankle stabilizers']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Levante uma perna do chão e gire o tornozelo em movimentos circulares. Execute o número desejado de círculos em uma direção e depois mude para a outra direção. Repita com a outra perna.', '/exercise-media/bstrainer/1368.gif', 'hasaneyldrm', '1368'),
  ('b1d7a80a-0000-4000-8000-000000003293'::uuid, null, 'arqueiro levanta', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Comece pendurando-se em uma barra suspensa com uma pegada pronada, um pouco mais larga que a largura dos ombros. Envolva seu núcleo e puxe as omoplatas para baixo e para trás. Ao se levantar, dobre um braço e traga o cotovelo para o lado, enquanto mantém o outro braço reto. Continue puxando até que o queixo esteja acima da barra e o braço dobrado esteja totalmente flexionado. Abaixe-se com controle, esticando o braço dobrado e repetindo o movimento do outro lado. Alterne os lados a cada repetição.', '/exercise-media/bstrainer/3293.gif', 'hasaneyldrm', '3293'),
  ('b1d7a80a-0000-4000-8000-000000003294'::uuid, null, 'Arqueiro flexão para cima', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas do que a largura dos ombros. Estenda um braço para o lado, paralelo ao chão. Abaixe o corpo dobrando os cotovelos, mantendo as costas retas e o núcleo engajado. Empurre de volta para a posição inicial. Repita do outro lado, estendendo o braço oposto para o lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3294.gif', 'hasaneyldrm', '3294'),
  ('b1d7a80a-0000-4000-8000-000000002355'::uuid, null, 'estilingues de braço pendurando pernas dobradas nos joelhos', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e os joelhos dobrados em um ângulo de 90 graus. Envolva o núcleo e levante os joelhos em direção ao peito, aproximando-os o mais possível dos cotovelos. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2355.gif', 'hasaneyldrm', '2355'),
  ('b1d7a80a-0000-4000-8000-000000002333'::uuid, null, 'estilingues de braço pendurando pernas retas', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as pernas esticadas para baixo. Envolva seu núcleo e levante as pernas à sua frente até que fiquem paralelas ao chão. Segure por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2333.gif', 'hasaneyldrm', '2333'),
  ('b1d7a80a-0000-4000-8000-000000003214'::uuid, null, 'braços afastados toque circular na ponta dos pés (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos para os lados. Mantendo as pernas retas, incline-se para a frente na cintura e desça em direção aos dedos dos pés com a mão direita. Ao se abaixar, levante simultaneamente a perna esquerda atrás de você, mantendo o equilíbrio. Retorne à posição inicial e repita o movimento com a mão esquerda alcançando os dedos dos pés e a perna direita levantada atrás de você. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3214.gif', 'hasaneyldrm', '3214'),
  ('b1d7a80a-0000-4000-8000-000000003204'::uuid, null, 'braços acima da cabeça abdominais completos (masculino)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Estenda os braços acima da cabeça, mantendo-os retos. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique na vertical. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3204.gif', 'hasaneyldrm', '3204'),
  ('b1d7a80a-0000-4000-8000-000000000009'::uuid, null, 'imersão torácica assistida (ajoelhamento)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a máquina na altura desejada e prenda os joelhos na almofada. Segure as alças com as palmas voltadas para baixo e os braços totalmente estendidos. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0009.gif', 'hasaneyldrm', '0009'),
  ('b1d7a80a-0000-4000-8000-000000000011'::uuid, null, 'elevação assistida do joelho pendurado', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva os músculos centrais e levante os joelhos em direção ao peito, dobrando os quadris e os joelhos. Faça uma pausa no início do movimento, contraindo o abdômen. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0011.gif', 'hasaneyldrm', '0011'),
  ('b1d7a80a-0000-4000-8000-000000000010'::uuid, null, 'elevação assistida do joelho em suspensão com lançamento para baixo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'machine', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva o núcleo e levante os joelhos em direção ao peito, mantendo as pernas juntas. Quando os joelhos estiverem na altura do peito, jogue as pernas de forma explosiva em direção ao chão, estendendo-as totalmente. Permita que suas pernas balancem para cima e repita o movimento pelo número desejado de repetições.', '/exercise-media/bstrainer/0010.gif', 'hasaneyldrm', '0010'),
  ('b1d7a80a-0000-4000-8000-000000001708'::uuid, null, 'alongamento assistido de panturrilhas deitadas', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Deite-se de costas com as pernas estendidas. Dobre um joelho e coloque o pé apoiado no chão. Usando as mãos ou uma toalha, puxe suavemente os dedos dos pés em direção ao corpo, sentindo um alongamento na panturrilha. Mantenha o alongamento por 20 a 30 segundos. Solte o alongamento e repita na outra perna.', '/exercise-media/bstrainer/1708.gif', 'hasaneyldrm', '1708'),
  ('b1d7a80a-0000-4000-8000-000000001709'::uuid, null, 'alongamento de glúteos deitado assistido', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Deite-se de costas com as pernas estendidas. Dobre o joelho direito e coloque o tornozelo direito na coxa esquerda, logo acima do joelho. Segure a coxa esquerda com as duas mãos e puxe-a suavemente em direção ao peito. Mantenha o alongamento por 20 a 30 segundos. Solte e repita do outro lado.', '/exercise-media/bstrainer/1709.gif', 'hasaneyldrm', '1709'),
  ('b1d7a80a-0000-4000-8000-000000001710'::uuid, null, 'alongamento assistido de glúteo e piriforme deitado', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Deite-se de costas com as pernas estendidas. Dobre o joelho direito e coloque o tornozelo direito na coxa esquerda, logo acima do joelho. Segure a coxa esquerda com as duas mãos e puxe-a suavemente em direção ao peito. Mantenha o alongamento por 20 a 30 segundos. Solte o alongamento e repita do outro lado.', '/exercise-media/bstrainer/1710.gif', 'hasaneyldrm', '1710'),
  ('b1d7a80a-0000-4000-8000-000000000012'::uuid, null, 'elevação assistida da perna em decúbito com projeção lateral para baixo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'obliques']::text[], 'machine', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Coloque as mãos sob os glúteos para obter apoio. Envolva os abdominais e levante as pernas do chão, mantendo-as retas. Mantendo as pernas juntas, abaixe-as para o lado até que fiquem alguns centímetros acima do solo. Faça uma pausa por um momento e depois levante as pernas de volta à posição inicial. Repita o movimento para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0012.gif', 'hasaneyldrm', '0012'),
  ('b1d7a80a-0000-4000-8000-000000000013'::uuid, null, 'elevação assistida da perna em decúbito com lançamento para baixo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'quadriceps']::text[], 'machine', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Coloque as mãos sob os glúteos para obter apoio. Envolva seu núcleo e levante as pernas do chão, mantendo-as retas. Levante as pernas até que fiquem perpendiculares ao chão. Abaixe as pernas de volta à posição inicial. Simultaneamente, jogue as pernas em direção ao chão, mantendo-as retas. Levante as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0013.gif', 'hasaneyldrm', '0013'),
  ('b1d7a80a-0000-4000-8000-000000000014'::uuid, null, 'movimento assistido torção russa', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Sente-se no chão com os joelhos dobrados e os pés apoiados no chão. Segure a bola medicinal com as duas mãos na frente do peito. Incline-se ligeiramente para trás, envolvendo os abdominais e mantendo as costas retas. Gire lentamente o tronco para a direita, trazendo a bola medicinal para o lado direito do corpo. Faça uma pausa por um momento e depois gire o tronco para a esquerda, trazendo a bola medicinal para o lado esquerdo do corpo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0014.gif', 'hasaneyldrm', '0014'),
  ('b1d7a80a-0000-4000-8000-000000000015'::uuid, null, 'pull-up paralelo assistido com pegada próxima', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a máquina ao peso e altura desejados. Coloque as mãos nas barras paralelas com uma pegada fechada, com as palmas voltadas uma para a outra. Pendure-se nas barras com os braços totalmente estendidos e os pés fora do chão. Envolva os músculos das costas e puxe o corpo em direção às barras, mantendo os cotovelos próximos ao corpo. Continue puxando até que seu queixo fique acima das barras. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0015.gif', 'hasaneyldrm', '0015'),
  ('b1d7a80a-0000-4000-8000-000000000016'::uuid, null, 'isquiotibiais em decúbito ventral assistido', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'lower back']::text[], 'machine', false, 'Deite-se de bruços sobre um tapete ou banco com as pernas totalmente estendidas. Tenha um parceiro ou use uma faixa de resistência para proteger os tornozelos. Envolva os isquiotibiais e levante as pernas em direção aos glúteos, mantendo os joelhos retos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0016.gif', 'hasaneyldrm', '0016'),
  ('b1d7a80a-0000-4000-8000-000000001713'::uuid, null, 'alongamento assistido dos quadríceps em decúbito ventral', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Deite-se de bruços no chão com as pernas estendidas. Dobre o joelho esquerdo e estenda a mão esquerda para trás para agarrar o pé ou tornozelo esquerdo. Puxe suavemente o pé esquerdo em direção aos glúteos, sentindo um alongamento no quadríceps esquerdo. Mantenha o alongamento por 20 a 30 segundos e depois solte. Repita com a perna direita.', '/exercise-media/bstrainer/1713.gif', 'hasaneyldrm', '1713'),
  ('b1d7a80a-0000-4000-8000-000000001714'::uuid, null, 'alongamento assistido do reto femoral em decúbito ventral', 'core', ARRAY['abs', 'quadriceps']::text[], ARRAY['quadriceps']::text[], 'machine', false, 'Deite-se de bruços no chão com as pernas esticadas. Dobre o joelho direito e estenda a mão direita para trás para agarrar o pé ou tornozelo direito. Puxe suavemente o pé ou tornozelo direito em direção aos glúteos, sentindo um alongamento na frente da coxa direita. Mantenha o alongamento por 20 a 30 segundos. Solte e repita do outro lado.', '/exercise-media/bstrainer/1714.gif', 'hasaneyldrm', '1714'),
  ('b1d7a80a-0000-4000-8000-000000000017'::uuid, null, 'pull-up assistido', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a máquina para as configurações de peso e altura desejadas. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Pendure-se com os braços totalmente estendidos e os pés fora do chão. Envolva os músculos das costas e puxe o corpo em direção às alças, mantendo os cotovelos próximos ao corpo. Continue puxando até que o queixo fique acima das alças. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0017.gif', 'hasaneyldrm', '0017'),
  ('b1d7a80a-0000-4000-8000-000000001716'::uuid, null, 'alongamento do peitoral maior sentado assistido com bola de estabilidade', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e as costas retas. Segure uma bola de estabilidade com as duas mãos e estenda os braços à sua frente. Abaixe lentamente a bola de estabilidade em direção ao peito, sentindo um alongamento nos músculos peitorais. Mantenha o alongamento por alguns segundos e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1716.gif', 'hasaneyldrm', '1716'),
  ('b1d7a80a-0000-4000-8000-000000001712'::uuid, null, 'alongamento assistido do adutor deitado de lado', 'isolation', ARRAY['adductors', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Deite-se de lado com as pernas esticadas e empilhadas uma sobre a outra. Dobre ligeiramente a perna de baixo para obter estabilidade. Coloque o pé de cima em uma superfície estável, como um banco ou degrau. Mantendo a perna de cima reta, abaixe-a lentamente em direção ao chão, sentindo um alongamento na parte interna da coxa. Mantenha o alongamento por 20 a 30 segundos. Volte à posição inicial e repita do outro lado.', '/exercise-media/bstrainer/1712.gif', 'hasaneyldrm', '1712'),
  ('b1d7a80a-0000-4000-8000-000000001758'::uuid, null, 'abdominais assistidos', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Sente-se na beira de um banco ou peça a alguém que segure seus pés. Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1758.gif', 'hasaneyldrm', '1758'),
  ('b1d7a80a-0000-4000-8000-000000001431'::uuid, null, 'barra fixa em pé assistida', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a máquina para o nível de assistência desejado. Fique na plataforma dos pés e segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha o peito para cima e os ombros para trás, envolva o núcleo e dobre levemente os joelhos. Puxe o corpo para cima flexionando os cotovelos e direcionando-os para os lados. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1431.gif', 'hasaneyldrm', '1431'),
  ('b1d7a80a-0000-4000-8000-000000001432'::uuid, null, 'pull-up em pé assistido', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a máquina para as configurações de peso e altura desejadas. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Envolva os dorsais e os bíceps e puxe-se em direção às alças. Faça uma pausa por um momento no topo, contraindo os músculos das costas. Abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1432.gif', 'hasaneyldrm', '1432'),
  ('b1d7a80a-0000-4000-8000-000000000018'::uuid, null, 'extensão assistida de tríceps em pé (com toalha)', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma toalha com as duas mãos atrás da cabeça. Mantenha os cotovelos próximos às orelhas e os braços parados. Estenda lentamente os antebraços para cima, apertando o tríceps na parte superior. Faça uma pausa por um momento e, em seguida, abaixe lentamente a toalha de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0018.gif', 'hasaneyldrm', '0018'),
  ('b1d7a80a-0000-4000-8000-000000000019'::uuid, null, 'mergulho assistido de tríceps (ajoelhamento)', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Ajuste a máquina ao peso e altura desejados. Ajoelhe-se na almofada de frente para a máquina, com as mãos segurando as alças. Abaixe o corpo dobrando os cotovelos, mantendo as costas retas e próximas à máquina. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0019.gif', 'hasaneyldrm', '0019'),
  ('b1d7a80a-0000-4000-8000-000000002364'::uuid, null, 'mergulho torácico assistido com pegada aberta (ajoelhamento)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a máquina na altura desejada e prenda os joelhos na almofada. Segure as alças com força e mantenha os cotovelos levemente dobrados. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Empurre-se de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2364.gif', 'hasaneyldrm', '2364'),
  ('b1d7a80a-0000-4000-8000-000000003220'::uuid, null, 'saltos montados (masculino)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada. Salte explosivamente para cima, estendendo as pernas e os braços. Enquanto estiver no ar, abra as pernas e leve os braços para os lados. Pouse suavemente com os pés afastados na largura dos ombros, dobrando os joelhos para absorver o impacto. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3220.gif', 'hasaneyldrm', '3220'),
  ('b1d7a80a-0000-4000-8000-000000003672'::uuid, null, 'passo para frente e para trás', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dê um passo à frente com o pé direito, dobrando o joelho e abaixando o corpo em uma posição de estocada. Empurre com o pé direito e volte à posição inicial. Repita o movimento com o pé esquerdo, alternando as pernas a cada passo. Continue andando para frente e para trás, mantendo um ritmo constante. Repita pela duração desejada ou número de repetições.', '/exercise-media/bstrainer/3672.gif', 'hasaneyldrm', '3672'),
  ('b1d7a80a-0000-4000-8000-000000001314'::uuid, null, 'extensão de costas na bola de exercícios', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e deite-se de bruços sobre ela, com os quadris apoiados na bola e os pés apoiados em uma parede ou outra superfície estável. Posicione as mãos atrás da cabeça ou cruzadas sobre o peito. Envolva o núcleo e levante lentamente a parte superior do corpo da bola, estendendo as costas até que o corpo forme uma linha reta da cabeça aos calcanhares. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1314.gif', 'hasaneyldrm', '1314'),
  ('b1d7a80a-0000-4000-8000-000000003297'::uuid, null, 'alavanca traseira', 'isolation', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms', 'core']::text[], 'bodyweight', false, 'Comece pendurado em uma barra pull-up com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Envolva seu núcleo e puxe as omoplatas para baixo e para trás. Dobre os joelhos e coloque-os em direção ao peito. Levante lentamente as pernas, mantendo-as retas, até que o corpo fique paralelo ao chão. Mantenha essa posição por alguns segundos e depois abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3297.gif', 'hasaneyldrm', '3297'),
  ('b1d7a80a-0000-4000-8000-000000001405'::uuid, null, 'alongamento do peitoral traseiro', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Estenda os braços à sua frente, paralelos ao chão. Cruze os braços na frente do corpo, com o braço direito sobre o braço esquerdo. Entrelace os dedos e gire as palmas para longe do corpo. Levante lentamente os braços para cima e para longe do corpo, sentindo um alongamento nas costas e no peito. Mantenha o alongamento por 15 a 30 segundos e depois solte. Repita no lado oposto.', '/exercise-media/bstrainer/1405.gif', 'hasaneyldrm', '1405'),
  ('b1d7a80a-0000-4000-8000-000000001473'::uuid, null, 'salto para trás', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e salte para trás, empurrando com os dois pés. Pouse suavemente na planta dos pés, dobrando os joelhos para absorver o impacto. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1473.gif', 'hasaneyldrm', '1473'),
  ('b1d7a80a-0000-4000-8000-000000000020'::uuid, null, 'quadro de equilíbrio', 'isolation', ARRAY['quads', 'calves']::text[], ARRAY['calves', 'hamstrings', 'glutes']::text[], 'bodyweight', false, 'Coloque a prancha de equilíbrio em uma superfície plana. Suba na prancha de equilíbrio com um pé, garantindo que esteja centralizado. Transfira lentamente o peso para o pé na prancha de equilíbrio, mantendo o núcleo engajado. Mantenha o equilíbrio e a estabilidade enquanto mantém a posição pelo período de tempo desejado. Repita o exercício com o outro pé.', '/exercise-media/bstrainer/0020.gif', 'hasaneyldrm', '0020'),
  ('b1d7a80a-0000-4000-8000-000000000968'::uuid, null, 'rosca alternada de bíceps com banda', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'band', true, 'Fique em pé com os pés afastados na largura dos ombros e segure a faixa com uma pegada por baixo, com as palmas voltadas para cima. Mantenha os cotovelos próximos ao corpo e lentamente enrole um braço em direção ao ombro, apertando o bíceps na parte superior. Abaixe o braço de volta à posição inicial e repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0968.gif', 'hasaneyldrm', '0968'),
  ('b1d7a80a-0000-4000-8000-000000000969'::uuid, null, 'banda alternando v-up', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'band', true, 'Deite-se de costas com as pernas esticadas e os braços estendidos acima da cabeça, segurando a faixa. Envolva os abdominais e levante as pernas e a parte superior do corpo do chão simultaneamente, alcançando as mãos na direção dos dedos dos pés. Ao abaixar as pernas e a parte superior do corpo, mude a posição das pernas, cruzando uma sobre a outra. Repita o movimento, alternando a posição das pernas a cada repetição. Continue pelo número desejado de repetições.', '/exercise-media/bstrainer/0969.gif', 'hasaneyldrm', '0969'),
  ('b1d7a80a-0000-4000-8000-000000000970'::uuid, null, 'pull-up assistido por banda', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'band', false, 'Prenda a faixa a uma barra suspensa ou a um ponto de ancoragem resistente. Suba na faixa e segure a barra com as palmas voltadas para você e as mãos um pouco mais largas que a largura dos ombros. Pendure-se com os braços totalmente estendidos, mantendo o núcleo engajado e os ombros para baixo e para trás. Puxe o corpo em direção à barra, apertando as omoplatas e empurrando os cotovelos para baixo em direção aos quadris. Continue puxando até que o queixo esteja acima da barra e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0970.gif', 'hasaneyldrm', '0970'),
  ('b1d7a80a-0000-4000-8000-000000000971'::uuid, null, 'desenrolamento da roda assistido por banda', 'core', ARRAY['abs', 'lower back']::text[], ARRAY['lower back']::text[], 'band', false, 'Ajoelhe-se no chão e segure as alças da faixa com as duas mãos, com as palmas voltadas para baixo. Coloque a faixa no chão à sua frente e posicione as mãos na largura dos ombros. Envolva seu núcleo e role lentamente a roda para frente, estendendo seu corpo o máximo que puder enquanto mantém o controle. Faça uma pausa por um momento no ponto mais distante e, em seguida, gire lentamente a roda em direção aos joelhos para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0971.gif', 'hasaneyldrm', '0971'),
  ('b1d7a80a-0000-4000-8000-000000001254'::uuid, null, 'supino de banda', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'band', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure as alças da faixa com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Estenda totalmente os braços, afastando as faixas do peito. Abaixe lentamente as faixas até o peito, mantendo os cotovelos em um ângulo de 90 graus. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1254.gif', 'hasaneyldrm', '1254'),
  ('b1d7a80a-0000-4000-8000-000000000980'::uuid, null, 'faixa de extensão de quadril curvada', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'band', false, 'Prenda a faixa a um ponto de ancoragem resistente na altura do tornozelo. Fique de costas para o ponto de ancoragem, com os pés afastados na largura dos ombros. Dê um passo para trás para criar tensão na faixa, mantendo os joelhos ligeiramente flexionados. Dobre os quadris e incline-se para a frente, mantendo a coluna neutra. Estenda a perna direita para trás, apertando os glúteos na parte superior. Abaixe a perna direita e repita com a perna esquerda. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/0980.gif', 'hasaneyldrm', '0980'),
  ('b1d7a80a-0000-4000-8000-000000000972'::uuid, null, 'crise de bicicleta de banda', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'obliques']::text[], 'band', false, 'Deite-se de costas com as mãos atrás da cabeça e os joelhos dobrados. Levante os pés do chão e traga o joelho direito em direção ao peito enquanto gira simultaneamente o tronco para trazer o cotovelo esquerdo em direção ao joelho direito. Estique a perna direita enquanto aproxima o joelho esquerdo em direção ao peito e gira o tronco para trazer o cotovelo direito em direção ao joelho esquerdo. Continue alternando o movimento de torção, como se estivesse pedalando uma bicicleta, enquanto mantém o núcleo engajado durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0972.gif', 'hasaneyldrm', '0972'),
  ('b1d7a80a-0000-4000-8000-000000000974'::uuid, null, 'pulldown de aperto próximo da banda', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem alto, como uma barra suspensa ou uma viga resistente. Fique de frente para o ponto de ancoragem e segure a faixa com uma pegada por baixo, com as mãos afastadas na largura dos ombros. Dê um passo para trás para criar tensão na faixa, mantendo os pés afastados na largura do quadril. Envolva o núcleo e mantenha as costas retas enquanto puxa a faixa em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente a faixa de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0974.gif', 'hasaneyldrm', '0974'),
  ('b1d7a80a-0000-4000-8000-000000000975'::uuid, null, 'flexão de pegada fechada', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'band', false, 'Coloque uma faixa em volta dos braços, logo acima dos cotovelos. Assuma uma posição de flexão com as mãos diretamente sob os ombros e o corpo em linha reta da cabeça aos calcanhares. Dobre os cotovelos e abaixe o peito em direção ao chão, mantendo os cotovelos próximos ao corpo. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0975.gif', 'hasaneyldrm', '0975'),
  ('b1d7a80a-0000-4000-8000-000000000976'::uuid, null, 'ondulação de concentração de banda', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'band', false, 'Sente-se em um banco ou cadeira com as pernas afastadas e os pés apoiados no chão. Segure uma ponta da faixa com a mão e pise na outra ponta com o pé do mesmo lado. Incline-se ligeiramente para a frente e apoie o cotovelo na parte interna da coxa, logo acima do joelho. Com a palma da mão voltada para cima, enrole lentamente a mão em direção ao ombro, mantendo o braço parado. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a mão de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0976.gif', 'hasaneyldrm', '0976'),
  ('b1d7a80a-0000-4000-8000-000000003117'::uuid, null, 'faixa fixa traseira close grip pulldown', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'band', false, 'Prenda a faixa em um ponto fixo acima de você, como uma barra suspensa ou uma viga resistente. Sente-se em um banco ou cadeira de frente para a banda, com os pés apoiados no chão e os joelhos dobrados. Segure a faixa com força, com as palmas voltadas para você. Mantenha as costas retas e envolva seu núcleo. Puxe a faixa para baixo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no final do movimento, sentindo a contração no seu grande dorsal. Solte lentamente a faixa de volta à posição inicial, mantendo o controle durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3117.gif', 'hasaneyldrm', '3117'),
  ('b1d7a80a-0000-4000-8000-000000003116'::uuid, null, 'faixa fixa traseira suspensa pulldown', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem resistente acima de sua cabeça. Fique de frente para o ponto de ancoragem com os pés afastados na largura dos ombros. Segure a faixa com uma pegada por baixo, com as mãos ligeiramente mais afastadas que a largura dos ombros. Dê um passo para trás para criar tensão na faixa, mantendo os braços totalmente estendidos. Envolva seu núcleo e aperte as omoplatas. Puxe a faixa para baixo em direção ao peito, conduzindo com os cotovelos. Faça uma pausa por um momento no final do movimento, sentindo a contração no seu grande dorsal. Libere lentamente a tensão na faixa e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3116.gif', 'hasaneyldrm', '3116'),
  ('b1d7a80a-0000-4000-8000-000000000977'::uuid, null, 'elevação lateral frontal da banda', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'upper back']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a faixa na frente das coxas com as palmas das mãos voltadas para baixo. Mantenha os braços retos e levante a faixa à sua frente até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a faixa de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0977.gif', 'hasaneyldrm', '0977'),
  ('b1d7a80a-0000-4000-8000-000000000978'::uuid, null, 'elevação frontal da banda', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a faixa na frente das coxas com as palmas das mãos voltadas para baixo. Mantenha os braços esticados e levante-os lentamente para a frente até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0978.gif', 'hasaneyldrm', '0978'),
  ('b1d7a80a-0000-4000-8000-000000001408'::uuid, null, 'levantamento de quadril com banda', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'band', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque uma faixa de resistência logo acima dos joelhos. Envolva seus glúteos e músculos centrais. Pressione os calcanhares no chão e levante os quadris do chão, apertando os glúteos na parte superior. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1408.gif', 'hasaneyldrm', '1408'),
  ('b1d7a80a-0000-4000-8000-000000000979'::uuid, null, 'prensa pallof horizontal de banda', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'glutes']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem resistente na altura da cintura. Fique perpendicular ao ponto de ancoragem com os pés afastados na largura dos ombros. Segure a alça da faixa com as duas mãos e afaste-se do ponto de ancoragem para criar tensão na faixa. Leve as mãos ao peito, mantendo os cotovelos dobrados e próximos ao corpo. Envolva seu núcleo e mantenha uma postura estável. Estenda os braços à sua frente, afastando a faixa do corpo. Mantenha a posição estendida por alguns segundos, concentrando-se em manter a tensão no núcleo. Lentamente, traga as mãos de volta ao peito, resistindo ao puxão da faixa. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0979.gif', 'hasaneyldrm', '0979'),
  ('b1d7a80a-0000-4000-8000-000000000981'::uuid, null, 'banda jack faca abdominais', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'band', false, 'Deite-se de costas com as pernas esticadas e os braços estendidos acima da cabeça, segurando a faixa. Envolva os abdominais e levante as pernas e a parte superior do corpo simultaneamente, aproximando as mãos dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas e a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0981.gif', 'hasaneyldrm', '0981'),
  ('b1d7a80a-0000-4000-8000-000000000983'::uuid, null, 'faixa ajoelhada pulldown de um braço', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids']::text[], 'band', true, 'Prenda a faixa em um ponto de ancoragem resistente acima de sua cabeça. Ajoelhe-se e segure a faixa com uma das mãos, com a palma voltada para baixo. Estenda o braço totalmente acima da cabeça, mantendo o cotovelo ligeiramente flexionado. Envolva os músculos posteriores e puxe a faixa para o lado, trazendo o cotovelo em direção à caixa torácica. Faça uma pausa na parte inferior, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0983.gif', 'hasaneyldrm', '0983'),
  ('b1d7a80a-0000-4000-8000-000000000985'::uuid, null, 'banda ajoelhada torcendo crunch', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem resistente na altura da cintura. Ajoelhe-se de costas para o ponto de ancoragem e segure a faixa com as duas mãos, mantendo os cotovelos dobrados e próximos aos lados. Envolva os abdominais e gire lentamente o tronco para o lado, trazendo as mãos em direção ao quadril oposto. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0985.gif', 'hasaneyldrm', '0985'),
  ('b1d7a80a-0000-4000-8000-000000000984'::uuid, null, 'faixa de rotação interna do quadril deitado', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'band', false, 'Deite-se de costas com as pernas esticadas e uma faixa de resistência enrolada em volta dos pés. Dobre os joelhos e leve-os em direção ao peito, mantendo os pés juntos. Gire lentamente os joelhos para fora, afastando-os um do outro, enquanto mantém os pés juntos. Faça uma pausa no final da rotação e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0984.gif', 'hasaneyldrm', '0984'),
  ('b1d7a80a-0000-4000-8000-000000001002'::uuid, null, 'faixa deitada com perna esticada levantada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'band', false, 'Deite-se de costas com as pernas esticadas e os pés juntos. Coloque a faixa ao redor dos arcos dos pés e segure as pontas da faixa com as mãos. Envolvendo os abdominais, levante ambas as pernas do chão até que fiquem perpendiculares ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1002.gif', 'hasaneyldrm', '1002'),
  ('b1d7a80a-0000-4000-8000-000000000986'::uuid, null, 'faixa de bíceps com um braço acima da cabeça', 'push_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'band', true, 'Fique em pé com os pés afastados na largura dos ombros e coloque uma extremidade da faixa sob o pé. Segure a outra extremidade da faixa com o braço totalmente estendido acima da cabeça e a palma voltada para a frente. Mantendo o braço parado, enrole o antebraço em direção ao ombro, apertando o bíceps. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente o antebraço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0986.gif', 'hasaneyldrm', '0986'),
  ('b1d7a80a-0000-4000-8000-000000000987'::uuid, null, 'agachamento dividido com uma perna e um braço', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'band', true, 'Fique em pé com os pés afastados na largura do quadril e coloque uma faixa de resistência ao redor dos tornozelos. Estenda uma perna para a frente e descanse a parte superior do pé em um banco ou dê um passo atrás de você. Segure-se em um suporte com uma mão para manter o equilíbrio. Dobre a perna de apoio e abaixe o corpo até uma posição agachada, mantendo o joelho alinhado com os dedos dos pés. Empurre o calcanhar para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0987.gif', 'hasaneyldrm', '0987'),
  ('b1d7a80a-0000-4000-8000-000000000988'::uuid, null, 'faixa um braço em pé remada baixa', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'band', true, 'Prenda a faixa a um ponto de ancoragem estável na altura da cintura. Fique de frente para o ponto de ancoragem com os pés afastados na largura dos ombros. Segure a faixa com uma mão, com a palma voltada para dentro, e dê um passo para trás para criar tensão na faixa. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Puxe a faixa em direção à cintura, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente a faixa de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0988.gif', 'hasaneyldrm', '0988'),
  ('b1d7a80a-0000-4000-8000-000000000989'::uuid, null, 'faixa com um braço torcendo o peito', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'band', true, 'Prenda a faixa a um ponto de ancoragem resistente na altura do peito. Fique de lado voltado para o ponto de ancoragem e segure a faixa com uma mão. Afaste-se do ponto de ancoragem para criar tensão na faixa. Posicione os pés na largura dos ombros e dobre ligeiramente os joelhos. Passe a mão que segura a faixa pelo corpo, em direção ao ombro oposto. Mantendo a tensão na faixa, empurre a mão para frente e para longe do corpo, estendendo o braço. Retorne lentamente à posição inicial e repita o número desejado de repetições. Troque de lado e repita o exercício com a outra mão.', '/exercise-media/bstrainer/0989.gif', 'hasaneyldrm', '0989'),
  ('b1d7a80a-0000-4000-8000-000000000990'::uuid, null, 'faixa um braço torcendo remada sentada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'band', true, 'Sente-se em um banco ou cadeira com os pés apoiados no chão e as costas retas. Segure a faixa com uma mão e estenda o braço totalmente à sua frente. Mantendo as costas retas, puxe a faixa em direção ao corpo dobrando o cotovelo e apertando as omoplatas. Ao mesmo tempo, gire o tronco em direção ao braço que puxa. Faça uma pausa por um momento no topo, depois libere lentamente a tensão da faixa e retorne à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0990.gif', 'hasaneyldrm', '0990'),
  ('b1d7a80a-0000-4000-8000-000000000991'::uuid, null, 'banda passa', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'band', false, 'Prenda uma faixa de resistência a um ponto de ancoragem resistente no nível do solo. Fique de costas para o ponto de ancoragem, com os pés afastados na largura dos ombros. Dê um passo à frente para criar tensão na faixa, mantendo os joelhos ligeiramente flexionados. Dobre os quadris e empurre os glúteos para trás, mantendo uma ligeira flexão dos joelhos. Abaixe o tronco até ficar paralelo ao chão, sentindo um alongamento nos isquiotibiais. Leve os quadris para a frente e contraia os glúteos para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0991.gif', 'hasaneyldrm', '0991'),
  ('b1d7a80a-0000-4000-8000-000000000992'::uuid, null, 'banda push sit-up', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'band', false, 'Prenda a faixa com segurança a um ponto de ancoragem estável. Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Segure a faixa com as duas mãos e estenda os braços em direção ao teto. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0992.gif', 'hasaneyldrm', '0992'),
  ('b1d7a80a-0000-4000-8000-000000000993'::uuid, null, 'banda reversa fly', 'pull_h', ARRAY['delts', 'upper back']::text[], ARRAY['upper back', 'trapezius']::text[], 'band', false, 'Prenda a faixa a um objeto estacionário na altura do peito. Fique em pé com os pés afastados na largura dos ombros e segure a faixa com as duas mãos à sua frente. Mantenha os braços retos e levante-os para os lados até que fiquem paralelos ao chão. Aperte as omoplatas no início do movimento. Abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0993.gif', 'hasaneyldrm', '0993'),
  ('b1d7a80a-0000-4000-8000-000000000994'::uuid, null, 'curvatura reversa do pulso com banda', 'isolation', ARRAY['forearms']::text[], ARRAY['forearms']::text[], 'band', false, 'Sente-se em um banco ou cadeira com os pés apoiados no chão. Segure a faixa com uma pegada pronada, com as palmas voltadas para baixo, e enrole-a nos dedos. Descanse os antebraços nas coxas, com os pulsos pendurados na borda. Enrole lentamente os pulsos para cima, apertando os antebraços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os pulsos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0994.gif', 'hasaneyldrm', '0994'),
  ('b1d7a80a-0000-4000-8000-000000000996'::uuid, null, 'faixa de rotação interna do quadril sentado', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'band', false, 'Sente-se em uma cadeira ou banco com as costas retas e os pés apoiados no chão. Coloque uma faixa de resistência em volta das coxas, logo acima dos joelhos. Mantenha os joelhos dobrados em um ângulo de 90 graus e os pés afastados na largura dos ombros. Envolva os glúteos e gire lentamente os joelhos para fora, empurrando contra a resistência da faixa. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0996.gif', 'hasaneyldrm', '0996'),
  ('b1d7a80a-0000-4000-8000-000000001011'::uuid, null, 'torção sentada na banda', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'band', false, 'Sente-se no chão com as pernas estendidas à sua frente e as costas retas. Enrole a faixa em volta da cintura e segure as pontas com as duas mãos. Envolva os abdominais e gire lentamente o tronco para o lado, mantendo as costas retas e os pés no chão. Faça uma pausa no final da torção e depois retorne lentamente à posição inicial. Repita a torção para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1011.gif', 'hasaneyldrm', '1011'),
  ('b1d7a80a-0000-4000-8000-000000000997'::uuid, null, 'pressão de ombro com faixa', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa sob os pés. Segure a faixa com as palmas voltadas para a frente e levante as mãos até a altura dos ombros, com os cotovelos dobrados. Pressione a faixa acima da cabeça, estendendo totalmente os braços. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a faixa até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0997.gif', 'hasaneyldrm', '0997'),
  ('b1d7a80a-0000-4000-8000-000000001018'::uuid, null, 'banda encolher os ombros', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa sob os pés, segurando as pontas com as mãos. Mantenha os braços retos e relaxados e deixe a faixa pendurada na frente das coxas. Envolva suas armadilhas encolhendo os ombros para cima, levantando a faixa o mais alto possível. Mantenha a contração por um momento e depois abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1018.gif', 'hasaneyldrm', '1018'),
  ('b1d7a80a-0000-4000-8000-000000000998'::uuid, null, 'extensão de tríceps lateral da banda', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a faixa com as duas mãos, com as palmas voltadas para baixo. Estenda os braços para os lados, mantendo-os paralelos ao chão. Dobre lentamente os cotovelos e leve as mãos em direção aos ombros, mantendo os braços imóveis. Faça uma pausa por um momento e, em seguida, estenda lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0998.gif', 'hasaneyldrm', '0998'),
  ('b1d7a80a-0000-4000-8000-000000000999'::uuid, null, 'panturrilha de perna única com banda', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'band', true, 'Fique em pé com os pés afastados na largura do quadril e coloque a faixa ao redor da planta do pé esquerdo. Segure-se em um objeto estável para manter o equilíbrio, se necessário. Levante lentamente o calcanhar esquerdo do chão, levantando o peso do corpo sobre a planta do pé. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar esquerdo de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para a perna direita.', '/exercise-media/bstrainer/0999.gif', 'hasaneyldrm', '0999'),
  ('b1d7a80a-0000-4000-8000-000000001000'::uuid, null, 'elevação reversa de panturrilha com faixa unipodal', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'band', true, 'Fique em pé com os pés afastados na largura do quadril e coloque a faixa ao redor da planta do pé. Segure-se em um objeto estável para manter o equilíbrio. Levante lentamente o calcanhar do chão, colocando o peso do corpo na planta do pé. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita o número desejado de repetições e depois mude para a outra perna.', '/exercise-media/bstrainer/1000.gif', 'hasaneyldrm', '1000'),
  ('b1d7a80a-0000-4000-8000-000000001001'::uuid, null, 'agachamento dividido com faixa unipodal', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'band', true, 'Fique em pé com os pés afastados na largura do quadril e coloque uma faixa de resistência ao redor dos tornozelos. Dê um grande passo à frente com o pé direito e um passo menor para trás com o pé esquerdo. Dobre os joelhos e abaixe o corpo até que a coxa direita fique paralela ao chão, mantendo o joelho esquerdo ligeiramente acima do solo. Empurre o calcanhar direito para retornar à posição inicial. Repita do outro lado.', '/exercise-media/bstrainer/1001.gif', 'hasaneyldrm', '1001'),
  ('b1d7a80a-0000-4000-8000-000000001004'::uuid, null, 'agachamento de banda', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e a faixa colocada logo acima dos joelhos. Mantendo o peito para cima e o núcleo engajado, empurre os quadris para trás e dobre os joelhos para agachar-se. Certifique-se de que seus joelhos estejam sobre os dedos dos pés e que seu peso esteja sobre os calcanhares. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1004.gif', 'hasaneyldrm', '1004'),
  ('b1d7a80a-0000-4000-8000-000000001003'::uuid, null, 'remada de agachamento banda', 'squat', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'back']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem resistente na altura da cintura. Fique de frente para o ponto de ancoragem com os pés afastados na largura dos ombros. Segure as alças da faixa com as palmas voltadas uma para a outra e os braços estendidos à sua frente. Dobre os joelhos e abaixe-se em uma posição agachada, mantendo as costas retas e o peito levantado. Na posição agachada, puxe as alças da faixa em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no topo, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1003.gif', 'hasaneyldrm', '1003'),
  ('b1d7a80a-0000-4000-8000-000000001005'::uuid, null, 'crise em pé da banda', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem resistente na altura da cintura. Fique de costas para o ponto de ancoragem, com os pés afastados na largura dos ombros. Segure a faixa com as duas mãos e leve-a até o peito, mantendo os cotovelos dobrados e próximos ao corpo. Envolva seus abdominais e lentamente avance, trazendo o peito em direção aos joelhos. Faça uma pausa por um momento no início da crise e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1005.gif', 'hasaneyldrm', '1005'),
  ('b1d7a80a-0000-4000-8000-000000001022'::uuid, null, 'banda em pé fileira delt traseira', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa sob os pés. Segure as alças da faixa com as palmas voltadas uma para a outra e os braços estendidos à sua frente. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Puxe a faixa em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1022.gif', 'hasaneyldrm', '1022'),
  ('b1d7a80a-0000-4000-8000-000000001007'::uuid, null, 'banda em pé torcendo crunch', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa na parte superior das costas, cruzando-a na frente do peito. Segure as pontas da faixa com as mãos, mantendo os cotovelos dobrados e próximos aos lados. Envolva os abdominais e gire o tronco para um lado, trazendo o cotovelo em direção ao joelho oposto. Faça uma pausa por um momento e depois retorne à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1007.gif', 'hasaneyldrm', '1007'),
  ('b1d7a80a-0000-4000-8000-000000001008'::uuid, null, 'avanço da banda', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'band', false, 'Coloque uma faixa em volta das coxas, logo acima dos joelhos. Fique de frente para um degrau ou plataforma com os pés afastados na largura do quadril. Suba na plataforma com o pé direito, empurrando o calcanhar. Estenda a perna esquerda atrás de você, mantendo-a reta. Abaixe o pé esquerdo de volta ao chão. Repita com o pé esquerdo subindo na plataforma. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/1008.gif', 'hasaneyldrm', '1008'),
  ('b1d7a80a-0000-4000-8000-000000001009'::uuid, null, 'faixa de levantamento terra com perna rígida', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa em volta dos tornozelos. Segure a faixa com as duas mãos na frente das coxas, com as palmas voltadas para o corpo. Mantendo as costas retas e o núcleo engajado, dobre os quadris e abaixe lentamente a parte superior do corpo em direção ao chão. Ao abaixar, empurre os quadris para trás e deixe os joelhos dobrarem ligeiramente. Abaixe a faixa em direção ao chão, sentindo um alongamento nos tendões da coxa. Faça uma pausa por um momento na parte inferior e, em seguida, envolva os glúteos e isquiotibiais para levantar a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1009.gif', 'hasaneyldrm', '1009'),
  ('b1d7a80a-0000-4000-8000-000000001023'::uuid, null, 'faixa reta para trás levantamento terra com perna rígida', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa em volta da parte superior das pernas. Segure a faixa com as duas mãos na frente das coxas, com as palmas voltadas para o corpo. Mantendo as costas retas e os joelhos ligeiramente dobrados, dobre os quadris e abaixe a faixa em direção ao chão. Sinta o alongamento dos isquiotibiais ao abaixar a faixa. Envolva os glúteos e isquiotibiais para levantar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1023.gif', 'hasaneyldrm', '1023'),
  ('b1d7a80a-0000-4000-8000-000000001010'::uuid, null, 'banda de levantamento terra com perna reta', 'hinge', ARRAY['spine', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa em volta dos pés. Segure a faixa com as duas mãos, com as palmas voltadas para o corpo, e mantenha os braços retos. Envolva seu núcleo e mantenha uma ligeira flexão nos joelhos. Incline-se lentamente para a frente na altura dos quadris, mantendo as costas retas e o peito levantado. Abaixe a faixa em direção ao chão, mantendo as pernas retas. Faça uma pausa na parte inferior e contraia os glúteos e isquiotibiais para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1010.gif', 'hasaneyldrm', '1010'),
  ('b1d7a80a-0000-4000-8000-000000001012'::uuid, null, 'prensa suspensa com torção de banda', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque a faixa sob os pés. Segure as alças da faixa na altura dos ombros com as palmas voltadas para frente. Envolva seu núcleo e pressione a faixa acima da cabeça, estendendo totalmente os braços. Ao pressionar, gire o tronco para o lado, mantendo os quadris estáveis. Faça uma pausa no topo e depois retorne à posição inicial. Repita a pressão e gire no lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1012.gif', 'hasaneyldrm', '1012'),
  ('b1d7a80a-0000-4000-8000-000000001369'::uuid, null, 'faixa de panturrilha com duas pernas - (faixa sob ambas as pernas) v. 2', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque uma faixa de resistência sob ambos os pés. Segure as pontas da faixa com as mãos para obter estabilidade. Levante os calcanhares do chão o mais alto possível, usando as panturrilhas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1369.gif', 'hasaneyldrm', '1369'),
  ('b1d7a80a-0000-4000-8000-000000001013'::uuid, null, 'pulldown oculto da banda', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'band', false, 'Prenda a faixa em um ponto de ancoragem alto, como uma barra suspensa ou uma viga resistente. Fique de frente para o ponto de ancoragem com os pés afastados na largura dos ombros. Segure a faixa com uma pegada por baixo, com as mãos ligeiramente mais afastadas que a largura dos ombros. Estenda os braços totalmente acima da cabeça, mantendo os cotovelos ligeiramente flexionados. Envolva os dorsais e puxe a faixa em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no final do movimento, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1013.gif', 'hasaneyldrm', '1013'),
  ('b1d7a80a-0000-4000-8000-000000001014'::uuid, null, 'banda v-up', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'band', false, 'Deite-se de costas com as pernas esticadas e os braços estendidos acima da cabeça, segurando a faixa. Envolvendo os abdominais, levante as pernas e a parte superior do corpo do chão simultaneamente, alcançando as mãos na direção dos dedos dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas e a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1014.gif', 'hasaneyldrm', '1014'),
  ('b1d7a80a-0000-4000-8000-000000001015'::uuid, null, 'prensa pallof vertical de banda', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'glutes']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e enrole a faixa em torno de um objeto resistente na altura do peito. Segure a faixa com as duas mãos e afaste-se do ponto de ancoragem, criando tensão na faixa. Posicione-se perpendicularmente ao ponto de ancoragem, com o lado voltado para a faixa. Estenda os braços à sua frente, mantendo as mãos na altura do peito. Envolva seu núcleo e pressione a faixa para longe do peito, estendendo totalmente os braços. Mantenha a posição por alguns segundos e, em seguida, traga lentamente a faixa de volta ao peito. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1015.gif', 'hasaneyldrm', '1015'),
  ('b1d7a80a-0000-4000-8000-000000001016'::uuid, null, 'curvatura do pulso da banda', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'band', false, 'Sente-se em um banco ou cadeira com os pés apoiados no chão. Segure a faixa com as duas mãos, com as palmas voltadas para cima, e descanse os antebraços nas coxas. Enrole lentamente os pulsos para cima, apertando os antebraços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os pulsos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1016.gif', 'hasaneyldrm', '1016'),
  ('b1d7a80a-0000-4000-8000-000000001017'::uuid, null, 'aumento da banda y', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'band', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a faixa na frente das coxas com as palmas voltadas para dentro. Mantenha os braços retos e levante-os para os lados, formando um ''Y'' com o corpo. Aperte as omoplatas no início do movimento. Abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1017.gif', 'hasaneyldrm', '1017'),
  ('b1d7a80a-0000-4000-8000-000000000023'::uuid, null, 'rosca alternada de bíceps com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', true, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra em cada mão, com as palmas voltadas para a frente. Mantenha os braços parados e expire enquanto enrola os pesos enquanto contrai os bíceps. Continue a levantar as barras até que os bíceps estejam totalmente contraídos e as barras estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire enquanto começa lentamente a abaixar as barras de volta à posição inicial. Repita pelo número desejado de repetições, alternando os braços.', '/exercise-media/bstrainer/0023.gif', 'hasaneyldrm', '0023'),
  ('b1d7a80a-0000-4000-8000-000000000024'::uuid, null, 'agachamento frontal com barra', 'squat', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes', 'calves']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e a barra apoiada na parte superior do peito, logo abaixo da clavícula. Segure a barra com uma pegada pronada, mantendo os cotovelos para cima e os braços paralelos ao chão. Abaixe o corpo até uma posição de agachamento, dobrando os joelhos e os quadris, mantendo as costas retas e o peito para cima. Faça uma pausa por um momento na parte inferior do agachamento e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0024.gif', 'hasaneyldrm', '0024'),
  ('b1d7a80a-0000-4000-8000-000000000025'::uuid, null, 'supino com barra', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada pronada um pouco mais larga que a largura dos ombros. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe a barra lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0025.gif', 'hasaneyldrm', '0025'),
  ('b1d7a80a-0000-4000-8000-000000000026'::uuid, null, 'agachamento com barra', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Coloque uma barra em um suporte de agachamento na altura do peito. Fique de costas para o rack, com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada, mantendo as costas retas e o peito para cima. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do rack e dê um passo para trás, garantindo que seus pés ainda estejam separados na largura dos ombros. Abaixe o corpo em um agachamento, mantendo os joelhos alinhados com os dedos dos pés. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0026.gif', 'hasaneyldrm', '0026'),
  ('b1d7a80a-0000-4000-8000-000000001316'::uuid, null, 'pulôver com barra e braço dobrado', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'barbell', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés no chão. Segure uma barra com uma pegada na largura dos ombros e estenda os braços acima do peito. Abaixe a barra atrás da cabeça enquanto mantém os braços ligeiramente flexionados. Faça uma pausa e levante a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1316.gif', 'hasaneyldrm', '1316'),
  ('b1d7a80a-0000-4000-8000-000000000027'::uuid, null, 'barra curvada sobre a remada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito para cima. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Puxe a barra em direção à parte inferior do peito, retraindo as omoplatas e contraindo os músculos das costas. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0027.gif', 'hasaneyldrm', '0027'),
  ('b1d7a80a-0000-4000-8000-000000002407'::uuid, null, 'rosca bíceps com barra (com arm blaster)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada por baixo, com as palmas voltadas para cima. Coloque os braços contra o blaster, mantendo os cotovelos próximos ao tronco. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2407.gif', 'hasaneyldrm', '2407'),
  ('b1d7a80a-0000-4000-8000-000000000028'::uuid, null, 'barra limpa e pressione', 'push_h', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes', 'shoulders', 'triceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e a barra no chão à sua frente. Dobre os joelhos e dobre os quadris para abaixar e segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Passe pelos calcanhares e estenda os quadris e joelhos para levantar a barra do chão, mantendo-a próxima ao corpo. Quando a barra atingir as coxas, estenda os quadris de forma explosiva, encolha os ombros e puxe a barra em direção ao peito. Quando a barra atingir a altura do peito, desça rapidamente por baixo dela e segure-a na altura dos ombros, com os cotovelos apontando para a frente e as palmas das mãos voltadas para cima. A partir da posição de captura, pressione a barra acima da cabeça, estendendo os braços e empurrando a barra para cima. Abaixe a barra de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0028.gif', 'hasaneyldrm', '0028'),
  ('b1d7a80a-0000-4000-8000-000000000029'::uuid, null, 'agachamento frontal com pegada limpa com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e a barra apoiada na parte superior do peito, com os cotovelos apontando para a frente. Abaixe o corpo dobrando os joelhos e empurrando os quadris para trás, como se estivesse recostado em uma cadeira. Mantenha o peito para cima e as costas retas enquanto desce, certificando-se de que os joelhos não ultrapassem os dedos dos pés. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para se levantar, estendendo os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0029.gif', 'hasaneyldrm', '0029'),
  ('b1d7a80a-0000-4000-8000-000000000030'::uuid, null, 'supino reto com barra fechada', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada fechada, um pouco mais estreita que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0030.gif', 'hasaneyldrm', '0030'),
  ('b1d7a80a-0000-4000-8000-000000000031'::uuid, null, 'rosca direta com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada por baixo, com as palmas voltadas para a frente. Mantenha os cotovelos próximos ao tronco e expire enquanto enrola os pesos enquanto contrai o bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire enquanto começa lentamente a abaixar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0031.gif', 'hasaneyldrm', '0031'),
  ('b1d7a80a-0000-4000-8000-000000000032'::uuid, null, 'levantamento terra com barra', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e a barra no chão à sua frente. Dobre os joelhos e dobre os quadris para abaixar o tronco e segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha as costas retas e o peito levantado enquanto você passa pelos calcanhares para levantar a barra do chão, estendendo os quadris e os joelhos. Ao ficar em pé, contraia os glúteos e mantenha o núcleo engajado. Abaixe a barra de volta ao chão dobrando os quadris e os joelhos, mantendo as costas retas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0032.gif', 'hasaneyldrm', '0032'),
  ('b1d7a80a-0000-4000-8000-000000000033'::uuid, null, 'supino de declínio com barra', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco inclinado com os pés seguros e a cabeça mais baixa que os quadris. Segure a barra com uma pegada pronada um pouco mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0033.gif', 'hasaneyldrm', '0033'),
  ('b1d7a80a-0000-4000-8000-000000000034'::uuid, null, 'pulôver com barra e braço dobrado', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'barbell', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os quadris e os pés protegidos. Segure uma barra com pegada pronada (palmas voltadas para você) e estenda os braços acima do peito. Abaixe a barra atrás da cabeça de forma controlada, mantendo os braços ligeiramente flexionados. Faça uma pausa por um momento e, em seguida, levante a barra de volta à posição inicial, contraindo os dorsais. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0034.gif', 'hasaneyldrm', '0034'),
  ('b1d7a80a-0000-4000-8000-000000000035'::uuid, null, 'declínio da barra, aderência próxima à pressão do crânio', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os pés e segure uma barra com força. Abaixe a barra em direção à testa dobrando os cotovelos, mantendo os braços parados. Faça uma pausa por um momento e estenda os braços para pressionar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0035.gif', 'hasaneyldrm', '0035'),
  ('b1d7a80a-0000-4000-8000-000000001255'::uuid, null, 'pulôver de declínio com barra', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os quadris e os pés protegidos. Segure a barra com uma pegada pronada (palmas voltadas para você) e com as mãos um pouco mais afastadas que a largura dos ombros. Estenda os braços acima do peito, mantendo uma ligeira flexão nos cotovelos. Abaixe a barra em um movimento de arco atrás da cabeça, sentindo um alongamento no peito e nos ombros. Faça uma pausa por um momento e depois retorne a barra à posição inicial invertendo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1255.gif', 'hasaneyldrm', '1255'),
  ('b1d7a80a-0000-4000-8000-000000000036'::uuid, null, 'barra declina pressão de grande aderência', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco inclinado com os pés seguros e a cabeça mais baixa que os quadris. Segure a barra com uma pegada larga, um pouco mais larga que a largura dos ombros. Abaixe a barra até o peito, mantendo os cotovelos para os lados. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0036.gif', 'hasaneyldrm', '0036'),
  ('b1d7a80a-0000-4000-8000-000000000037'::uuid, null, 'pulôver com barra larga e larga', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'barbell', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os quadris e os pés protegidos. Segure uma barra com uma pegada ampla e estenda os braços acima do peito. Abaixe a barra atrás da cabeça de maneira controlada, mantendo os braços retos. Faça uma pausa e levante a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0037.gif', 'hasaneyldrm', '0037'),
  ('b1d7a80a-0000-4000-8000-000000000038'::uuid, null, 'rosca direta com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada por baixo, com as palmas voltadas para cima. Deixe a barra pendurada com o braço estendido na frente das coxas. Mantendo os braços parados, enrole a barra em direção ao peito, contraindo os bíceps. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0038.gif', 'hasaneyldrm', '0038'),
  ('b1d7a80a-0000-4000-8000-000000001370'::uuid, null, 'elevação de panturrilha com barra no chão', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'barbell', false, 'Coloque uma barra no chão à sua frente. Fique em pé com as pontas dos pés na borda da barra, com os calcanhares pendurados. Segure-se em um objeto estável para manter o equilíbrio, se necessário. Levante os calcanhares o mais alto possível, usando as panturrilhas para levantar o corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1370.gif', 'hasaneyldrm', '1370'),
  ('b1d7a80a-0000-4000-8000-000000000039'::uuid, null, 'agachamento frontal com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na frente do peito com as mãos na largura dos ombros e os cotovelos apontando para a frente. Envolva o núcleo e mantenha o peito levantado enquanto abaixa o corpo até uma posição agachada, empurrando os quadris para trás e dobrando os joelhos. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0039.gif', 'hasaneyldrm', '0039'),
  ('b1d7a80a-0000-4000-8000-000000000041'::uuid, null, 'elevação frontal com barra', 'isolation', ARRAY['delts', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra na frente das coxas com uma pegada pronada. Mantenha os braços retos e levante a barra para frente e para cima até atingir a altura dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0041.gif', 'hasaneyldrm', '0041'),
  ('b1d7a80a-0000-4000-8000-000000000040'::uuid, null, 'levantamento frontal com barra e pulôver', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as palmas voltadas para baixo. Mantenha os braços retos e levante a barra à sua frente até atingir a altura dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Em seguida, abaixe a barra atrás da cabeça, mantendo os braços retos. Faça uma pausa na parte inferior e, em seguida, levante a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0040.gif', 'hasaneyldrm', '0040'),
  ('b1d7a80a-0000-4000-8000-000000000042'::uuid, null, 'agachamento frontal com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na frente dos ombros, apoiando-a na clavícula e nos ombros. Envolva o núcleo e mantenha o peito levantado enquanto abaixa o corpo até uma posição agachada, empurrando os quadris para trás e dobrando os joelhos. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0042.gif', 'hasaneyldrm', '0042'),
  ('b1d7a80a-0000-4000-8000-000000000043'::uuid, null, 'agachamento completo com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na parte superior das costas, apoiando-a nas armadilhas ou no deltóide posterior. Envolva seu núcleo e mantenha o peito para cima enquanto começa a abaixar o corpo. Dobre os joelhos e os quadris, empurrando os quadris para trás e para baixo, como se estivesse sentado em uma cadeira. Abaixe-se até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Mantenha os joelhos alinhados com os dedos dos pés e o peso nos calcanhares. Passe pelos calcanhares para se levantar, estendendo os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0043.gif', 'hasaneyldrm', '0043'),
  ('b1d7a80a-0000-4000-8000-000000001461'::uuid, null, 'agachamento completo com barra (ponto de vista de trás)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na parte superior das costas, apoiando-a nas armadilhas ou no deltóide posterior. Envolva seu núcleo e mantenha o peito para cima enquanto começa a abaixar o corpo. Dobre os joelhos e os quadris, empurrando os quadris para trás e para baixo, como se estivesse sentado em uma cadeira. Abaixe o corpo até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Mantenha os joelhos alinhados com os dedos dos pés e o peso nos calcanhares. Passe pelos calcanhares para se levantar, estendendo os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1461.gif', 'hasaneyldrm', '1461'),
  ('b1d7a80a-0000-4000-8000-000000001462'::uuid, null, 'agachamento completo com barra (ponto de vista lateral)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na parte superior das costas, apoiando-a nas armadilhas ou no deltóide posterior. Envolva seu núcleo e mantenha o peito para cima enquanto começa a abaixar o corpo. Dobre os joelhos e os quadris, empurrando os quadris para trás e para baixo, como se estivesse sentado em uma cadeira. Abaixe o corpo até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Mantenha os joelhos alinhados com os dedos dos pés e o peso nos calcanhares. Passe pelos calcanhares para se levantar, estendendo os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1462.gif', 'hasaneyldrm', '1462'),
  ('b1d7a80a-0000-4000-8000-000000001545'::uuid, null, 'agachamento zercher completo com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na dobra dos cotovelos, com as mãos segurando a barra para estabilidade. Envolva seu núcleo e mantenha o peito levantado enquanto abaixa os quadris para trás e para baixo, em uma posição de agachamento. Mantenha os joelhos alinhados com os dedos dos pés e o peso nos calcanhares. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Passe pelos calcanhares para se levantar, apertando os glúteos no topo do movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1545.gif', 'hasaneyldrm', '1545'),
  ('b1d7a80a-0000-4000-8000-000000001409'::uuid, null, 'ponte de glúteos com barra', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', false, 'Comece deitando-se de costas no chão, com os joelhos dobrados e os pés apoiados no chão. Coloque uma barra sobre os quadris, segurando-a firmemente com as duas mãos. Envolva os glúteos e os músculos centrais e, em seguida, levante os quadris do chão até que o corpo forme uma linha reta dos joelhos até os ombros. Faça uma pausa na parte superior, apertando os glúteos. Abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1409.gif', 'hasaneyldrm', '1409'),
  ('b1d7a80a-0000-4000-8000-000000003562'::uuid, null, 'ponte de glúteo com barra duas pernas no banco (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'core']::text[], 'barbell', false, 'Comece sentando-se na beira de um banco, com a parte superior das costas apoiada nele e os pés apoiados no chão, afastados na largura do quadril. Coloque uma barra sobre os quadris, segurando-a firmemente com as duas mãos. Envolva os glúteos e os músculos centrais e, em seguida, pressione os calcanhares para levantar os quadris do banco, criando uma linha reta dos joelhos até os ombros. Faça uma pausa na parte superior, apertando os glúteos. Abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3562.gif', 'hasaneyldrm', '3562'),
  ('b1d7a80a-0000-4000-8000-000000000044'::uuid, null, 'barra bom dia', 'hinge', ARRAY['hamstrings', 'lower back']::text[], ARRAY['lower back']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e a barra apoiada na parte superior das costas. Mantendo as costas retas e o núcleo engajado, incline-se para a frente na altura dos quadris, empurrando as nádegas para trás como se estivesse tentando tocar a parede atrás de você com os glúteos. Abaixe o tronco até ficar paralelo ao chão, sentindo um alongamento nos isquiotibiais. Faça uma pausa por um momento e depois retorne à posição inicial, contraindo os glúteos e empurrando os quadris para a frente. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0044.gif', 'hasaneyldrm', '0044'),
  ('b1d7a80a-0000-4000-8000-000000000045'::uuid, null, 'supino com barra guilhotina', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Abaixe a barra lentamente em direção ao pescoço, mantendo os cotovelos apontados para fora. Faça uma pausa quando a barra estiver logo acima do pescoço. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0045.gif', 'hasaneyldrm', '0045'),
  ('b1d7a80a-0000-4000-8000-000000000046'::uuid, null, 'agachamento com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os dedos dos pés ligeiramente voltados para fora. Segure a barra atrás das pernas, apoiando-a na parte superior das coxas. Abaixe o corpo dobrando os joelhos e quadris, mantendo as costas retas e o peito para cima. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0046.gif', 'hasaneyldrm', '0046'),
  ('b1d7a80a-0000-4000-8000-000000001436'::uuid, null, 'agachamento com barra alta', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Coloque a barra na parte superior das costas, apoiando-a nas armadilhas. Envolva o núcleo e mantenha o peito erguido ao começar a agachar-se, empurrando os quadris para trás e dobrando os joelhos. Abaixe-se até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Passe pelos calcanhares para se levantar, estendendo os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1436.gif', 'hasaneyldrm', '1436'),
  ('b1d7a80a-0000-4000-8000-000000000047'::uuid, null, 'supino inclinado com barra', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se no banco com os pés apoiados no chão. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos em um ângulo de 45 graus. Faça uma pausa na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0047.gif', 'hasaneyldrm', '0047'),
  ('b1d7a80a-0000-4000-8000-000000001719'::uuid, null, 'supino inclinado com barra inclinada e aperto próximo', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se no banco com os pés apoiados no chão. Segure a barra com uma pegada fechada, um pouco mais estreita que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1719.gif', 'hasaneyldrm', '1719'),
  ('b1d7a80a-0000-4000-8000-000000000048'::uuid, null, 'supino com pegada reversa inclinada com barra', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se no banco e segure a barra com uma pegada invertida, com as mãos ligeiramente mais afastadas que a largura dos ombros. Desembale a barra e abaixe-a em direção à parte superior do peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento na parte inferior e, em seguida, empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0048.gif', 'hasaneyldrm', '0048'),
  ('b1d7a80a-0000-4000-8000-000000000049'::uuid, null, 'remada inclinada com barra', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se de bruços no banco, com o peito apoiado na almofada e os pés apoiados no chão. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e o núcleo engajado. Puxe a barra em direção ao peito, apertando as omoplatas. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0049.gif', 'hasaneyldrm', '0049'),
  ('b1d7a80a-0000-4000-8000-000000000050'::uuid, null, 'levantamento de ombro inclinado com barra', 'isolation', ARRAY['serratus anterior', 'deltoids']::text[], ARRAY['deltoids', 'trapezius']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com as costas apoiadas na almofada e os pés apoiados no chão. Segure uma barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra até a altura dos ombros, mantendo os cotovelos levemente flexionados. Levante lentamente a barra acima da cabeça, estendendo totalmente os braços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0050.gif', 'hasaneyldrm', '0050'),
  ('b1d7a80a-0000-4000-8000-000000000051'::uuid, null, 'agachamento jefferson com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra com uma pegada pronada, apoiando-a na frente do corpo, logo abaixo da cintura. Dê um passo com o pé esquerdo para a frente e o pé direito para trás, mantendo os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada, mantendo as costas retas e o peito para cima. Empurre os calcanhares para voltar à posição inicial. Repita o movimento, alternando o pé para frente e para trás a cada repetição.', '/exercise-media/bstrainer/0051.gif', 'hasaneyldrm', '0051'),
  ('b1d7a80a-0000-4000-8000-000000000052'::uuid, null, 'supino com barra jm', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Abaixe a barra até o peito, mantendo os cotovelos próximos ao corpo. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0052.gif', 'hasaneyldrm', '0052'),
  ('b1d7a80a-0000-4000-8000-000000000053'::uuid, null, 'agachamento com salto com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ficando em pé, com os pés afastados na largura dos ombros, segurando uma barra na parte superior das costas. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Quando chegar ao final do agachamento, exploda para cima saltando do chão. Ao pular, estenda os quadris, joelhos e tornozelos, empurrando os dedos dos pés. Pouse suavemente de volta à posição de agachamento e repita imediatamente o movimento pelo número desejado de repetições.', '/exercise-media/bstrainer/0053.gif', 'hasaneyldrm', '0053'),
  ('b1d7a80a-0000-4000-8000-000000001410'::uuid, null, 'estocada lateral com barra', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma barra na parte superior das costas. Dê um grande passo para o lado com o pé direito, mantendo o pé esquerdo plantado. Dobre o joelho direito e abaixe o corpo em uma posição de estocada, mantendo a perna esquerda reta. Empurre com o pé direito e retorne à posição inicial. Repita do outro lado, pisando com o pé esquerdo.', '/exercise-media/bstrainer/1410.gif', 'hasaneyldrm', '1410'),
  ('b1d7a80a-0000-4000-8000-000000001435'::uuid, null, 'agachamento com barra baixa', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e a barra apoiada na parte superior das costas. Mantendo o peito para cima e o núcleo engajado, abaixe lentamente o corpo dobrando os joelhos e empurrando os quadris para trás. Continue abaixando até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1435.gif', 'hasaneyldrm', '1435'),
  ('b1d7a80a-0000-4000-8000-000000000054'::uuid, null, 'estocada com barra', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e uma barra apoiada na parte superior das costas. Dê um passo à frente com o pé direito, mantendo o tronco ereto. Abaixe o corpo dobrando o joelho direito até que a coxa fique paralela ao chão. Empurre o calcanhar direito para retornar à posição inicial. Repita com a perna esquerda, alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/0054.gif', 'hasaneyldrm', '0054'),
  ('b1d7a80a-0000-4000-8000-000000001720'::uuid, null, 'barra deitada atrás da cabeça extensão de tríceps', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure uma barra com uma pegada pronada, com as mãos na largura dos ombros e estenda os braços sobre o peito. Mantendo os braços parados, abaixe lentamente a barra atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1720.gif', 'hasaneyldrm', '1720'),
  ('b1d7a80a-0000-4000-8000-000000000055'::uuid, null, 'barra deitada com pegada fechada', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com força, com as mãos afastadas na largura dos ombros e as palmas voltadas para os pés. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe lentamente a barra em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra tocar seu peito e empurre-a de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0055.gif', 'hasaneyldrm', '0055'),
  ('b1d7a80a-0000-4000-8000-000000000056'::uuid, null, 'barra deitada extensão de tríceps com pegada fechada', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure a barra com força, com as mãos afastadas na largura dos ombros e as palmas voltadas para cima. Estenda totalmente os braços, levantando a barra acima do peito. Mantendo os braços parados, abaixe lentamente a barra em direção à testa, dobrando os cotovelos. Faça uma pausa na parte inferior e, em seguida, estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0056.gif', 'hasaneyldrm', '0056'),
  ('b1d7a80a-0000-4000-8000-000000000057'::uuid, null, 'extensão deitada com barra', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure a barra com uma pegada pronada, com as mãos afastadas na largura dos ombros e estenda os braços sobre o peito. Mantendo os braços parados, abaixe lentamente a barra em direção à testa, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0057.gif', 'hasaneyldrm', '0057'),
  ('b1d7a80a-0000-4000-8000-000000000058'::uuid, null, 'levantamento de barra deitado (no quadril)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'barbell', false, 'Deite-se de costas em um banco com os pés apoiados no chão e os joelhos dobrados. Segure a barra com uma pegada pronada e posicione-a nos quadris. Envolvendo os glúteos, levante os quadris do banco até que o corpo forme uma linha reta dos joelhos até os ombros. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0058.gif', 'hasaneyldrm', '0058'),
  ('b1d7a80a-0000-4000-8000-000000000059'::uuid, null, 'curl de pregador deitado com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Sente-se em um banco de pregador com o peito apoiado na almofada e os braços estendidos sobre a borda, segurando uma barra com uma pegada por baixo. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0059.gif', 'hasaneyldrm', '0059'),
  ('b1d7a80a-0000-4000-8000-000000000061'::uuid, null, 'extensão de tríceps deitado com barra', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure a barra com uma pegada pronada, com as mãos afastadas na largura dos ombros e estenda os braços sobre o peito. Mantendo os braços parados, abaixe lentamente a barra em direção à testa, dobrando os cotovelos. Faça uma pausa na parte inferior e, em seguida, estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0061.gif', 'hasaneyldrm', '0061'),
  ('b1d7a80a-0000-4000-8000-000000000060'::uuid, null, 'barra deitada tríceps extensão triturador de crânio', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure a barra com uma pegada pronada, com as mãos afastadas na largura dos ombros e estenda os braços sobre o peito. Mantendo os braços parados, abaixe lentamente a barra em direção à testa, dobrando os cotovelos. Faça uma pausa por um momento quando a barra estiver logo acima da testa e, em seguida, estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0060.gif', 'hasaneyldrm', '0060'),
  ('b1d7a80a-0000-4000-8000-000000000063'::uuid, null, 'agachamento com barra estreita', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos apontando ligeiramente para fora. Segure a barra na parte superior das costas, apoiando-a nas armadilhas ou no deltóide posterior. Envolva o núcleo e mantenha o peito erguido enquanto abaixa lentamente o corpo, dobrando os joelhos e empurrando os quadris para trás. Continue abaixando até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0063.gif', 'hasaneyldrm', '0063'),
  ('b1d7a80a-0000-4000-8000-000000000064'::uuid, null, 'barra com um braço dobrado sobre a remada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure uma barra com uma das mãos usando uma pegada pronada. Incline-se para a frente na altura dos quadris, mantendo as costas retas e a cabeça em uma posição neutra. Puxe a barra em direção ao peito, mantendo o cotovelo próximo ao corpo e apertando as omoplatas. Abaixe a barra de volta à posição inicial de maneira controlada. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0064.gif', 'hasaneyldrm', '0064'),
  ('b1d7a80a-0000-4000-8000-000000000065'::uuid, null, 'supino com barra com um braço', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', true, 'Deite-se de costas no chão, com os joelhos dobrados e os pés apoiados no chão. Segure a barra com uma mão, com a palma voltada para cima, e estenda o braço sobre o peito. Abaixe lentamente a barra em direção ao peito, mantendo o cotovelo próximo ao corpo. Faça uma pausa na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0065.gif', 'hasaneyldrm', '0065'),
  ('b1d7a80a-0000-4000-8000-000000000066'::uuid, null, 'levantamento terra lateral com barra com um braço', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'lower back']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma barra em uma das mãos com uma pegada pronada. Mantenha as costas retas e o núcleo engajado. Dobre os quadris e abaixe a barra em direção à parte externa da perna, mantendo o braço reto e o peito para cima. Abaixe a barra o máximo que puder, mantendo a boa forma. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0066.gif', 'hasaneyldrm', '0066'),
  ('b1d7a80a-0000-4000-8000-000000000067'::uuid, null, 'arranco de um braço com barra', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'forearms', 'core']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura dos ombros, os dedos apontando ligeiramente para fora. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Dobre os joelhos e abaixe os quadris até uma posição de agachamento, mantendo as costas retas e o peito para cima. Estenda explosivamente os quadris, joelhos e tornozelos, empurrando a barra para cima. Quando a barra atingir a altura do peito, puxe-a para cima com o braço, mantendo-a próxima ao corpo. Gire o cotovelo sob a barra e estenda o braço totalmente acima da cabeça, travando o cotovelo. Abaixe a barra de volta à posição inicial de maneira controlada. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0067.gif', 'hasaneyldrm', '0067'),
  ('b1d7a80a-0000-4000-8000-000000000068'::uuid, null, 'agachamento unilateral com barra', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra na parte superior das costas. Levante um pé do chão e estenda-o para frente, mantendo-o paralelo ao chão. Dobre a perna de apoio e abaixe o corpo como se estivesse sentado em uma cadeira, mantendo o peito para cima e as costas retas. Abaixe-se até que a coxa fique paralela ao chão e empurre o calcanhar para retornar à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/0068.gif', 'hasaneyldrm', '0068'),
  ('b1d7a80a-0000-4000-8000-000000000069'::uuid, null, 'agachamento aéreo com barra', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra com uma pegada ampla, posicionando-a acima da cabeça com os braços totalmente estendidos. Envolva seu núcleo e abaixe o corpo em uma posição de agachamento, mantendo o peito para cima e os joelhos acompanhando os dedos dos pés. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0069.gif', 'hasaneyldrm', '0069'),
  ('b1d7a80a-0000-4000-8000-000000001411'::uuid, null, 'barra com as palmas para baixo e o pulso curvado sobre um banco', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e os antebraços apoiados nas coxas, com as palmas voltadas para baixo. Segure uma barra com uma pegada pronada, com as mãos na largura dos ombros. Abaixe a barra em direção ao chão flexionando os pulsos, mantendo os antebraços parados. Faça uma pausa por um momento na parte inferior e, em seguida, levante lentamente a barra estendendo os pulsos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1411.gif', 'hasaneyldrm', '1411'),
  ('b1d7a80a-0000-4000-8000-000000001412'::uuid, null, 'barra com as palmas para cima e o pulso curvado sobre um banco', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure uma barra com uma pegada por baixo, com as palmas voltadas para cima. Descanse os antebraços no banco, permitindo que os pulsos fiquem pendurados na borda. Mantendo os antebraços parados, expire e curve os pulsos para cima o máximo possível. Mantenha a posição contraída por uma breve pausa, depois inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1412.gif', 'hasaneyldrm', '1412'),
  ('b1d7a80a-0000-4000-8000-000000003017'::uuid, null, 'linha pendlay com barra', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito para cima. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Puxe a barra em direção à parte superior do abdômen, apertando as omoplatas. Abaixe a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3017.gif', 'hasaneyldrm', '3017'),
  ('b1d7a80a-0000-4000-8000-000000001751'::uuid, null, 'prensas de barra', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Configure uma barra em um rack de energia na altura do peito. Fique de frente para a barra e posicione-se embaixo dela, com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe a barra em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1751.gif', 'hasaneyldrm', '1751'),
  ('b1d7a80a-0000-4000-8000-000000000070'::uuid, null, 'rosca pregadora com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Sente-se em um banco de pregador com os braços apoiados na almofada e o peito contra o suporte. Segure a barra com uma pegada por baixo, um pouco mais larga que a largura dos ombros. Mantendo os braços parados, expire e enrole a barra em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0070.gif', 'hasaneyldrm', '0070'),
  ('b1d7a80a-0000-4000-8000-000000000071'::uuid, null, 'abdominais com barra', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'barbell', false, 'Deite-se de costas em uma esteira com os joelhos dobrados e os pés apoiados no chão. Segure a barra com uma pegada pronada, apoiando-a no peito. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0071.gif', 'hasaneyldrm', '0071'),
  ('b1d7a80a-0000-4000-8000-000000000072'::uuid, null, 'ondulação inclinada prona com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se de bruços no banco com o peito e o estômago apoiados nele. Segure uma barra com uma pegada por baixo, na largura dos ombros. Estenda totalmente os braços, permitindo que a barra fique pendurada no chão. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0072.gif', 'hasaneyldrm', '0072'),
  ('b1d7a80a-0000-4000-8000-000000000073'::uuid, null, 'pulôver com barra', 'isolation', ARRAY['lats', 'chest']::text[], ARRAY['chest', 'triceps']::text[], 'barbell', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés no chão. Segure uma barra com uma pegada na largura dos ombros e estenda os braços acima do peito. Mantendo os braços retos, abaixe a barra atrás da cabeça de maneira controlada até sentir um alongamento nos dorsais. Faça uma pausa e levante a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0073.gif', 'hasaneyldrm', '0073'),
  ('b1d7a80a-0000-4000-8000-000000000022'::uuid, null, 'pulôver com barra para pressionar', 'push_h', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'chest', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés no chão. Segure a barra com uma pegada pronada (palmas voltadas para você) e estenda os braços acima do peito. Mantendo os braços retos, abaixe a barra atrás da cabeça em um movimento em arco até sentir um alongamento no grande dorsal. Faça uma pausa por um momento, depois inverta o movimento e pressione a barra de volta à posição inicial, acima do peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0022.gif', 'hasaneyldrm', '0022'),
  ('b1d7a80a-0000-4000-8000-000000000074'::uuid, null, 'puxador de rack de barra', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', false, 'Coloque uma barra em um rack na altura do joelho. Fique em pé com os pés afastados na largura dos ombros, os dedos apontando ligeiramente para fora. Dobre os quadris e os joelhos para abaixar-se e segure a barra com uma pegada pronada, com as mãos afastadas na largura dos ombros. Envolva o núcleo e levante a barra estendendo os quadris e os joelhos, puxando os ombros para trás e apertando os glúteos na parte superior. Abaixe a barra de volta à posição inicial, dobrando os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0074.gif', 'hasaneyldrm', '0074'),
  ('b1d7a80a-0000-4000-8000-000000000075'::uuid, null, 'elevação traseira do deltóide com barra', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as palmas voltadas para baixo. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Levante a barra para os lados, mantendo os braços retos, até ficarem paralelos ao chão. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0075.gif', 'hasaneyldrm', '0075'),
  ('b1d7a80a-0000-4000-8000-000000000076'::uuid, null, 'remada deltóide posterior com barra', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure uma barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Puxe a barra em direção ao peito, apertando as omoplatas. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0076.gif', 'hasaneyldrm', '0076'),
  ('b1d7a80a-0000-4000-8000-000000000078'::uuid, null, 'estocada traseira com barra', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e uma barra apoiada na parte superior das costas. Dê um passo para trás com o pé direito, pousando na planta do pé. Dobre os dois joelhos para abaixar o corpo até que a coxa esquerda fique paralela ao chão. Empurre o calcanhar esquerdo para retornar à posição inicial. Repita com a outra perna.', '/exercise-media/bstrainer/0078.gif', 'hasaneyldrm', '0078'),
  ('b1d7a80a-0000-4000-8000-000000000077'::uuid, null, 'estocada traseira com barra v. 2', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra na parte superior das costas. Dê um passo para trás com o pé direito, pousando na planta do pé. Dobre os dois joelhos para abaixar o corpo até que a coxa esquerda fique paralela ao chão. Empurre o calcanhar esquerdo para retornar à posição inicial. Repita com a outra perna.', '/exercise-media/bstrainer/0077.gif', 'hasaneyldrm', '0077'),
  ('b1d7a80a-0000-4000-8000-000000000079'::uuid, null, 'rosca reversa do pulso com barra v. 2', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e os joelhos dobrados. Segure uma barra com uma pegada pronada, com as palmas voltadas para baixo e as mãos na largura dos ombros. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados na borda. Mantendo os antebraços parados, expire e curve os pulsos para cima o máximo possível. Mantenha a posição contraída por uma breve pausa, depois inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0079.gif', 'hasaneyldrm', '0079'),
  ('b1d7a80a-0000-4000-8000-000000002187'::uuid, null, 'supino reto reverso com barra', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada invertida, com as mãos na largura dos ombros. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe lentamente a barra em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra estiver logo acima do seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2187.gif', 'hasaneyldrm', '2187'),
  ('b1d7a80a-0000-4000-8000-000000000080'::uuid, null, 'rosca reversa com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as palmas voltadas para baixo. Mantenha os braços parados e expire enquanto enrola a barra para cima, contraindo os bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire enquanto abaixa lentamente a barra de volta à posição inicial, mantendo os braços parados. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0080.gif', 'hasaneyldrm', '0080'),
  ('b1d7a80a-0000-4000-8000-000000000118'::uuid, null, 'pegada reversa com barra dobrada sobre a remada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure uma barra com uma pegada pronada, com as palmas voltadas para baixo e as mãos ligeiramente mais afastadas que a largura dos ombros. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito para cima, até que o tronco fique quase paralelo ao chão. Puxe a barra em direção à parte inferior do peito, apertando as omoplatas. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0118.gif', 'hasaneyldrm', '0118'),
  ('b1d7a80a-0000-4000-8000-000000001256'::uuid, null, 'supino reto com barra reversa e declínio', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco inclinado com os pés seguros e a cabeça mais baixa que os quadris. Segure a barra com uma pegada reversa, ligeiramente mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1256.gif', 'hasaneyldrm', '1256'),
  ('b1d7a80a-0000-4000-8000-000000001257'::uuid, null, 'supino inclinado com barra reversa', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se no banco com os pés apoiados no chão. Segure a barra com uma pegada invertida, com as mãos ligeiramente mais afastadas que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1257.gif', 'hasaneyldrm', '1257'),
  ('b1d7a80a-0000-4000-8000-000000001317'::uuid, null, 'linha de banco inclinado com aderência reversa com barra', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco de frente para o encosto com o peito apoiado nele. Segure a barra com uma pegada invertida (palmas voltadas para baixo) e com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha as costas retas e o núcleo engajado. Puxe a barra em direção à parte superior do abdômen, apertando as omoplatas. Faça uma pausa por um momento no início do movimento. Abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1317.gif', 'hasaneyldrm', '1317'),
  ('b1d7a80a-0000-4000-8000-000000001721'::uuid, null, 'triturador de crânio com pegada reversa com barra', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure a barra com uma pegada invertida, as palmas voltadas para o rosto e as mãos na largura dos ombros. Estenda os braços sobre o peito, mantendo os cotovelos para dentro e os pulsos retos. Abaixe lentamente a barra em direção à testa, dobrando os cotovelos, mantendo os braços parados. Faça uma pausa na parte inferior e, em seguida, estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1721.gif', 'hasaneyldrm', '1721'),
  ('b1d7a80a-0000-4000-8000-000000000081'::uuid, null, 'curl de pregador reverso com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Sente-se em um banco de pregador com o peito apoiado na almofada e os braços estendidos para baixo, segurando uma barra com uma pegada pronada. Mantendo os braços parados, expire e enrole a barra para cima enquanto contrai o bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0081.gif', 'hasaneyldrm', '0081'),
  ('b1d7a80a-0000-4000-8000-000000000082'::uuid, null, 'curvatura reversa do pulso com barra', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure uma barra com uma pegada pronada, com as palmas voltadas para baixo. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados na borda. Enrole lentamente os pulsos para cima, trazendo a barra em direção ao corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0082.gif', 'hasaneyldrm', '0082'),
  ('b1d7a80a-0000-4000-8000-000000000084'::uuid, null, 'rolamento com barra', 'core', ARRAY['abs', 'lower back']::text[], ARRAY['lower back']::text[], 'barbell', false, 'Ajoelhe-se no chão e segure uma barra com as duas mãos, na largura dos ombros. Role a barra para frente, estendendo os braços e mantendo o núcleo engajado. Continue rolando para frente até que seu corpo esteja totalmente estendido e seus braços acima da cabeça. Faça uma pausa por um momento e, em seguida, role lentamente a barra em direção aos joelhos, mantendo o controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0084.gif', 'hasaneyldrm', '0084'),
  ('b1d7a80a-0000-4000-8000-000000000083'::uuid, null, 'rollout com barra do banco', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'barbell', false, 'Comece ajoelhando-se no chão com uma barra colocada em um banco à sua frente. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantendo o núcleo engajado e as costas retas, role lentamente a barra para a frente, estendendo os braços à sua frente. Continue rolando a barra para frente até que seu corpo esteja totalmente estendido e seus braços acima da cabeça. Faça uma pausa por um momento na posição totalmente estendida e, em seguida, role lentamente a barra de volta em direção ao corpo, retornando à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0083.gif', 'hasaneyldrm', '0083'),
  ('b1d7a80a-0000-4000-8000-000000000085'::uuid, null, 'levantamento terra romeno com barra', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos dos pés apontando para a frente. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Flexione os quadris, mantendo as costas retas e os joelhos ligeiramente flexionados. Abaixe a barra em direção ao chão, mantendo-a próxima ao corpo. Sinta o alongamento dos isquiotibiais ao abaixar a barra. Depois de sentir um alongamento nos isquiotibiais, empurre os quadris para a frente e fique em pé. Contraia os glúteos no início do movimento. Abaixe a barra de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0085.gif', 'hasaneyldrm', '0085'),
  ('b1d7a80a-0000-4000-8000-000000000086'::uuid, null, 'barra sentada atrás da cabeça imprensa militar', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do suporte e abaixe-a até a altura dos ombros, atrás da cabeça. Pressione a barra para cima até que seus braços estejam totalmente estendidos. Abaixe a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0086.gif', 'hasaneyldrm', '0086'),
  ('b1d7a80a-0000-4000-8000-000000000087'::uuid, null, 'Bradford Rocky Press sentado com barra', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra até a altura dos ombros, mantendo os cotovelos levemente flexionados e apontando para frente. Pressione a barra acima da cabeça, estendendo totalmente os braços. Abaixe a barra de volta à altura dos ombros e repita o número desejado de repetições.', '/exercise-media/bstrainer/0087.gif', 'hasaneyldrm', '0087'),
  ('b1d7a80a-0000-4000-8000-000000000088'::uuid, null, 'panturrilha sentada com barra', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e uma barra apoiada nas coxas. Coloque as pontas dos pés em uma plataforma elevada, como um bloco ou degrau. Posicione a barra sobre as coxas e segure-a firmemente com as mãos. Mantendo as costas retas e o núcleo engajado, levante os calcanhares do chão estendendo os tornozelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0088.gif', 'hasaneyldrm', '0088'),
  ('b1d7a80a-0000-4000-8000-000000001371'::uuid, null, 'panturrilha sentada com barra', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e uma barra apoiada nas coxas. Coloque as pontas dos pés em uma plataforma elevada, como um bloco ou degrau. Abaixe os calcanhares o máximo possível, sentindo um alongamento nas panturrilhas. Levante os calcanhares o mais alto possível, contraindo as panturrilhas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1371.gif', 'hasaneyldrm', '1371'),
  ('b1d7a80a-0000-4000-8000-000000001718'::uuid, null, 'barra sentada com pegada fechada atrás da extensão do tríceps do pescoço', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure a barra com força atrás do pescoço, com as palmas voltadas para a frente. Mantenha os cotovelos próximos à cabeça e abaixe lentamente a barra em direção à parte de trás da cabeça. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1718.gif', 'hasaneyldrm', '1718'),
  ('b1d7a80a-0000-4000-8000-000000000089'::uuid, null, 'ondulação de concentração com pegada fechada sentada com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure uma barra com uma pegada por baixo, com as mãos afastadas na largura dos ombros. Descanse os braços contra a parte interna das coxas, logo acima dos joelhos, e deixe a barra pendurada na sua frente. Mantendo os braços parados, expire e enrole a barra em direção aos ombros, contraindo os bíceps. Mantenha a posição contraída por uma breve pausa, depois inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0089.gif', 'hasaneyldrm', '0089'),
  ('b1d7a80a-0000-4000-8000-000000000090'::uuid, null, 'barra sentada bom dia', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e uma barra apoiada na parte superior das costas. Mantenha as costas retas e o peito erguido. Incline-se lentamente para a frente na altura dos quadris, abaixando o tronco em direção ao chão. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0090.gif', 'hasaneyldrm', '0090'),
  ('b1d7a80a-0000-4000-8000-000000000091'::uuid, null, 'supino sentado com barra', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do suporte e coloque-a na altura dos ombros, com os cotovelos dobrados e as palmas das mãos voltadas para a frente. Pressione a barra acima da cabeça, estendendo totalmente os braços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta ao nível dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0091.gif', 'hasaneyldrm', '0091'),
  ('b1d7a80a-0000-4000-8000-000000000092'::uuid, null, 'extensão de tríceps acima da cabeça com barra sentada', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure uma barra com uma pegada pronada, com as mãos na largura dos ombros, e levante-a acima da cabeça. Abaixe a barra atrás da cabeça dobrando os cotovelos, mantendo os braços próximos à cabeça. Faça uma pausa e estenda os braços para levantar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0092.gif', 'hasaneyldrm', '0092'),
  ('b1d7a80a-0000-4000-8000-000000000094'::uuid, null, 'torção sentada com barra', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'barbell', false, 'Sente-se em um banco plano com os pés apoiados no chão e os joelhos dobrados. Segure uma barra com as duas mãos na frente do peito, mantendo os cotovelos levemente flexionados. Envolva o núcleo e gire lentamente o tronco para o lado, mantendo as costas retas. Faça uma pausa por um momento no final da torção e depois gire lentamente de volta à posição inicial. Repita a torção para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0094.gif', 'hasaneyldrm', '0094'),
  ('b1d7a80a-0000-4000-8000-000000000095'::uuid, null, 'encolher de ombros com barra', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra à sua frente com uma pegada pronada. Mantenha os braços retos e as costas retas durante todo o exercício. Levante os ombros em direção às orelhas o mais alto possível, apertando as armadilhas na parte superior. Segure por um momento e, em seguida, abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0095.gif', 'hasaneyldrm', '0095'),
  ('b1d7a80a-0000-4000-8000-000000000096'::uuid, null, 'barra lateral dobrada v. 2', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com as duas mãos, com as palmas voltadas para baixo. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Dobre lentamente o tronco para o lado direito, abaixando a barra em direção ao joelho direito. Faça uma pausa por um momento e depois retorne à posição inicial. Repita o movimento no lado esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0096.gif', 'hasaneyldrm', '0096'),
  ('b1d7a80a-0000-4000-8000-000000000098'::uuid, null, 'agachamento lateral com barra', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando ligeiramente para fora. Segure uma barra na parte superior das costas, apoiando-a nas armadilhas. Envolva o núcleo e mantenha o peito erguido enquanto abaixa o corpo até uma posição agachada, dobrando os joelhos e os quadris. Ao abaixar, empurre os joelhos para os lados e mantenha o peso sobre os calcanhares. Abaixe até que as coxas fiquem paralelas ao chão e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0098.gif', 'hasaneyldrm', '0098'),
  ('b1d7a80a-0000-4000-8000-000000000097'::uuid, null, 'agachamento lateral com barra v. 2', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando ligeiramente para fora. Segure uma barra na parte superior das costas, apoiando-a nos ombros. Dê um grande passo para o lado com o pé direito, mantendo o pé esquerdo plantado. Dobre o joelho direito e abaixe o corpo até uma posição agachada, mantendo o peito para cima e as costas retas. Empurre o calcanhar direito para retornar à posição inicial. Repita do outro lado, saindo com o pé esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0097.gif', 'hasaneyldrm', '0097'),
  ('b1d7a80a-0000-4000-8000-000000001756'::uuid, null, 'levantamento terra de uma perna com barra', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura do quadril, segurando uma barra na frente das coxas com uma pegada pronada. Transfira o peso para o pé esquerdo e levante ligeiramente o pé direito do chão. Incline-se para a frente na altura dos quadris, mantendo as costas retas e a perna direita estendida atrás de você para manter o equilíbrio. Abaixe a barra em direção ao solo, mantendo-a próxima ao corpo e com a perna esquerda levemente flexionada. Faça uma pausa por um momento na parte inferior e, em seguida, envolva os glúteos e isquiotibiais para levantar o tronco de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1756.gif', 'hasaneyldrm', '1756'),
  ('b1d7a80a-0000-4000-8000-000000000099'::uuid, null, 'agachamento dividido com barra e perna única', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma barra na parte superior das costas. Dê um grande passo à frente com uma perna, mantendo o tronco ereto. Abaixe o corpo dobrando o joelho e o quadril da frente, enquanto mantém a perna de trás reta. Continue abaixando até que a coxa da frente fique paralela ao chão. Faça uma pausa por um momento e empurre o calcanhar dianteiro para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0099.gif', 'hasaneyldrm', '0099'),
  ('b1d7a80a-0000-4000-8000-000000002799'::uuid, null, 'levantamento de perna alternado sentado com barra', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'barbell', true, 'Sente-se em um banco com as costas retas e segure uma barra nas coxas. Mantendo as pernas retas, levante uma perna o mais alto possível enquanto mantém a outra perna no chão. Abaixe a perna levantada e repita com a outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/2799.gif', 'hasaneyldrm', '2799'),
  ('b1d7a80a-0000-4000-8000-000000002800'::uuid, null, 'elevação de perna alternada sentada com barra (feminino)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'quadriceps']::text[], 'barbell', true, 'Sente-se em um banco com as costas retas e segure uma barra nas coxas. Coloque as mãos nas laterais do banco para apoio. Mantendo as pernas retas, levante uma perna o mais alto possível, mantendo-a paralela ao chão. Abaixe a perna novamente e repita com a outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/2800.gif', 'hasaneyldrm', '2800'),
  ('b1d7a80a-0000-4000-8000-000000000100'::uuid, null, 'esquiador com barra', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra na frente das coxas com uma pegada pronada. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Simultaneamente, levante a barra em direção aos ombros enquanto salta ligeiramente do chão. Ao chegar ao topo do movimento, inverta rapidamente o movimento e abaixe a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0100.gif', 'hasaneyldrm', '0100'),
  ('b1d7a80a-0000-4000-8000-000000000101'::uuid, null, 'agachamento rápido com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na parte superior das costas, apoiando-a nas armadilhas ou no deltóide posterior. Envolva o núcleo e mantenha o peito para cima enquanto abaixa os quadris para trás e para baixo, como se estivesse sentado em uma cadeira. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Passe pelos calcanhares para se levantar, apertando os glúteos na parte superior. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0101.gif', 'hasaneyldrm', '0101'),
  ('b1d7a80a-0000-4000-8000-000000002810'::uuid, null, 'agachamento dividido com barra v. 2', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ficando em pé, com os pés afastados na largura dos ombros, segurando uma barra na parte superior das costas. Dê um grande passo à frente com o pé direito, mantendo o tronco ereto. Abaixe o corpo dobrando os joelhos e quadris até que a coxa direita fique paralela ao chão. Faça uma pausa por um momento e empurre o calcanhar direito para retornar à posição inicial. Repita com a perna esquerda para a frente pelo número desejado de repetições.', '/exercise-media/bstrainer/2810.gif', 'hasaneyldrm', '2810'),
  ('b1d7a80a-0000-4000-8000-000000000102'::uuid, null, 'agachamento com barra (de joelhos)', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ajoelhando-se no chão com os joelhos afastados na largura do quadril e os dedos dos pés apontando para a frente. Coloque uma barra sobre os ombros, segurando-a com uma pegada pronada e com as mãos um pouco mais afastadas que a largura dos ombros. Envolva seu núcleo e mantenha o peito levantado enquanto abaixa lentamente o corpo, dobrando os joelhos, mantendo as costas retas. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0102.gif', 'hasaneyldrm', '0102'),
  ('b1d7a80a-0000-4000-8000-000000002798'::uuid, null, 'agachamento com barra, salto, estocada traseira', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ficando em pé, com os pés afastados na largura dos ombros, segurando uma barra na parte superior das costas. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Exploda para cima, saltando do chão o mais alto que puder. Pouse suavemente sobre os pés e imediatamente dê um passo para trás com uma perna em uma estocada reversa. Abaixe o corpo até que a coxa da frente fique paralela ao chão, mantendo as costas retas. Empurre o calcanhar dianteiro para retornar à posição inicial. Repita a sequência de salto e estocada na outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/2798.gif', 'hasaneyldrm', '2798'),
  ('b1d7a80a-0000-4000-8000-000000000103'::uuid, null, 'barra em pé ab rollout', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra com as duas mãos na frente das coxas. Envolva seu núcleo e role lentamente a barra em direção ao chão, mantendo as costas retas e os braços estendidos. Continue rolando a barra para frente até que seu corpo esteja totalmente estendido e suas mãos diretamente acima da cabeça. Faça uma pausa por um momento e, em seguida, role lentamente a barra em direção às coxas, mantendo o controle e o núcleo engajado. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0103.gif', 'hasaneyldrm', '0103'),
  ('b1d7a80a-0000-4000-8000-000000000104'::uuid, null, 'flexão de pulso com barra em pé para trás', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada. Apoie a barra nas costas das mãos, com as palmas voltadas para baixo e os dedos apontando para o corpo. Mantendo os braços parados, expire e enrole os pulsos para cima o máximo possível. Mantenha a posição contraída por uma breve pausa, depois inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0104.gif', 'hasaneyldrm', '0104'),
  ('b1d7a80a-0000-4000-8000-000000000105'::uuid, null, 'Bradford Press com barra em pé', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra na frente dos ombros com uma pegada pronada. Pressione a barra acima da cabeça, estendendo totalmente os braços. Abaixe a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0105.gif', 'hasaneyldrm', '0105'),
  ('b1d7a80a-0000-4000-8000-000000001372'::uuid, null, 'panturrilha em pé com barra', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque uma barra na parte superior das costas. Levante os calcanhares do chão o mais alto possível, usando apenas os dedos dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1372.gif', 'hasaneyldrm', '1372'),
  ('b1d7a80a-0000-4000-8000-000000000106'::uuid, null, 'barra em pé, curl de aperto próximo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada por baixo, com as mãos juntas. Mantenha os cotovelos próximos ao tronco e os braços parados durante todo o movimento. Expire enquanto enrola os pesos enquanto contrai o bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire enquanto lentamente começa a trazer a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0106.gif', 'hasaneyldrm', '0106'),
  ('b1d7a80a-0000-4000-8000-000000001456'::uuid, null, 'barra em pé, imprensa militar de aperto próximo', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra com uma pegada pronada, com as mãos um pouco mais próximas do que a largura dos ombros. Levante a barra até a altura dos ombros, mantendo os cotovelos próximos ao corpo. Pressione a barra acima da cabeça, estendendo totalmente os braços. Abaixe a barra de volta à altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1456.gif', 'hasaneyldrm', '1456'),
  ('b1d7a80a-0000-4000-8000-000000002414'::uuid, null, 'ondulação de concentração em pé com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra em uma das mãos, com a palma voltada para cima. Descanse a mão oposta na coxa para obter apoio. Mantendo o braço parado, expire e enrole o peso em direção ao ombro. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente o peso de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/2414.gif', 'hasaneyldrm', '2414'),
  ('b1d7a80a-0000-4000-8000-000000000107'::uuid, null, 'barra em pé com elevação frontal acima da cabeça', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma barra na frente das coxas com uma pegada pronada. Mantenha as costas retas e envolva seu núcleo. Levante lentamente a barra à sua frente, mantendo os braços retos e as palmas das mãos voltadas para baixo. Continue levantando até que a barra esteja ligeiramente acima do nível dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0107.gif', 'hasaneyldrm', '0107'),
  ('b1d7a80a-0000-4000-8000-000000000108'::uuid, null, 'elevação de panturrilha com barra em pé', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e coloque uma barra na parte superior das costas. Levante os calcanhares do chão o mais alto possível, usando as panturrilhas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0108.gif', 'hasaneyldrm', '0108'),
  ('b1d7a80a-0000-4000-8000-000000000109'::uuid, null, 'extensão de tríceps acima da cabeça com barra', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada. Levante a barra acima da cabeça, estendendo totalmente os braços. Mantendo os braços próximos à cabeça, abaixe lentamente a barra atrás da cabeça, dobrando os cotovelos. Faça uma pausa e, em seguida, levante a barra de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0109.gif', 'hasaneyldrm', '0109'),
  ('b1d7a80a-0000-4000-8000-000000000110'::uuid, null, 'rosca direta reversa com barra em pé', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada por baixo, com as palmas voltadas para cima. Mantenha os cotovelos próximos ao tronco e os braços parados. Expire e enrole os pesos enquanto contrai o bíceps, aproximando a barra o mais próximo possível dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0110.gif', 'hasaneyldrm', '0110'),
  ('b1d7a80a-0000-4000-8000-000000000111'::uuid, null, 'levantamento de panturrilha com barra em pé e balanço', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra na parte superior das costas. Levante os calcanhares do chão o mais alto possível, equilibrando-se na planta dos pés. Abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0111.gif', 'hasaneyldrm', '0111'),
  ('b1d7a80a-0000-4000-8000-000000000112'::uuid, null, 'torção com barra em pé', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra na frente do peito com as duas mãos, com as palmas voltadas para baixo. Envolva seu núcleo e mantenha as costas retas durante todo o exercício. Gire lentamente o tronco para a direita, girando sobre os pés e quadris, enquanto mantém a parte inferior do corpo estável. Faça uma pausa no final da torção e depois retorne lentamente à posição inicial. Repita a torção para o lado esquerdo. Continue alternando torções para o número desejado de repetições.', '/exercise-media/bstrainer/0112.gif', 'hasaneyldrm', '0112'),
  ('b1d7a80a-0000-4000-8000-000000001629'::uuid, null, 'barra em pé com grande aderência para bíceps', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada por baixo, com as mãos mais afastadas que a largura dos ombros. Mantenha as costas retas e os cotovelos próximos ao tronco. Expire e enrole a barra em direção aos ombros, mantendo os braços parados. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1629.gif', 'hasaneyldrm', '1629'),
  ('b1d7a80a-0000-4000-8000-000000001457'::uuid, null, 'barra em pé ampla imprensa militar', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra com uma pegada pronada, um pouco mais larga que a largura dos ombros. Levante a barra até a altura dos ombros, mantendo os cotovelos ligeiramente à frente da barra. Pressione a barra acima da cabeça, estendendo totalmente os braços. Abaixe a barra de volta à altura dos ombros e repita o número desejado de repetições.', '/exercise-media/bstrainer/1457.gif', 'hasaneyldrm', '1457'),
  ('b1d7a80a-0000-4000-8000-000000000113'::uuid, null, 'rosca direta com barra em pé', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'barbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as mãos mais afastadas que a largura dos ombros. Deixe a barra pendurada com o braço estendido na frente das coxas, com as palmas voltadas para longe do corpo. Mantendo os braços parados, expire e enrole a barra para cima, contraindo os bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0113.gif', 'hasaneyldrm', '0113'),
  ('b1d7a80a-0000-4000-8000-000000000114'::uuid, null, 'subida com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique na frente de um banco ou pise com uma barra apoiada na parte superior das costas. Coloque um pé no banco ou degrau, garantindo que todo o pé esteja em contato com a superfície. Empurre o calcanhar e suba no banco ou degrau, estendendo totalmente o quadril e o joelho. Faça uma breve pausa no topo e depois abaixe-se de volta à posição inicial. Repita com a perna oposta. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/0114.gif', 'hasaneyldrm', '0114'),
  ('b1d7a80a-0000-4000-8000-000000000115'::uuid, null, 'perna dura com barra, bom dia', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra na parte superior das costas, apoiando-a nas armadilhas. Mantendo as costas retas, incline-se para a frente na altura dos quadris, empurrando os glúteos para trás. Abaixe o tronco até ficar paralelo ao chão, sentindo um alongamento nos isquiotibiais. Envolva os glúteos e isquiotibiais para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0115.gif', 'hasaneyldrm', '0115'),
  ('b1d7a80a-0000-4000-8000-000000000116'::uuid, null, 'levantamento terra com barra reta', 'hinge', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos dos pés apontando para a frente. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Dobre os quadris e abaixe a barra em direção ao chão, mantendo as costas retas e os joelhos ligeiramente flexionados. Abaixe a barra até sentir um alongamento nos isquiotibiais. Envolva os isquiotibiais e os glúteos para levantar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0116.gif', 'hasaneyldrm', '0116'),
  ('b1d7a80a-0000-4000-8000-000000000117'::uuid, null, 'levantamento terra de sumô com barra', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'lower back']::text[], 'barbell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando para fora. Coloque uma barra no chão à sua frente, centralizada entre os pés. Dobre os joelhos e abaixe os quadris, mantendo as costas retas e o peito para cima, para segurar a barra com uma pegada pronada. Envolva o núcleo e passe pelos calcanhares para levantar a barra do chão, estendendo os quadris e os joelhos simultaneamente. Ao levantar, mantenha o peito para cima e as costas retas e empurre os quadris para a frente para envolver totalmente os glúteos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial, mantendo o controle durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0117.gif', 'hasaneyldrm', '0117'),
  ('b1d7a80a-0000-4000-8000-000000003305'::uuid, null, 'propulsor de barra', 'isolation', ARRAY['delts', 'quadriceps']::text[], ARRAY['quadriceps', 'glutes', 'hamstrings', 'core']::text[], 'barbell', false, 'Comece ficando em pé, com os pés afastados na largura dos ombros, segurando uma barra na altura dos ombros com uma pegada pronada. Abaixe-se em uma posição de agachamento dobrando os joelhos e empurrando os quadris para trás. Ao chegar ao final do agachamento, mova explosivamente os calcanhares para se levantar, pressionando simultaneamente a barra acima da cabeça. Abaixe a barra de volta à altura dos ombros enquanto volta para a posição de agachamento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3305.gif', 'hasaneyldrm', '3305'),
  ('b1d7a80a-0000-4000-8000-000000000120'::uuid, null, 'remada vertical com barra', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Deixe a barra pendurada na frente das coxas, com os braços totalmente estendidos. Mantendo as costas retas e o núcleo engajado, expire e levante a barra em direção ao queixo, conduzindo com os cotovelos. Faça uma pausa por um momento no topo, inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0120.gif', 'hasaneyldrm', '0120'),
  ('b1d7a80a-0000-4000-8000-000000000119'::uuid, null, 'remada vertical com barra v. 2', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Deixe a barra pendurada na frente das coxas, com os braços totalmente estendidos. Mantendo as costas retas, expire e levante a barra em direção ao queixo, conduzindo com os cotovelos. Faça uma pausa por um momento no topo, inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0119.gif', 'hasaneyldrm', '0119'),
  ('b1d7a80a-0000-4000-8000-000000000121'::uuid, null, 'remada vertical com barra v. 3', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Deixe a barra pendurada na frente das coxas, com os braços totalmente estendidos. Mantendo o núcleo engajado e as costas retas, expire enquanto levanta a barra em direção ao queixo, liderando com os cotovelos. Faça uma pausa por um momento no topo e inspire enquanto abaixa lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0121.gif', 'hasaneyldrm', '0121'),
  ('b1d7a80a-0000-4000-8000-000000000122'::uuid, null, 'supino largo com barra', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada larga, um pouco mais larga que a largura dos ombros. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe a barra lentamente em direção ao peito, mantendo os cotovelos ligeiramente abertos. Faça uma pausa por um momento quando a barra tocar seu peito e empurre-a de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0122.gif', 'hasaneyldrm', '0122'),
  ('b1d7a80a-0000-4000-8000-000000001258'::uuid, null, 'supino reto com barra larga e reverso', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'barbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra com uma pegada reversa ampla, um pouco mais larga que a largura dos ombros. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe a barra lentamente em direção ao peito, mantendo os cotovelos dobrados e os pulsos retos. Faça uma pausa por um momento quando a barra tocar seu peito e empurre-a de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1258.gif', 'hasaneyldrm', '1258'),
  ('b1d7a80a-0000-4000-8000-000000000124'::uuid, null, 'agachamento amplo com barra', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando ligeiramente para fora. Segure a barra na parte superior das costas, apoiando-a nas armadilhas ou no deltóide posterior. Envolva seu núcleo e mantenha o peito para cima enquanto abaixa o corpo em um agachamento, empurrando os quadris para trás e dobrando os joelhos. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0124.gif', 'hasaneyldrm', '0124'),
  ('b1d7a80a-0000-4000-8000-000000000123'::uuid, null, 'remada vertical com barra larga', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma barra com uma pegada pronada, com as mãos mais afastadas que a largura dos ombros. Deixe a barra pendurada na frente das coxas, com os braços totalmente estendidos. Mantendo as costas retas, expire e levante a barra em direção ao queixo, conduzindo com os cotovelos. Faça uma pausa por um momento no topo, inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0123.gif', 'hasaneyldrm', '0123'),
  ('b1d7a80a-0000-4000-8000-000000000126'::uuid, null, 'flexão de pulso com barra', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e os antebraços apoiados nas coxas, segurando uma barra com uma pegada por baixo. Deixe a barra rolar até a ponta dos dedos, mantendo os pulsos retos. Enrole lentamente a barra em direção aos antebraços, flexionando os pulsos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0126.gif', 'hasaneyldrm', '0126'),
  ('b1d7a80a-0000-4000-8000-000000000125'::uuid, null, 'rosca direta de pulso com barra v. 2', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e os joelhos dobrados. Segure uma barra com uma pegada supinada, com as palmas voltadas para cima e as mãos na largura dos ombros. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados na borda. Enrole lentamente os pulsos para cima, trazendo a barra em direção aos antebraços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0125.gif', 'hasaneyldrm', '0125'),
  ('b1d7a80a-0000-4000-8000-000000000127'::uuid, null, 'agachamento zercher com barra', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure a barra na dobra dos cotovelos, com as mãos segurando a barra para estabilidade. Envolva seu núcleo e mantenha o peito levantado enquanto abaixa os quadris para trás e para baixo, em uma posição de agachamento. Mantenha os joelhos alinhados com os dedos dos pés e o peso nos calcanhares. Faça uma pausa por um momento na parte inferior do agachamento e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0127.gif', 'hasaneyldrm', '0127'),
  ('b1d7a80a-0000-4000-8000-000000003212'::uuid, null, 'toque básico na ponta do pé (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços ao lado do corpo. Incline-se para a frente na cintura, mantendo as costas retas e os joelhos ligeiramente flexionados. Alcance os dedos dos pés com as mãos, mantendo as pernas o mais retas possível. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3212.gif', 'hasaneyldrm', '3212'),
  ('b1d7a80a-0000-4000-8000-000000000128'::uuid, null, 'lutando contra cordas', 'isolation', ARRAY['delts', 'forearms']::text[], ARRAY['forearms', 'core']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure uma ponta da corda em cada mão, com as palmas voltadas uma para a outra. Levante os braços até a altura dos ombros, mantendo os cotovelos ligeiramente flexionados. Comece a fazer ondas alternadas com as cordas levantando e abaixando rapidamente cada braço. Continue pela duração ou número de repetições desejado.', '/exercise-media/bstrainer/0128.gif', 'hasaneyldrm', '0128'),
  ('b1d7a80a-0000-4000-8000-000000003360'::uuid, null, 'urso rastejando', 'isolation', ARRAY['cardiovascular system', 'core']::text[], ARRAY['core', 'shoulders', 'triceps']::text[], 'bodyweight', false, 'Comece de quatro, com as mãos diretamente sob os ombros e os joelhos diretamente sob os quadris. Levante ligeiramente os joelhos do chão, mantendo as costas retas e o núcleo engajado. Mova a mão direita e o pé esquerdo para frente simultaneamente, seguidos pela mão esquerda e pelo pé direito. Continue rastejando para frente, alternando os movimentos das mãos e dos pés. Mantenha um ritmo constante e mantenha o núcleo tenso durante todo o exercício. Continue pela distância ou tempo desejado.', '/exercise-media/bstrainer/3360.gif', 'hasaneyldrm', '3360'),
  ('b1d7a80a-0000-4000-8000-000000001259'::uuid, null, 'alongamento do peito atrás da cabeça', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros. Entrelace os dedos atrás da cabeça com os cotovelos apontando para fora. Aperte lentamente as omoplatas e empurre o peito para a frente. Mantenha o alongamento por 15 a 30 segundos. Solte o alongamento e repita conforme desejado.', '/exercise-media/bstrainer/1259.gif', 'hasaneyldrm', '1259'),
  ('b1d7a80a-0000-4000-8000-000000000129'::uuid, null, 'mergulho no banco (joelhos dobrados)', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se na beira de um banco ou cadeira com as mãos segurando a borda próxima aos quadris. Deslize a bunda para fora do banco e estique as pernas à sua frente, mantendo os calcanhares no chão. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas próximas ao banco. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0129.gif', 'hasaneyldrm', '0129'),
  ('b1d7a80a-0000-4000-8000-000000001399'::uuid, null, 'mergulho de banco no chão', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se na beira de um banco ou cadeira com as mãos segurando a borda e os dedos apontando para frente. Deslize a bunda para fora do banco, apoiando o peso com as mãos. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Empurre-se de volta à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1399.gif', 'hasaneyldrm', '1399'),
  ('b1d7a80a-0000-4000-8000-000000000130'::uuid, null, 'extensão de quadril em banco', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Sente-se em um banco com as costas apoiadas no banco e os pés apoiados no chão. Coloque as mãos no banco para apoio. Envolva os glúteos e isquiotibiais e, em seguida, levante os quadris do banco até que o corpo forme uma linha reta dos joelhos até os ombros. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0130.gif', 'hasaneyldrm', '0130'),
  ('b1d7a80a-0000-4000-8000-000000003019'::uuid, null, 'flexões de banco', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Posicione-se sob uma barra ou superfície horizontal resistente na altura do peito. Agarre a barra ou superfície com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Pendure-se com os braços totalmente estendidos e o corpo reto. Puxe o peito em direção à barra ou superfície, apertando as omoplatas e dobrando os cotovelos. Continue puxando até que seu queixo esteja acima da barra ou superfície. Abaixe-se de volta à posição inicial com controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3019.gif', 'hasaneyldrm', '3019'),
  ('b1d7a80a-0000-4000-8000-000000003639'::uuid, null, 'joelho dobrado deitado torcido (masculino)', 'isolation', ARRAY['glutes', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Estenda os braços para os lados, perpendiculares ao corpo. Mantendo os joelhos juntos, abaixe-os lentamente para o lado, com o objetivo de tocar o chão com os joelhos. Faça uma pausa por um momento, depois envolva o núcleo e levante lentamente os joelhos de volta à posição inicial. Repita o movimento para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3639.gif', 'hasaneyldrm', '3639'),
  ('b1d7a80a-0000-4000-8000-000000001770'::uuid, null, 'rosca direta de concentração para bíceps', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'bodyweight', false, 'Sente-se em um banco com as pernas afastadas e os pés apoiados no chão. Segure um haltere com uma das mãos e coloque o cotovelo na parte interna da coxa, logo acima do joelho. Com a palma da mão voltada para cima, enrole o haltere em direção ao ombro enquanto mantém o braço parado. Contraia o bíceps no início do movimento e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1770.gif', 'hasaneyldrm', '1770'),
  ('b1d7a80a-0000-4000-8000-000000000139'::uuid, null, 'flexões estreitas de bíceps', 'pull_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com as palmas voltadas para você e na largura dos ombros. Envolva seu núcleo e puxe-se em direção à barra, concentrando-se em usar o bíceps para levantar o corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0139.gif', 'hasaneyldrm', '0139'),
  ('b1d7a80a-0000-4000-8000-000000000140'::uuid, null, 'flexão de bíceps', 'pull_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com as palmas voltadas para longe de você e na largura dos ombros. Envolva seu núcleo e levante-se dobrando os cotovelos, trazendo o peito em direção à barra. Faça uma pausa no início do movimento e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0140.gif', 'hasaneyldrm', '0140'),
  ('b1d7a80a-0000-4000-8000-000000000137'::uuid, null, 'corpo para cima', 'isolation', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Comece colocando as mãos em uma superfície elevada, como um banco ou barras paralelas, com as palmas voltadas para baixo e os dedos apontando para frente. Estenda as pernas à sua frente, mantendo os calcanhares no chão e o corpo reto. Abaixe o corpo dobrando os cotovelos, mantendo-os próximos ao corpo, até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e empurre as palmas das mãos para esticar os braços e levantar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0137.gif', 'hasaneyldrm', '0137'),
  ('b1d7a80a-0000-4000-8000-000000003543'::uuid, null, 'agachamento drop jump com peso corporal', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Salte explosivamente, estendendo os quadris, joelhos e tornozelos. Enquanto estiver no ar, junte rapidamente os pés. Pouse suavemente na planta dos pés e imediatamente volte para a posição de agachamento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3543.gif', 'hasaneyldrm', '3543'),
  ('b1d7a80a-0000-4000-8000-000000003544'::uuid, null, 'prancha lateral inclinada com peso corporal', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'shoulders']::text[], 'bodyweight', false, 'Comece deitando-se de lado com as pernas estendidas e empilhadas uma sobre a outra. Coloque o antebraço no chão, diretamente abaixo do ombro, com o cotovelo dobrado em um ângulo de 90 graus. Envolva o núcleo e levante os quadris do chão, criando uma linha reta da cabeça aos pés. Mantenha esta posição pelo tempo desejado. Abaixe os quadris de volta ao chão e repita do outro lado.', '/exercise-media/bstrainer/3544.gif', 'hasaneyldrm', '3544'),
  ('b1d7a80a-0000-4000-8000-000000001771'::uuid, null, 'extensão de tríceps ajoelhado com peso corporal', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'bodyweight', false, 'Ajoelhe-se no chão com os joelhos afastados na largura do quadril. Coloque as mãos no chão à sua frente, na largura dos ombros, com os dedos apontando para a frente. Estenda as pernas retas atrás de você, equilibrando-se nas pontas dos pés e nas mãos, formando uma linha reta da cabeça aos calcanhares. Dobre os cotovelos e abaixe a parte superior do corpo em direção ao chão, mantendo os cotovelos próximos aos lados. Faça uma pausa por um momento na parte inferior e, em seguida, empurre as mãos para esticar os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1771.gif', 'hasaneyldrm', '1771'),
  ('b1d7a80a-0000-4000-8000-000000001769'::uuid, null, 'rosca direta de bíceps deitada de lado com peso corporal', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas estendidas e a cabeça apoiada no braço. Segure o braço contra o lado do corpo e dobre o cotovelo para enrolar o antebraço em direção ao ombro. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente o antebraço de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1769.gif', 'hasaneyldrm', '1769'),
  ('b1d7a80a-0000-4000-8000-000000003168'::uuid, null, 'linha de agachamento com peso corporal', 'squat', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um objeto resistente ou um treinador de suspensão com os braços estendidos. Abaixe o corpo até uma posição de agachamento, mantendo as costas retas e os joelhos atrás dos dedos dos pés. A partir da posição de agachamento, puxe o corpo em direção ao objeto ou ao treinador de suspensão, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3168.gif', 'hasaneyldrm', '3168'),
  ('b1d7a80a-0000-4000-8000-000000003167'::uuid, null, 'remada de agachamento com peso corporal (com toalha)', 'squat', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma toalha à sua frente com as palmas voltadas para baixo. Dobre os joelhos e abaixe o corpo até uma posição agachada, mantendo as costas retas e o peito erguido. Ao agachar, puxe simultaneamente a toalha em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do agachamento e, em seguida, retorne lentamente à posição inicial enquanto estende os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3167.gif', 'hasaneyldrm', '3167'),
  ('b1d7a80a-0000-4000-8000-000000001373'::uuid, null, 'panturrilha em pé com peso corporal', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos apontando para a frente. Coloque as mãos em uma parede ou superfície estável para manter o equilíbrio. Levante lentamente os calcanhares do chão, levantando o peso do corpo sobre a planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1373.gif', 'hasaneyldrm', '1373'),
  ('b1d7a80a-0000-4000-8000-000000003156'::uuid, null, 'peso corporal em pé e remada com um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure um haltere em uma das mãos com pegada neutra. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Puxe o haltere em direção ao peito, mantendo o cotovelo próximo ao corpo e apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/3156.gif', 'hasaneyldrm', '3156'),
  ('b1d7a80a-0000-4000-8000-000000003158'::uuid, null, 'peso corporal em pé remada com pegada fechada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Incline-se para a frente na cintura, mantendo as costas retas e o núcleo engajado. Estenda os braços esticados à sua frente, segurando a barra ou as alças com força. Puxe a barra ou as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no início do movimento, depois solte lentamente e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3158.gif', 'hasaneyldrm', '3158'),
  ('b1d7a80a-0000-4000-8000-000000003162'::uuid, null, 'peso corporal em pé, remada com um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure um haltere em uma das mãos. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Deixe o haltere pendurado à sua frente, com o braço totalmente estendido. Puxe o haltere em direção ao peito, mantendo o cotovelo próximo ao corpo. Aperte as omoplatas no início do movimento. Abaixe o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/3162.gif', 'hasaneyldrm', '3162'),
  ('b1d7a80a-0000-4000-8000-000000003161'::uuid, null, 'peso corporal em pé, remada com um braço (com toalha)', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure uma toalha com uma das mãos. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Puxe a toalha em direção ao peito, apertando as omoplatas. Faça uma pausa na parte superior e, em seguida, abaixe lentamente a toalha de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/3161.gif', 'hasaneyldrm', '3161'),
  ('b1d7a80a-0000-4000-8000-000000003166'::uuid, null, 'remada em pé com peso corporal', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure uma barra ou alças com uma pegada pronada, com as palmas voltadas para baixo. Mantenha as costas retas e o núcleo engajado. Puxe a barra ou as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no início do movimento. Solte lentamente e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3166.gif', 'hasaneyldrm', '3166'),
  ('b1d7a80a-0000-4000-8000-000000003165'::uuid, null, 'remada em pé com peso corporal (com toalha)', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma toalha à sua frente com as duas mãos. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Puxe a toalha em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3165.gif', 'hasaneyldrm', '3165'),
  ('b1d7a80a-0000-4000-8000-000000000138'::uuid, null, 'de baixo para cima', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Dobre os joelhos e leve-os em direção ao peito, mantendo os pés fora do chão. Envolvendo os abdominais, levante os quadris do chão, trazendo os joelhos em direção à cabeça. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0138.gif', 'hasaneyldrm', '0138'),
  ('b1d7a80a-0000-4000-8000-000000001374'::uuid, null, 'box jump down com estabilização de uma perna', 'isolation', ARRAY['calves', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes']::text[], 'bodyweight', true, 'Fique na frente de uma caixa ou plataforma com os pés afastados na largura dos ombros. Dobre os joelhos e pule sobre a caixa, pousando suavemente com um pé na caixa e o outro pendurado na borda. Estabilize-se na caixa com o pé que está sobre ela, mantendo o outro pé fora do chão. Mantenha essa posição por alguns segundos, envolvendo os músculos da panturrilha para manter o equilíbrio. Desça lentamente com o pé que está na caixa, retornando à posição inicial. Repita o exercício com a outra perna.', '/exercise-media/bstrainer/1374.gif', 'hasaneyldrm', '1374'),
  ('b1d7a80a-0000-4000-8000-000000002466'::uuid, null, 'ponte - alpinista (corpo cruzado)', 'core', ARRAY['abs', 'glutes']::text[], ARRAY['glutes', 'quadriceps', 'hamstrings', 'shoulders', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta. Envolva o núcleo e levante o pé direito do chão, aproximando o joelho direito do cotovelo esquerdo. Retorne o pé direito à posição inicial e repita o movimento com o pé esquerdo em direção ao cotovelo direito. Continue alternando os lados, movendo-se em um ritmo controlado. Mantenha os quadris nivelados e evite levantá-los muito alto ou deixá-los cair muito. Mantenha um padrão respiratório constante durante todo o exercício. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2466.gif', 'hasaneyldrm', '2466'),
  ('b1d7a80a-0000-4000-8000-000000001160'::uuid, null, 'burpee', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'chest']::text[], 'bodyweight', false, 'Comece em pé, com os pés afastados na largura dos ombros. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e colocando as mãos no chão à sua frente. Jogue os pés para trás em uma posição de flexão. Faça uma flexão, mantendo o corpo em linha reta. Salte os pés de volta para a posição de agachamento. Salte de forma explosiva, alcançando os braços acima da cabeça. Pouse suavemente e imediatamente abaixe as costas em uma posição de agachamento para iniciar a próxima repetição.', '/exercise-media/bstrainer/1160.gif', 'hasaneyldrm', '1160'),
  ('b1d7a80a-0000-4000-8000-000000000870'::uuid, null, 'bundas', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos ao lado do corpo, com as palmas voltadas para baixo. Envolvendo os abdominais, levante as pernas do chão, aproximando os joelhos do peito. No início do movimento, contraia os abdominais e faça uma pausa por um momento. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0870.gif', 'hasaneyldrm', '0870'),
  ('b1d7a80a-0000-4000-8000-000000001494'::uuid, null, 'pose de ioga de borboleta', 'push_h', ARRAY['adductors', 'hamstrings']::text[], ARRAY['hamstrings', 'groin']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Dobre os joelhos e junte as solas dos pés, permitindo que os joelhos caiam para os lados. Segure os tornozelos ou pés com as mãos. Sente-se ereto e alongue a coluna. Pressione suavemente os joelhos em direção ao chão, sentindo um alongamento na parte interna das coxas. Mantenha esta posição por algumas respirações. Para soltar, levante lentamente os joelhos e estenda as pernas.', '/exercise-media/bstrainer/1494.gif', 'hasaneyldrm', '1494'),
  ('b1d7a80a-0000-4000-8000-000000000148'::uuid, null, 'prensa de ombro alternada com cabo', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'cable', true, 'Fique em pé com os pés afastados na largura dos ombros e segure as alças da máquina de cabos com uma pegada pronada. Posicione as mãos na altura dos ombros, com as palmas voltadas para a frente. Mantenha seu núcleo engajado e suas costas retas. Pressione uma alça para cima e para frente até que seu braço esteja totalmente estendido. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça de volta à posição inicial. Repita com o outro braço. Alterne entre os braços para o número desejado de repetições.', '/exercise-media/bstrainer/0148.gif', 'hasaneyldrm', '0148'),
  ('b1d7a80a-0000-4000-8000-000000000149'::uuid, null, 'extensão alternada de tríceps com cabo', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', true, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a alça do cabo com a mão direita e levante o braço de modo que o braço fique paralelo ao chão e o cotovelo dobrado em um ângulo de 90 graus. Mantenha o braço parado e estenda o antebraço para trás, esticando totalmente o braço. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita com o braço esquerdo. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0149.gif', 'hasaneyldrm', '0149'),
  ('b1d7a80a-0000-4000-8000-000000003235'::uuid, null, 'flexão de perna inversa assistida por cabo', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'calves']::text[], 'cable', false, 'Ajuste a máquina de cabos para que a fixação do tornozelo fique na configuração mais baixa. Deite-se de bruços no banco com as pernas esticadas e o acessório para tornozelo preso aos tornozelos. Segure-se nas alças do banco para obter estabilidade. Mantendo a parte superior do corpo parada, expire e enrole as pernas em direção aos glúteos, flexionando os joelhos. Faça uma pausa por um momento no início do movimento, apertando os isquiotibiais. Inspire e abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3235.gif', 'hasaneyldrm', '3235'),
  ('b1d7a80a-0000-4000-8000-000000000150'::uuid, null, 'pulldown lateral da barra de cabos', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Ajuste a polia do cabo para uma posição alta e prenda uma barra reta. Sente-se de frente para a máquina de cabos, com os pés apoiados no chão e os joelhos ligeiramente dobrados. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Incline-se ligeiramente para trás e mantenha o peito erguido, mantendo um leve arco na parte inferior das costas. Puxe a barra para baixo em direção ao peito, liderando com os cotovelos e apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, retorne lentamente a barra à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0150.gif', 'hasaneyldrm', '0150'),
  ('b1d7a80a-0000-4000-8000-000000000151'::uuid, null, 'supino com cabo', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'cable', false, 'Ajuste a máquina de cabos à altura do peito e prenda as alças. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure as alças com força e dê um passo à frente para criar tensão nos cabos. Posicione os pés firmemente no chão e envolva o núcleo. Dobre os cotovelos e coloque as mãos na altura dos ombros, mantendo os cotovelos em um ângulo de 90 graus. Empurre as alças para frente, estendendo os braços totalmente à sua frente. Faça uma pausa por um momento e depois inverta lentamente o movimento, trazendo as mãos de volta ao nível dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0151.gif', 'hasaneyldrm', '0151'),
  ('b1d7a80a-0000-4000-8000-000000001630'::uuid, null, 'enrolamento próximo do cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia baixa. Fique de frente para a máquina com os pés afastados na largura dos ombros e os joelhos ligeiramente dobrados. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Expire e levante a barra em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1630.gif', 'hasaneyldrm', '1630'),
  ('b1d7a80a-0000-4000-8000-000000001631'::uuid, null, 'ondulação de concentração do cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Sente-se em um banco ou cadeira com os pés apoiados no chão e os joelhos ligeiramente flexionados. Segure a alça do cabo com uma pegada por baixo e apoie o cotovelo na parte interna da coxa. Mantendo o braço parado, expire e enrole a alça do cabo em direção ao ombro enquanto contrai o bíceps. Faça uma pausa por um momento no início do movimento, depois inspire e abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1631.gif', 'hasaneyldrm', '1631'),
  ('b1d7a80a-0000-4000-8000-000000000152'::uuid, null, 'extensão de concentração de cabo (no joelho)', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Sente-se em um banco ou cadeira com os joelhos dobrados e os pés apoiados no chão. Segure a alça do cabo com a mão direita e coloque o cotovelo na parte interna do joelho direito. Estenda totalmente o braço, mantendo o cotovelo parado e próximo ao joelho. Faça uma pausa no topo e, em seguida, abaixe lentamente o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0152.gif', 'hasaneyldrm', '0152'),
  ('b1d7a80a-0000-4000-8000-000000000153'::uuid, null, 'pulldown lateral cruzado do cabo', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Prenda uma alça de cabo em cada lado de uma máquina de cabo na altura dos ombros. Fique no meio da máquina com os pés afastados na largura dos ombros. Segure as alças com força e dê um passo para trás para criar tensão nos cabos. Incline-se ligeiramente para a frente a partir dos quadris, mantendo as costas retas e o peito erguido. Puxe as alças para baixo e ao longo do corpo, apertando as omoplatas. Faça uma pausa por um momento no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0153.gif', 'hasaneyldrm', '0153'),
  ('b1d7a80a-0000-4000-8000-000000000154'::uuid, null, 'cruzamento de cabo inverte voo', 'push_h', ARRAY['delts', 'rhomboids']::text[], ARRAY['rhomboids', 'trapezius']::text[], 'cable', false, 'Prenda uma alça em D a cada cabo de polia baixa e fique no meio da máquina de cruzamento de cabos. Segure as alças com uma pegada pronada (palmas voltadas para baixo) e dê um passo à frente, posicionando os pés na largura dos ombros. Dobre ligeiramente os joelhos e incline-se para a frente na cintura, mantendo as costas retas e os abdominais contraídos. Com os braços estendidos para os lados e ligeiramente dobrados nos cotovelos, expire e aperte as omoplatas enquanto puxa os cabos para trás e para cima em um movimento reverso. Faça uma pausa por um momento no pico da contração, depois inspire e retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0154.gif', 'hasaneyldrm', '0154'),
  ('b1d7a80a-0000-4000-8000-000000000155'::uuid, null, 'variação de cruzamento de cabo', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Ajuste as polias do cabo à altura do peito. Fique no centro da máquina de cabos com um pé na frente do outro. Segure as alças com as palmas voltadas para baixo e os braços estendidos para os lados. Dê um passo à frente, mantendo os braços ligeiramente flexionados. Com uma ligeira flexão dos cotovelos, junte as mãos na frente do peito. Faça uma pausa por um momento e depois retorne lentamente os braços à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0155.gif', 'hasaneyldrm', '0155'),
  ('b1d7a80a-0000-4000-8000-000000000868'::uuid, null, 'ondulação do cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure o acessório do cabo com uma pegada supinada, com as palmas voltadas para cima. Mantenha os cotovelos próximos aos lados e os braços parados. Expire e enrole o cabo em direção aos ombros, contraindo o bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente a fixação do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0868.gif', 'hasaneyldrm', '0868'),
  ('b1d7a80a-0000-4000-8000-000000000157'::uuid, null, 'levantamento terra com cabo', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'lower back']::text[], 'cable', false, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Dobre os quadris e os joelhos, abaixando o tronco até que as costas fiquem paralelas ao chão. Segure as alças do cabo com uma pegada pronada, mantendo os braços retos e os ombros para trás. Envolva os glúteos e isquiotibiais para levantar as alças do cabo, estendendo os quadris e ficando em pé. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0157.gif', 'hasaneyldrm', '0157'),
  ('b1d7a80a-0000-4000-8000-000000000158'::uuid, null, 'declínio do cabo voar', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'cable', false, 'Ajuste a máquina de cabos para uma posição de declínio. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure as alças com as palmas voltadas para a frente e os braços estendidos à sua frente. Mantendo uma ligeira flexão nos cotovelos, abra os braços para os lados em um movimento controlado. Faça uma pausa por um momento na posição totalmente estendida e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0158.gif', 'hasaneyldrm', '0158'),
  ('b1d7a80a-0000-4000-8000-000000001260'::uuid, null, 'cabo recusar pressão de um braço', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'cable', true, 'Ajuste a máquina de cabos para uma posição de declínio. Fique de costas para a máquina e segure a alça com uma mão. Posicione-se com as costas apoiadas no banco de declínio e o braço estendido à sua frente. Dobre o cotovelo e abaixe a alça em direção ao peito, mantendo o braço parado. Faça uma pausa na parte inferior e empurre a alça de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1260.gif', 'hasaneyldrm', '1260'),
  ('b1d7a80a-0000-4000-8000-000000001261'::uuid, null, 'imprensa de recusa de cabo', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'cable', false, 'Ajuste a máquina de cabos para uma posição de declínio. Sente-se no banco inclinado de frente para a máquina de cabos. Segure as alças com força e posicione-as na altura do peito. Mantenha os pés apoiados no chão e as costas firmemente apoiadas no banco. Expire e afaste as alças do corpo, estendendo totalmente os braços. Faça uma pausa no final do movimento, contraindo os músculos do peito. Inspire e retorne lentamente as alças à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1261.gif', 'hasaneyldrm', '1261'),
  ('b1d7a80a-0000-4000-8000-000000000159'::uuid, null, 'declínio do cabo sentado em remada de grande aderência', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se no banco inclinado de frente para a máquina de cabos, com os pés firmemente colocados nos apoios para os pés. Segure o acessório do cabo com uma pegada ampla, com as palmas voltadas para baixo. Incline-se ligeiramente para trás, mantendo as costas retas e o núcleo engajado. Puxe o cabo em direção à parte inferior do tórax, apertando as omoplatas. Faça uma pausa por um momento no pico da contração e, em seguida, solte lentamente o cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0159.gif', 'hasaneyldrm', '0159'),
  ('b1d7a80a-0000-4000-8000-000000001632'::uuid, null, 'enrolamento de arrasto do cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure o acessório do cabo com uma pegada supinada, com as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole o cabo em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente o cabo de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1632.gif', 'hasaneyldrm', '1632'),
  ('b1d7a80a-0000-4000-8000-000000000160'::uuid, null, 'linha de aderência larga sentada no chão do cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se no chão com as pernas estendidas e as costas retas. Prenda uma alça de cabo a uma polia baixa e posicione a máquina de cabos atrás de você. Segure a alça com um aperto amplo, com as palmas voltadas para baixo. Incline-se ligeiramente para trás, mantendo as costas retas e o peito levantado. Puxe a alça em direção à cintura, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente a alça de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0160.gif', 'hasaneyldrm', '0160'),
  ('b1d7a80a-0000-4000-8000-000000000161'::uuid, null, 'elevação do cabo para frente', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'forearms']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a alça do cabo com uma pegada pronada, com as palmas voltadas para baixo e os braços totalmente estendidos à sua frente. Mantendo os braços retos, levante a alça do cabo até a altura dos ombros. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0161.gif', 'hasaneyldrm', '0161'),
  ('b1d7a80a-0000-4000-8000-000000000162'::uuid, null, 'elevação frontal do cabo', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'forearms']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a alça do cabo com uma pegada pronada. Mantenha as costas retas e o núcleo engajado. Levante a alça do cabo à sua frente, mantendo os braços retos e as palmas voltadas para baixo. Continue levantando até que seus braços fiquem paralelos ao chão. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0162.gif', 'hasaneyldrm', '0162'),
  ('b1d7a80a-0000-4000-8000-000000000164'::uuid, null, 'elevação frontal do ombro com cabo', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'biceps']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a alça do cabo com uma pegada pronada. Mantenha as costas retas e o núcleo engajado. Levante a alça do cabo à sua frente, mantendo os braços retos e as palmas voltadas para baixo. Continue levantando até que seus braços fiquem paralelos ao chão. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0164.gif', 'hasaneyldrm', '0164'),
  ('b1d7a80a-0000-4000-8000-000000000165'::uuid, null, 'cabo martelo enrolado (com corda)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Fique em pé, com os pés afastados na largura dos ombros e uma ligeira flexão dos joelhos. Segure o acessório do cabo com uma pegada por baixo, as palmas voltadas uma para a outra e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar o cabo até que seus bíceps estejam totalmente contraídos e a corda esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e comece lentamente a abaixar o acessório do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0165.gif', 'hasaneyldrm', '0165'),
  ('b1d7a80a-0000-4000-8000-000000001722'::uuid, null, 'extensão de tríceps suspensa com polia alta', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma corda a uma polia alta e fique de costas para a máquina. Segure a corda com as duas mãos e estenda os braços acima da cabeça. Mantenha os cotovelos próximos à cabeça e os braços parados. Abaixe lentamente a corda atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1722.gif', 'hasaneyldrm', '1722'),
  ('b1d7a80a-0000-4000-8000-000000000167'::uuid, null, 'fileira alta de cabo (ajoelhado)', 'pull_v', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'cable', false, 'Prenda uma barra reta a uma máquina de cabos na altura do peito. Ajoelhe-se em frente à máquina de cabos e agarre a barra com uma pegada pronada, com as mãos afastadas na largura dos ombros. Sente-se sobre os calcanhares, mantendo as costas retas e o núcleo engajado. Puxe a barra em direção à parte superior do abdômen, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0167.gif', 'hasaneyldrm', '0167'),
  ('b1d7a80a-0000-4000-8000-000000000168'::uuid, null, 'adução de quadril por cabo', 'isolation', ARRAY['adductors', 'glutes']::text[], ARRAY['glutes', 'quadriceps']::text[], 'cable', false, 'Prenda a tornozeleira no tornozelo e fique de frente para a máquina de cabos. Posicione-se suficientemente longe da máquina para que haja tensão no cabo. Coloque as mãos na máquina para apoio. Mantendo a perna esticada, mova lentamente a perna pelo corpo em direção à linha média. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0168.gif', 'hasaneyldrm', '0168'),
  ('b1d7a80a-0000-4000-8000-000000000169'::uuid, null, 'supino inclinado com cabo', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Ajuste o banco para uma inclinação de 45 graus. Prenda as alças dos cabos nas polias altas. Sente-se no banco de frente para a máquina de cabos, com os pés apoiados no chão. Segure as alças com força e leve-as até a altura dos ombros. Empurre as alças para frente e para cima até que seus braços estejam totalmente estendidos. Faça uma pausa por um momento e, em seguida, abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0169.gif', 'hasaneyldrm', '0169'),
  ('b1d7a80a-0000-4000-8000-000000001318'::uuid, null, 'fileira de banco inclinado com cabos', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'rear deltoids']::text[], 'cable', false, 'Configure um banco inclinado em um ângulo de 45 graus e prenda uma alça de cabo na polia baixa. Sente-se no banco de frente para a máquina de cabos, com os pés apoiados no chão e os joelhos ligeiramente dobrados. Segure a alça do cabo com força e estenda os braços totalmente à sua frente. Incline-se para a frente a partir dos quadris, mantendo as costas retas e o núcleo engajado. Puxe a alça do cabo em direção ao peito, retraindo as omoplatas e dobrando os cotovelos. Contraia os músculos das costas no início do movimento e, em seguida, estenda lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1318.gif', 'hasaneyldrm', '1318'),
  ('b1d7a80a-0000-4000-8000-000000000171'::uuid, null, 'mosca inclinada do cabo', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Ajuste a máquina de cabos para uma posição baixa e prenda as alças. Sente-se em um banco inclinado com as costas apoiadas na almofada e os pés apoiados no chão. Segure as alças com força e estenda os braços à sua frente. Mantendo uma ligeira flexão nos cotovelos, abra os braços para os lados em um movimento controlado. Faça uma pausa por um momento na posição totalmente estendida e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0171.gif', 'hasaneyldrm', '0171'),
  ('b1d7a80a-0000-4000-8000-000000000170'::uuid, null, 'mosca inclinada do cabo (na bola de estabilidade)', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Configure uma bola de estabilidade em um ângulo inclinado. Prenda as alças dos cabos às polias altas de uma máquina de cabos. Sente-se na bola de estabilidade de costas para a máquina, com os pés firmemente plantados no chão. Segure as alças do cabo com uma pegada pronada, com as palmas voltadas para frente. Incline-se ligeiramente para a frente, mantendo as costas retas e o núcleo engajado. Com um movimento controlado, abra os braços para os lados, mantendo uma ligeira flexão nos cotovelos. Continue o movimento até que seus braços fiquem paralelos ao chão. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0170.gif', 'hasaneyldrm', '0170'),
  ('b1d7a80a-0000-4000-8000-000000000172'::uuid, null, 'pushdown de inclinação do cabo', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia alta. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Incline-se ligeiramente para a frente e mantenha as costas retas. Puxe a barra para baixo em direção às coxas, estendendo os cotovelos. Faça uma pausa na parte inferior e, em seguida, retorne lentamente a barra à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0172.gif', 'hasaneyldrm', '0172'),
  ('b1d7a80a-0000-4000-8000-000000000173'::uuid, null, 'extensão de tríceps com inclinação de cabo', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Ajuste a máquina de cabos para uma posição de polia baixa. Anexe uma barra reta ao cabo. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada e estenda os braços acima da cabeça. Incline-se ligeiramente para a frente, mantendo as costas retas e o núcleo engajado. Dobre os cotovelos e abaixe a barra atrás da cabeça, mantendo os braços próximos às orelhas. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0173.gif', 'hasaneyldrm', '0173'),
  ('b1d7a80a-0000-4000-8000-000000000174'::uuid, null, 'cabo judô flip', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'shoulders']::text[], 'cable', false, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a alça do cabo com as duas mãos na altura do peito, com as palmas voltadas para baixo. Envolva seu núcleo e gire o tronco para a direita, puxando o cabo pelo corpo. Ao girar, gire o pé de trás e permita que os quadris girem naturalmente. Estenda totalmente os braços e finalize o movimento passando a alça do cabo por cima do ombro. Retorne à posição inicial invertendo o movimento, girando o tronco de volta ao centro. Repita o movimento no lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0174.gif', 'hasaneyldrm', '0174'),
  ('b1d7a80a-0000-4000-8000-000000000860'::uuid, null, 'retrocesso do cabo', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure a alça do cabo com a mão direita e dê um passo para trás para criar tensão no cabo. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Mantenha o braço próximo ao corpo e o cotovelo dobrado em um ângulo de 90 graus. Estenda o antebraço para trás, esticando totalmente o braço. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0860.gif', 'hasaneyldrm', '0860'),
  ('b1d7a80a-0000-4000-8000-000000000175'::uuid, null, 'crise de ajoelhamento de cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Prenda uma alça de corda a uma polia alta e ajoelhe-se de costas para a máquina. Segure a alça da corda com as duas mãos e coloque-a atrás da cabeça, mantendo os cotovelos voltados para os lados. Mantendo os quadris parados, flexione a cintura e contraia o tronco em direção às coxas. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0175.gif', 'hasaneyldrm', '0175'),
  ('b1d7a80a-0000-4000-8000-000000003697'::uuid, null, 'cabo ajoelhado linha deltóide traseira (com corda) (masculino)', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'cable', false, 'Prenda uma alça de corda a uma polia baixa e ajoelhe-se de frente para a máquina. Segure a corda com uma pegada neutra (palmas voltadas uma para a outra) e estenda os braços totalmente à sua frente. Mantendo as costas retas e o núcleo engajado, puxe a corda em direção ao corpo, retraindo as omoplatas. Aperte as omoplatas no final do movimento e segure por uma breve pausa. Libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3697.gif', 'hasaneyldrm', '3697'),
  ('b1d7a80a-0000-4000-8000-000000000176'::uuid, null, 'extensão de tríceps ajoelhada com cabo', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma alça de corda a uma polia alta e ajoelhe-se de frente para a máquina de cabos. Segure a corda com uma pegada neutra (palmas voltadas uma para a outra) e coloque as mãos nas laterais da cabeça. Mantenha os cotovelos próximos à cabeça e os braços parados durante todo o exercício. Estenda os antebraços contraindo os tríceps até que os braços estejam totalmente estendidos. Faça uma pausa e retorne lentamente à posição inicial, dobrando os cotovelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0176.gif', 'hasaneyldrm', '0176'),
  ('b1d7a80a-0000-4000-8000-000000002330'::uuid, null, 'cabo lat pulldown amplitude completa de movimento', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Sente-se na máquina de pulldown com os joelhos posicionados sob as almofadas. Segure a barra do cabo com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Incline-se ligeiramente para trás e mantenha o peito erguido, mantendo um leve arco na parte inferior das costas. Puxe a barra para baixo em direção à parte superior do peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2330.gif', 'hasaneyldrm', '2330'),
  ('b1d7a80a-0000-4000-8000-000000000177'::uuid, null, 'pulldown lateral por cabo (com fixação de corda)', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Prenda um acessório de corda à máquina de cabos em uma posição alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a corda com uma pegada pronada, com as palmas voltadas uma para a outra. Mantenha as costas retas e incline-se ligeiramente para trás. Puxe a corda para os lados, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento. Libere lentamente a tensão e deixe a corda retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0177.gif', 'hasaneyldrm', '0177'),
  ('b1d7a80a-0000-4000-8000-000000002616'::uuid, null, 'pulldown lateral do cabo com barra em V', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se na máquina suspensa de cabos e segure o acessório da barra em V com uma pegada pronada. Ajuste a joelheira para que suas coxas fiquem seguras sob ela. Mantenha as costas retas e incline-se ligeiramente para trás. Puxe a barra em V para baixo em direção à parte superior do peito, mantendo os cotovelos próximos ao corpo. Contraia os músculos das costas na parte inferior do movimento. Retorne lentamente a barra V à posição inicial e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2616.gif', 'hasaneyldrm', '2616'),
  ('b1d7a80a-0000-4000-8000-000000000178'::uuid, null, 'elevação lateral do cabo', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'triceps']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e segure as alças do cabo com uma pegada pronada. Mantenha os braços retos e o núcleo engajado. Levante os braços para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0178.gif', 'hasaneyldrm', '0178'),
  ('b1d7a80a-0000-4000-8000-000000000179'::uuid, null, 'cabo voo baixo', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Prenda as alças nas polias baixas de uma máquina de cabos e selecione um peso apropriado. Fique no meio da máquina com os pés afastados na largura dos ombros e uma ligeira flexão dos joelhos. Segure as alças com força e estenda os braços para os lados, mantendo uma ligeira flexão nos cotovelos. Mantendo o controle, traga lentamente os braços para a frente em um movimento amplo, cruzando-os na frente do corpo. Faça uma pausa por um momento no auge do movimento, sentindo o alongamento dos músculos do peito. Inverta o movimento e retorne lentamente os braços à posição inicial, mantendo a tensão nos músculos do peito o tempo todo. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0179.gif', 'hasaneyldrm', '0179'),
  ('b1d7a80a-0000-4000-8000-000000000180'::uuid, null, 'cabo fileira baixa sentada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se na máquina com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure as alças com uma pegada pronada, com as palmas voltadas para baixo. Mantenha as costas retas e incline-se ligeiramente para a frente, mantendo uma ligeira flexão nos cotovelos. Puxe as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0180.gif', 'hasaneyldrm', '0180'),
  ('b1d7a80a-0000-4000-8000-000000001634'::uuid, null, 'rosca bíceps deitada com cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia baixa. Deite-se de bruços em um banco plano com os pés apoiados no chão. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Estenda os braços totalmente, mantendo os cotovelos próximos ao corpo. Mantendo os braços parados, expire e enrole a barra em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1634.gif', 'hasaneyldrm', '1634'),
  ('b1d7a80a-0000-4000-8000-000000000182'::uuid, null, 'cabo deitado, enrolamento próximo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia baixa. Deite-se de bruços em um banco plano com os pés apoiados no chão. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Estenda os braços totalmente, mantendo os cotovelos próximos ao corpo. Mantendo os braços parados, enrole a barra em direção ao peito, contraindo os bíceps. Faça uma pausa no topo, apertando o bíceps. Abaixe lentamente a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0182.gif', 'hasaneyldrm', '0182'),
  ('b1d7a80a-0000-4000-8000-000000000184'::uuid, null, 'pulôver extensor de cabo (com fixação de corda)', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'cable', false, 'Prenda uma corda a uma máquina de cabos e coloque a polia na posição mais alta. Deite-se em um banco com a cabeça voltada para a máquina de cabos. Segure a corda com as duas mãos e estenda os braços acima do peito. Mantendo os braços retos, abaixe lentamente a corda atrás da cabeça enquanto mantém o controle. Faça uma pausa por um momento na parte inferior e, em seguida, levante lentamente a corda de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0184.gif', 'hasaneyldrm', '0184'),
  ('b1d7a80a-0000-4000-8000-000000000185'::uuid, null, 'cabo deitado mosca', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Prenda as alças aos cabos e deite-se em um banco com os pés apoiados no chão. Segure as alças com as palmas voltadas uma para a outra e os braços estendidos acima do peito. Mantendo uma ligeira flexão nos cotovelos, abaixe os braços para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa por um momento e contraia os músculos do peito para trazer os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0185.gif', 'hasaneyldrm', '0185'),
  ('b1d7a80a-0000-4000-8000-000000000186'::uuid, null, 'extensão de tríceps deitado cabo v. 2', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma alça de corda a uma máquina de cabo de polia baixa. Deite-se em um banco plano voltado para cima, com a cabeça voltada para a máquina de cabos. Segure a alça da corda com as duas mãos, com as palmas voltadas uma para a outra, e estenda os braços sobre o peito. Mantendo os braços parados, abaixe lentamente a alça da corda em direção à testa, dobrando os cotovelos. Faça uma pausa na parte inferior e, em seguida, estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0186.gif', 'hasaneyldrm', '0186'),
  ('b1d7a80a-0000-4000-8000-000000000188'::uuid, null, 'cabo médio mosca', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Conecte os cabos em ambos os lados de uma máquina de cabos na altura do peito. Fique no centro da máquina com um pé ligeiramente à frente do outro. Segure as alças com força e estenda os braços para os lados. Mantenha uma ligeira flexão nos cotovelos e uma ligeira inclinação para a frente. Envolva os músculos do peito e leve os braços para a frente em um movimento amplo. Faça uma pausa por um momento no centro e, em seguida, retorne lentamente os braços à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0188.gif', 'hasaneyldrm', '0188'),
  ('b1d7a80a-0000-4000-8000-000000000189'::uuid, null, 'cabo um braço dobrado sobre a linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', true, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Segure a alça do cabo com uma mão, com a palma voltada para dentro, e estenda totalmente o braço. Puxe a alça do cabo em direção ao corpo, mantendo o cotovelo próximo ao corpo, até que a mão alcance a parte inferior do peito. Faça uma pausa por um momento e, em seguida, estenda lentamente o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0189.gif', 'hasaneyldrm', '0189'),
  ('b1d7a80a-0000-4000-8000-000000000190'::uuid, null, 'flexão de um braço com cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada supinada, com a palma voltada para cima. Mantenha o cotovelo próximo ao lado do corpo e lentamente enrole o antebraço em direção ao ombro. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente o antebraço de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0190.gif', 'hasaneyldrm', '0190'),
  ('b1d7a80a-0000-4000-8000-000000001262'::uuid, null, 'cabo um braço declínio peito mosca', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'cable', true, 'Prenda uma alça em D a uma máquina com cabo de polia baixa e coloque a bancada em um ângulo de declínio. Deite-se no banco com a cabeça voltada para a máquina e segure a alça com a mão direita. Estenda o braço acima do peito, mantendo uma ligeira flexão no cotovelo. Com um movimento controlado, abaixe o braço para o lado até que a mão fique alinhada com o ombro. Faça uma pausa, depois inverta o movimento e traga o braço de volta à posição inicial. Repita o número desejado de repetições, depois mude para o braço esquerdo e repita o exercício.', '/exercise-media/bstrainer/1262.gif', 'hasaneyldrm', '1262'),
  ('b1d7a80a-0000-4000-8000-000000001263'::uuid, null, 'cabo com um braço voando na bola de exercícios', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure uma alça de cabo com uma mão e estenda o braço para o lado, paralelo ao chão. Mantenha o cotovelo ligeiramente dobrado e a palma da mão voltada para a frente. Lentamente, passe o braço pelo corpo, apertando os músculos do peito. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1263.gif', 'hasaneyldrm', '1263'),
  ('b1d7a80a-0000-4000-8000-000000001264'::uuid, null, 'cabo com um braço inclinado para mosca na bola de exercícios', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas apoiadas em um banco inclinado. Segure a alça do cabo com uma das mãos, com o braço estendido e a palma voltada para dentro. Mantendo uma ligeira flexão no cotovelo, abaixe lentamente o braço para o lado até que a mão fique alinhada com o ombro. Faça uma pausa por um momento e contraia os músculos do peito para trazer o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1264.gif', 'hasaneyldrm', '1264'),
  ('b1d7a80a-0000-4000-8000-000000001265'::uuid, null, 'prensa inclinada com um braço com cabo', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', true, 'Ajuste a máquina de cabos para uma posição de polia baixa. Sente-se em um banco inclinado de costas para a máquina de cabos. Segure a alça com uma mão e leve-a até a altura dos ombros. Posicione os pés firmemente no chão e mantenha uma posição estável. Pressione a alça para frente e para cima, estendendo totalmente o braço. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1265.gif', 'hasaneyldrm', '1265'),
  ('b1d7a80a-0000-4000-8000-000000001266'::uuid, null, 'cabo de inclinação de um braço na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'cable', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas apoiadas em um banco inclinado. Segure a alça do cabo com uma mão e posicione o braço em um ângulo de 90 graus com o cotovelo dobrado. Pressione a alça do cabo para frente e para cima, estendendo totalmente o braço. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1266.gif', 'hasaneyldrm', '1266'),
  ('b1d7a80a-0000-4000-8000-000000000191'::uuid, null, 'cabo um braço lateral dobrado', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'trapezius']::text[], 'cable', true, 'Fique em pé com os pés afastados na largura dos ombros, de frente para uma máquina de cabos. Segure a alça com uma mão e dê um passo para trás para criar tensão no cabo. Incline-se para a frente na cintura, mantendo as costas retas e o núcleo engajado. Estenda o braço para o lado, paralelo ao chão, com uma ligeira flexão no cotovelo. Lentamente, traga o braço de volta à posição inicial, mantendo o controle durante todo o movimento. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0191.gif', 'hasaneyldrm', '0191'),
  ('b1d7a80a-0000-4000-8000-000000000192'::uuid, null, 'cabo elevação lateral com um braço', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'triceps']::text[], 'cable', true, 'Fique em pé com os pés afastados na largura dos ombros, de frente para a máquina de cabos. Segure a alça do cabo com uma mão, com a palma voltada para baixo, e fique longe o suficiente da máquina para que haja tensão no cabo. Mantenha o braço esticado e levante-o lentamente para o lado até ficar paralelo ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0192.gif', 'hasaneyldrm', '0192'),
  ('b1d7a80a-0000-4000-8000-000000001633'::uuid, null, 'cabo pregador de um braço enrolado', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Ajuste a máquina de cabos de modo que a almofada de enrolamento do pregador fique na altura do peito. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada por baixo e posicione o braço contra a almofada de curvatura do pregador. Mantenha as costas retas e o núcleo engajado. Enrole lentamente a alça do cabo em direção ao ombro, mantendo o braço contra a almofada. Faça uma pausa no início do movimento, apertando o bíceps. Abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições. Troque de braço e repita o exercício.', '/exercise-media/bstrainer/1633.gif', 'hasaneyldrm', '1633'),
  ('b1d7a80a-0000-4000-8000-000000001267'::uuid, null, 'cabo pressão de um braço na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'cable', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure uma alça de cabo com uma mão e posicione o braço na altura do peito, com o cotovelo dobrado. Coloque a outra mão no quadril para obter estabilidade. Pressione a alça do cabo para frente, estendendo totalmente o braço. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1267.gif', 'hasaneyldrm', '1267'),
  ('b1d7a80a-0000-4000-8000-000000003563'::uuid, null, 'cabo suspenso com um braço', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', true, 'Anexe uma única alça a uma máquina de cabo de polia alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a alça com força e estenda totalmente o braço. Mantenha as costas retas e o núcleo engajado. Puxe a alça para baixo em direção ao seu lado, mantendo o cotovelo próximo ao corpo. Faça uma pausa por um momento na parte inferior do movimento, apertando o músculo posterior. Solte lentamente a alça de volta à posição inicial. Repita pelo número desejado de repetições. Troque de lado e repita o exercício com o outro braço.', '/exercise-media/bstrainer/3563.gif', 'hasaneyldrm', '3563'),
  ('b1d7a80a-0000-4000-8000-000000001635'::uuid, null, 'cabo um braço pregador reverso curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Ajuste a máquina de cabos para que a polia fique na posição mais baixa. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a alça do cabo com um aperto de mão e posicione o braço contra a almofada do banco do pregador. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Enrole lentamente o antebraço em direção ao bíceps, mantendo o braço parado contra a almofada. Faça uma pausa no início do movimento, apertando o bíceps. Abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições. Troque de braço e repita o exercício.', '/exercise-media/bstrainer/1635.gif', 'hasaneyldrm', '1635'),
  ('b1d7a80a-0000-4000-8000-000000000193'::uuid, null, 'cabo um braço reto para trás remada alta (ajoelhado)', 'pull_v', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'cable', true, 'Prenda uma alça a uma máquina de cabo na altura da cintura. Ajoelhe-se de frente para a máquina de cabos e segure a alça com uma das mãos. Mantenha as costas retas e o núcleo engajado. Puxe a alça em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento. Solte lentamente a alça de volta à posição inicial. Repita pelo número desejado de repetições. Troque de lado e repita o exercício com o outro braço.', '/exercise-media/bstrainer/0193.gif', 'hasaneyldrm', '0193'),
  ('b1d7a80a-0000-4000-8000-000000001723'::uuid, null, 'cabo pushdown de tríceps com um braço', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Fique de frente para uma máquina de cabo com uma barra reta na altura do peito. Segure a barra com força e dê um passo para trás para criar tensão no cabo. Posicione os pés na largura dos ombros e dobre ligeiramente os joelhos. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Comece com o braço totalmente estendido e perpendicular ao chão. Mantendo o braço parado, expire e empurre a barra para baixo até que o braço esteja totalmente estendido. Faça uma pausa, inspire e retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1723.gif', 'hasaneyldrm', '1723'),
  ('b1d7a80a-0000-4000-8000-000000001636'::uuid, null, 'ondulação aérea do cabo', 'push_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Mantenha os cotovelos próximos aos lados e os braços parados. Expire e enrole a barra em direção à testa, mantendo os braços parados. Faça uma pausa no final do movimento, apertando o bíceps. Inspire e retorne lentamente a barra à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1636.gif', 'hasaneyldrm', '1636'),
  ('b1d7a80a-0000-4000-8000-000000001637'::uuid, null, 'enrolamento aéreo do cabo na bola de exercícios', 'push_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'cable', false, 'Sente-se em uma bola de exercícios e segure a alça do cabo com uma pegada por baixo. Estenda os braços totalmente acima da cabeça, mantendo os cotovelos próximos às orelhas. Enrole lentamente o cabo em direção à testa, mantendo os braços parados. Faça uma pausa por um momento no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1637.gif', 'hasaneyldrm', '1637'),
  ('b1d7a80a-0000-4000-8000-000000000194'::uuid, null, 'extensão de tríceps por cabo (fixação de corda)', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma corda a uma máquina de cabos em uma posição alta. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure a corda com as duas mãos, com as palmas voltadas uma para a outra, e coloque-as acima da cabeça. Mantenha os braços próximos à cabeça e os cotovelos apontando para a frente. Abaixe lentamente a corda atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0194.gif', 'hasaneyldrm', '0194'),
  ('b1d7a80a-0000-4000-8000-000000001319'::uuid, null, 'fileira rotacional da palma do cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Prenda uma alça a uma máquina de cabo na altura da cintura. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a alça com uma pegada pronada, com as palmas voltadas para baixo. Dê um passo para trás para criar tensão no cabo, mantendo as costas retas e os joelhos ligeiramente flexionados. Puxe a alça em direção ao corpo, girando as palmas das mãos para cima enquanto faz isso. Aperte as omoplatas no final do movimento. Solte lentamente a alça de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1319.gif', 'hasaneyldrm', '1319'),
  ('b1d7a80a-0000-4000-8000-000000000195'::uuid, null, 'cabo pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Ajuste a máquina de cabos de modo que a almofada de enrolamento do pregador fique na altura do peito. Sente-se no banco de pregador e coloque os braços na almofada, segurando o acessório do cabo com uma pegada por baixo. Mantenha as costas retas e os cotovelos dobrados ao lado do corpo. Enrole lentamente o cabo em direção aos ombros, apertando os bíceps no topo do movimento. Faça uma pausa por um momento e, em seguida, abaixe lentamente o acessório do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0195.gif', 'hasaneyldrm', '0195'),
  ('b1d7a80a-0000-4000-8000-000000001268'::uuid, null, 'prensa de cabo na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'cable', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e os joelhos formando um ângulo de 90 graus. Segure as alças do cabo na altura do peito, com as palmas voltadas para baixo e os cotovelos dobrados. Envolva seu núcleo e pressione as alças do cabo para frente até que seus braços estejam totalmente estendidos. Faça uma pausa por um momento, depois libere lentamente a tensão e traga as alças do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1268.gif', 'hasaneyldrm', '1268'),
  ('b1d7a80a-0000-4000-8000-000000000196'::uuid, null, 'passagem de cabo (com corda)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'cable', false, 'Fique de costas para a máquina de cabos, com os pés afastados na largura dos ombros. Segure o acessório da corda com as duas mãos e dê um passo à frente, criando tensão no cabo. Dobre os quadris e abaixe a parte superior do corpo até ficar paralela ao chão, mantendo as costas retas. Envolva os glúteos e isquiotibiais para puxar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0196.gif', 'hasaneyldrm', '0196'),
  ('b1d7a80a-0000-4000-8000-000000000198'::uuid, null, 'pulldown do cabo', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Ajuste a máquina suspensa por cabo de modo que o assento fique a uma altura confortável e a joelheira esteja segura. Sente-se no assento com as costas retas e os pés apoiados no chão. Segure a barra do cabo com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Incline-se um pouco para trás e envolva seu núcleo. Puxe a barra do cabo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0198.gif', 'hasaneyldrm', '0198'),
  ('b1d7a80a-0000-4000-8000-000000000197'::uuid, null, 'pulldown do cabo (barra pro lat)', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Ajuste a altura do assento de forma que as coxas fiquem paralelas ao chão e os pés apoiados no chão. Segure a barra lateral com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Sente-se e incline-se ligeiramente para trás, mantendo o peito erguido e as costas retas. Puxe a barra para baixo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0197.gif', 'hasaneyldrm', '0197'),
  ('b1d7a80a-0000-4000-8000-000000001638'::uuid, null, 'rosca bíceps suspensa com cabo', 'pull_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta à máquina de cabos na configuração mais alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Mantenha os cotovelos próximos aos lados e os braços parados. Expire e enrole lentamente a barra em direção às coxas, mantendo os pulsos retos. Faça uma pausa no final do movimento, apertando o bíceps. Inspire e retorne lentamente a barra à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1638.gif', 'hasaneyldrm', '1638'),
  ('b1d7a80a-0000-4000-8000-000000000201'::uuid, null, 'empurrão do cabo', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia alta. Fique de frente para a máquina com os pés afastados na largura dos ombros e uma ligeira flexão dos joelhos. Segure a barra com uma pegada pronada, com as mãos na largura dos ombros. Mantenha os cotovelos próximos aos lados e os braços parados. Expire e empurre a barra para baixo até que os cotovelos estejam totalmente estendidos. Faça uma pausa, inspire e retorne lentamente a barra à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0201.gif', 'hasaneyldrm', '0201'),
  ('b1d7a80a-0000-4000-8000-000000000199'::uuid, null, 'pushdown de cabo (braço reto) v. 2', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia alta. Fique de frente para a máquina com os pés afastados na largura dos ombros e uma ligeira flexão dos joelhos. Segure a barra com uma pegada pronada, mantendo os braços retos e as palmas voltadas para baixo. Envolva o núcleo e mantenha as costas retas enquanto expira e empurra a barra para baixo em direção às coxas. Faça uma pausa na parte inferior e, em seguida, retorne lentamente a barra à posição inicial enquanto inspira. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0199.gif', 'hasaneyldrm', '0199'),
  ('b1d7a80a-0000-4000-8000-000000000200'::uuid, null, 'pushdown de cabo (com fixação de corda)', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Prenda um acessório de corda a uma polia alta em uma máquina de cabo. Fique de frente para a máquina com os pés afastados na largura dos ombros e uma ligeira flexão dos joelhos. Segure a corda com uma pegada pronada, com as palmas voltadas uma para a outra. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Expire e empurre a corda para baixo, estendendo os cotovelos até que os braços estejam totalmente estendidos. Faça uma pausa por um momento, inspire e retorne lentamente à posição inicial, permitindo que os cotovelos flexionem. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0200.gif', 'hasaneyldrm', '0200'),
  ('b1d7a80a-0000-4000-8000-000000000202'::uuid, null, 'linha deltóide traseira do cabo (estribos)', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'cable', false, 'Prenda uma alça de estribo a uma polia de cabo baixa e fique de frente para a máquina. Segure a alça com a mão esquerda e dê um passo para trás com o pé direito, posicionando o corpo ligeiramente inclinado. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Com o braço esquerdo estendido e a palma da mão voltada para baixo, puxe a alça em direção ao peito, retraindo a omoplata. Faça uma pausa no início do movimento, apertando a omoplata. Solte lentamente a alça de volta à posição inicial e repita o número desejado de repetições. Troque de lado e repita o exercício com o braço direito.', '/exercise-media/bstrainer/0202.gif', 'hasaneyldrm', '0202'),
  ('b1d7a80a-0000-4000-8000-000000000203'::uuid, null, 'cabo delt row traseiro (com corda)', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'cable', false, 'Prenda uma alça de corda a uma máquina de cabo de polia baixa. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a alça da corda com uma pegada pronada, com as palmas voltadas uma para a outra. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Mantenha os cotovelos ligeiramente dobrados e puxe a corda em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0203.gif', 'hasaneyldrm', '0203'),
  ('b1d7a80a-0000-4000-8000-000000000204'::uuid, null, 'cabo de acionamento traseiro', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'cable', false, 'Prenda uma alça a uma máquina com cabo de polia baixa e fique de costas para a máquina. Segure a alça com força e estenda os braços à sua frente. Mantendo os cotovelos parados, puxe a alça em direção ao corpo, apertando o tríceps no final do movimento. Retorne lentamente a alça à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0204.gif', 'hasaneyldrm', '0204'),
  ('b1d7a80a-0000-4000-8000-000000000205'::uuid, null, 'pulldown traseiro do cabo', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Ajuste a máquina de cabos para que a polia fique na posição mais alta. Sente-se de frente para a máquina, com os pés apoiados no chão e os joelhos ligeiramente flexionados. Segure o acessório do cabo com uma pegada pronada, com as mãos ligeiramente mais afastadas que a largura dos ombros. Incline-se ligeiramente para trás, mantendo as costas retas e o peito erguido. Puxe o cabo para baixo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente o cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0205.gif', 'hasaneyldrm', '0205'),
  ('b1d7a80a-0000-4000-8000-000000000873'::uuid, null, 'trituração reversa do cabo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'cable', false, 'Prenda um cabo a uma polia baixa e deite-se voltado para cima em um tapete. Segure o cabo com as duas mãos e estenda os braços em direção ao teto. Dobre os joelhos e levante as pernas, aproximando as coxas do peito. Mantendo a parte superior do corpo estável, enrole a pélvis em direção ao peito, levantando os quadris do tapete. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0873.gif', 'hasaneyldrm', '0873'),
  ('b1d7a80a-0000-4000-8000-000000000206'::uuid, null, 'curvatura reversa do cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia baixa. Fique de frente para a máquina com os pés afastados na largura dos ombros e os joelhos ligeiramente dobrados. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Expire e levante a barra em direção aos ombros, contraindo os bíceps. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0206.gif', 'hasaneyldrm', '0206'),
  ('b1d7a80a-0000-4000-8000-000000002406'::uuid, null, 'cabo reverso grip tríceps pushdown (sz-bar) (com arm blaster)', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta à máquina de cabos na configuração mais alta. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a barra com uma pegada por baixo, com as palmas voltadas para cima e as mãos na largura dos ombros. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Envolva o tríceps e empurre lentamente a barra para baixo até que os braços estejam totalmente estendidos. Faça uma pausa na parte inferior e, em seguida, retorne lentamente a barra à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2406.gif', 'hasaneyldrm', '2406'),
  ('b1d7a80a-0000-4000-8000-000000001413'::uuid, null, 'cabo reverso flexão de um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada supinada, com a palma voltada para baixo. Mantenha o cotovelo próximo ao lado do corpo e lentamente enrole o antebraço em direção ao ombro. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente o antebraço de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1413.gif', 'hasaneyldrm', '1413'),
  ('b1d7a80a-0000-4000-8000-000000000209'::uuid, null, 'enrolamento de pregador reverso de cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Ajuste a máquina de cabos de modo que a almofada de enrolamento do pregador fique na altura do peito. Sente-se no banco de pregador e coloque os braços na almofada, com as palmas voltadas para baixo e os cotovelos totalmente estendidos. Segure as alças do cabo com uma pegada por baixo, na largura dos ombros. Mantendo os braços parados, expire e enrole as alças em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente as alças de volta à posição inicial, estendendo totalmente os cotovelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0209.gif', 'hasaneyldrm', '0209'),
  ('b1d7a80a-0000-4000-8000-000000000210'::uuid, null, 'curvatura reversa do pulso do cabo', 'isolation', ARRAY['forearms']::text[], ARRAY['forearms', 'wrists']::text[], 'cable', false, 'Prenda um cabo a uma polia baixa e sente-se em um banco de frente para a máquina de cabos. Segure a alça do cabo com uma pegada pronada, com as palmas voltadas para baixo. Descanse os antebraços nas coxas, com os pulsos pendurados na borda. Mantendo os antebraços parados, expire e curve os pulsos para cima o máximo possível. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os pulsos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0210.gif', 'hasaneyldrm', '0210'),
  ('b1d7a80a-0000-4000-8000-000000000207'::uuid, null, 'pushdown de aderência reversa do cabo', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada por baixo, com as palmas voltadas para cima e as mãos na largura dos ombros. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Usando o tríceps, empurre a barra para baixo até que os braços estejam totalmente estendidos e os tríceps contraídos. Faça uma pausa e retorne lentamente a barra à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0207.gif', 'hasaneyldrm', '0207'),
  ('b1d7a80a-0000-4000-8000-000000000208'::uuid, null, 'cabo reverso-grip reto para trás sentado em fileira alta', 'pull_v', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se no assento de frente para a máquina de cabos, com os pés apoiados no chão. Segure o acessório do cabo com uma pegada por baixo, com as palmas voltadas para cima e as mãos na largura dos ombros. Mantenha as costas retas e incline-se ligeiramente para a frente a partir dos quadris. Puxe o cabo em direção ao tronco, retraindo as omoplatas e contraindo os músculos das costas. Faça uma pausa por um momento no pico da contração e, em seguida, solte lentamente o cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0208.gif', 'hasaneyldrm', '0208'),
  ('b1d7a80a-0000-4000-8000-000000001320'::uuid, null, 'linha sentada cruzada de cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se na máquina de remo com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure os cabos com uma pegada pronada, com as palmas voltadas uma para a outra. Incline-se ligeiramente para trás, mantendo as costas retas e o núcleo engajado. Puxe as cordas em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1320.gif', 'hasaneyldrm', '1320'),
  ('b1d7a80a-0000-4000-8000-000000001321'::uuid, null, 'corda de cabo fileira sentada elevada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se no assento elevado de frente para a máquina de cabos. Segure as alças do cabo com uma pegada pronada, com as palmas voltadas uma para a outra. Mantenha as costas retas e incline-se ligeiramente para trás, mantendo uma ligeira flexão dos joelhos. Puxe o cabo em direção ao corpo, retraindo as omoplatas e contraindo os músculos das costas. Faça uma pausa por um momento na posição totalmente contraída. Libere lentamente a tensão e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1321.gif', 'hasaneyldrm', '1321'),
  ('b1d7a80a-0000-4000-8000-000000001322'::uuid, null, 'extensão de corda de cabo linha de banco inclinado', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'cable', false, 'Configure um banco inclinado em um ângulo de 45 graus e prenda uma máquina de cabos na polia baixa. Prenda uma alça de corda à máquina de cabo e sente-se no banco inclinado de frente para a máquina. Segure a alça da corda com uma pegada pronada e incline-se para frente, mantendo as costas retas. Estenda totalmente os braços, puxando a corda em direção à parte superior do peito, mantendo os cotovelos próximos ao corpo. Aperte as omoplatas no final do movimento. Libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1322.gif', 'hasaneyldrm', '1322'),
  ('b1d7a80a-0000-4000-8000-000000001639'::uuid, null, 'cabo corda martelo pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Prenda um acessório de corda a uma máquina de cabo de polia baixa. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a corda com uma pegada neutra (palmas voltadas uma para a outra). Posicione os braços contra o banco do pregador, mantendo os cotovelos ligeiramente flexionados. Mantendo os braços parados, expire e enrole a corda em direção aos ombros, contraindo os bíceps. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente a corda de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1639.gif', 'hasaneyldrm', '1639'),
  ('b1d7a80a-0000-4000-8000-000000001724'::uuid, null, 'cabo corda polia alta extensão de tríceps acima da cabeça', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma corda a uma polia alta e ajuste o peso de acordo. Fique de costas para a máquina de polia, com os pés afastados na largura dos ombros. Segure a corda com as duas mãos, com as palmas voltadas para baixo, e coloque-as acima da cabeça. Mantenha os braços próximos à cabeça e perpendiculares ao chão. Abaixe lentamente a corda atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1724.gif', 'hasaneyldrm', '1724'),
  ('b1d7a80a-0000-4000-8000-000000001725'::uuid, null, 'extensão de tríceps inclinada de corda de cabo', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma corda a uma polia alta e ajuste o banco inclinado para um ângulo confortável. Fique de costas para a polia, com os pés afastados na largura dos ombros. Segure a corda com uma pegada pronada e estenda os braços acima da cabeça. Mantenha os cotovelos próximos à cabeça e os braços parados durante todo o exercício. Abaixe a corda atrás da cabeça dobrando os cotovelos até que os antebraços toquem o bíceps. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1725.gif', 'hasaneyldrm', '1725'),
  ('b1d7a80a-0000-4000-8000-000000001726'::uuid, null, 'corda de cabo apoiada no chão extensão de tríceps', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Prenda uma corda a uma máquina de cabos e coloque-a na posição mais baixa. Deite-se no chão voltado para cima, com a cabeça voltada para a máquina de cabos. Segure a corda com as duas mãos, com as palmas voltadas uma para a outra, e estenda os braços em direção ao teto. Mantenha os braços parados e abaixe lentamente a corda em direção à testa, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1726.gif', 'hasaneyldrm', '1726'),
  ('b1d7a80a-0000-4000-8000-000000001640'::uuid, null, 'cabo corda um braço martelo pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Prenda uma alça de corda a uma máquina de cabo de polia baixa. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a alça da corda com uma pegada supinada, com as palmas voltadas para cima. Posicione o braço contra o banco do pregador, mantendo o cotovelo ligeiramente dobrado. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Enrole lentamente a alça da corda em direção ao ombro, mantendo o braço parado. Contraia o bíceps no início do movimento e, em seguida, abaixe lentamente a alça da corda de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1640.gif', 'hasaneyldrm', '1640'),
  ('b1d7a80a-0000-4000-8000-000000001323'::uuid, null, 'fila sentada de corda de cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se na máquina de remo com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure os cabos com uma pegada pronada, com as palmas voltadas uma para a outra. Mantenha as costas retas e incline-se ligeiramente para a frente, mantendo uma ligeira flexão nos cotovelos. Puxe os cabos em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1323.gif', 'hasaneyldrm', '1323'),
  ('b1d7a80a-0000-4000-8000-000000000211'::uuid, null, 'cabo torções russas (na bola de estabilidade)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'cable', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure a alça do cabo com as duas mãos e estenda os braços à sua frente. Incline-se ligeiramente para trás, mantendo as costas retas e o núcleo engajado. Gire o tronco para a direita, trazendo a alça do cabo em direção ao quadril direito. Faça uma pausa e gire o tronco para a esquerda, trazendo a alça do cabo em direção ao quadril esquerdo. Continue alternando torções para o número desejado de repetições.', '/exercise-media/bstrainer/0211.gif', 'hasaneyldrm', '0211'),
  ('b1d7a80a-0000-4000-8000-000000002144'::uuid, null, 'prensa torácica sentada com cabo', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'cable', false, 'Ajuste a altura do assento e as alças dos cabos para uma posição confortável. Sente-se no banco com as costas retas e os pés apoiados no chão. Segure as alças do cabo com uma pegada pronada na altura dos ombros. Empurre as alças para frente e para longe do corpo, estendendo totalmente os braços. Faça uma pausa por um momento e, em seguida, traga lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2144.gif', 'hasaneyldrm', '2144'),
  ('b1d7a80a-0000-4000-8000-000000000212'::uuid, null, 'crise assentada no cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Sente-se em uma máquina de cabo com os pés apoiados no chão e os joelhos dobrados. Segure a alça do cabo com as duas mãos e posicione-a atrás da cabeça. Envolva os abdominais e enrole lentamente a parte superior do corpo para a frente, trazendo o peito em direção aos joelhos. Faça uma pausa no topo e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0212.gif', 'hasaneyldrm', '0212'),
  ('b1d7a80a-0000-4000-8000-000000001641'::uuid, null, 'ondulação assentada no cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Sente-se em uma máquina de cabo com os pés apoiados no chão e as costas retas. Segure o acessório do cabo com uma pegada supinada, com as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole o cabo em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente o cabo de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1641.gif', 'hasaneyldrm', '1641'),
  ('b1d7a80a-0000-4000-8000-000000000213'::uuid, null, 'fileira alta assentada em cabo (barra em V)', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Sente-se na máquina de cabo com os pés apoiados no chão e os joelhos ligeiramente dobrados. Segure o acessório da barra em V com uma pegada pronada, com as palmas voltadas uma para a outra e as mãos na largura dos ombros. Mantenha as costas retas e incline-se ligeiramente para a frente a partir dos quadris. Puxe a barra em V em direção ao tronco, retraindo as omoplatas e contraindo os músculos das costas. Faça uma pausa por um momento no pico da contração, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0213.gif', 'hasaneyldrm', '0213'),
  ('b1d7a80a-0000-4000-8000-000000000214'::uuid, null, 'cabo sentado em linha alternada com um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', true, 'Sente-se em um banco de frente para uma máquina de cabos, com os pés apoiados no chão e os joelhos ligeiramente flexionados. Segure a alça com uma mão e mantenha o braço totalmente estendido à sua frente. Puxe a alça em direção ao corpo, retraindo a omoplata e mantendo o cotovelo próximo ao corpo. Faça uma pausa no início do movimento, contraindo os músculos das costas. Solte lentamente a alça de volta à posição inicial. Repita com o outro braço. Alterne entre os braços para o número desejado de repetições.', '/exercise-media/bstrainer/0214.gif', 'hasaneyldrm', '0214'),
  ('b1d7a80a-0000-4000-8000-000000001642'::uuid, null, 'enrolamento de concentração de um braço sentado no cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', true, 'Sente-se em um banco com os pés apoiados no chão e as costas retas. Segure uma alça de cabo com uma mão e coloque o cotovelo na parte interna da coxa, logo acima do joelho. Mantenha o braço parado e enrole a alça do cabo em direção ao ombro enquanto expira. Faça uma pausa no início do movimento, apertando o bíceps. Abaixe lentamente a alça do cabo de volta à posição inicial enquanto inspira. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1642.gif', 'hasaneyldrm', '1642'),
  ('b1d7a80a-0000-4000-8000-000000001643'::uuid, null, 'enrolamento suspenso no cabo', 'push_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'cable', false, 'Sente-se em um banco de frente para a máquina de cabos, com os pés apoiados no chão. Segure o acessório do cabo com uma pegada por baixo, com as palmas voltadas para cima e as mãos na largura dos ombros. Mantenha os braços parados e os cotovelos próximos ao corpo. Expire e enrole o cabo em direção aos ombros, contraindo o bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente o cabo de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1643.gif', 'hasaneyldrm', '1643'),
  ('b1d7a80a-0000-4000-8000-000000000215'::uuid, null, 'elevação lateral traseira assentada em cabo', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'cable', false, 'Sente-se em um banco de frente para a máquina de cabos, com os pés apoiados no chão. Segure as alças do cabo com força e estenda os braços à sua frente. Mantendo os braços retos, levante-os lentamente para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0215.gif', 'hasaneyldrm', '0215'),
  ('b1d7a80a-0000-4000-8000-000000000861'::uuid, null, 'remada sentada em cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se na máquina de remo de cabos com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure as alças com força, mantendo as costas retas e os ombros relaxados. Puxe as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0861.gif', 'hasaneyldrm', '0861'),
  ('b1d7a80a-0000-4000-8000-000000000216'::uuid, null, 'rotação interna do ombro assentado no cabo', 'isolation', ARRAY['delts', 'rotator cuff']::text[], ARRAY['rotator cuff', 'triceps']::text[], 'cable', false, 'Sente-se em um banco ou cadeira de frente para a máquina de cabos, com os pés apoiados no chão. Segure a alça do cabo com o braço estendido à sua frente, paralelo ao chão. Mantenha o cotovelo ligeiramente dobrado e as omoplatas puxadas para trás e para baixo. Gire lentamente o braço para dentro, trazendo a alça do cabo em direção ao centro do corpo. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0216.gif', 'hasaneyldrm', '0216'),
  ('b1d7a80a-0000-4000-8000-000000002399'::uuid, null, 'torção assentada no cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Sente-se em uma máquina de cabo com os pés apoiados no chão e os joelhos ligeiramente dobrados. Segure a alça do cabo com as duas mãos e estenda os braços à sua frente. Mantendo o núcleo engajado, gire lentamente o tronco para um lado, puxando o cabo pelo corpo. Faça uma pausa por um momento no final da amplitude de movimento e, em seguida, gire lentamente de volta à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/2399.gif', 'hasaneyldrm', '2399'),
  ('b1d7a80a-0000-4000-8000-000000000218'::uuid, null, 'fileira de punho largo com assento de cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Sente-se na máquina de remo de cabos com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure a alça com um aperto amplo, com as palmas voltadas para baixo. Mantenha as costas retas e incline-se ligeiramente para a frente a partir dos quadris. Puxe a alça em direção à parte inferior do peito, apertando as omoplatas. Faça uma pausa por um momento no pico da contração. Solte lentamente a alça de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0218.gif', 'hasaneyldrm', '0218'),
  ('b1d7a80a-0000-4000-8000-000000000219'::uuid, null, 'prensa de ombro com cabo', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'cable', false, 'Ajuste a máquina de cabos de forma que as alças fiquem na altura dos ombros. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure as alças com força e leve-as até a altura dos ombros, com os cotovelos dobrados e apontando para fora. Pressione as alças para cima até que seus braços estejam totalmente estendidos acima da cabeça. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0219.gif', 'hasaneyldrm', '0219'),
  ('b1d7a80a-0000-4000-8000-000000000220'::uuid, null, 'encolher de ombros', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure as alças do cabo com força e deixe os braços pendurados à sua frente. Mantendo os braços retos, encolha os ombros em direção às orelhas. Mantenha a contração por um momento e depois abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0220.gif', 'hasaneyldrm', '0220'),
  ('b1d7a80a-0000-4000-8000-000000000222'::uuid, null, 'curvatura lateral do cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a alça do cabo com uma mão. Mantenha as costas retas e o núcleo engajado. Dobre lentamente para o lado na cintura, abaixando a alça do cabo em direção ao joelho. Faça uma pausa por um momento e depois retorne à posição inicial. Repita do outro lado. Alterne os lados para o número desejado de repetições.', '/exercise-media/bstrainer/0222.gif', 'hasaneyldrm', '0222'),
  ('b1d7a80a-0000-4000-8000-000000000221'::uuid, null, 'flexão lateral do cabo (bola bosu)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma alça de cabo com uma das mãos. Coloque a outra mão no quadril. Envolva seu núcleo e incline-se lentamente para o lado em direção à mão que segura o cabo, mantendo as costas retas. Faça uma pausa por um momento no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0221.gif', 'hasaneyldrm', '0221'),
  ('b1d7a80a-0000-4000-8000-000000000223'::uuid, null, 'trituração lateral do cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Prenda uma alça de cabo a uma polia baixa e fique de lado em relação à máquina. Segure a alça com a mão mais afastada da máquina e coloque a outra mão no quadril. Mantenha os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Com os abdominais engajados, dobre lateralmente na cintura, trazendo o cotovelo em direção ao quadril. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0223.gif', 'hasaneyldrm', '0223'),
  ('b1d7a80a-0000-4000-8000-000000001717'::uuid, null, 'remada de agachamento com cabo (com fixação de corda)', 'squat', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Prenda uma corda a uma máquina de cabos na altura da cintura. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada, mantendo as costas retas e o peito erguido. Segure a corda com uma pegada pronada, com as mãos na largura dos ombros. Envolva seu núcleo e puxe a corda em direção ao seu corpo, apertando as omoplatas. Mantenha os cotovelos próximos ao corpo e continue puxando até que as mãos alcancem o peito. Faça uma pausa no início do movimento, depois solte lentamente a corda e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1717.gif', 'hasaneyldrm', '1717'),
  ('b1d7a80a-0000-4000-8000-000000001644'::uuid, null, 'onda de agachamento com cabo', 'squat', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Prenda uma alça de cabo na configuração mais baixa de uma máquina de cabo. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada supinada, com as palmas voltadas para cima e os braços totalmente estendidos. Abaixe o corpo até uma posição de agachamento, mantendo as costas retas e os joelhos atrás dos dedos dos pés. Ao se agachar, enrole a alça do cabo em direção aos ombros, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento no topo da rosca, apertando o bíceps. Abaixe lentamente a alça do cabo de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1644.gif', 'hasaneyldrm', '1644'),
  ('b1d7a80a-0000-4000-8000-000000000224'::uuid, null, 'cabo em pé para trás, curvatura do pulso', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'cable', false, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada pronada, com as palmas voltadas para baixo. Mantenha os braços retos e os cotovelos próximos ao corpo. Enrole lentamente os pulsos para cima, trazendo a alça do cabo em direção ao corpo. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0224.gif', 'hasaneyldrm', '0224'),
  ('b1d7a80a-0000-4000-8000-000000001375'::uuid, null, 'panturrilha em pé com cabo', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'cable', false, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure as alças da máquina de cabo ou prenda uma tira de tornozelo nos tornozelos. Levante os calcanhares do chão estendendo os tornozelos o mais alto possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1375.gif', 'hasaneyldrm', '1375'),
  ('b1d7a80a-0000-4000-8000-000000000225'::uuid, null, 'cabo em pé cross-over fly reverso alto', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Prenda uma alça em D em cada lado de uma máquina de cabos na altura dos ombros. Fique no meio da máquina de cabos com os pés afastados na largura dos ombros. Segure as alças com força e estenda os braços para os lados, com as palmas voltadas para a frente. Mantenha uma ligeira flexão nos cotovelos e mantenha as costas retas durante todo o exercício. Envolva os músculos dos ombros e aperte as omoplatas enquanto puxa as alças em direção à frente do corpo. Faça uma pausa no pico do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0225.gif', 'hasaneyldrm', '0225'),
  ('b1d7a80a-0000-4000-8000-000000000226'::uuid, null, 'trituração do cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Prenda uma alça de cabo a uma polia alta e fique de costas para a máquina. Segure a alça com as duas mãos e coloque-a atrás da cabeça, mantendo os cotovelos dobrados. Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Mantendo os abdominais engajados, expire e contraia o tronco em direção aos joelhos, trazendo os cotovelos em direção às coxas. Faça uma pausa por um momento no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0226.gif', 'hasaneyldrm', '0226'),
  ('b1d7a80a-0000-4000-8000-000000000874'::uuid, null, 'trituração do cabo (com fixação de corda)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Prenda uma corda a uma máquina de cabos na altura do peito. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Segure a corda com as duas mãos e coloque-a atrás da cabeça, mantendo os cotovelos dobrados. Envolva os abdominais e lentamente contraia o tronco para a frente, aproximando os cotovelos dos joelhos. Faça uma pausa por um momento no início da crise e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0874.gif', 'hasaneyldrm', '0874'),
  ('b1d7a80a-0000-4000-8000-000000000227'::uuid, null, 'mosca em pé', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Prenda as alças aos cabos na altura do peito. Fique em pé com os pés afastados na largura dos ombros, de costas para a máquina de cabos. Segure as alças com uma pegada pronada, com as palmas voltadas para frente. Dê um passo à frente ligeiramente para criar tensão nos cabos. Mantenha o núcleo engajado e as costas retas durante todo o exercício. Com uma ligeira flexão dos cotovelos, traga lentamente os braços para a frente e juntos na frente do peito. Contraia os músculos do peito no pico do movimento. Inverta lentamente o movimento, retornando os braços à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0227.gif', 'hasaneyldrm', '0227'),
  ('b1d7a80a-0000-4000-8000-000000000228'::uuid, null, 'extensão de quadril em pé com cabo', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'cable', false, 'Prenda um cabo a uma polia baixa e fique de costas para a máquina. Coloque o cabo em volta do tornozelo e fique em pé com os pés afastados na largura dos ombros. Mantenha o núcleo engajado e as costas retas durante todo o exercício. Estenda lentamente a perna para trás, apertando os glúteos no início do movimento. Faça uma pausa por um momento e depois retorne à posição inicial. Repita pelo número desejado de repetições. Troque de lado e repita com a outra perna.', '/exercise-media/bstrainer/0228.gif', 'hasaneyldrm', '0228'),
  ('b1d7a80a-0000-4000-8000-000000000229'::uuid, null, 'enrolamento interno do cabo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada supinada, com as palmas voltadas para cima. Mantenha os cotovelos próximos aos lados e os braços parados. Expire e enrole a alça do cabo em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0229.gif', 'hasaneyldrm', '0229'),
  ('b1d7a80a-0000-4000-8000-000000000230'::uuid, null, 'elevador de cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'cable', false, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a alça do cabo com as duas mãos e posicione-a na altura da cintura. Envolva seu núcleo e mantenha as costas retas durante todo o exercício. Mantendo os braços retos, expire e levante a alça do cabo em direção ao ombro oposto, girando o tronco. Faça uma pausa na parte superior, inspire e abaixe lentamente a alça do cabo de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0230.gif', 'hasaneyldrm', '0230'),
  ('b1d7a80a-0000-4000-8000-000000000231'::uuid, null, 'cabo em pé extensão de tríceps de um braço', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', true, 'Fique em pé com os pés afastados na largura dos ombros, de frente para a máquina de cabos. Segure a alça do cabo com a mão direita, com a palma voltada para baixo, e posicione o braço de forma que fique totalmente estendido e paralelo ao chão. Mantenha o cotovelo parado e próximo ao corpo. Dobre lentamente o cotovelo, abaixando a alça do cabo em direção à parte de trás da cabeça. Faça uma pausa por um momento no final do movimento e, em seguida, estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de lado e execute o exercício com o braço esquerdo.', '/exercise-media/bstrainer/0231.gif', 'hasaneyldrm', '0231'),
  ('b1d7a80a-0000-4000-8000-000000001376'::uuid, null, 'cabo em pé com elevação de panturrilha com uma perna', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'cable', true, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure a máquina de cabos para obter suporte. Levante uma perna do chão e equilibre-se na outra perna. Levante lentamente o calcanhar do chão, levantando o corpo na ponta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/1376.gif', 'hasaneyldrm', '1376'),
  ('b1d7a80a-0000-4000-8000-000000000232'::uuid, null, 'pulldown em pé (com corda)', 'pull_v', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'cable', false, 'Prenda uma corda à máquina de cabos na configuração mais alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a corda com uma pegada pronada, com as palmas voltadas para baixo. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Puxe a corda em direção às coxas, apertando os bíceps. Faça uma pausa por um momento na parte inferior e, em seguida, solte lentamente a corda de volta. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0232.gif', 'hasaneyldrm', '0232'),
  ('b1d7a80a-0000-4000-8000-000000000233'::uuid, null, 'linha de deltóide traseira em posição de cabo (com corda)', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'cable', false, 'Fique de frente para uma máquina de cabo com os pés afastados na largura dos ombros. Segure o acessório do cabo com as duas mãos, com as palmas voltadas uma para a outra, e dê um passo para trás para criar tensão no cabo. Mantenha as costas retas e o núcleo engajado. Puxe o cabo em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente o cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0233.gif', 'hasaneyldrm', '0233'),
  ('b1d7a80a-0000-4000-8000-000000001727'::uuid, null, 'cabo em pé, pegada reversa, extensão de tríceps com um braço acima da cabeça', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', true, 'Fique de costas para a máquina de cabos, com os pés afastados na largura dos ombros. Segure a alça do cabo com uma pegada por baixo e estenda o braço acima da cabeça, mantendo o cotovelo próximo à cabeça. Mantenha o braço parado e abaixe lentamente a alça do cabo atrás da cabeça, dobrando o cotovelo. Faça uma pausa na parte inferior e estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1727.gif', 'hasaneyldrm', '1727'),
  ('b1d7a80a-0000-4000-8000-000000000234'::uuid, null, 'fileira de cabos (barra em V)', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'cable', false, 'Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure o acessório da barra em V com uma pegada pronada, com as palmas voltadas para baixo. Mantenha as costas retas e o núcleo engajado. Puxe a barra em V em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0234.gif', 'hasaneyldrm', '0234'),
  ('b1d7a80a-0000-4000-8000-000000000235'::uuid, null, 'rotação externa do ombro em pé do cabo', 'isolation', ARRAY['delts', 'rotator cuff']::text[], ARRAY['rotator cuff', 'trapezius']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a alça do cabo com o braço estendido à sua frente, paralelo ao chão. Mantenha o cotovelo ligeiramente dobrado e as omoplatas puxadas para trás. Gire lentamente o braço para fora, longe do corpo, enquanto mantém o cotovelo na mesma posição. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0235.gif', 'hasaneyldrm', '0235'),
  ('b1d7a80a-0000-4000-8000-000000000236'::uuid, null, 'fileira de torção de cabo (barra em V)', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'cable', false, 'Prenda um acessório de barra em V a uma máquina de cabos na altura do peito. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a barra em V com uma pegada pronada, com as palmas voltadas para baixo. Dê um passo para trás para criar tensão no cabo. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Puxe a barra em V em direção ao tronco, retraindo as omoplatas e dobrando os cotovelos. Ao puxar, gire o tronco para o lado, apertando as omoplatas. Faça uma pausa no início do movimento, sentindo a contração na parte superior das costas. Libere lentamente a tensão e retorne à posição inicial, desenrolando o tronco. Repita o movimento pelo número desejado de repetições, alternando a direção de torção a cada repetição.', '/exercise-media/bstrainer/0236.gif', 'hasaneyldrm', '0236'),
  ('b1d7a80a-0000-4000-8000-000000001269'::uuid, null, 'cabo em pé, cruzamentos retos', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Fique no meio de uma máquina de cabo com os pés afastados na largura dos ombros. Segure as alças dos cabos com as palmas voltadas para baixo e os braços estendidos para os lados. Mantendo os braços retos, junte as mãos na frente do corpo, cruzando-as uma sobre a outra. Faça uma pausa e retorne lentamente à posição inicial, mantendo os braços estendidos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1269.gif', 'hasaneyldrm', '1269'),
  ('b1d7a80a-0000-4000-8000-000000000238'::uuid, null, 'pulldown de braço reto com cabo', 'pull_v', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'biceps']::text[], 'cable', false, 'Anexe uma barra reta à polia alta de uma máquina de cabos. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, mantendo os braços retos e as palmas voltadas para baixo. Envolva os dorsais e puxe a barra para baixo em direção às coxas, mantendo os braços retos durante todo o movimento. Faça uma pausa na parte inferior e, em seguida, retorne lentamente a barra à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0238.gif', 'hasaneyldrm', '0238'),
  ('b1d7a80a-0000-4000-8000-000000000237'::uuid, null, 'pulldown de braço reto com cabo (com corda)', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Prenda uma corda à máquina de cabos na configuração mais alta. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a corda com as duas mãos, com as palmas voltadas para baixo. Estenda os braços totalmente à sua frente, mantendo os cotovelos ligeiramente dobrados. Envolva os dorsais e puxe lentamente a corda em direção às coxas, mantendo os braços retos. Faça uma pausa na parte inferior, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0237.gif', 'hasaneyldrm', '0237'),
  ('b1d7a80a-0000-4000-8000-000000000239'::uuid, null, 'cabo reto para trás, fileira sentada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms', 'shoulders']::text[], 'cable', false, 'Sente-se na máquina de remo de cabos com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure as alças do cabo com uma pegada pronada, com as palmas voltadas para baixo. Mantenha as costas retas e incline-se ligeiramente para a frente a partir dos quadris. Puxe as alças do cabo em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0239.gif', 'hasaneyldrm', '0239'),
  ('b1d7a80a-0000-4000-8000-000000000240'::uuid, null, 'cabo supino mosca reversa', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'cable', false, 'Prenda uma alça em D a uma máquina de cabo de polia baixa e deite-se de bruços em uma bancada plana. Segure a alça D com cada mão, com as palmas voltadas para baixo, e estenda os braços à sua frente. Mantendo os braços retos, levante-os para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0240.gif', 'hasaneyldrm', '0240'),
  ('b1d7a80a-0000-4000-8000-000000002464'::uuid, null, 'cabo Thibaudeau caiaque linha', 'pull_h', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Prenda uma alça de cabo a uma polia baixa e sente-se de frente para a máquina com os pés apoiados no chão. Segure a alça com a mão direita e estenda totalmente o braço, mantendo uma leve flexão no cotovelo. Incline-se para a frente a partir dos quadris, mantendo as costas retas e os abdominais engajados. Puxe a alça em direção ao tronco, retraindo a omoplata e dobrando o cotovelo, mantendo o braço próximo ao corpo. Contraia os músculos das costas no início do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições, depois troque de lado e execute com o braço esquerdo.', '/exercise-media/bstrainer/2464.gif', 'hasaneyldrm', '2464'),
  ('b1d7a80a-0000-4000-8000-000000000241'::uuid, null, 'pushdown de tríceps cabo (v-bar)', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Conecte um acessório de barra em V à máquina de cabos na configuração mais alta. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a barra em V com uma pegada pronada, com as palmas voltadas para baixo e as mãos na largura dos ombros. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Envolva o tríceps e expire enquanto empurra a barra em V para baixo até que os braços estejam totalmente estendidos. Faça uma pausa no final do movimento, contraindo o tríceps. Inspire enquanto retorna lentamente a barra em V à posição inicial, mantendo o controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0241.gif', 'hasaneyldrm', '0241'),
  ('b1d7a80a-0000-4000-8000-000000002405'::uuid, null, 'cabo tríceps pushdown (v-bar) (com arm blaster)', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Conecte um acessório de barra em V à máquina de cabos na configuração mais alta. Fique de frente para a máquina de cabos com os pés afastados na largura dos ombros. Segure a barra em V com uma pegada pronada, com as palmas voltadas para baixo e as mãos na largura dos ombros. Mantenha os cotovelos próximos ao corpo e os braços parados durante todo o exercício. Envolva o tríceps e expire enquanto empurra a barra em V para baixo até que os braços estejam totalmente estendidos. Faça uma pausa no final do movimento, contraindo o tríceps. Inspire enquanto retorna lentamente a barra em V à posição inicial, mantendo o controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2405.gif', 'hasaneyldrm', '2405'),
  ('b1d7a80a-0000-4000-8000-000000000242'::uuid, null, 'trituração reversa da dobra do cabo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'cable', false, 'Prenda um cabo a uma polia baixa e deite-se sobre um tapete voltado para cima. Segure o cabo com as duas mãos e estenda os braços acima do peito. Dobre os joelhos e levante as pernas, aproximando os joelhos do peito. Ao mesmo tempo, enrole a pélvis em direção ao peito, levantando os quadris do chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas e os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0242.gif', 'hasaneyldrm', '0242'),
  ('b1d7a80a-0000-4000-8000-000000000243'::uuid, null, 'torção do cabo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros, de frente para a máquina de cabos. Segure a alça do cabo com as duas mãos na frente do peito, mantendo os braços levemente flexionados. Envolva seu núcleo e gire o tronco para a direita, puxando o cabo pelo corpo. Faça uma pausa no final do movimento, sentindo a contração nos abdominais e oblíquos. Retorne lentamente à posição inicial, resistindo à tração do cabo. Repita o movimento para o lado esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0243.gif', 'hasaneyldrm', '0243'),
  ('b1d7a80a-0000-4000-8000-000000000862'::uuid, null, 'torção do cabo (cima-baixo)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros, de frente para a máquina de cabos. Segure a alça do cabo com as duas mãos na frente do peito, mantendo os braços levemente flexionados. Envolva o núcleo e gire lentamente o tronco para o lado, mantendo os quadris e as pernas estáveis. Faça uma pausa no final da rotação e depois retorne lentamente à posição inicial. Repita a rotação para o lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0862.gif', 'hasaneyldrm', '0862'),
  ('b1d7a80a-0000-4000-8000-000000000244'::uuid, null, 'tração de torção do cabo', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'biceps']::text[], 'cable', false, 'Prenda uma alça de cabo a uma polia baixa e fique de frente para a máquina. Segure a alça com a mão esquerda e afaste-se da máquina, estendendo totalmente o braço. Posicione os pés na largura dos ombros, com os joelhos ligeiramente flexionados. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Puxe a alça em direção ao corpo, girando o tronco para a direita ao fazer isso. Contraia os músculos das costas no final do movimento. Retorne lentamente à posição inicial, mantendo a tensão no cabo. Repita pelo número desejado de repetições, depois troque de lado e execute com a mão direita.', '/exercise-media/bstrainer/0244.gif', 'hasaneyldrm', '0244'),
  ('b1d7a80a-0000-4000-8000-000000001645'::uuid, null, 'cabo flexão de dois braços em banco inclinado', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'cable', false, 'Sente-se em um banco inclinado com as costas apoiadas na almofada e os pés apoiados no chão. Segure as alças do cabo com uma pegada supinada, com as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole as alças em direção aos ombros enquanto contrai os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente as alças de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1645.gif', 'hasaneyldrm', '1645'),
  ('b1d7a80a-0000-4000-8000-000000001728'::uuid, null, 'cabo de retrocesso de tríceps de dois braços', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a alça do cabo em cada mão com as palmas voltadas para dentro e os braços dobrados em um ângulo de 90 graus. Mantendo os braços parados, estenda os antebraços para trás até que os braços estejam totalmente estendidos. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1728.gif', 'hasaneyldrm', '1728'),
  ('b1d7a80a-0000-4000-8000-000000000245'::uuid, null, 'pulldown por baixo do cabo', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'cable', false, 'Ajuste a máquina de cabos de modo que a barra suspensa fique a uma altura acima de sua cabeça. Sente-se no assento e agarre a barra suspensa com uma pegada por baixo, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha as costas retas e incline-se ligeiramente para trás. Puxe a barra para baixo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0245.gif', 'hasaneyldrm', '0245'),
  ('b1d7a80a-0000-4000-8000-000000001270'::uuid, null, 'cruzamentos da parte superior do tórax do cabo', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'cable', false, 'Prenda as alças aos cabos na altura do peito. Fique no centro da máquina de cabos com um pé ligeiramente à frente do outro. Segure as alças com as palmas voltadas para baixo e os braços estendidos para os lados. Mantenha uma ligeira flexão nos cotovelos e envolva o núcleo. Junte os cabos na frente do peito, cruzando-os. Contraia os músculos do peito no pico do movimento. Solte lentamente os cabos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1270.gif', 'hasaneyldrm', '1270'),
  ('b1d7a80a-0000-4000-8000-000000001324'::uuid, null, 'linha superior do cabo', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'cable', false, 'Prenda uma barra reta a uma máquina de cabos na altura do peito. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha as costas retas e o núcleo engajado. Puxe a barra em direção à parte superior do peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento. Solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1324.gif', 'hasaneyldrm', '1324'),
  ('b1d7a80a-0000-4000-8000-000000000246'::uuid, null, 'fileira vertical de cabos', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'cable', false, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente dobrados e segure o acessório do cabo com uma pegada pronada. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Puxe o acessório do cabo em direção ao queixo, guiando-o com os cotovelos. Pare por um momento no topo, apertando as omoplatas. Abaixe lentamente a fixação do cabo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0246.gif', 'hasaneyldrm', '0246'),
  ('b1d7a80a-0000-4000-8000-000000001325'::uuid, null, 'cabo pulldown traseiro com pegada larga atrás do pescoço', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Ajuste a máquina de cabos de modo que a barra suspensa fique a uma altura acima de sua cabeça. Sente-se no assento e agarre a barra suspensa com uma pegada ampla. Mantenha as costas retas e o peito erguido enquanto se inclina ligeiramente para trás. Puxe a barra para baixo em direção à parte superior do peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1325.gif', 'hasaneyldrm', '1325'),
  ('b1d7a80a-0000-4000-8000-000000000247'::uuid, null, 'curvatura do pulso do cabo', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'cable', false, 'Anexe uma barra reta a uma máquina de cabo de polia baixa. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada por baixo, com as palmas voltadas para cima e as mãos na largura dos ombros. Descanse os antebraços em um banco ou almofada, com os pulsos pendurados na borda. Mantendo os antebraços parados, expire e curve os pulsos para cima o máximo possível. Faça uma pausa no topo, inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0247.gif', 'hasaneyldrm', '0247'),
  ('b1d7a80a-0000-4000-8000-000000001407'::uuid, null, 'alongamento de panturrilha com as mãos contra a parede', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Fique de frente para uma parede com os pés afastados na largura do quadril. Coloque as mãos contra a parede na altura dos ombros. Dê um passo para trás com um pé, mantendo o calcanhar no chão e a perna esticada. Dobre ligeiramente o joelho da frente e incline-se para a frente, sentindo um alongamento na panturrilha. Mantenha o alongamento por 20 a 30 segundos. Troque as pernas e repita o alongamento.', '/exercise-media/bstrainer/1407.gif', 'hasaneyldrm', '1407'),
  ('b1d7a80a-0000-4000-8000-000000001377'::uuid, null, 'alongamento de panturrilha com as mãos apoiadas na parede', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Fique de frente para uma parede com os pés afastados na largura do quadril. Coloque as mãos contra a parede na altura dos ombros. Dê um passo para trás com o pé direito, mantendo o calcanhar no chão e a perna esticada. Dobre o joelho esquerdo e incline-se para a frente, mantendo a perna de trás esticada e o calcanhar no chão. Mantenha o alongamento por 20 a 30 segundos. Troque as pernas e repita o alongamento.', '/exercise-media/bstrainer/1377.gif', 'hasaneyldrm', '1377'),
  ('b1d7a80a-0000-4000-8000-000000001378'::uuid, null, 'alongamento de panturrilha com corda', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Fique de frente para uma parede ou objeto resistente com os pés afastados na largura do quadril. Segure as pontas da corda em cada mão e coloque o meio da corda em volta da planta do pé direito. Dê um passo para trás com o pé esquerdo, mantendo o calcanhar no chão e a perna esticada. Incline-se para a frente, mantendo as costas retas, e puxe suavemente a corda para esticar a panturrilha. Mantenha o alongamento por 20 a 30 segundos e depois solte. Repita na outra perna.', '/exercise-media/bstrainer/1378.gif', 'hasaneyldrm', '1378'),
  ('b1d7a80a-0000-4000-8000-000000000248'::uuid, null, 'linha deitada com barra curvada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Coloque uma barra no chão e deite-se de bruços em um banco com o peito um pouco afastado da borda. Abaixe-se e agarre a barra com uma pegada pronada, um pouco mais larga que a largura dos ombros. Com as pernas esticadas e os pés no chão, levante a barra do chão estendendo os braços. Puxe a barra em direção ao peito, apertando as omoplatas. Abaixe a barra de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0248.gif', 'hasaneyldrm', '0248'),
  ('b1d7a80a-0000-4000-8000-000000002963'::uuid, null, 'cadeira do capitão com perna reta levantada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Sente-se na cadeira do capitão com as costas apoiadas no encosto e os antebraços apoiados nas almofadas dos braços. Mantenha a parte superior do corpo estável e as costas retas. Envolva os abdominais e levante as pernas à sua frente, mantendo-as retas. Continue levantando até que suas pernas fiquem paralelas ao chão ou o mais alto que você puder chegar confortavelmente. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2963.gif', 'hasaneyldrm', '2963'),
  ('b1d7a80a-0000-4000-8000-000000001548'::uuid, null, 'alongamento de perna de cadeira', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'calves']::text[], 'bodyweight', false, 'Sente-se na beirada de uma cadeira com as costas retas e os pés apoiados no chão. Estenda uma perna esticada à sua frente, mantendo o calcanhar no chão. Incline-se ligeiramente para a frente, sentindo um alongamento no quadríceps. Mantenha esta posição por 20 a 30 segundos. Troque as pernas e repita o alongamento.', '/exercise-media/bstrainer/1548.gif', 'hasaneyldrm', '1548'),
  ('b1d7a80a-0000-4000-8000-000000001271'::uuid, null, 'alongamento do peito e da frente dos ombros', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Estenda os braços esticados à sua frente, na altura dos ombros. Cruze os braços na frente do corpo, com o braço direito em cima do braço esquerdo. Entrelace os dedos e pressione as palmas uma contra a outra. Aperte suavemente as omoplatas e empurre as mãos para a frente, sentindo um alongamento no peito e na frente dos ombros. Mantenha o alongamento por 20 a 30 segundos e depois solte. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1271.gif', 'hasaneyldrm', '1271'),
  ('b1d7a80a-0000-4000-8000-000000000251'::uuid, null, 'mergulho no peito', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Posicione-se nas barras paralelas com os braços totalmente estendidos e o corpo reto. Abaixe o corpo dobrando os cotovelos até que os ombros fiquem abaixo dos cotovelos. Empurre-se de volta à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0251.gif', 'hasaneyldrm', '0251'),
  ('b1d7a80a-0000-4000-8000-000000001430'::uuid, null, 'mergulho no peito (na gaiola dip-pull-up)', 'pull_v', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Ajuste as barras de imersão a uma altura que permita agarrá-las confortavelmente. Fique entre as barras e coloque as mãos em cada barra, um pouco mais afastadas que a largura dos ombros. Salte e estique os braços, apoiando o peso do corpo nas barras. Dobre os joelhos e cruze os tornozelos atrás de você. Abaixe o corpo dobrando os cotovelos, mantendo o peito para cima e os ombros para baixo. Continue abaixando até que os ombros fiquem abaixo dos cotovelos ou até sentir um alongamento no peito. Empurre as palmas das mãos e estenda os cotovelos para levantar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1430.gif', 'hasaneyldrm', '1430'),
  ('b1d7a80a-0000-4000-8000-000000002462'::uuid, null, 'mergulho de peito na barra reta', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Agarre as barras paralelas com as palmas das mãos voltadas para baixo e os braços totalmente estendidos. Dobre os joelhos e cruze os tornozelos. Abaixe o corpo dobrando os braços até que os ombros fiquem abaixo dos cotovelos. Empurre-se de volta à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2462.gif', 'hasaneyldrm', '2462'),
  ('b1d7a80a-0000-4000-8000-000000001272'::uuid, null, 'alongamento de peito com bola de exercícios', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e as costas retas. Segure a bola de exercícios com as duas mãos e estenda os braços à sua frente. Lentamente, traga a bola de exercícios em direção ao peito, sentindo um alongamento nos músculos do peito. Mantenha o alongamento por alguns segundos e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1272.gif', 'hasaneyldrm', '1272'),
  ('b1d7a80a-0000-4000-8000-000000003216'::uuid, null, 'flexão de peito (masculino)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas que a largura dos ombros e o corpo em linha reta. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Ao se abaixar, bata no peito com a mão direita. Empurre-se de volta à posição inicial. Repita o movimento, desta vez batendo no peito com a mão esquerda. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3216.gif', 'hasaneyldrm', '3216'),
  ('b1d7a80a-0000-4000-8000-000000001326'::uuid, null, 'queixo para cima', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com as palmas voltadas para você e na largura dos ombros. Envolva seu núcleo e puxe seu corpo em direção à barra, liderando com o peito. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1326.gif', 'hasaneyldrm', '1326'),
  ('b1d7a80a-0000-4000-8000-000000000253'::uuid, null, 'barras fixas (aperto paralelo estreito)', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com uma pegada estreita e paralela, com as palmas voltadas para você. Envolva os músculos das costas e puxe o corpo em direção à barra, mantendo os cotovelos próximos ao corpo. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0253.gif', 'hasaneyldrm', '0253'),
  ('b1d7a80a-0000-4000-8000-000000000257'::uuid, null, 'círculos de alongamento de joelho', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e as mãos nos quadris. Dobre ligeiramente os joelhos e levante os calcanhares do chão, equilibrando-se na planta dos pés. Mantendo os joelhos dobrados, gire-os em movimentos circulares, primeiro no sentido horário e depois no sentido anti-horário. Execute o movimento pelo número desejado de repetições.', '/exercise-media/bstrainer/0257.gif', 'hasaneyldrm', '0257'),
  ('b1d7a80a-0000-4000-8000-000000001273'::uuid, null, 'bater palmas, empurrar para cima', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta com as mãos ligeiramente mais afastadas que a largura dos ombros. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo o núcleo engajado. Empurre as palmas das mãos de forma explosiva para impulsionar o corpo do chão. Enquanto estiver no ar, bata palmas antes de pousar de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1273.gif', 'hasaneyldrm', '1273'),
  ('b1d7a80a-0000-4000-8000-000000000258'::uuid, null, 'flexão de relógio', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Ao abaixar, gire o corpo para a esquerda, estendendo o braço esquerdo para o lado. Empurre de volta à posição inicial, enquanto gira o corpo para o centro. Repita a flexão, desta vez girando o corpo para a direita e estendendo o braço direito para o lado. Continue alternando os lados a cada repetição.', '/exercise-media/bstrainer/0258.gif', 'hasaneyldrm', '0258'),
  ('b1d7a80a-0000-4000-8000-000000001327'::uuid, null, 'aperto próximo na barra fixa', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra pull-up com as palmas das mãos voltadas para você e na largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e os pés fora do chão. Envolva os músculos das costas e puxe o corpo em direção à barra, mantendo os cotovelos próximos ao corpo. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1327.gif', 'hasaneyldrm', '1327'),
  ('b1d7a80a-0000-4000-8000-000000000259'::uuid, null, 'flexão de pegada fechada', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta com as mãos juntas, diretamente sob os ombros. Envolva o núcleo e abaixe o corpo em direção ao chão, mantendo os cotovelos próximos ao corpo. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0259.gif', 'hasaneyldrm', '0259'),
  ('b1d7a80a-0000-4000-8000-000000002398'::uuid, null, 'flexão de pegada fechada (de joelhos)', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Comece ficando de joelhos, com as mãos na largura dos ombros e os joelhos na largura do quadril. Abaixe a parte superior do corpo em direção ao chão, dobrando os cotovelos, mantendo-os próximos ao corpo. Faça uma pausa por um momento quando seu peito estiver logo acima do solo. Empurre as palmas das mãos para esticar os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2398.gif', 'hasaneyldrm', '2398'),
  ('b1d7a80a-0000-4000-8000-000000000260'::uuid, null, 'casulos', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0260.gif', 'hasaneyldrm', '0260'),
  ('b1d7a80a-0000-4000-8000-000000001468'::uuid, null, 'toque de dedo do pé com torção de caranguejo', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Comece sentando no chão com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás de você, os dedos apontando para os pés, e levante os quadris do chão. Estenda uma perna esticada à sua frente e, ao mesmo tempo, estenda a mão oposta em direção aos dedos dos pés. Volte à posição inicial e repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1468.gif', 'hasaneyldrm', '1468'),
  ('b1d7a80a-0000-4000-8000-000000000262'::uuid, null, 'flexão de corpo cruzado', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante a parte superior do corpo do chão e gire para trazer o cotovelo direito em direção ao joelho esquerdo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita do outro lado, aproximando o cotovelo esquerdo do joelho direito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0262.gif', 'hasaneyldrm', '0262'),
  ('b1d7a80a-0000-4000-8000-000000000267'::uuid, null, 'crunch (mãos acima da cabeça)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Estenda os braços acima da cabeça. Envolvendo os abdominais, levante a parte superior do corpo do chão, curvando-se para a frente em direção aos joelhos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0267.gif', 'hasaneyldrm', '0267'),
  ('b1d7a80a-0000-4000-8000-000000000271'::uuid, null, 'crunch (na bola de estabilidade)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Deite-se sobre a bola até que a parte inferior das costas esteja apoiada e a parte superior do corpo fique paralela ao chão. Coloque as mãos atrás da cabeça ou sobre o peito. Envolva os abdominais e levante a parte superior do corpo em direção aos joelhos, curvando o tronco para a frente. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0271.gif', 'hasaneyldrm', '0271'),
  ('b1d7a80a-0000-4000-8000-000000000272'::uuid, null, 'crunch (na bola de estabilidade, braços esticados)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Deite-se sobre a bola até que a parte inferior das costas esteja apoiada e a parte superior do corpo fique paralela ao chão. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva os abdominais e levante a parte superior do corpo da bola, curvando os ombros em direção aos quadris. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0272.gif', 'hasaneyldrm', '0272'),
  ('b1d7a80a-0000-4000-8000-000000000274'::uuid, null, 'piso crunch', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolva os abdominais e levante os ombros do chão, curvando-se para a frente em direção aos joelhos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0274.gif', 'hasaneyldrm', '0274'),
  ('b1d7a80a-0000-4000-8000-000000003016'::uuid, null, 'enrolar', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3016.gif', 'hasaneyldrm', '3016'),
  ('b1d7a80a-0000-4000-8000-000000003769'::uuid, null, 'agachamento com reverência', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dê um passo diagonalmente atrás e transversalmente ao corpo com o pé direito, cruzando-o atrás da perna esquerda. Dobre os joelhos como se estivesse fazendo uma reverência, abaixando o corpo em direção ao chão. Mantenha o tronco ereto e o peso no pé da frente. Empurre o pé da frente para retornar à posição inicial. Repita do outro lado, dando um passo diagonal para trás e atravessando o corpo com o pé esquerdo.', '/exercise-media/bstrainer/3769.gif', 'hasaneyldrm', '3769'),
  ('b1d7a80a-0000-4000-8000-000000002331'::uuid, null, 'bicicleta cross trainer', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se no bicicleta cross trainer. Coloque os pés nos pedais e segure o guidão. Comece a pedalar com um movimento suave e controlado. Mantenha um ritmo constante e aumente a resistência, se desejar. Continue pedalando durante a duração desejada do seu treino cardiovascular.', '/exercise-media/bstrainer/2331.gif', 'hasaneyldrm', '2331'),
  ('b1d7a80a-0000-4000-8000-000000000276'::uuid, null, 'inseto morto', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os braços estendidos em direção ao teto. Dobre os joelhos e levante as pernas do chão, criando um ângulo de 90 graus nos quadris e joelhos. Envolva o núcleo e a região lombar para pressioná-la no chão. Abaixe lentamente o braço direito e a perna esquerda em direção ao chão, mantendo-os retos e pairando logo acima do chão. Faça uma pausa por um momento e depois retorne à posição inicial. Repita o movimento com o braço esquerdo e a perna direita. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0276.gif', 'hasaneyldrm', '0276'),
  ('b1d7a80a-0000-4000-8000-000000000277'::uuid, null, 'crise de declínio', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se em um banco inclinado com os pés firmes e os joelhos dobrados em um ângulo de 90 graus. Coloque as mãos atrás da cabeça ou sobre o peito. Envolva os abdominais e levante a parte superior do corpo em direção aos joelhos, curvando o tronco. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0277.gif', 'hasaneyldrm', '0277'),
  ('b1d7a80a-0000-4000-8000-000000000279'::uuid, null, 'recusar flexão', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Coloque as mãos no chão um pouco mais afastadas que a largura dos ombros, com os pés elevados em uma superfície estável. Mantenha o corpo em linha reta da cabeça aos pés, envolvendo os músculos centrais. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0279.gif', 'hasaneyldrm', '0279'),
  ('b1d7a80a-0000-4000-8000-000000000282'::uuid, null, 'recusar abdominais', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se em um banco inclinado com os pés firmes e os joelhos dobrados. Coloque as mãos atrás da cabeça ou sobre o peito. Envolva os abdominais e levante a parte superior do corpo do banco, curvando-se para a frente em direção aos joelhos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0282.gif', 'hasaneyldrm', '0282'),
  ('b1d7a80a-0000-4000-8000-000000001274'::uuid, null, 'flexão profunda', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas que a largura dos ombros e o corpo em linha reta. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1274.gif', 'hasaneyldrm', '1274'),
  ('b1d7a80a-0000-4000-8000-000000000283'::uuid, null, 'flexão de diamante', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta com as mãos juntas, formando um diamante com os polegares e indicadores. Mantenha o corpo em linha reta da cabeça aos pés, envolvendo o núcleo e os glúteos. Abaixe o peito em direção ao formato de diamante formado pelas mãos, mantendo os cotovelos próximos ao corpo. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0283.gif', 'hasaneyldrm', '0283'),
  ('b1d7a80a-0000-4000-8000-000000000284'::uuid, null, 'criação de bezerros de burro', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique com os dedos dos pés em uma superfície elevada, como um degrau ou bloco. Coloque as mãos em um suporte estável, como uma parede ou um corrimão, para manter o equilíbrio. Levante os calcanhares o mais alto possível, colocando o peso do corpo na planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0284.gif', 'hasaneyldrm', '0284'),
  ('b1d7a80a-0000-4000-8000-000000001275'::uuid, null, 'flexão para cima', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta com as mãos ligeiramente mais afastadas que a largura dos ombros. Abaixe o peito em direção ao chão, mantendo os cotovelos próximos ao corpo. Quando seu peito estiver logo acima do chão, coloque rapidamente os joelhos no chão. Empurre-se de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1275.gif', 'hasaneyldrm', '1275'),
  ('b1d7a80a-0000-4000-8000-000000000285'::uuid, null, 'rosca alternada de bíceps com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé com um haltere em cada mão, as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições, alternando os braços.', '/exercise-media/bstrainer/0285.gif', 'hasaneyldrm', '0285'),
  ('b1d7a80a-0000-4000-8000-000000002403'::uuid, null, 'rosca alternada de bíceps com halteres (com arm blaster)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé, com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para a frente. Coloque o blaster de braço na parte superior dos braços, garantindo um ajuste seguro. Mantendo os braços parados, expire e enrole um haltere em direção ao ombro enquanto contrai o bíceps. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita o movimento com o braço oposto. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/2403.gif', 'hasaneyldrm', '2403'),
  ('b1d7a80a-0000-4000-8000-000000001646'::uuid, null, 'rosca pregadora com martelo alternativo com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco de pregador com um haltere em cada mão, as palmas voltadas para o tronco e os braços totalmente estendidos. Mantenha os braços parados e expire enquanto enrola os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pela quantidade recomendada de repetições.', '/exercise-media/bstrainer/1646.gif', 'hasaneyldrm', '1646'),
  ('b1d7a80a-0000-4000-8000-000000001647'::uuid, null, 'curl de pregador alternativo com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco de pregador com um haltere em cada mão, com as palmas voltadas para cima. Descanse os braços na almofada do banco do pregador, permitindo que os braços se estendam totalmente. Mantendo os braços parados, expire e enrole o haltere na mão direita enquanto contrai o bíceps. Continue a enrolar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Faça uma pausa por um momento, inspire e abaixe lentamente o haltere de volta à posição inicial. Repita o movimento com o braço esquerdo. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/1647.gif', 'hasaneyldrm', '1647'),
  ('b1d7a80a-0000-4000-8000-000000001648'::uuid, null, 'rosca direta com martelo sentado alternado com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco com um haltere em cada mão, as palmas voltadas para o tronco e os braços estendidos para baixo. Mantenha as costas retas e os cotovelos próximos ao tronco. Expire e enrole o haltere da mão direita em direção ao ombro, mantendo o braço parado. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Faça uma pausa por um breve momento, inspire e abaixe lentamente o haltere de volta à posição inicial. Repita o movimento com o braço esquerdo. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/1648.gif', 'hasaneyldrm', '1648'),
  ('b1d7a80a-0000-4000-8000-000000000286'::uuid, null, 'supino lateral alternativo com halteres', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros. Pressione um haltere acima da cabeça enquanto mantém o outro haltere na altura dos ombros. Abaixe o haltere pressionado de volta à altura dos ombros enquanto pressiona o outro haltere acima da cabeça. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0286.gif', 'hasaneyldrm', '0286'),
  ('b1d7a80a-0000-4000-8000-000000001649'::uuid, null, 'rosca alternada com halteres e perna levantada na bola de exercícios', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para a frente. Coloque uma bola de exercícios atrás de você e posicione um pé em cima dela, mantendo o equilíbrio. Com os braços totalmente estendidos e os cotovelos próximos ao corpo, enrole um haltere em direção ao ombro enquanto mantém o braço parado. Abaixe o haltere de volta à posição inicial e repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/1649.gif', 'hasaneyldrm', '1649'),
  ('b1d7a80a-0000-4000-8000-000000001650'::uuid, null, 'rosca direta de bíceps sentada alternada com halteres na bola de exercícios', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole um haltere enquanto gira o antebraço até que a palma da mão fique voltada para o ombro. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita a curvatura com o outro braço. Continue alternando os cachos até o número desejado de repetições.', '/exercise-media/bstrainer/1650.gif', 'hasaneyldrm', '1650'),
  ('b1d7a80a-0000-4000-8000-000000002137'::uuid, null, 'haltere arnold press', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper chest']::text[], 'dumbbell', false, 'Sente-se em um banco com apoio para as costas e segure um haltere em cada mão na altura dos ombros, com as palmas voltadas para o corpo e os cotovelos dobrados. Pressione os halteres para cima até que os braços estejam totalmente estendidos e as palmas das mãos voltadas para a frente. Gire os pulsos ao levantar, de modo que as palmas das mãos fiquem voltadas para a frente no início do movimento. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2137.gif', 'hasaneyldrm', '2137'),
  ('b1d7a80a-0000-4000-8000-000000000287'::uuid, null, 'haltere arnold press v. 2', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper chest']::text[], 'dumbbell', false, 'Sente-se em um banco com apoio para as costas e segure um haltere em cada mão na altura dos ombros, com as palmas voltadas para o corpo e os cotovelos dobrados. Pressione os halteres para cima até que os braços estejam totalmente estendidos e as palmas das mãos voltadas para a frente. Gire os pulsos ao levantar, de modo que as palmas das mãos fiquem voltadas para a frente no início do movimento. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0287.gif', 'hasaneyldrm', '0287'),
  ('b1d7a80a-0000-4000-8000-000000000288'::uuid, null, 'haltere em volta do pulôver', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'latissimus dorsi']::text[], 'dumbbell', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés firmemente no chão. Segure um haltere com as duas mãos e estenda os braços acima do peito. Mantendo os braços retos, abaixe lentamente o haltere atrás da cabeça em um movimento de arco. Faça uma pausa na parte inferior e, em seguida, levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0288.gif', 'hasaneyldrm', '0288'),
  ('b1d7a80a-0000-4000-8000-000000000289'::uuid, null, 'supino com halteres', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure um haltere em cada mão, com as palmas voltadas para a frente e os braços estendidos acima do peito. Abaixe os halteres lentamente até as laterais do peito, mantendo os cotovelos em um ângulo de 90 graus. Faça uma pausa e empurre os halteres de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0289.gif', 'hasaneyldrm', '0289'),
  ('b1d7a80a-0000-4000-8000-000000000290'::uuid, null, 'supino sentado com halteres', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'dumbbell', false, 'Sente-se em um banco com um haltere em cada mão, apoiado nas coxas. Incline-se para trás e posicione os halteres nas laterais do peito, com as palmas voltadas para a frente. Pressione os halteres para cima até que os braços estejam totalmente estendidos. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0290.gif', 'hasaneyldrm', '0290'),
  ('b1d7a80a-0000-4000-8000-000000000291'::uuid, null, 'agachamento com halteres', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Coloque um haltere no chão em frente a um banco. Fique de costas para o banco, com os pés afastados na largura dos ombros. Dobre os joelhos e os quadris para abaixar-se em direção ao banco, mantendo o peito para cima e as costas retas. Assim que seus glúteos tocarem o banco, empurre os calcanhares para voltar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0291.gif', 'hasaneyldrm', '0291'),
  ('b1d7a80a-0000-4000-8000-000000000293'::uuid, null, 'haltere curvado sobre a remada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure um haltere em cada mão com as palmas voltadas para o corpo. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Deixe os braços pendurados em direção ao chão, com os cotovelos ligeiramente flexionados. Puxe os halteres em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0293.gif', 'hasaneyldrm', '0293'),
  ('b1d7a80a-0000-4000-8000-000000001651'::uuid, null, 'estocada de rosca bíceps com halteres com movimento de boliche', 'lunge', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para a frente. Dê um passo à frente com o pé direito, dobrando o joelho direito e abaixando o corpo para uma posição de estocada. Ao avançar, levante os halteres em direção aos ombros, mantendo os cotovelos próximos ao corpo. Na parte inferior da estocada, gire o tronco para a direita, como se estivesse jogando uma bola. Inverta o movimento, recuando com o pé direito e retornando à posição inicial enquanto abaixa os halteres. Repita o movimento de estocada e curvatura, desta vez girando o tronco para a esquerda. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1651.gif', 'hasaneyldrm', '1651'),
  ('b1d7a80a-0000-4000-8000-000000001652'::uuid, null, 'rosca bíceps com halteres na bola de exercícios com a perna levantada', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para a frente e os braços totalmente estendidos. Enrole lentamente os halteres em direção aos ombros, mantendo os cotovelos próximos aos lados. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Ao realizar a rosca direta para bíceps, levante uma perna do chão e mantenha-a no ar durante o exercício. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1652.gif', 'hasaneyldrm', '1652'),
  ('b1d7a80a-0000-4000-8000-000000001653'::uuid, null, 'rosca bíceps com halteres e postura de cegonha', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para a frente. Estenda uma perna atrás de você, equilibrando-se na ponta do pé. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1653.gif', 'hasaneyldrm', '1653'),
  ('b1d7a80a-0000-4000-8000-000000000294'::uuid, null, 'rosca bíceps com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0294.gif', 'hasaneyldrm', '0294'),
  ('b1d7a80a-0000-4000-8000-000000002401'::uuid, null, 'rosca bíceps com halteres (com arm blaster)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para a frente. Mantenha os cotovelos próximos ao tronco e os braços parados. Expire e enrole os pesos enquanto contrai o bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2401.gif', 'hasaneyldrm', '2401'),
  ('b1d7a80a-0000-4000-8000-000000001654'::uuid, null, 'rosca bíceps com halteres reversa', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, as palmas voltadas para baixo e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1654.gif', 'hasaneyldrm', '1654'),
  ('b1d7a80a-0000-4000-8000-000000001655'::uuid, null, 'agachamento com rosca bíceps com halteres', 'squat', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para a frente. Mantendo as costas retas e os cotovelos próximos ao corpo, expire e enrole os halteres em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1655.gif', 'hasaneyldrm', '1655'),
  ('b1d7a80a-0000-4000-8000-000000001656'::uuid, null, 'rosca bíceps com halteres v sentar na bola bosu', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', false, 'Sente-se em uma bola bosu com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure um haltere em cada mão com as palmas voltadas para a frente e os braços totalmente estendidos ao lado do corpo. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1656.gif', 'hasaneyldrm', '1656'),
  ('b1d7a80a-0000-4000-8000-000000001201'::uuid, null, 'burpee com halteres', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'triceps', 'core']::text[], 'dumbbell', false, 'Comece em pé, com os pés afastados na largura dos ombros e um haltere em cada mão. Abaixe o corpo até a posição de agachamento, colocando os halteres no chão à sua frente. Jogue os pés para trás em uma posição de flexão, mantendo o corpo em linha reta. Faça uma flexão, dobrando os cotovelos e abaixando o peito em direção ao chão. Salte com os pés em direção às mãos, aterrissando em uma posição agachada. Levante-se de forma explosiva, levantando os halteres do chão e trazendo-os até os ombros. Pressione os halteres acima da cabeça, estendendo totalmente os braços. Abaixe os halteres até os ombros e repita toda a sequência pelo número desejado de repetições.', '/exercise-media/bstrainer/1201.gif', 'hasaneyldrm', '1201'),
  ('b1d7a80a-0000-4000-8000-000000000295'::uuid, null, 'limpeza de halteres', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Dobre os joelhos e abaixe os quadris até uma posição de agachamento, mantendo as costas retas e o peito para cima. Estenda explosivamente os quadris e os joelhos, passando pelos calcanhares para pular do chão. Ao pular, encolha os ombros e puxe os halteres em direção aos ombros, mantendo-os próximos ao corpo. Pegue os halteres na altura dos ombros, com os cotovelos apontando para a frente e as palmas das mãos voltadas para cima. Abaixe os halteres de volta à posição inicial, invertendo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0295.gif', 'hasaneyldrm', '0295'),
  ('b1d7a80a-0000-4000-8000-000000001731'::uuid, null, 'supino com pegada fechada com halteres', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco plano com um haltere em cada mão, apoiado nas coxas. Usando as coxas para ajudar a levantar os halteres, levante-os um de cada vez para poder segurá-los à sua frente, na largura dos ombros. Uma vez na largura dos ombros, gire os pulsos para a frente de modo que as palmas das mãos fiquem voltadas para longe de você. Esta será sua posição inicial. Ao inspirar, abaixe lentamente os halteres para o lado até que fiquem no nível do peito. Ao expirar, use o tríceps para levantar os halteres de volta à posição inicial. Certifique-se de usar apenas o tríceps e não os antebraços ou bíceps para ajudar a levantar os halteres. Após uma segunda pausa na posição contraída, repita o movimento pela quantidade prescrita de repetições.', '/exercise-media/bstrainer/1731.gif', 'hasaneyldrm', '1731'),
  ('b1d7a80a-0000-4000-8000-000000000296'::uuid, null, 'supino fechado com halteres', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco plano com um haltere em cada mão, apoiado nas coxas. Usando as coxas para ajudar a levantar os halteres, levante-os um de cada vez para poder segurá-los à sua frente, na largura dos ombros. Uma vez na largura dos ombros, gire os pulsos para a frente de modo que as palmas das mãos fiquem voltadas para longe de você. Esta será sua posição inicial. Ao inspirar, abaixe lentamente os halteres para o lado até que fiquem no nível do peito. Ao expirar, use o tríceps para levantar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0296.gif', 'hasaneyldrm', '0296'),
  ('b1d7a80a-0000-4000-8000-000000000297'::uuid, null, 'ondulação de concentração com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com as pernas afastadas e um haltere em uma das mãos, apoiando o cotovelo na parte interna da coxa. Estenda totalmente o braço e segure o haltere com uma pegada por baixo. Mantendo o braço parado, expire e enrole o peso em direção ao ombro enquanto contrai o bíceps. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0297.gif', 'hasaneyldrm', '0297'),
  ('b1d7a80a-0000-4000-8000-000000003635'::uuid, null, 'estocada para frente contralateral com halteres', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Dê um passo à frente com o pé direito, mantendo as costas retas e o núcleo engajado. Abaixe o corpo dobrando os joelhos até que a coxa direita fique paralela ao chão. Empurre o calcanhar direito para retornar à posição inicial. Repita com a perna esquerda. Alterne as pernas para o número desejado de repetições.', '/exercise-media/bstrainer/3635.gif', 'hasaneyldrm', '3635'),
  ('b1d7a80a-0000-4000-8000-000000000298'::uuid, null, 'rosca direta de martelo com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o corpo. Mantenha os cotovelos próximos ao tronco e os braços parados. Expire e enrole os pesos enquanto contrai o bíceps, trazendo os halteres pelo corpo em direção ao ombro oposto. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0298.gif', 'hasaneyldrm', '0298'),
  ('b1d7a80a-0000-4000-8000-000000001657'::uuid, null, 'rosca direta com martelo com halteres v. 2', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o corpo. Mantenha os cotovelos próximos ao tronco e os braços parados. Expire e enrole os pesos enquanto contrai o bíceps, aproximando os halteres o mais próximo possível do ombro oposto. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1657.gif', 'hasaneyldrm', '1657'),
  ('b1d7a80a-0000-4000-8000-000000000299'::uuid, null, 'imprensa cubana com halteres', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros com as palmas voltadas para baixo. Mantendo o núcleo engajado e os cotovelos levemente flexionados, pressione os halteres para cima e acima da cabeça até que os braços estejam totalmente estendidos. Gire os pulsos de modo que as palmas das mãos fiquem voltadas para a frente. Abaixe lentamente os halteres de volta à posição inicial, girando os pulsos de volta à posição inicial enquanto faz isso. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0299.gif', 'hasaneyldrm', '0299'),
  ('b1d7a80a-0000-4000-8000-000000002136'::uuid, null, 'supino cubano com halteres v. 2', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros com as palmas voltadas para baixo. Mantendo o núcleo engajado e as costas retas, pressione os halteres acima da cabeça até que os braços estejam totalmente estendidos. Gire os pulsos de modo que as palmas das mãos fiquem voltadas para a frente. Abaixe os halteres até a altura dos ombros, girando os pulsos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2136.gif', 'hasaneyldrm', '2136'),
  ('b1d7a80a-0000-4000-8000-000000000300'::uuid, null, 'levantamento terra com halteres', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos apontando para a frente. Segure um haltere em cada mão, com as palmas voltadas para o corpo e os braços estendidos para baixo. Dobre os quadris e os joelhos, abaixando os halteres em direção ao chão, mantendo as costas retas. Empurre os calcanhares e estenda os quadris e joelhos, levantando os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0300.gif', 'hasaneyldrm', '0300'),
  ('b1d7a80a-0000-4000-8000-000000000301'::uuid, null, 'supino de declínio com halteres', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco inclinado com os pés seguros e a cabeça mais baixa que os quadris. Segure um haltere em cada mão e estenda os braços acima do peito, com as palmas voltadas para a frente. Abaixe os halteres lentamente até as laterais do peito, mantendo os cotovelos em um ângulo de 90 graus. Empurre os halteres de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0301.gif', 'hasaneyldrm', '0301'),
  ('b1d7a80a-0000-4000-8000-000000000302'::uuid, null, 'haltere declina mosca', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco inclinado com os pés seguros e a cabeça mais baixa que os quadris. Segure um haltere em cada mão com as palmas voltadas uma para a outra e os braços estendidos acima do peito. Abaixe os halteres para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa por um momento e contraia os músculos do peito para trazer os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0302.gif', 'hasaneyldrm', '0302'),
  ('b1d7a80a-0000-4000-8000-000000000303'::uuid, null, 'halteres declinam prensa de martelo', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco inclinado com os pés seguros e a cabeça mais baixa que os quadris. Segure um haltere em cada mão com as palmas voltadas uma para a outra e os braços estendidos acima do peito. Abaixe os halteres nas laterais do peito, mantendo os cotovelos levemente flexionados. Pressione os halteres de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0303.gif', 'hasaneyldrm', '0303'),
  ('b1d7a80a-0000-4000-8000-000000001276'::uuid, null, 'halteres declinam mosca com um braço', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco inclinado com um haltere em uma das mãos, apoiando-o na coxa. Usando a coxa para ajudar a levantar o haltere, levante-o até a largura dos ombros, com a palma da mão voltada para o tronco. Gire o pulso de forma que a palma da mão fique voltada para frente. Ao inspirar, abaixe o haltere lentamente para o lado até sentir um alongamento no peito. Expire e use os músculos do peito para trazer o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1276.gif', 'hasaneyldrm', '1276'),
  ('b1d7a80a-0000-4000-8000-000000001617'::uuid, null, 'halteres declinam prensa de martelo com um braço', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco inclinado com um haltere em uma das mãos, apoiado no peito. Estenda o braço para cima, mantendo o cotovelo ligeiramente dobrado. Abaixe o haltere em direção ao ombro, mantendo o cotovelo próximo ao corpo. Pressione o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1617.gif', 'hasaneyldrm', '1617'),
  ('b1d7a80a-0000-4000-8000-000000000305'::uuid, null, 'encolher de ombros com halteres', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders', 'rhomboids']::text[], 'dumbbell', false, 'Configure um banco declinado em um ângulo de 45 graus. Deite-se de bruços no banco com o peito e o estômago apoiados nele. Segure um haltere em cada mão com os braços totalmente estendidos em direção ao chão. Mantendo os braços retos, levante os ombros em direção às orelhas o mais alto possível. Segure a contração por um momento e depois abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0305.gif', 'hasaneyldrm', '0305'),
  ('b1d7a80a-0000-4000-8000-000000000304'::uuid, null, 'encolher de ombros com halteres v. 2', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders', 'rhomboids']::text[], 'dumbbell', false, 'Configure um banco declinado em um ângulo de 45 graus. Deite-se de bruços no banco com o peito e o estômago apoiados nele. Segure um haltere em cada mão com as palmas voltadas uma para a outra e os braços totalmente estendidos. Mantendo os braços retos, levante os ombros o mais alto possível enquanto aperta as omoplatas. Segure a contração por uma breve pausa e depois abaixe os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0304.gif', 'hasaneyldrm', '0304'),
  ('b1d7a80a-0000-4000-8000-000000000306'::uuid, null, 'extensão de tríceps com declínio de halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os pés e segure um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda totalmente os braços, mantendo os cotovelos próximos à cabeça. Abaixe os halteres lentamente atrás da cabeça, dobrando os cotovelos. Faça uma pausa e depois levante os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0306.gif', 'hasaneyldrm', '0306'),
  ('b1d7a80a-0000-4000-8000-000000000307'::uuid, null, 'haltere declínio twist fly', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os quadris. Segure um haltere em cada mão com as palmas voltadas uma para a outra e os braços estendidos sobre o peito. Abaixe os halteres para os lados em um amplo arco até sentir um alongamento no peito. Ao abaixar os halteres, gire os pulsos de modo que as palmas das mãos fiquem voltadas para a frente na parte inferior do movimento. Inverta o movimento e traga os halteres de volta à posição inicial, contraindo os músculos do peito na parte superior. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0307.gif', 'hasaneyldrm', '0307'),
  ('b1d7a80a-0000-4000-8000-000000001437'::uuid, null, 'rosca direta com halteres', 'isolation', ARRAY['forearms', 'wrist flexors']::text[], ARRAY['wrist flexors', 'wrist extensors']::text[], 'dumbbell', false, 'Sente-se em um banco ou cadeira com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos, apoiando o antebraço na coxa e com a palma voltada para cima. Deixe o haltere rolar até a ponta dos dedos e, em seguida, enrole-o novamente flexionando os dedos. Repita pelo número desejado de repetições e depois mude para a outra mão.', '/exercise-media/bstrainer/1437.gif', 'hasaneyldrm', '1437'),
  ('b1d7a80a-0000-4000-8000-000000000308'::uuid, null, 'mosca com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda os braços sobre o peito, com uma ligeira flexão nos cotovelos. Mantendo uma ligeira flexão nos cotovelos, abaixe os braços para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa, depois inverta o movimento e traga os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0308.gif', 'hasaneyldrm', '0308'),
  ('b1d7a80a-0000-4000-8000-000000001277'::uuid, null, 'mosca com halteres na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios e segure um haltere em cada mão. Ande com os pés para a frente e role o corpo para baixo até que a cabeça, o pescoço e a parte superior das costas fiquem apoiados na bola. Estenda os braços acima do peito, com as palmas voltadas uma para a outra. Dobre ligeiramente os cotovelos e abaixe os braços para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa por um momento, depois inverta o movimento e contraia os músculos do peito enquanto traz os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1277.gif', 'hasaneyldrm', '1277'),
  ('b1d7a80a-0000-4000-8000-000000001732'::uuid, null, 'extensão de tríceps com estocada para frente com halteres', 'lunge', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Mantenha as costas retas e o peito erguido. Estenda os braços acima da cabeça, mantendo os cotovelos próximos às orelhas. Abaixe os halteres atrás da cabeça dobrando os cotovelos. Faça uma pausa por um momento e depois estique os braços para retornar à posição inicial. Repita o movimento pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1732.gif', 'hasaneyldrm', '1732'),
  ('b1d7a80a-0000-4000-8000-000000000310'::uuid, null, 'elevação frontal com halteres', 'isolation', ARRAY['delts', 'biceps']::text[], ARRAY['biceps', 'trapezius']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para as coxas. Mantendo os braços retos, expire e levante os halteres à sua frente até que fiquem na altura dos ombros. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0310.gif', 'hasaneyldrm', '0310'),
  ('b1d7a80a-0000-4000-8000-000000000309'::uuid, null, 'elevação frontal com halteres v. 2', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'biceps']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para as coxas. Mantenha as costas retas e envolva seu núcleo. Levante lentamente os halteres à sua frente, com os braços esticados, até que fiquem na altura dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0309.gif', 'hasaneyldrm', '0309'),
  ('b1d7a80a-0000-4000-8000-000000000311'::uuid, null, 'haltere completo pode elevação lateral', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rotator cuff']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para o corpo. Mantenha as costas retas e envolva seu núcleo. Levante os braços para os lados, mantendo uma ligeira flexão dos cotovelos, até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0311.gif', 'hasaneyldrm', '0311'),
  ('b1d7a80a-0000-4000-8000-000000001760'::uuid, null, 'agachamento com taça com halteres', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere verticalmente contra o peito com as duas mãos. Mantendo o peito para cima e o núcleo engajado, abaixe o corpo até uma posição agachada, empurrando os quadris para trás e dobrando os joelhos. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1760.gif', 'hasaneyldrm', '1760'),
  ('b1d7a80a-0000-4000-8000-000000000313'::uuid, null, 'rosca martelo com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o tronco. Mantenha os cotovelos próximos ao tronco e gire as palmas das mãos até que fiquem voltadas para frente. Esta será sua posição inicial. Agora, mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Em seguida, inspire e comece lentamente a abaixar os halteres de volta à posição inicial. Repita pela quantidade recomendada de repetições.', '/exercise-media/bstrainer/0313.gif', 'hasaneyldrm', '0313'),
  ('b1d7a80a-0000-4000-8000-000000001659'::uuid, null, 'rosca martelo com halteres na bola de exercícios', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para o corpo e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os halteres enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1659.gif', 'hasaneyldrm', '1659'),
  ('b1d7a80a-0000-4000-8000-000000000312'::uuid, null, 'rosca direta com halteres v. 2', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o tronco. Mantenha os cotovelos próximos ao tronco e gire as palmas das mãos até que fiquem voltadas para frente. Esta será sua posição inicial. Agora, mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Em seguida, inspire e comece lentamente a abaixar os halteres de volta à posição inicial. Repita pela quantidade recomendada de repetições.', '/exercise-media/bstrainer/0312.gif', 'hasaneyldrm', '0312'),
  ('b1d7a80a-0000-4000-8000-000000002402'::uuid, null, 'rosca direta com halteres (com arm blaster)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o tronco. Mantenha os cotovelos próximos ao tronco e gire as palmas das mãos até que fiquem voltadas para frente. Esta será sua posição inicial. Agora, enquanto mantém o braço parado, expire e enrole os pesos enquanto contrai o bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Em seguida, inspire e comece lentamente a abaixar os halteres de volta à posição inicial. Repita pela quantidade recomendada de repetições.', '/exercise-media/bstrainer/2402.gif', 'hasaneyldrm', '2402'),
  ('b1d7a80a-0000-4000-8000-000000001664'::uuid, null, 'rosca alta com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para a frente. Mantenha os braços parados e enrole os halteres o mais alto possível enquanto contrai os bíceps. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1664.gif', 'hasaneyldrm', '1664'),
  ('b1d7a80a-0000-4000-8000-000000003545'::uuid, null, 'supino alternado inclinado com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Sente-se em um banco inclinado com um haltere em cada mão, apoiado nas coxas. Incline-se para trás no banco e use as coxas para ajudar a levantar os halteres até a altura dos ombros, com as palmas voltadas para a frente. Uma vez na altura dos ombros, gire os pulsos de modo que as palmas das mãos fiquem voltadas para a frente. Empurre os halteres para cima com o peito e os ombros, estendendo totalmente os braços. Abaixe os halteres de volta à posição inicial, mantendo os cotovelos ligeiramente flexionados. Repita pelo número desejado de repetições, alternando os braços.', '/exercise-media/bstrainer/3545.gif', 'hasaneyldrm', '3545'),
  ('b1d7a80a-0000-4000-8000-000000000314'::uuid, null, 'supino inclinado com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com os pés apoiados no chão e as costas firmemente pressionadas contra o banco. Segure um haltere em cada mão, com as palmas voltadas para a frente, e levante-os até a altura dos ombros. Abaixe lentamente os halteres nas laterais do peito, mantendo os cotovelos em um ângulo de 90 graus. Empurre os halteres de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0314.gif', 'hasaneyldrm', '0314'),
  ('b1d7a80a-0000-4000-8000-000000000315'::uuid, null, 'rosca bíceps inclinada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0315.gif', 'hasaneyldrm', '0315'),
  ('b1d7a80a-0000-4000-8000-000000000316'::uuid, null, 'criação de inclinação com halteres', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com as costas apoiadas na almofada e os pés apoiados no chão. Segure um haltere em cada mão com uma pegada pronada, com as palmas voltadas para a frente. Comece com os braços totalmente estendidos, perpendiculares ao chão. Abaixe os halteres lentamente até as laterais do peito, mantendo os cotovelos em um ângulo de 90 graus. Faça uma pausa na parte inferior e empurre os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0316.gif', 'hasaneyldrm', '0316'),
  ('b1d7a80a-0000-4000-8000-000000000318'::uuid, null, 'rosca inclinada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Coloque um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão, com as palmas voltadas para a frente. Descanse os braços no banco inclinado e deixe os cotovelos pendurados, estendendo totalmente os braços. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0318.gif', 'hasaneyldrm', '0318'),
  ('b1d7a80a-0000-4000-8000-000000000317'::uuid, null, 'rosca inclinada com halteres v. 2', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0317.gif', 'hasaneyldrm', '0317'),
  ('b1d7a80a-0000-4000-8000-000000000319'::uuid, null, 'mosca inclinada com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Defina um banco inclinado em um ângulo de 45 graus. Sente-se no banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Deite-se no banco e pressione os halteres até a posição inicial, diretamente acima do peito. Abaixe os halteres para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa por um momento e contraia os músculos do peito para trazer os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0319.gif', 'hasaneyldrm', '0319'),
  ('b1d7a80a-0000-4000-8000-000000001278'::uuid, null, 'mosca inclinada com halteres na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se em uma bola de exercícios e role para frente até que a parte superior das costas esteja apoiada no banco inclinado. Segure um haltere em cada mão com as palmas voltadas uma para a outra e os braços estendidos acima do peito. Abaixe os halteres para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa por um momento e contraia os músculos do peito para trazer os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1278.gif', 'hasaneyldrm', '1278'),
  ('b1d7a80a-0000-4000-8000-000000000320'::uuid, null, 'rosca direta com martelo inclinado com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, as palmas voltadas para o tronco e os braços totalmente estendidos. Mantenha as costas apoiadas no banco e os pés apoiados no chão. Enquanto mantém os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0320.gif', 'hasaneyldrm', '0320'),
  ('b1d7a80a-0000-4000-8000-000000000321'::uuid, null, 'prensa de martelo inclinada com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Defina um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão, apoiado nas coxas. Deite-se no banco e posicione os halteres na altura dos ombros, com as palmas voltadas uma para a outra. Pressione os halteres para cima e para longe do corpo até que os braços estejam totalmente estendidos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0321.gif', 'hasaneyldrm', '0321'),
  ('b1d7a80a-0000-4000-8000-000000001618'::uuid, null, 'prensa de martelo inclinada com halteres na bola de exercícios', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com um haltere em cada mão, com as palmas voltadas uma para a outra. Ande com os pés para a frente e role o corpo pela bola até que a cabeça, o pescoço e a parte superior das costas estejam apoiados na bola. Segure os halteres na altura dos ombros, cotovelos dobrados e apontando para os lados. Pressione os halteres para cima e ligeiramente para dentro, mantendo as palmas voltadas uma para a outra. Estenda os braços totalmente, apertando os tríceps no topo do movimento. Abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1618.gif', 'hasaneyldrm', '1618'),
  ('b1d7a80a-0000-4000-8000-000000000322'::uuid, null, 'inclinação interna do bíceps com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, com as palmas voltadas uma para a outra. Descanse os braços no banco, permitindo que os cotovelos fiquem pendurados e as palmas das mãos voltadas para a frente. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0322.gif', 'hasaneyldrm', '0322'),
  ('b1d7a80a-0000-4000-8000-000000001279'::uuid, null, 'halteres inclinados com um braço e mosca', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'dumbbell', true, 'Ajuste o banco inclinado para um ângulo de 30-45 graus. Sente-se no banco com um haltere em uma das mãos, apoiando-o na coxa. Deite-se no banco, mantendo os pés apoiados no chão. Segure o haltere com o braço estendido sobre o peito. Abaixe o haltere para o lado em um amplo arco, mantendo uma ligeira flexão no cotovelo. Faça uma pausa quando seu braço estiver paralelo ao chão e depois inverta o movimento para trazer o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1279.gif', 'hasaneyldrm', '1279'),
  ('b1d7a80a-0000-4000-8000-000000001280'::uuid, null, 'haltere inclinado com um braço na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com um haltere em uma das mãos. Ande com os pés para a frente e role o corpo para baixo até que a cabeça, o pescoço e a parte superior das costas estejam apoiados na bola. Segure o haltere com o braço estendido sobre o peito, com a palma voltada para dentro. Abaixe lentamente o haltere para o lado, mantendo uma ligeira flexão no cotovelo. Faça uma pausa por um momento quando seu braço estiver paralelo ao chão. Envolva os músculos do peito para trazer o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1280.gif', 'hasaneyldrm', '1280'),
  ('b1d7a80a-0000-4000-8000-000000001619'::uuid, null, 'halteres inclinados com martelo de um braço', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'dumbbell', true, 'Sente-se em um banco inclinado com um haltere em uma das mãos, apoiado na coxa. Encoste-se no banco e use a coxa para ajudar a levantar o haltere até a altura dos ombros. Gire o pulso de forma que a palma da mão fique voltada para dentro, em direção ao corpo. Pressione o haltere para cima e para longe do corpo, estendendo totalmente o braço. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1619.gif', 'hasaneyldrm', '1619'),
  ('b1d7a80a-0000-4000-8000-000000001620'::uuid, null, 'haltere inclinado com martelo de um braço na bola de exercícios', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com um haltere em uma das mãos. Ande com os pés para a frente e role o corpo para baixo até que a cabeça, o pescoço e a parte superior das costas estejam apoiados na bola. Segure o haltere com a palma da mão voltada para dentro e o cotovelo dobrado em um ângulo de 90 graus. Pressione o haltere em direção ao teto, esticando o braço. Abaixe o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1620.gif', 'hasaneyldrm', '1620'),
  ('b1d7a80a-0000-4000-8000-000000000323'::uuid, null, 'inclinação com halteres elevação lateral de um braço', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'triceps']::text[], 'dumbbell', true, 'Sente-se em um banco inclinado com um haltere em uma das mãos, apoiando-o na coxa. Incline-se para a frente e posicione o braço contra a parte interna da coxa. Levante o haltere para o lado, mantendo o braço ligeiramente flexionado e a palma da mão voltada para baixo. Continue levantando até que seu braço fique paralelo ao chão. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0323.gif', 'hasaneyldrm', '0323'),
  ('b1d7a80a-0000-4000-8000-000000001281'::uuid, null, 'inclinação com halteres, pressão de um braço', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Sente-se em um banco inclinado com um haltere em uma das mãos, apoiado na coxa. Deite-se no banco e posicione o haltere na altura dos ombros, com a palma da mão voltada para frente. Pressione o haltere para cima e ligeiramente para dentro, estendendo totalmente o braço. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1281.gif', 'hasaneyldrm', '1281'),
  ('b1d7a80a-0000-4000-8000-000000001282'::uuid, null, 'inclinação do haltere, pressão de um braço na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com um haltere em uma das mãos e os pés apoiados no chão. Caminhe lentamente para a frente, rolando a bola até que a cabeça, o pescoço e a parte superior das costas estejam apoiados na bola. Segure o haltere na altura dos ombros com a palma da mão voltada para frente. Pressione o haltere para cima até que seu braço esteja totalmente estendido. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1282.gif', 'hasaneyldrm', '1282'),
  ('b1d7a80a-0000-4000-8000-000000000324'::uuid, null, 'halteres inclinados com palma para dentro', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Plante os pés firmemente no chão e mantenha as costas retas contra o banco. Comece com os halteres na altura dos ombros, cotovelos dobrados e palmas voltadas uma para a outra. Pressione os halteres para cima e para longe do corpo, estendendo totalmente os braços. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0324.gif', 'hasaneyldrm', '0324'),
  ('b1d7a80a-0000-4000-8000-000000001283'::uuid, null, 'supino inclinado com halteres na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com um haltere em cada mão, com as palmas voltadas para a frente. Caminhe lentamente para a frente, rolando o corpo pela bola até que a cabeça, o pescoço e a parte superior das costas estejam apoiados na bola. Segure os halteres na altura dos ombros, cotovelos dobrados e apontando para os lados. Pressione os halteres para cima, estendendo totalmente os braços. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1283.gif', 'hasaneyldrm', '1283'),
  ('b1d7a80a-0000-4000-8000-000000000325'::uuid, null, 'elevação inclinada com halteres', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'triceps']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, apoiado nas coxas. Encoste-se no banco e levante os halteres até a altura dos ombros, com as palmas voltadas para a frente. Mantendo as costas apoiadas no banco, expire e levante os halteres acima da cabeça, estendendo totalmente os braços. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0325.gif', 'hasaneyldrm', '0325'),
  ('b1d7a80a-0000-4000-8000-000000000326'::uuid, null, 'elevação lateral traseira com inclinação do haltere', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com o peito apoiado no encosto e segure um haltere em cada mão. Estenda os braços para baixo com as palmas voltadas uma para a outra. Mantendo uma ligeira flexão nos cotovelos, levante os braços para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0326.gif', 'hasaneyldrm', '0326'),
  ('b1d7a80a-0000-4000-8000-000000000327'::uuid, null, 'remada inclinada com halteres', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Pegue um haltere em cada mão e sente-se no banco com o peito encostado na inclinação. Estenda os braços totalmente, permitindo que os halteres fiquem pendurados nos ombros. Puxe os halteres em direção ao peito, apertando as omoplatas. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0327.gif', 'hasaneyldrm', '0327'),
  ('b1d7a80a-0000-4000-8000-000000000328'::uuid, null, 'levantamento de ombro inclinado com halteres', 'isolation', ARRAY['serratus anterior', 'deltoids']::text[], ARRAY['deltoids', 'trapezius']::text[], 'dumbbell', false, 'Coloque um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão, com as palmas voltadas para baixo. Apoie os halteres nas coxas e recoste-se no banco. Use as coxas para ajudar a levantar os halteres até a altura dos ombros e, em seguida, gire os pulsos de modo que as palmas das mãos fiquem voltadas para a frente. Expire e levante lentamente os halteres acima da cabeça, mantendo uma ligeira flexão nos cotovelos. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0328.gif', 'hasaneyldrm', '0328'),
  ('b1d7a80a-0000-4000-8000-000000000329'::uuid, null, 'encolher de ombros inclinado com halteres', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Coloque um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão. Coloque os pés apoiados no chão e deixe os braços pendurados para baixo, com as palmas voltadas para o corpo. Mantendo os braços retos, encolha os ombros em direção às orelhas, o mais alto possível. Mantenha a contração por um momento e depois abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0329.gif', 'hasaneyldrm', '0329'),
  ('b1d7a80a-0000-4000-8000-000000003542'::uuid, null, 'elevação t inclinada com halteres', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', false, 'Coloque um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão, com as palmas voltadas para dentro. Incline-se para a frente e deixe os braços pendurados para baixo, perpendiculares ao chão. Mantendo os braços retos, levante-os para os lados até que fiquem paralelos ao chão, formando um ''T'' com o corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3542.gif', 'hasaneyldrm', '3542'),
  ('b1d7a80a-0000-4000-8000-000000000330'::uuid, null, 'extensão de tríceps inclinada com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, com as palmas voltadas para dentro. Estenda os braços totalmente acima da cabeça, mantendo os cotovelos próximos à cabeça. Abaixe os halteres atrás da cabeça dobrando os cotovelos, mantendo os braços parados. Faça uma pausa e, em seguida, levante os halteres de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0330.gif', 'hasaneyldrm', '0330'),
  ('b1d7a80a-0000-4000-8000-000000000331'::uuid, null, 'flyes torcidos inclinados com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Coloque um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão, com as palmas voltadas uma para a outra. Deite-se no banco e pressione os halteres até a posição inicial, diretamente acima do peito, com os braços estendidos. Abaixe os halteres para os lados em um amplo arco até sentir um alongamento no peito. Ao abaixar os halteres, gire os pulsos de modo que as palmas das mãos fiquem voltadas para a frente na parte inferior do movimento. Inverta o movimento e traga os halteres de volta à posição inicial, contraindo os músculos do peito na parte superior. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0331.gif', 'hasaneyldrm', '0331'),
  ('b1d7a80a-0000-4000-8000-000000001733'::uuid, null, 'haltere inclinado extensão de dois braços', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco inclinado com um haltere em cada mão, apoiado nas coxas. Deite-se lentamente no banco, mantendo os halteres próximos ao peito. Quando estiver totalmente deitado, estenda os braços em direção ao teto, mantendo os cotovelos ligeiramente flexionados. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1733.gif', 'hasaneyldrm', '1733'),
  ('b1d7a80a-0000-4000-8000-000000003541'::uuid, null, 'inclinação do haltere y-raise', 'isolation', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'rear deltoids']::text[], 'dumbbell', false, 'Coloque um banco inclinado em um ângulo de 45 graus e sente-se nele com um haltere em cada mão, com as palmas voltadas para dentro. Incline-se ligeiramente para a frente e deixe os braços pendurados para baixo, mantendo uma ligeira flexão nos cotovelos. Levante os braços para os lados e em forma de Y até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3541.gif', 'hasaneyldrm', '3541'),
  ('b1d7a80a-0000-4000-8000-000000000332'::uuid, null, 'cruz de ferro com halteres', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão ao lado do corpo. Levante os braços para os lados até ficarem paralelos ao chão, formando um T com o corpo. Faça uma pausa por um momento e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0332.gif', 'hasaneyldrm', '0332'),
  ('b1d7a80a-0000-4000-8000-000000000333'::uuid, null, 'retrocesso com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Aproxime os braços ao lado do corpo, com os cotovelos dobrados em um ângulo de 90 graus. Estenda os braços para trás, apertando o tríceps no topo do movimento. Faça uma pausa por um momento e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0333.gif', 'hasaneyldrm', '0333'),
  ('b1d7a80a-0000-4000-8000-000000001734'::uuid, null, 'propinas com halteres na bola de exercícios', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para dentro e os braços dobrados em um ângulo de 90 graus. Estenda os braços para trás, apertando o tríceps no topo do movimento. Faça uma pausa por um momento e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1734.gif', 'hasaneyldrm', '1734'),
  ('b1d7a80a-0000-4000-8000-000000001660'::uuid, null, 'bola de exercício de rosca bíceps ajoelhada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Ajoelhe-se no chão com uma bola de exercícios à sua frente. Coloque os cotovelos em cima da bola de exercícios, segurando um haltere em cada mão com as palmas voltadas para cima. Mantendo os braços parados, expire e enrole os halteres enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1660.gif', 'hasaneyldrm', '1660'),
  ('b1d7a80a-0000-4000-8000-000000000334'::uuid, null, 'elevação lateral com halteres', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para o corpo. Mantenha as costas retas e envolva seu núcleo. Levante os braços para os lados até ficarem paralelos ao chão, mantendo uma ligeira flexão nos cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0334.gif', 'hasaneyldrm', '0334'),
  ('b1d7a80a-0000-4000-8000-000000000335'::uuid, null, 'haltere lateral para elevação frontal', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'biceps']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para o corpo. Mantenha as costas retas e envolva seu núcleo. Levante os braços para os lados até ficarem paralelos ao chão, mantendo uma ligeira flexão nos cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Em seguida, levante os braços à sua frente até que fiquem paralelos ao chão, novamente mantendo uma ligeira flexão nos cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0335.gif', 'hasaneyldrm', '0335'),
  ('b1d7a80a-0000-4000-8000-000000000336'::uuid, null, 'estocada com halteres', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Mantenha as costas retas e o peito erguido enquanto abaixa o corpo. Empurre o calcanhar direito para retornar à posição inicial. Repita com a perna esquerda. Alterne as pernas para o número desejado de repetições.', '/exercise-media/bstrainer/0336.gif', 'hasaneyldrm', '0336'),
  ('b1d7a80a-0000-4000-8000-000000001658'::uuid, null, 'estocada com halteres com rosca bíceps', 'lunge', ARRAY['biceps', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para a frente. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. O joelho direito deve estar dobrado em um ângulo de 90 graus e o joelho esquerdo deve pairar logo acima do solo. Ao avançar, enrole simultaneamente os halteres em direção aos ombros, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento na parte inferior da estocada e, em seguida, empurre o calcanhar direito para retornar à posição inicial, abaixando os halteres de volta para os lados. Repita a estocada e a rosca bíceps no lado oposto, dando um passo à frente com o pé esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1658.gif', 'hasaneyldrm', '1658'),
  ('b1d7a80a-0000-4000-8000-000000000337'::uuid, null, 'extensão deitada com halteres (na face)', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure um haltere com as duas mãos e estenda os braços acima do peito, com as palmas voltadas uma para a outra. Mantendo os braços parados, abaixe lentamente o haltere em um arco atrás da cabeça até que os antebraços fiquem paralelos ao chão. Faça uma pausa e contraia o tríceps para trazer o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0337.gif', 'hasaneyldrm', '0337'),
  ('b1d7a80a-0000-4000-8000-000000001729'::uuid, null, 'extensão alternada com halteres deitado', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda os braços sobre o peito, mantendo uma ligeira flexão nos cotovelos. Abaixe um haltere em direção à cabeça, dobrando o cotovelo, enquanto mantém o outro braço estendido. Faça uma pausa na parte inferior e, em seguida, levante o haltere de volta à posição inicial. Repita com o outro braço, alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1729.gif', 'hasaneyldrm', '1729'),
  ('b1d7a80a-0000-4000-8000-000000000338'::uuid, null, 'halteres deitado cotovelo', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, as palmas voltadas uma para a outra e os braços estendidos sobre o peito. Abaixe os halteres em direção aos ombros, dobrando os cotovelos, mantendo os braços parados. Faça uma pausa na parte inferior e, em seguida, pressione os halteres de volta à posição inicial, estendendo os cotovelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0338.gif', 'hasaneyldrm', '0338'),
  ('b1d7a80a-0000-4000-8000-000000000863'::uuid, null, 'rotação externa do ombro com halteres deitado', 'isolation', ARRAY['delts', 'rotator cuff']::text[], ARRAY['rotator cuff', 'triceps']::text[], 'dumbbell', false, 'Deite-se de lado em um banco plano, com o braço apoiado ao lado do corpo e o cotovelo dobrado em 90 graus. Segure um haltere na mão com a palma voltada para baixo. Mantendo o braço encostado ao lado do corpo, gire lentamente o antebraço para cima, tanto quanto possível. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente o antebraço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0863.gif', 'hasaneyldrm', '0863'),
  ('b1d7a80a-0000-4000-8000-000000000339'::uuid, null, 'haltere deitado femoral', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes']::text[], 'dumbbell', false, 'Deite-se de costas com as pernas estendidas e um haltere apoiado na parte inferior do abdômen. Dobre os joelhos e leve o haltere em direção aos glúteos, mantendo os pés apoiados no chão. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0339.gif', 'hasaneyldrm', '0339'),
  ('b1d7a80a-0000-4000-8000-000000000340'::uuid, null, 'prensa de martelo deitado com halteres', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, as palmas voltadas uma para a outra e os braços estendidos para cima. Abaixe os halteres nas laterais do peito, mantendo os cotovelos em um ângulo de 90 graus. Pressione os halteres de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0340.gif', 'hasaneyldrm', '0340'),
  ('b1d7a80a-0000-4000-8000-000000002470'::uuid, null, 'haltere deitado no chão levantamento deltóide posterior', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Deite-se de bruços no chão com um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda os braços à sua frente, mantendo uma ligeira flexão nos cotovelos. Envolvendo os músculos dos ombros, levante os braços para cima e para os lados, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2470.gif', 'hasaneyldrm', '2470'),
  ('b1d7a80a-0000-4000-8000-000000000341'::uuid, null, 'halter deitado deltóide de um braço atrás', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', true, 'Deite-se de bruços em um banco plano com um haltere em uma das mãos e a palma voltada para dentro. Estenda o braço em direção ao chão, mantendo-o próximo ao corpo. Levante o braço para cima e para trás, apertando a omoplata em direção à coluna. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0341.gif', 'hasaneyldrm', '0341'),
  ('b1d7a80a-0000-4000-8000-000000000343'::uuid, null, 'haltere deitado com um braço pressionado', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco com um haltere em uma das mãos e os pés apoiados no chão. Segure o haltere na altura dos ombros com a palma da mão voltada para frente. Pressione o haltere para cima até que seu braço esteja totalmente estendido. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0343.gif', 'hasaneyldrm', '0343'),
  ('b1d7a80a-0000-4000-8000-000000000342'::uuid, null, 'haltere deitado com um braço, press v. 2', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco com as costas apoiadas e os pés apoiados no chão. Segure um haltere com uma das mãos, com a palma voltada para os pés. Estenda o braço em direção ao teto, mantendo o cotovelo ligeiramente dobrado. Abaixe lentamente o haltere em direção ao peito, mantendo o cotovelo próximo ao corpo. Faça uma pausa na parte inferior e empurre o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0342.gif', 'hasaneyldrm', '0342'),
  ('b1d7a80a-0000-4000-8000-000000000344'::uuid, null, 'haltere deitado com um braço em extensão de tríceps pronada', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco com as costas e a cabeça apoiadas e os pés apoiados no chão. Segure um haltere em uma das mãos, com a palma voltada para baixo, e estenda o braço acima do ombro. Mantendo o braço parado, abaixe lentamente o haltere atrás da cabeça, dobrando o cotovelo. Faça uma pausa na parte inferior e estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0344.gif', 'hasaneyldrm', '0344'),
  ('b1d7a80a-0000-4000-8000-000000000345'::uuid, null, 'haltere deitado com um braço elevação lateral traseira', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', true, 'Deite-se de bruços em um banco plano com um haltere em uma das mãos, pendurado no chão. Mantenha o braço esticado e levante o haltere para o lado, longe do corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0345.gif', 'hasaneyldrm', '0345'),
  ('b1d7a80a-0000-4000-8000-000000000346'::uuid, null, 'haltere deitado com um braço supinado extensão de tríceps', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Deite-se em um banco com as costas e a cabeça apoiadas e os pés apoiados no chão. Segure um haltere com uma das mãos e estenda o braço acima do ombro. Mantendo o braço parado, abaixe lentamente o haltere atrás da cabeça, dobrando o cotovelo. Faça uma pausa na parte inferior e estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0346.gif', 'hasaneyldrm', '0346'),
  ('b1d7a80a-0000-4000-8000-000000000347'::uuid, null, 'pronação deitada com halteres', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com o peito voltado para baixo e os braços estendidos para baixo, segurando um haltere em cada mão. Gire as palmas das mãos para que fiquem voltadas para cima. Mantendo os braços parados, expire e enrole os halteres enquanto gira as palmas das mãos para baixo. Inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0347.gif', 'hasaneyldrm', '0347'),
  ('b1d7a80a-0000-4000-8000-000000002705'::uuid, null, 'haltere deitado em pronação no chão', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'dumbbell', false, 'Deite-se no chão com o rosto para baixo e os braços estendidos à sua frente, segurando um haltere em cada mão. Gire as palmas das mãos para que fiquem voltadas para o chão. Mantendo os braços retos, levante os halteres do chão contraindo os antebraços. Continue levantando até que os antebraços estejam totalmente contraídos e os halteres estejam na altura dos ombros. Segure por um momento e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2705.gif', 'hasaneyldrm', '2705'),
  ('b1d7a80a-0000-4000-8000-000000001284'::uuid, null, 'pulôver deitado com halteres na bola de exercícios', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'back']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios e role para frente até que a parte superior das costas esteja apoiada na bola. Segure um haltere com as duas mãos e estenda os braços sobre o peito. Abaixe lentamente o haltere atrás da cabeça, mantendo os braços retos. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1284.gif', 'hasaneyldrm', '1284'),
  ('b1d7a80a-0000-4000-8000-000000001328'::uuid, null, 'halteres deitados na remada delt traseira', 'pull_h', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'biceps']::text[], 'dumbbell', false, 'Deite-se de bruços em um banco plano com um haltere em cada mão, com as palmas voltadas para dentro. Estenda os braços em direção ao chão, mantendo uma ligeira flexão nos cotovelos. Envolvendo os músculos das costas, levante os halteres em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1328.gif', 'hasaneyldrm', '1328'),
  ('b1d7a80a-0000-4000-8000-000000000348'::uuid, null, 'elevação lateral traseira com halteres deitado', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', false, 'Deite-se de bruços em um banco plano com um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda os braços em direção ao chão, mantendo uma ligeira flexão nos cotovelos. Envolvendo os músculos dos ombros, levante os braços para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0348.gif', 'hasaneyldrm', '0348'),
  ('b1d7a80a-0000-4000-8000-000000001735'::uuid, null, 'haltere deitado em extensão única', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em uma das mãos e o braço totalmente estendido acima do peito. Abaixe o haltere de maneira controlada em direção à testa, mantendo o braço parado. Faça uma breve pausa na parte inferior do movimento e, em seguida, estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1735.gif', 'hasaneyldrm', '1735'),
  ('b1d7a80a-0000-4000-8000-000000000349'::uuid, null, 'supinação deitada com halteres', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com os pés apoiados no chão. Segure um haltere em cada mão com as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, enrole os halteres em direção aos ombros, contraindo os antebraços. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0349.gif', 'hasaneyldrm', '0349'),
  ('b1d7a80a-0000-4000-8000-000000002706'::uuid, null, 'haltere deitado em supinação no chão', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se de costas no chão, com as pernas estendidas e os braços ao lado do corpo, segurando um haltere em cada mão. Gire as palmas das mãos para cima, mantendo os cotovelos próximos aos lados. Enrole lentamente os halteres em direção aos ombros, apertando os antebraços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2706.gif', 'hasaneyldrm', '2706'),
  ('b1d7a80a-0000-4000-8000-000000001661'::uuid, null, 'rosca direta de bíceps com halteres deitado em decúbito dorsal', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Deite-se em um banco com as costas e a cabeça apoiadas e os pés apoiados no chão. Segure um haltere em cada mão com as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1661.gif', 'hasaneyldrm', '1661'),
  ('b1d7a80a-0000-4000-8000-000000000350'::uuid, null, 'haltere deitado em decúbito dorsal', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0350.gif', 'hasaneyldrm', '0350'),
  ('b1d7a80a-0000-4000-8000-000000000351'::uuid, null, 'extensão de tríceps deitado com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda os braços sobre o peito, mantendo os cotovelos próximos ao corpo. Abaixe os halteres em direção à testa, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0351.gif', 'hasaneyldrm', '0351'),
  ('b1d7a80a-0000-4000-8000-000000001662'::uuid, null, 'haltere deitado com curvatura larga', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1662.gif', 'hasaneyldrm', '1662'),
  ('b1d7a80a-0000-4000-8000-000000000352'::uuid, null, 'supino reto com halteres com pegada neutra', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure um haltere em cada mão com uma pegada neutra (palmas voltadas uma para a outra) e os braços estendidos sobre o peito. Abaixe lentamente os halteres em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa na parte inferior e empurre os halteres de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0352.gif', 'hasaneyldrm', '0352'),
  ('b1d7a80a-0000-4000-8000-000000001285'::uuid, null, 'banco com halteres com um braço e mosca', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Sente-se em um banco plano com um haltere em uma das mãos, apoiando-o no topo da coxa. Deite-se no banco, mantendo o haltere pressionado contra a coxa. Usando a mão livre, ajude a levantar o haltere até a posição inicial. Segure o haltere diretamente acima do ombro, com o braço estendido e a palma da mão voltada para dentro. Abaixe o haltere para o lado em um amplo arco, mantendo uma ligeira flexão no cotovelo. Faça uma pausa quando seu braço estiver paralelo ao chão, depois inverta o movimento e traga o haltere de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de braço e repita.', '/exercise-media/bstrainer/1285.gif', 'hasaneyldrm', '1285'),
  ('b1d7a80a-0000-4000-8000-000000000292'::uuid, null, 'remada com halteres com um braço dobrado', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos com a palma voltada para o corpo. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Deixe o haltere pendurado em direção ao chão, com o braço totalmente estendido. Puxe o haltere em direção ao peito, mantendo o cotovelo próximo ao corpo e apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0292.gif', 'hasaneyldrm', '0292'),
  ('b1d7a80a-0000-4000-8000-000000001286'::uuid, null, 'haltere com um braço no peito na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com um haltere em uma das mãos e os pés apoiados no chão. Ande com os pés para a frente, rolando a bola até que a parte superior das costas esteja apoiada na bola e a cabeça, o pescoço e os ombros fiquem fora da bola. Estenda o braço com o haltere acima do peito, com a palma voltada para dentro. Abaixe lentamente o haltere para o lado, mantendo uma ligeira flexão no cotovelo. Faça uma pausa por um momento quando seu braço estiver paralelo ao chão. Envolva os músculos do peito para trazer o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1286.gif', 'hasaneyldrm', '1286'),
  ('b1d7a80a-0000-4000-8000-000000000353'::uuid, null, 'rosca direta de concentração com um braço com halteres (na bola de estabilidade)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure um haltere com uma das mãos, com a palma voltada para cima e o braço estendido em direção ao chão. Descanse o cotovelo na parte interna da coxa, logo acima do joelho. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro enquanto contrai o bíceps. Faça uma pausa por um momento no início do movimento, depois inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de braço e repita.', '/exercise-media/bstrainer/0353.gif', 'hasaneyldrm', '0353'),
  ('b1d7a80a-0000-4000-8000-000000001287'::uuid, null, 'halteres com um braço declínio no peito', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', true, 'Deite-se em um banco inclinado com um haltere em uma das mãos, apoiado no peito. Coloque os pés apoiados no chão e mantenha as costas pressionadas contra o banco. Estenda o braço e empurre o haltere em direção ao teto, estendendo totalmente o cotovelo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1287.gif', 'hasaneyldrm', '1287'),
  ('b1d7a80a-0000-4000-8000-000000001288'::uuid, null, 'haltere com um braço voando na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com um haltere em uma das mãos e os pés apoiados no chão. Ande com os pés para a frente e role o corpo para baixo até que a parte superior das costas esteja apoiada na bola de exercícios. Estenda o braço com o haltere acima do peito, com a palma voltada para dentro. Abaixe lentamente o haltere para o lado, mantendo uma ligeira flexão no cotovelo. Faça uma pausa por um momento e contraia os músculos do peito para trazer o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1288.gif', 'hasaneyldrm', '1288'),
  ('b1d7a80a-0000-4000-8000-000000001736'::uuid, null, 'supino francês com halteres com um braço na bola de exercícios', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos, com a palma voltada para cima e o cotovelo dobrado em um ângulo de 90 graus. Estenda o braço em direção ao teto, mantendo o cotovelo parado. Abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1736.gif', 'hasaneyldrm', '1736'),
  ('b1d7a80a-0000-4000-8000-000000001663'::uuid, null, 'rosca pregadora com martelo de um braço e haltere', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco de pregador com um haltere em uma das mãos e o braço apoiado na almofada. Segure o haltere com uma pegada neutra (palmas voltadas para o corpo). Mantendo o braço parado, expire e enrole o haltere em direção ao ombro. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1663.gif', 'hasaneyldrm', '1663'),
  ('b1d7a80a-0000-4000-8000-000000001621'::uuid, null, 'halteres com martelo de um braço na bola de exercícios', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos, com a palma voltada para dentro e o cotovelo dobrado em um ângulo de 90 graus. Coloque a outra mão no quadril para obter estabilidade. Pressione o haltere para cima, estendendo totalmente o braço. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1621.gif', 'hasaneyldrm', '1621'),
  ('b1d7a80a-0000-4000-8000-000000001289'::uuid, null, 'halteres com um braço inclinado no peito', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Ajuste o banco inclinado para um ângulo de 45 graus. Sente-se no banco com as costas apoiadas na almofada e os pés apoiados no chão. Segure um haltere em uma das mãos com uma pegada pronada, apoiando-o no ombro. Empurre o haltere para cima e para longe do corpo, estendendo totalmente o braço. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1289.gif', 'hasaneyldrm', '1289'),
  ('b1d7a80a-0000-4000-8000-000000000354'::uuid, null, 'recuo de um braço com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere na mão direita. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Traga o cotovelo direito para o lado, mantendo-o dobrado em um ângulo de 90 graus. Estenda o braço direito para trás, apertando o tríceps no início do movimento. Abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0354.gif', 'hasaneyldrm', '0354'),
  ('b1d7a80a-0000-4000-8000-000000000355'::uuid, null, 'elevação lateral com halteres com um braço', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'triceps']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos com a palma voltada para o corpo. Mantenha as costas retas e o núcleo engajado durante todo o exercício. Levante o haltere para o lado, mantendo o braço reto e a palma da mão voltada para baixo. Continue levantando até que seu braço fique paralelo ao chão. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0355.gif', 'hasaneyldrm', '0355'),
  ('b1d7a80a-0000-4000-8000-000000000356'::uuid, null, 'elevação lateral com halteres com um braço e apoio', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rotator cuff']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos, com a palma voltada para o corpo. Coloque a outra mão em uma superfície estável, como um banco ou parede, para se apoiar. Mantenha as costas retas e envolva seu núcleo. Levante o haltere para o lado, mantendo o braço reto e a palma da mão voltada para baixo. Continue levantando até que seu braço fique paralelo ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0356.gif', 'hasaneyldrm', '0356'),
  ('b1d7a80a-0000-4000-8000-000000001290'::uuid, null, 'haltere com um braço na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'core']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure um haltere com uma das mãos e posicione-o na altura dos ombros, com o cotovelo dobrado e a palma voltada para frente. Pressione lentamente o haltere para cima até que o braço esteja totalmente estendido, enquanto mantém o núcleo engajado e o equilíbrio na bola de exercícios. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1290.gif', 'hasaneyldrm', '1290'),
  ('b1d7a80a-0000-4000-8000-000000001665'::uuid, null, 'rosca direta com um braço com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Deite-se de bruços em um banco plano com um haltere em uma das mãos e a palma voltada para baixo. Estenda o braço totalmente, deixando-o pendurado em direção ao chão. Mantendo o braço parado, enrole o haltere em direção ao ombro, contraindo o bíceps. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1665.gif', 'hasaneyldrm', '1665'),
  ('b1d7a80a-0000-4000-8000-000000001666'::uuid, null, 'rosca direta com halteres com um braço inclinado e martelo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Deite-se de bruços em um banco plano com um haltere em uma das mãos, a palma voltada para o corpo e o braço totalmente estendido. Mantenha o braço parado e enrole o haltere em direção ao ombro, contraindo o bíceps. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1666.gif', 'hasaneyldrm', '1666'),
  ('b1d7a80a-0000-4000-8000-000000001291'::uuid, null, 'pulôver de um braço com halteres na bola de exercícios', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'latissimus dorsi', 'rhomboids']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure um haltere com uma mão e estenda o braço acima do peito. Abaixe lentamente o haltere atrás da cabeça, mantendo o braço reto. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1291.gif', 'hasaneyldrm', '1291'),
  ('b1d7a80a-0000-4000-8000-000000000358'::uuid, null, 'rosca reversa do pulso com halteres e um braço', 'isolation', ARRAY['forearms', 'wrist extensors']::text[], ARRAY['wrist extensors']::text[], 'dumbbell', true, 'Sente-se em um banco ou cadeira com os pés apoiados no chão. Segure um haltere em uma das mãos com uma pegada pronada, com a palma voltada para baixo. Descanse o antebraço na coxa, com o pulso pendurado na borda. Abaixe lentamente o haltere em direção ao chão flexionando o pulso. Faça uma pausa na parte inferior e, em seguida, enrole lentamente o pulso em direção ao corpo. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0358.gif', 'hasaneyldrm', '0358'),
  ('b1d7a80a-0000-4000-8000-000000000359'::uuid, null, 'mosca reversa com haltere de um braço (com apoio)', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', true, 'Sente-se em um banco com os pés apoiados no chão e as costas retas. Segure um haltere em uma das mãos com a palma voltada para dentro. Incline-se para a frente e coloque a mão livre no banco para se apoiar. Mantenha o braço ligeiramente flexionado e levante-o para o lado até ficar paralelo ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0359.gif', 'hasaneyldrm', '0359'),
  ('b1d7a80a-0000-4000-8000-000000001622'::uuid, null, 'supino reverso com halteres com um braço', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', true, 'Sente-se em um banco plano com um haltere em uma das mãos, com a palma voltada para o corpo. Coloque os pés apoiados no chão e mantenha as costas retas. Levante o haltere até a altura dos ombros, mantendo o cotovelo próximo ao corpo. Pressione o haltere para cima até que seu braço esteja totalmente estendido. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1622.gif', 'hasaneyldrm', '1622'),
  ('b1d7a80a-0000-4000-8000-000000001414'::uuid, null, 'rosca direta reversa com halteres e um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco de pregador com o peito apoiado na almofada e o braço estendido sobre a borda do banco, segurando um haltere com uma pegada por baixo. Abaixe o haltere lentamente até que seu braço esteja totalmente estendido. Enrole o haltere em direção ao ombro, mantendo o braço parado. Contraia o bíceps no início do movimento e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1414.gif', 'hasaneyldrm', '1414'),
  ('b1d7a80a-0000-4000-8000-000000001667'::uuid, null, 'rosca direta reversa com halteres com um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé com um haltere em uma das mãos, palma voltada para baixo e braço totalmente estendido. Mantendo o braço parado, enrole o haltere em direção ao ombro, flexionando o cotovelo. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1667.gif', 'hasaneyldrm', '1667'),
  ('b1d7a80a-0000-4000-8000-000000001668'::uuid, null, 'rosca bíceps sentada com halteres com um braço na bola de exercícios', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos, com a palma voltada para cima e o braço totalmente estendido. Mantendo o braço parado, enrole o haltere em direção ao ombro, contraindo o bíceps. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1668.gif', 'hasaneyldrm', '1668'),
  ('b1d7a80a-0000-4000-8000-000000001669'::uuid, null, 'rosca martelo com halteres sentado com um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere com uma mão com pegada neutra (palmas voltadas uma para a outra). Descanse o cotovelo na parte interna da coxa, logo acima do joelho. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1669.gif', 'hasaneyldrm', '1669'),
  ('b1d7a80a-0000-4000-8000-000000001415'::uuid, null, 'flexão de pulso neutra com halteres sentado com um braço', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'dumbbell', true, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em uma das mãos, com a palma voltada para cima. Descanse o antebraço na coxa, permitindo que o pulso fique pendurado na borda. Mantendo o antebraço parado, levante o pulso o máximo possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o pulso de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para a outra mão.', '/exercise-media/bstrainer/1415.gif', 'hasaneyldrm', '1415'),
  ('b1d7a80a-0000-4000-8000-000000000361'::uuid, null, 'supino com um braço e halteres', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos na altura dos ombros, com a palma voltada para a frente. Pressione o haltere para cima até que seu braço esteja totalmente estendido acima da cabeça. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0361.gif', 'hasaneyldrm', '0361'),
  ('b1d7a80a-0000-4000-8000-000000000360'::uuid, null, 'halteres com um braço e ombros v. 2', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos na altura dos ombros, com a palma voltada para a frente. Envolva seu núcleo e pressione o haltere para cima, estendendo totalmente o braço. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta ao nível dos ombros. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0360.gif', 'hasaneyldrm', '0360'),
  ('b1d7a80a-0000-4000-8000-000000003888'::uuid, null, 'arranco de um braço com halteres', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'core']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos com uma pegada pronada. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Abaixe o haltere em direção ao chão, mantendo-o próximo ao corpo. Estenda explosivamente os quadris, joelhos e tornozelos, conduzindo o haltere para cima em linha reta. Quando o haltere atingir a altura dos ombros, gire rapidamente a mão e dê um soco acima da cabeça, estendendo totalmente o braço. Pegue o haltere acima da cabeça com uma ligeira flexão nos joelhos e quadris. Abaixe o haltere de volta à posição inicial de maneira controlada. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/3888.gif', 'hasaneyldrm', '3888'),
  ('b1d7a80a-0000-4000-8000-000000001670'::uuid, null, 'rosca direta com halteres com um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé com um haltere em uma das mãos, palma voltada para frente e braço totalmente estendido. Mantendo o braço parado, expire e enrole o peso para cima enquanto contrai o bíceps. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1670.gif', 'hasaneyldrm', '1670'),
  ('b1d7a80a-0000-4000-8000-000000001671'::uuid, null, 'rosca direta com haltere com um braço em pé e martelo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o tronco. Mantenha os cotovelos próximos ao tronco e os braços parados. Expire e enrole os pesos enquanto contrai o bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1671.gif', 'hasaneyldrm', '1671'),
  ('b1d7a80a-0000-4000-8000-000000000362'::uuid, null, 'extensão de tríceps de um braço com halteres (no banco)', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere com uma mão e coloque a outra no banco para se apoiar. Levante o haltere acima da cabeça, mantendo o braço próximo à cabeça e o cotovelo apontando para a frente. Abaixe o haltere atrás da cabeça dobrando o cotovelo, mantendo o braço parado. Estenda o braço de volta à posição inicial, esticando totalmente o cotovelo. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0362.gif', 'hasaneyldrm', '0362'),
  ('b1d7a80a-0000-4000-8000-000000000363'::uuid, null, 'remada vertical com halteres com um braço', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos com uma pegada pronada. Deixe o haltere pendurado com o braço estendido na frente das coxas, com a palma da mão voltada para o corpo. Mantendo as costas retas e o núcleo engajado, expire e levante o haltere em direção ao queixo, conduzindo com o cotovelo. Faça uma pausa por um momento no topo, inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0363.gif', 'hasaneyldrm', '0363'),
  ('b1d7a80a-0000-4000-8000-000000000364'::uuid, null, 'rosca direta de pulso com halteres', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'dumbbell', true, 'Sente-se em um banco ou cadeira com os pés apoiados no chão. Segure um haltere com uma das mãos, apoiando o antebraço na coxa. Permita que seu pulso se estenda, deixando o haltere rolar em direção aos seus dedos. Enrole lentamente o pulso para cima, trazendo o haltere em direção ao antebraço. Repita pelo número desejado de repetições e depois mude para a outra mão.', '/exercise-media/bstrainer/0364.gif', 'hasaneyldrm', '0364'),
  ('b1d7a80a-0000-4000-8000-000000001672'::uuid, null, 'haltere um braço zottman pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco de pregador e segure um haltere em uma das mãos com uma pegada por baixo. Descanse o braço no banco do pregador, permitindo que ele se estenda totalmente. Enrole o haltere em direção ao ombro, mantendo o braço parado. No topo do cacho, gire o pulso de modo que a palma da mão fique voltada para cima. Abaixe lentamente o haltere de volta à posição inicial, girando o pulso de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1672.gif', 'hasaneyldrm', '1672'),
  ('b1d7a80a-0000-4000-8000-000000001292'::uuid, null, 'mosca de uma perna com halteres na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com um haltere em cada mão, com as palmas voltadas uma para a outra. Coloque um pé no chão e estenda a outra perna à sua frente. Incline-se ligeiramente para a frente e estenda os braços para os lados, mantendo uma ligeira flexão nos cotovelos. Abaixe lentamente os halteres para baixo e para os lados, sentindo um alongamento no peito. Faça uma pausa por um momento na parte inferior e contraia os músculos do peito para trazer os halteres de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1292.gif', 'hasaneyldrm', '1292'),
  ('b1d7a80a-0000-4000-8000-000000000365'::uuid, null, 'haltere sobre banco flexão de pulso neutra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão, com as palmas voltadas para cima. Descanse os antebraços no banco, permitindo que os pulsos fiquem pendurados na borda. Mantendo os braços parados, expire e enrole os halteres em direção aos ombros. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0365.gif', 'hasaneyldrm', '0365'),
  ('b1d7a80a-0000-4000-8000-000000000366'::uuid, null, 'haltere sobre banco flexão de pulso neutra com um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em um banco com um haltere em uma das mãos e o braço estendido sobre o banco, com a palma voltada para cima. Mantenha o braço parado e enrole o haltere em direção ao ombro, mantendo o pulso em uma posição neutra. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0366.gif', 'hasaneyldrm', '0366'),
  ('b1d7a80a-0000-4000-8000-000000001441'::uuid, null, 'haltere sobre banco flexão reversa do pulso com um braço', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'dumbbell', true, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em uma das mãos, com a palma voltada para baixo. Descanse o antebraço no banco com o pulso pendurado na borda. Enrole lentamente o pulso para cima, trazendo o haltere em direção ao antebraço. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1441.gif', 'hasaneyldrm', '1441'),
  ('b1d7a80a-0000-4000-8000-000000000367'::uuid, null, 'haltere sobre banco flexão de pulso com um braço', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', true, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em uma das mãos, com a palma voltada para baixo. Descanse o antebraço no banco com o pulso pendurado na borda. Enrole lentamente o pulso para cima, trazendo o haltere em direção ao antebraço. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0367.gif', 'hasaneyldrm', '0367'),
  ('b1d7a80a-0000-4000-8000-000000000368'::uuid, null, 'haltere sobre o banco inverte a curvatura do pulso', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão, com as palmas voltadas para baixo. Descanse os antebraços no banco, permitindo que os pulsos fiquem pendurados na borda. Enrole lentamente os pulsos para cima, trazendo os halteres em direção ao corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0368.gif', 'hasaneyldrm', '0368'),
  ('b1d7a80a-0000-4000-8000-000000000369'::uuid, null, 'haltere sobre flexão de pulso no banco', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'dumbbell', false, 'Sente-se em um banco com os antebraços apoiados no banco e as palmas das mãos voltadas para cima, segurando um haltere em cada mão. Deixe seus pulsos pendurados na borda do banco. Enrole lentamente os pulsos para cima, apertando os antebraços no início do movimento. Faça uma pausa por um momento e, em seguida, abaixe lentamente os pulsos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0369.gif', 'hasaneyldrm', '0369'),
  ('b1d7a80a-0000-4000-8000-000000001329'::uuid, null, 'palma da mão com halteres rotacional dobrada sobre a remada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Incline-se para a frente na altura dos quadris, mantendo as costas retas e os joelhos ligeiramente flexionados. Deixe os braços pendurados para baixo, com as palmas voltadas para o corpo. Envolva o núcleo e puxe os halteres em direção ao peito, mantendo os cotovelos próximos ao corpo. Ao puxar os halteres para cima, gire as palmas das mãos para que fiquem voltadas para longe do corpo. Aperte as omoplatas no início do movimento. Abaixe lentamente os halteres de volta à posição inicial, girando as palmas das mãos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1329.gif', 'hasaneyldrm', '1329'),
  ('b1d7a80a-0000-4000-8000-000000001623'::uuid, null, 'palmas com halteres no supino inclinado', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com as costas apoiadas no encosto e os pés apoiados no chão. Segure um haltere em cada mão com uma pegada pronada, com as palmas voltadas para dentro. Estenda os braços acima do peito, mantendo uma ligeira flexão nos cotovelos. Abaixe os halteres lentamente em direção aos ombros, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento na parte inferior e, em seguida, pressione os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1623.gif', 'hasaneyldrm', '1623'),
  ('b1d7a80a-0000-4000-8000-000000000370'::uuid, null, 'rosca martelo pêssego com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o tronco. Mantenha os cotovelos próximos ao tronco e gire as palmas das mãos até que fiquem voltadas para frente. Esta será sua posição inicial. Agora, mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Em seguida, inspire e comece lentamente a abaixar os halteres de volta à posição inicial. Repita pela quantidade recomendada de repetições.', '/exercise-media/bstrainer/0370.gif', 'hasaneyldrm', '0370'),
  ('b1d7a80a-0000-4000-8000-000000000371'::uuid, null, 'agachamento plyo com halteres', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão ao lado do corpo. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Ao chegar ao final do agachamento, exploda para cima, saltando do chão. Enquanto estiver no ar, mude rapidamente a posição dos pés, pousando com o pé oposto à frente. Abaixe imediatamente o corpo de volta à posição de agachamento e repita o salto, trocando os pés novamente. Continue alternando a posição dos pés a cada salto até o número desejado de repetições.', '/exercise-media/bstrainer/0371.gif', 'hasaneyldrm', '0371'),
  ('b1d7a80a-0000-4000-8000-000000000372'::uuid, null, 'rosca pregadora com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco de pregador com os braços apoiados na almofada e o peito contra ela. Segure um haltere em cada mão com as palmas voltadas para cima e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0372.gif', 'hasaneyldrm', '0372'),
  ('b1d7a80a-0000-4000-8000-000000001673'::uuid, null, 'pregador com halteres enrolado sobre bola de exercícios', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos, apoiando o cotovelo na bola de exercícios. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro. Faça uma pausa no topo, inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1673.gif', 'hasaneyldrm', '1673'),
  ('b1d7a80a-0000-4000-8000-000000001293'::uuid, null, 'supino com halteres na bola de exercícios', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e halteres em cada mão, apoiados nas coxas. Caminhe lentamente para a frente, rolando a bola de exercícios até que a parte inferior das costas esteja apoiada na bola e os joelhos formem um ângulo de 90 graus. Levante os halteres até a altura dos ombros, com as palmas voltadas para a frente. Pressione os halteres para cima até que os braços estejam totalmente estendidos. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1293.gif', 'hasaneyldrm', '1293'),
  ('b1d7a80a-0000-4000-8000-000000000373'::uuid, null, 'Extensão de tríceps com pegada pronada com halteres', 'isolation', ARRAY['triceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco ou cadeira com as costas retas e os pés apoiados no chão. Segure um haltere com as duas mãos, com as palmas voltadas para baixo, e estenda os braços acima da cabeça. Mantendo os braços próximos à cabeça e os cotovelos apontando para a frente, abaixe lentamente o haltere atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0373.gif', 'hasaneyldrm', '0373'),
  ('b1d7a80a-0000-4000-8000-000000000374'::uuid, null, 'rosca inclinada prona com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Ajuste o banco para uma inclinação de 45 graus. Deite-se de bruços no banco com o peito e o estômago apoiados nele. Segure um haltere em cada mão com as palmas voltadas para baixo e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0374.gif', 'hasaneyldrm', '0374'),
  ('b1d7a80a-0000-4000-8000-000000001674'::uuid, null, 'rosca direta inclinada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Ajuste o banco para uma inclinação de 45 graus. Deite-se de bruços no banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Deixe os braços pendurados em direção ao chão, mantendo os cotovelos ligeiramente flexionados. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1674.gif', 'hasaneyldrm', '1674'),
  ('b1d7a80a-0000-4000-8000-000000000375'::uuid, null, 'pulôver com halteres', 'isolation', ARRAY['pectorals', 'latissimus dorsi']::text[], ARRAY['latissimus dorsi', 'triceps']::text[], 'dumbbell', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés no chão. Segure um haltere com as duas mãos e estenda os braços acima do peito. Mantendo uma ligeira flexão nos cotovelos, abaixe lentamente o haltere atrás da cabeça até sentir um alongamento no peito e nos ombros. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0375.gif', 'hasaneyldrm', '0375'),
  ('b1d7a80a-0000-4000-8000-000000001294'::uuid, null, 'pulôver com halteres extensão de quadril em bola de exercício', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e o haltere apoiado nas coxas. Caminhe lentamente para a frente, rolando a bola de exercícios pelas costas até que a cabeça, o pescoço e a parte superior das costas estejam apoiados na bola. Segure o haltere com as duas mãos e estenda os braços sobre o peito, mantendo uma ligeira flexão nos cotovelos. Abaixe o haltere atrás da cabeça, mantendo os braços retos e mantendo o controle. Faça uma pausa e levante o haltere de volta à posição inicial. Mantendo os braços estendidos, levante os quadris do chão, apertando os glúteos e envolvendo o núcleo. Abaixe os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1294.gif', 'hasaneyldrm', '1294'),
  ('b1d7a80a-0000-4000-8000-000000001295'::uuid, null, 'pulôver com halteres na bola de exercícios', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'latissimus dorsi']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios e segure um haltere com as duas mãos acima do peito e os braços estendidos. Abaixe lentamente o haltere atrás da cabeça, mantendo os braços retos. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1295.gif', 'hasaneyldrm', '1295'),
  ('b1d7a80a-0000-4000-8000-000000001700'::uuid, null, 'push press com halteres', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros. Dobre ligeiramente os joelhos e abaixe o corpo, depois estenda as pernas de forma explosiva e pressione os halteres acima da cabeça. Trave os braços no início do movimento e abaixe os halteres de volta ao nível dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1700.gif', 'hasaneyldrm', '1700'),
  ('b1d7a80a-0000-4000-8000-000000000376'::uuid, null, 'elevação com halteres', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para o corpo. Mantenha as costas retas e envolva seu núcleo. Levante os braços para os lados até ficarem paralelos ao chão, mantendo uma ligeira flexão nos cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0376.gif', 'hasaneyldrm', '0376'),
  ('b1d7a80a-0000-4000-8000-000000002292'::uuid, null, 'levantamento delt traseiro com halteres', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para o corpo. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Levante os braços para os lados, mantendo uma ligeira flexão nos cotovelos, até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2292.gif', 'hasaneyldrm', '2292'),
  ('b1d7a80a-0000-4000-8000-000000000377'::uuid, null, 'halter delt traseiro row_shoulder', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure um haltere em cada mão com as palmas voltadas para o corpo. Incline-se para a frente na cintura, mantendo as costas retas e o núcleo engajado. Estenda os braços em direção ao chão, com uma ligeira flexão nos cotovelos. Levante os halteres para os lados, apertando as omoplatas. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0377.gif', 'hasaneyldrm', '0377'),
  ('b1d7a80a-0000-4000-8000-000000000378'::uuid, null, 'mosca traseira com halteres', 'push_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Estenda os braços em direção ao chão, com as palmas voltadas uma para a outra. Mantendo uma ligeira flexão nos cotovelos, levante os braços para os lados e aperte as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0378.gif', 'hasaneyldrm', '0378'),
  ('b1d7a80a-0000-4000-8000-000000000380'::uuid, null, 'elevação lateral traseira com halteres', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para o corpo. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Levante os braços para os lados, mantendo uma ligeira flexão nos cotovelos, até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0380.gif', 'hasaneyldrm', '0380'),
  ('b1d7a80a-0000-4000-8000-000000000379'::uuid, null, 'elevação lateral traseira com halteres (cabeça de apoio)', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Levante os braços para os lados, mantendo uma ligeira flexão dos cotovelos, até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0379.gif', 'hasaneyldrm', '0379'),
  ('b1d7a80a-0000-4000-8000-000000000381'::uuid, null, 'estocada traseira com halteres', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Dê um passo para trás com o pé direito, abaixando o corpo para uma posição de estocada. Dobre o joelho esquerdo e abaixe o corpo até que a coxa esquerda fique paralela ao chão. Faça uma pausa por um momento e empurre o calcanhar esquerdo para retornar à posição inicial. Repita do outro lado, recuando com o pé esquerdo.', '/exercise-media/bstrainer/0381.gif', 'hasaneyldrm', '0381'),
  ('b1d7a80a-0000-4000-8000-000000000382'::uuid, null, 'haltere inverte aderência rosca bíceps', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, as palmas voltadas para baixo e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0382.gif', 'hasaneyldrm', '0382'),
  ('b1d7a80a-0000-4000-8000-000000001624'::uuid, null, 'supino reverso com halteres', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com os pés apoiados no chão e os joelhos dobrados. Segure um haltere em cada mão com uma pegada pronada, com as palmas voltadas para os pés. Estenda os braços em direção ao teto, mantendo uma ligeira flexão nos cotovelos. Abaixe lentamente os halteres em direção ao peito, permitindo que os cotovelos se abram para os lados. Faça uma pausa na parte inferior e empurre os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1624.gif', 'hasaneyldrm', '1624'),
  ('b1d7a80a-0000-4000-8000-000000000383'::uuid, null, 'voo reverso com halteres', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Estenda os braços à sua frente, com as palmas voltadas uma para a outra. Mantendo uma ligeira flexão nos cotovelos, levante os braços para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0383.gif', 'hasaneyldrm', '0383'),
  ('b1d7a80a-0000-4000-8000-000000001330'::uuid, null, 'banco inclinado com pegada reversa com halteres, remada com um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', true, 'Configure um banco inclinado em um ângulo de 45 graus. Coloque um haltere no chão ao lado do banco. Fique de frente para o banco com os pés afastados na largura dos ombros. Dobre a cintura e coloque o joelho esquerdo e a mão esquerda no banco para apoio. Pegue o haltere com a mão direita usando uma pegada reversa (palma voltada para baixo). Mantenha as costas retas e o núcleo engajado. Puxe o haltere em direção ao peito, mantendo o cotovelo próximo ao corpo. Contraia os músculos das costas no início do movimento. Abaixe o haltere de volta à posição inicial de maneira controlada. Repita pelo número desejado de repetições. Troque de lado e repita o exercício com o braço esquerdo.', '/exercise-media/bstrainer/1330.gif', 'hasaneyldrm', '1330'),
  ('b1d7a80a-0000-4000-8000-000000001331'::uuid, null, 'halteres com pegada reversa banco inclinado linha de dois braços', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'dumbbell', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com o peito apoiado no encosto e os pés apoiados no chão. Segure um haltere em cada mão com uma pegada por baixo. Incline-se para a frente e deixe os braços pendurados para baixo, totalmente estendidos. Puxe os halteres em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1331.gif', 'hasaneyldrm', '1331'),
  ('b1d7a80a-0000-4000-8000-000000002327'::uuid, null, 'remada com pegada reversa com halteres (feminino)', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure um haltere em cada mão com uma pegada pronada, com as palmas voltadas para o corpo. Incline-se para a frente na cintura, mantendo as costas retas e o núcleo engajado. Deixe os braços pendurados para baixo, totalmente estendidos, com uma ligeira flexão nos cotovelos. Puxe os halteres em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2327.gif', 'hasaneyldrm', '2327'),
  ('b1d7a80a-0000-4000-8000-000000000384'::uuid, null, 'curl de pregador reverso com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco de pregador com os braços apoiados na almofada e o peito contra o suporte. Segure um haltere em cada mão com uma pegada supinada, com as palmas voltadas para cima. Mantendo os braços parados, expire e enrole os halteres enquanto contrai os bíceps. Continue a enrolar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0384.gif', 'hasaneyldrm', '0384'),
  ('b1d7a80a-0000-4000-8000-000000001675'::uuid, null, 'rosca aranha reversa com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, as palmas voltadas para o corpo e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1675.gif', 'hasaneyldrm', '1675'),
  ('b1d7a80a-0000-4000-8000-000000000385'::uuid, null, 'rosca reversa do pulso com halteres', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'dumbbell', false, 'Sente-se em um banco ou cadeira com os pés apoiados no chão. Segure um haltere em cada mão com uma pegada pronada, com as palmas voltadas para baixo. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados na borda. Enrole lentamente os pulsos para cima, trazendo os halteres em direção ao corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0385.gif', 'hasaneyldrm', '0385'),
  ('b1d7a80a-0000-4000-8000-000000001459'::uuid, null, 'levantamento terra romeno com halteres', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Mantendo as costas retas e o núcleo engajado, dobre os quadris e abaixe os halteres em direção ao chão, permitindo que os joelhos dobrem ligeiramente. Abaixe os halteres até sentir um alongamento nos isquiotibiais, depois empurre os calcanhares e envolva os glúteos para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1459.gif', 'hasaneyldrm', '1459'),
  ('b1d7a80a-0000-4000-8000-000000000386'::uuid, null, 'rotação reversa do haltere fly', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para dentro. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Levante os braços para os lados, mantendo uma ligeira flexão nos cotovelos, até que fiquem paralelos ao chão. Gire os braços de forma que as palmas fiquem voltadas para baixo. Abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0386.gif', 'hasaneyldrm', '0386'),
  ('b1d7a80a-0000-4000-8000-000000002397'::uuid, null, 'scott press com halteres', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'dumbbell', false, 'Sente-se em um banco com um haltere em cada mão, com as palmas voltadas para frente. Levante os halteres até a altura dos ombros, com os cotovelos dobrados e as palmas das mãos voltadas para a frente. Pressione os halteres para cima até que os braços estejam totalmente estendidos. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2397.gif', 'hasaneyldrm', '2397'),
  ('b1d7a80a-0000-4000-8000-000000000387'::uuid, null, 'elevação frontal alternada sentada com halteres', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'biceps']::text[], 'dumbbell', true, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere em cada mão com as palmas voltadas para o corpo e os braços estendidos ao lado do corpo. Mantendo os braços retos, levante um haltere à sua frente até que fique paralelo ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita com o outro braço. Alterne entre os braços para o número desejado de repetições.', '/exercise-media/bstrainer/0387.gif', 'hasaneyldrm', '0387'),
  ('b1d7a80a-0000-4000-8000-000000001676'::uuid, null, 'rosca de martelo alternada sentada com halteres na bola de exercícios', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para o corpo e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole um haltere em direção ao ombro, mantendo a palma da mão voltada para o corpo. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita o movimento com o braço oposto. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/1676.gif', 'hasaneyldrm', '1676'),
  ('b1d7a80a-0000-4000-8000-000000000388'::uuid, null, 'supino alternado sentado com halteres', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'dumbbell', true, 'Sente-se em um banco com um haltere em cada mão, com as palmas voltadas para frente. Levante os halteres até a altura dos ombros, com os cotovelos dobrados e as palmas das mãos voltadas para a frente. Pressione um haltere acima da cabeça, estendendo totalmente o braço. Abaixe o haltere de volta à altura dos ombros. Repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0388.gif', 'hasaneyldrm', '0388'),
  ('b1d7a80a-0000-4000-8000-000000003546'::uuid, null, 'ombro alternado sentado com halteres', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', true, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere em cada mão, com as palmas voltadas para dentro, e levante-os até a altura dos ombros. Pressione um haltere acima da cabeça enquanto mantém o outro haltere na altura dos ombros. Abaixe o haltere levantado de volta à altura dos ombros enquanto pressiona simultaneamente o outro haltere acima da cabeça. Continue alternando entre os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/3546.gif', 'hasaneyldrm', '3546'),
  ('b1d7a80a-0000-4000-8000-000000000389'::uuid, null, 'extensão de banco sentado com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere com as duas mãos e estenda os braços acima da cabeça. Abaixe lentamente o haltere atrás da cabeça, mantendo os cotovelos próximos às orelhas. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0389.gif', 'hasaneyldrm', '0389'),
  ('b1d7a80a-0000-4000-8000-000000002317'::uuid, null, 'levantamento lateral com halteres sentado com braço flexionado', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere em cada mão com as palmas voltadas para o corpo e os braços dobrados em um ângulo de 90 graus. Mantendo os cotovelos dobrados, levante os braços para os lados até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2317.gif', 'hasaneyldrm', '2317'),
  ('b1d7a80a-0000-4000-8000-000000001730'::uuid, null, 'haltere sentado curvado sobre recuo alternado', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'dumbbell', true, 'Sente-se em um banco com um haltere em cada mão, com as palmas voltadas para dentro. Incline-se para a frente na cintura, mantendo as costas retas e paralelas ao chão. Estenda um braço para trás, mantendo-o próximo ao corpo, até que o braço esteja totalmente estendido. Faça uma pausa por um momento e abaixe lentamente o haltere de volta à posição inicial. Repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/1730.gif', 'hasaneyldrm', '1730'),
  ('b1d7a80a-0000-4000-8000-000000001737'::uuid, null, 'halter sentado curvado sobre extensão de tríceps', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão. Incline-se para a frente na cintura, mantendo as costas retas e a cabeça erguida. Estenda os braços para trás, mantendo os cotovelos próximos à cabeça. Faça uma pausa por um momento e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1737.gif', 'hasaneyldrm', '1737'),
  ('b1d7a80a-0000-4000-8000-000000001677'::uuid, null, 'rosca bíceps sentada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão, com as palmas voltadas para cima. Mantenha as costas retas e os cotovelos próximos ao tronco. Expire e levante os halteres em direção aos ombros, contraindo os bíceps. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1677.gif', 'hasaneyldrm', '1677'),
  ('b1d7a80a-0000-4000-8000-000000000390'::uuid, null, 'rosca bíceps sentada com halteres (na bola de estabilidade)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os halteres enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0390.gif', 'hasaneyldrm', '0390'),
  ('b1d7a80a-0000-4000-8000-000000003547'::uuid, null, 'rosca direta de bíceps sentado com halteres até pressão de ombro', 'push_v', ARRAY['biceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere em cada mão com as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os cotovelos próximos ao corpo, enrole os halteres em direção aos ombros. Quando os antebraços estiverem na vertical, gire os pulsos de forma que as palmas fiquem voltadas para a frente. Pressione os halteres acima da cabeça até que os braços estejam totalmente estendidos. Abaixe os halteres de volta à posição inicial, invertendo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3547.gif', 'hasaneyldrm', '3547'),
  ('b1d7a80a-0000-4000-8000-000000001379'::uuid, null, 'panturrilha sentada com halteres', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'dumbbell', false, 'Sente-se em um banco ou cadeira com os pés apoiados no chão e um haltere apoiado nas coxas. Coloque as pontas dos pés em uma superfície elevada, como um degrau ou bloco, com os calcanhares pendurados na borda. Segure o haltere para estabilidade. Levante os calcanhares o mais alto possível, colocando o peso do corpo na planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1379.gif', 'hasaneyldrm', '1379'),
  ('b1d7a80a-0000-4000-8000-000000000391'::uuid, null, 'rosca sentada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e um haltere em cada mão, com as palmas voltadas para a frente. Mantenha as costas retas e os cotovelos próximos ao tronco. Expire e levante os halteres em direção aos ombros, contraindo os bíceps. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0391.gif', 'hasaneyldrm', '0391'),
  ('b1d7a80a-0000-4000-8000-000000000392'::uuid, null, 'elevação frontal sentada com halteres', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'biceps']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e um haltere em cada mão, apoiado nas coxas. Mantenha as costas retas e o núcleo engajado. Levante os halteres à sua frente, com as palmas voltadas para baixo, até que fiquem na altura dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0392.gif', 'hasaneyldrm', '0392'),
  ('b1d7a80a-0000-4000-8000-000000001678'::uuid, null, 'rosca direta com martelo sentado com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com um haltere em cada mão, as palmas voltadas para o tronco e os braços estendidos para baixo. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1678.gif', 'hasaneyldrm', '1678'),
  ('b1d7a80a-0000-4000-8000-000000000393'::uuid, null, 'rosca interna do bíceps sentada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão, com as palmas voltadas para cima. Descanse os braços nas coxas, permitindo que os halteres fiquem pendurados. Mantendo os braços parados, enrole os halteres em direção aos ombros, contraindo os bíceps. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0393.gif', 'hasaneyldrm', '0393'),
  ('b1d7a80a-0000-4000-8000-000000000394'::uuid, null, 'recuo sentado com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente a partir dos quadris, mantendo as costas retas. Aproxime os braços ao lado do corpo e mantenha os cotovelos dobrados em um ângulo de 90 graus. Estenda os braços para trás, apertando o tríceps no topo do movimento. Faça uma pausa por um momento e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0394.gif', 'hasaneyldrm', '0394'),
  ('b1d7a80a-0000-4000-8000-000000000396'::uuid, null, 'elevação lateral sentada com halteres', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'upper back']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e um haltere em cada mão, apoiado nas coxas. Mantenha as costas retas e o núcleo engajado. Levante os halteres para os lados com uma ligeira flexão dos cotovelos, até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0396.gif', 'hasaneyldrm', '0396'),
  ('b1d7a80a-0000-4000-8000-000000000395'::uuid, null, 'elevação lateral sentada com halteres v. 2', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'triceps']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e um haltere em cada mão, apoiado nas coxas. Mantenha as costas retas e o núcleo engajado. Levante os halteres para os lados com uma ligeira flexão dos cotovelos, até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0395.gif', 'hasaneyldrm', '0395'),
  ('b1d7a80a-0000-4000-8000-000000000397'::uuid, null, 'flexão de pulso neutra sentada com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão, com as palmas voltadas uma para a outra. Descanse os antebraços nas coxas, permitindo que os halteres fiquem pendurados. Mantendo os pulsos em uma posição neutra, levante os halteres em direção aos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0397.gif', 'hasaneyldrm', '0397'),
  ('b1d7a80a-0000-4000-8000-000000001679'::uuid, null, 'rosca direta de bíceps com um braço sentado com halteres na bola de exercícios com a perna levantada', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', true, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos, com a palma voltada para cima e o braço totalmente estendido. Coloque a outra mão no quadril para obter estabilidade. Enrole lentamente o haltere em direção ao ombro, mantendo o braço parado. Faça uma pausa no início do movimento, apertando o bíceps. Abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições. Troque de braço e repita o exercício.', '/exercise-media/bstrainer/1679.gif', 'hasaneyldrm', '1679'),
  ('b1d7a80a-0000-4000-8000-000000000398'::uuid, null, 'haltere sentado com recuo de um braço', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em uma das mãos. Dobre o tronco para a frente na altura da cintura, mantendo as costas retas e paralelas ao chão. Estenda o braço para trás, mantendo o cotovelo próximo ao corpo. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0398.gif', 'hasaneyldrm', '0398'),
  ('b1d7a80a-0000-4000-8000-000000000399'::uuid, null, 'haltere sentado com um braço girado', 'isolation', ARRAY['forearms', 'shoulders']::text[], ARRAY['shoulders', 'biceps']::text[], 'dumbbell', true, 'Sente-se em um banco com as costas retas e segure um haltere em uma das mãos, apoiando-o na coxa. Levante o haltere até a altura dos ombros, mantendo o cotovelo próximo ao corpo. Gire o antebraço para fora, longe do corpo, enquanto mantém o braço parado. Faça uma pausa no topo e gire lentamente o antebraço de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0399.gif', 'hasaneyldrm', '0399'),
  ('b1d7a80a-0000-4000-8000-000000000400'::uuid, null, 'levantamento de panturrilha unipodal sentado com halteres', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'dumbbell', true, 'Sente-se em um banco ou cadeira com os pés apoiados no chão e um haltere apoiado na coxa direita. Estenda a perna esquerda à sua frente, mantendo o pé flexionado. Coloque a planta do pé direito em uma superfície elevada, como um degrau ou plataforma de peso. Usando os músculos da panturrilha, levante o calcanhar direito o mais alto possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0400.gif', 'hasaneyldrm', '0400'),
  ('b1d7a80a-0000-4000-8000-000000001380'::uuid, null, 'levantamento de panturrilha unipodal sentado com halteres - pegada de martelo', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'dumbbell', true, 'Sente-se em um banco ou cadeira com os pés apoiados no chão e um haltere apoiado nas coxas. Coloque um pé em uma superfície elevada, como um degrau ou bloco, com o calcanhar pendurado na borda. Segure o haltere com um punho de martelo, o que significa que as palmas das mãos ficam voltadas uma para a outra e os dedos envolvem o cabo. Mantendo o núcleo engajado e as costas retas, levante lentamente o calcanhar o mais alto possível, empurrando a planta do pé. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita o número desejado de repetições e depois mude para a outra perna.', '/exercise-media/bstrainer/1380.gif', 'hasaneyldrm', '1380'),
  ('b1d7a80a-0000-4000-8000-000000001381'::uuid, null, 'levantamento de panturrilha unipodal sentado com halteres - palma para cima', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'dumbbell', true, 'Sente-se em um banco ou cadeira com as costas retas e os pés apoiados no chão. Segure um haltere com uma das mãos e coloque-o em cima da coxa, com a palma voltada para cima. Levante uma perna do chão e estenda-a à sua frente, mantendo o joelho ligeiramente dobrado. Levante o calcanhar o mais alto possível, empurrando a planta do pé. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1381.gif', 'hasaneyldrm', '1381'),
  ('b1d7a80a-0000-4000-8000-000000000401'::uuid, null, 'haltere sentado palmas para cima curvatura do pulso', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em cada mão, com as palmas voltadas para cima. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados na borda. Enrole lentamente os pulsos para cima, apertando os antebraços no início do movimento. Faça uma pausa por um momento e depois abaixe os pulsos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0401.gif', 'hasaneyldrm', '0401'),
  ('b1d7a80a-0000-4000-8000-000000000402'::uuid, null, 'rosca direta de pregador sentado com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco de pregador com os pés apoiados no chão. Segure um haltere em uma mão com uma pegada por baixo, apoiando o braço contra a almofada do pregador. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro. Faça uma pausa por um momento no topo, inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0402.gif', 'hasaneyldrm', '0402'),
  ('b1d7a80a-0000-4000-8000-000000000403'::uuid, null, 'halteres sentados com pegada reversa e concentração de curvatura', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure um haltere em uma das mãos, com a palma voltada para cima. Descanse o cotovelo na parte interna da coxa, logo acima do joelho. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0403.gif', 'hasaneyldrm', '0403'),
  ('b1d7a80a-0000-4000-8000-000000001738'::uuid, null, 'haltere sentado com pegada reversa extensão de tríceps com um braço acima da cabeça', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere com uma pegada supinada e estenda o braço acima da cabeça. Abaixe o haltere atrás da cabeça dobrando o cotovelo, mantendo o braço parado. Faça uma pausa por um momento e depois estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1738.gif', 'hasaneyldrm', '1738'),
  ('b1d7a80a-0000-4000-8000-000000000405'::uuid, null, 'desenvolvimento de ombros sentado com halteres', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', false, 'Sente-se em um banco com um haltere em cada mão, apoiado nas coxas. Levante os halteres até a altura dos ombros, com as palmas voltadas para a frente. Pressione os halteres para cima até que seus braços estejam totalmente estendidos acima da cabeça. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0405.gif', 'hasaneyldrm', '0405'),
  ('b1d7a80a-0000-4000-8000-000000000404'::uuid, null, 'desenvolvimento de ombros sentado com halteres (pega paralela)', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', false, 'Sente-se em um banco com um haltere em cada mão, com as palmas voltadas para dentro. Levante os halteres até a altura dos ombros, cotovelos dobrados e palmas das mãos voltadas para frente. Pressione os halteres para cima até que seus braços estejam totalmente estendidos acima da cabeça. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0404.gif', 'hasaneyldrm', '0404'),
  ('b1d7a80a-0000-4000-8000-000000002188'::uuid, null, 'extensão de tríceps sentado com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere com as duas mãos e estenda os braços acima da cabeça. Dobre os cotovelos e abaixe o haltere atrás da cabeça, mantendo os braços próximos às orelhas. Faça uma pausa, depois estique os braços e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2188.gif', 'hasaneyldrm', '2188'),
  ('b1d7a80a-0000-4000-8000-000000000406'::uuid, null, 'encolher de ombros com halteres', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão com as palmas voltadas para o corpo. Mantenha os braços retos e deixe os halteres pendurados ao lado do corpo. Levante os ombros o mais alto possível, como se estivesse tentando tocar as orelhas com os ombros. Mantenha a contração por um segundo e, em seguida, abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0406.gif', 'hasaneyldrm', '0406'),
  ('b1d7a80a-0000-4000-8000-000000000407'::uuid, null, 'flexão lateral com halteres', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'dumbbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure um haltere em uma das mãos, deixando-o pendurado ao seu lado. Mantendo as costas retas e o núcleo engajado, incline-se lentamente para o lado na cintura em direção ao lado oposto do haltere, abaixando o peso o máximo que puder confortavelmente. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições, depois troque de lado e repita.', '/exercise-media/bstrainer/0407.gif', 'hasaneyldrm', '0407'),
  ('b1d7a80a-0000-4000-8000-000000000408'::uuid, null, 'lado do haltere deitado com uma mão levantada', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'dumbbell', false, 'Deite-se de lado com as pernas estendidas e a cabeça apoiada no braço. Segure um haltere na mão de cima com a palma voltada para baixo. Mantendo o braço reto, levante o haltere até a altura dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0408.gif', 'hasaneyldrm', '0408'),
  ('b1d7a80a-0000-4000-8000-000000003664'::uuid, null, 'prancha lateral com halteres com mosca traseira', 'push_h', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'dumbbell', false, 'Comece deitando-se de lado com as pernas estendidas e empilhadas uma sobre a outra. Coloque o antebraço no chão, diretamente abaixo do ombro, mantendo o cotovelo dobrado em um ângulo de 90 graus. Segure um haltere na mão de cima, com o braço estendido em direção ao chão. Envolva o núcleo e levante os quadris do chão, criando uma linha reta da cabeça aos calcanhares. Mantendo a posição da prancha lateral, levante o haltere em direção ao teto, apertando as omoplatas. Abaixe o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/3664.gif', 'hasaneyldrm', '3664'),
  ('b1d7a80a-0000-4000-8000-000000003548'::uuid, null, 'haltere com braço único para carregar acima da cabeça', 'push_v', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'core']::text[], 'dumbbell', true, 'Fique em pé, com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos. Levante o haltere acima da cabeça, estendendo totalmente o braço. Envolva seu núcleo e mantenha as costas retas enquanto caminha para frente, mantendo o haltere acima da cabeça. Continue caminhando pela distância ou tempo desejado. Troque de mãos e repita o exercício.', '/exercise-media/bstrainer/3548.gif', 'hasaneyldrm', '3548'),
  ('b1d7a80a-0000-4000-8000-000000000409'::uuid, null, 'elevação de panturrilha unipodal com halteres', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles']::text[], 'dumbbell', true, 'Fique na beira de um degrau ou plataforma com os calcanhares pendurados e os dedos dos pés no degrau. Segure um haltere com uma mão e coloque a outra mão em uma parede ou corrimão para se apoiar. Levante o calcanhar o mais alto possível, colocando o corpo na ponta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar abaixo do degrau. Repita o número desejado de repetições e depois mude para a outra perna.', '/exercise-media/bstrainer/0409.gif', 'hasaneyldrm', '0409'),
  ('b1d7a80a-0000-4000-8000-000000001757'::uuid, null, 'levantamento terra unipodal com halteres', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura do quadril, segurando um haltere na mão direita. Transfira o peso para a perna esquerda e levante ligeiramente o pé direito do chão. Mantendo as costas retas, incline-se para a frente na altura dos quadris e abaixe o haltere em direção ao chão. Ao mesmo tempo, estenda a perna direita para trás, mantendo uma ligeira flexão no joelho esquerdo. Abaixe o haltere até que o tronco e a perna direita fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, envolva os glúteos e isquiotibiais para retornar à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1757.gif', 'hasaneyldrm', '1757'),
  ('b1d7a80a-0000-4000-8000-000000002805'::uuid, null, 'Levantamento terra unipodal com halteres e suporte stepbox', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura do quadril, segurando um haltere na mão direita. Coloque o pé esquerdo em um degrau ou superfície elevada atrás de você. Mantendo as costas retas e o núcleo engajado, incline-se para a frente na altura dos quadris, abaixando o haltere em direção ao chão. Ao abaixar o haltere, levante simultaneamente a perna esquerda atrás de você, mantendo uma linha reta da cabeça aos calcanhares. Abaixe o haltere até sentir um alongamento no tendão direito e depois retorne à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/2805.gif', 'hasaneyldrm', '2805'),
  ('b1d7a80a-0000-4000-8000-000000000410'::uuid, null, 'Agachamento dividido com uma perna com halteres', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Dê um passo à frente com um pé e posicione-os de forma que o pé da frente fique apoiado no chão e o pé de trás elevado em um banco ou degrau. Abaixe o corpo dobrando o joelho da frente e o quadril, mantendo o joelho de trás levemente flexionado e o calcanhar de trás fora do chão. Continue abaixando até que a coxa da frente fique paralela ao chão e, em seguida, empurre o calcanhar da frente para retornar à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/0410.gif', 'hasaneyldrm', '0410'),
  ('b1d7a80a-0000-4000-8000-000000000411'::uuid, null, 'agachamento unilateral com halteres', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Estenda uma perna para a frente e mantenha-a fora do chão durante todo o exercício. Dobre a perna de apoio e abaixe o corpo como se estivesse sentado em uma cadeira. Mantenha o peito erguido e as costas retas. Faça uma pausa por um momento na parte inferior e empurre o calcanhar para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0411.gif', 'hasaneyldrm', '0411'),
  ('b1d7a80a-0000-4000-8000-000000000413'::uuid, null, 'agachamento com halteres', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão ao lado do corpo. Mantendo o peito para cima e o núcleo engajado, abaixe o corpo dobrando os joelhos e os quadris, como se estivesse sentado em uma cadeira. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0413.gif', 'hasaneyldrm', '0413'),
  ('b1d7a80a-0000-4000-8000-000000003560'::uuid, null, 'halteres em pé alternam rosca direta e pressão com martelo', 'push_h', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', true, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o corpo. Mantenha os cotovelos próximos ao tronco e as costas retas. Expire e enrole o haltere da mão direita em direção ao ombro, mantendo o braço parado. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita a curvatura com a mão esquerda. Depois de completar a rosca direta com a mão esquerda, expire e pressione o haltere com a mão direita acima da cabeça. Estenda totalmente o braço e segure por um momento no topo. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita a pressão com a mão esquerda. Continue alternando entre cachos e pressões até o número desejado de repetições.', '/exercise-media/bstrainer/3560.gif', 'hasaneyldrm', '3560'),
  ('b1d7a80a-0000-4000-8000-000000000414'::uuid, null, 'haltere em pé supino alternado', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros, com as palmas voltadas para a frente. Pressione um haltere acima da cabeça, estendendo totalmente o braço. Abaixe o haltere de volta ao nível dos ombros. Repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0414.gif', 'hasaneyldrm', '0414'),
  ('b1d7a80a-0000-4000-8000-000000000415'::uuid, null, 'elevação alternada com halteres em pé', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'forearms']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para o corpo. Mantenha as costas retas e o núcleo engajado. Levante um haltere para o lado, mantendo o braço reto e a palma da mão voltada para baixo. Continue levantando até que seu braço fique paralelo ao chão. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita com o outro braço. Alterne entre os braços para o número desejado de repetições.', '/exercise-media/bstrainer/0415.gif', 'hasaneyldrm', '0415'),
  ('b1d7a80a-0000-4000-8000-000000001739'::uuid, null, 'halteres em pé alternando retrocesso de tríceps', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Estenda os braços para trás, mantendo os cotovelos próximos ao corpo. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita com o outro braço, alternando os lados a cada repetição.', '/exercise-media/bstrainer/1739.gif', 'hasaneyldrm', '1739'),
  ('b1d7a80a-0000-4000-8000-000000002143'::uuid, null, 'haltere em pé ao redor do mundo', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Estenda os braços para os lados, na altura dos ombros, com as palmas voltadas para baixo. Mantendo os braços retos, gire-os lentamente em movimentos circulares, colocando os halteres na frente do corpo e depois acima da cabeça. Continue o movimento circular, trazendo os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2143.gif', 'hasaneyldrm', '2143'),
  ('b1d7a80a-0000-4000-8000-000000001740'::uuid, null, 'haltere em pé curvado sobre extensão de tríceps com um braço', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos. Incline-se para a frente na cintura, mantendo as costas retas e paralelas ao chão. Estenda o braço para trás, mantendo o cotovelo próximo ao corpo. Abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1740.gif', 'hasaneyldrm', '1740'),
  ('b1d7a80a-0000-4000-8000-000000001741'::uuid, null, 'haltere em pé curvado sobre extensão de tríceps com dois braços', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Incline-se para a frente na cintura, mantendo as costas retas e os joelhos ligeiramente flexionados. Estenda os braços para trás, mantendo os cotovelos próximos ao corpo. Abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1741.gif', 'hasaneyldrm', '1741'),
  ('b1d7a80a-0000-4000-8000-000000000416'::uuid, null, 'rosca bíceps em pé com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, as palmas voltadas para a frente e os braços totalmente estendidos. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0416.gif', 'hasaneyldrm', '0416'),
  ('b1d7a80a-0000-4000-8000-000000000417'::uuid, null, 'panturrilha em pé com halteres', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão. Levante os calcanhares do chão o mais alto possível, usando as panturrilhas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0417.gif', 'hasaneyldrm', '0417'),
  ('b1d7a80a-0000-4000-8000-000000000418'::uuid, null, 'ondulação de concentração com halteres em pé', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos, com o braço totalmente estendido e a palma voltada para dentro. Coloque a mão oposta na coxa para apoio. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro, contraindo o bíceps. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0418.gif', 'hasaneyldrm', '0418'),
  ('b1d7a80a-0000-4000-8000-000000000419'::uuid, null, 'levantamento frontal com halteres acima da cabeça', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'biceps']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Mantenha os braços retos e levante os halteres à sua frente, elevando-os acima da cabeça. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0419.gif', 'hasaneyldrm', '0419'),
  ('b1d7a80a-0000-4000-8000-000000002321'::uuid, null, 'rosca interna do bíceps em pé com halteres v. 2', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o tronco. Mantenha os cotovelos próximos ao tronco e gire as palmas das mãos até que fiquem voltadas para frente. Enquanto mantém os braços parados, enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Lentamente, comece a trazer os halteres de volta à posição inicial enquanto inspira. Repita pela quantidade recomendada de repetições.', '/exercise-media/bstrainer/2321.gif', 'hasaneyldrm', '2321'),
  ('b1d7a80a-0000-4000-8000-000000000420'::uuid, null, 'retrocesso com halteres em pé', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Estenda os braços para trás, apertando o tríceps no topo do movimento. Faça uma pausa por um momento e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0420.gif', 'hasaneyldrm', '0420'),
  ('b1d7a80a-0000-4000-8000-000000000421'::uuid, null, 'rosca direta com halteres em pé com um braço', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé, com os pés afastados na largura dos ombros e segure um haltere em uma das mãos, com a palma voltada para cima. Coloque a mão livre na coxa para apoio. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro, contraindo o bíceps. Continue a levantar o haltere até que os bíceps estejam totalmente contraídos e o haltere esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0421.gif', 'hasaneyldrm', '0421'),
  ('b1d7a80a-0000-4000-8000-000000000422'::uuid, null, 'haltere em pé com flexão de braço (sobre banco inclinado)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos com a palma voltada para frente. Coloque a outra mão em um banco inclinado para apoio. Mantendo o braço parado, expire e enrole o haltere em direção ao ombro, contraindo o bíceps. Faça uma pausa no topo, inspire e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/0422.gif', 'hasaneyldrm', '0422'),
  ('b1d7a80a-0000-4000-8000-000000001680'::uuid, null, 'haltere em pé com um braço flexionado sobre banco inclinado', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos. Coloque a outra mão em um banco inclinado para apoio. Mantendo o braço parado, enrole o haltere em direção ao ombro, contraindo o bíceps. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1680.gif', 'hasaneyldrm', '1680'),
  ('b1d7a80a-0000-4000-8000-000000000423'::uuid, null, 'haltere em pé com extensão de um braço', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos. Levante o haltere acima da cabeça, estendendo totalmente o braço. Mantenha o braço próximo à cabeça e perpendicular ao chão. Abaixe lentamente o haltere atrás da cabeça, dobrando o cotovelo. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0423.gif', 'hasaneyldrm', '0423'),
  ('b1d7a80a-0000-4000-8000-000000000424'::uuid, null, 'haltere em pé com um braço e palma na imprensa', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em uma das mãos na altura dos ombros, com a palma voltada para dentro. Envolva seu núcleo e mantenha as costas retas. Pressione o haltere para cima até que seu braço esteja totalmente estendido. Faça uma pausa no topo e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0424.gif', 'hasaneyldrm', '0424'),
  ('b1d7a80a-0000-4000-8000-000000000425'::uuid, null, 'halteres em pé com um braço rosca reversa', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', true, 'Fique em pé, com os pés afastados na largura dos ombros e segure um haltere em uma das mãos com uma pegada pronada. Mantenha o braço totalmente estendido e próximo ao corpo, com a palma da mão voltada para baixo. Enrole lentamente o haltere em direção ao ombro, mantendo o braço parado. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0425.gif', 'hasaneyldrm', '0425'),
  ('b1d7a80a-0000-4000-8000-000000000426'::uuid, null, 'supino com halteres em pé', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros, com as palmas voltadas para a frente. Pressione os halteres para cima até que seus braços estejam totalmente estendidos acima da cabeça. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0426.gif', 'hasaneyldrm', '0426'),
  ('b1d7a80a-0000-4000-8000-000000000427'::uuid, null, 'halteres em pé com as palmas das mãos na imprensa', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão na altura dos ombros, com as palmas voltadas para dentro. Mantendo o núcleo engajado e as costas retas, pressione os halteres para cima até que os braços estejam totalmente estendidos acima da cabeça. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0427.gif', 'hasaneyldrm', '0427'),
  ('b1d7a80a-0000-4000-8000-000000000428'::uuid, null, 'curl de pregador em pé com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para a frente. Descanse a parte de trás dos braços contra o banco do pregador ou um banco inclinado, com os cotovelos ligeiramente dobrados. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os halteres até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0428.gif', 'hasaneyldrm', '0428'),
  ('b1d7a80a-0000-4000-8000-000000000429'::uuid, null, 'rosca reversa em pé com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para o corpo. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar os pesos até que os bíceps estejam totalmente contraídos e os halteres estejam na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0429.gif', 'hasaneyldrm', '0429'),
  ('b1d7a80a-0000-4000-8000-000000000430'::uuid, null, 'extensão de tríceps em pé com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos. Levante o haltere acima da cabeça, mantendo o braço reto. Dobre o cotovelo e abaixe o haltere atrás da cabeça, mantendo o braço parado. Estenda o braço de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0430.gif', 'hasaneyldrm', '0430'),
  ('b1d7a80a-0000-4000-8000-000000002293'::uuid, null, 'haltere em pé zottman pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para a frente. Coloque os braços contra o banco do pregador e mantenha os cotovelos ligeiramente dobrados. Enrole os halteres em direção aos ombros, mantendo os braços parados. No início do movimento, gire os pulsos de forma que as palmas fiquem voltadas para baixo. Abaixe lentamente os halteres de volta à posição inicial, girando os pulsos de volta à posição inicial também. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2293.gif', 'hasaneyldrm', '2293'),
  ('b1d7a80a-0000-4000-8000-000000001684'::uuid, null, 'halteres intensificam o equilíbrio de uma perna com rosca bíceps', 'isolation', ARRAY['biceps', 'quadriceps']::text[], ARRAY['quadriceps', 'glutes', 'hamstrings']::text[], 'dumbbell', true, 'Fique na frente de um degrau ou plataforma com um haltere em cada mão, com as palmas voltadas para o corpo. Coloque o pé direito no degrau, garantindo que todo o pé esteja em contato com a superfície. Envolva o núcleo e empurre o calcanhar direito para levantar o corpo no degrau, trazendo o joelho esquerdo em direção ao peito. No topo do movimento, faça uma rosca bíceps dobrando os cotovelos e trazendo os halteres em direção aos ombros. Abaixe os halteres e simultaneamente abaixe o pé esquerdo de volta ao chão. Repita o movimento do lado oposto, subindo com o pé esquerdo e enrolando os halteres. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1684.gif', 'hasaneyldrm', '1684'),
  ('b1d7a80a-0000-4000-8000-000000000431'::uuid, null, 'step-up com halteres', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique na frente de um banco ou pise com um haltere em cada mão, com as palmas voltadas para o corpo. Coloque o pé direito no banco ou degrau, garantindo que todo o pé esteja em contato com a superfície. Empurre o calcanhar direito e levante o corpo sobre o banco ou degrau, esticando a perna direita. Coloque o pé esquerdo no banco ou degrau, ficando totalmente ereto. Desça com o pé esquerdo, seguido pelo pé direito, retornando à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0431.gif', 'hasaneyldrm', '0431'),
  ('b1d7a80a-0000-4000-8000-000000002796'::uuid, null, 'estocada com halteres', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique na frente de um degrau ou plataforma com um haltere em cada mão, com as palmas voltadas para os lados. Coloque o pé direito no degrau, garantindo que todo o pé esteja na superfície. Empurre o calcanhar direito e levante o corpo até o degrau, levantando também o pé esquerdo. Quando ambos os pés estiverem no degrau, abaixe o pé esquerdo de volta à posição inicial, mantendo o pé direito no degrau. Repita o movimento, alternando o pé com o qual você pisa a cada vez. Continue pelo número desejado de repetições.', '/exercise-media/bstrainer/2796.gif', 'hasaneyldrm', '2796'),
  ('b1d7a80a-0000-4000-8000-000000002812'::uuid, null, 'Agachamento dividido com halteres', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique na frente de um banco ou pise com um haltere em cada mão, com as palmas voltadas para o corpo. Coloque o pé direito no banco ou degrau, garantindo que todo o pé esteja em contato com a superfície. Suba no banco ou pise com o pé direito, empurrando o calcanhar para levantar o corpo. Ao subir, levante simultaneamente o joelho esquerdo em direção ao peito. Faça uma pausa no início do movimento e abaixe lentamente o pé esquerdo de volta ao chão, mantendo o pé direito no banco ou degrau. Repita o movimento com o pé esquerdo no banco ou degrau. Continue alternando entre o pé direito e esquerdo pelo número desejado de repetições.', '/exercise-media/bstrainer/2812.gif', 'hasaneyldrm', '2812'),
  ('b1d7a80a-0000-4000-8000-000000000432'::uuid, null, 'levantamento terra com perna rígida com halteres', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Mantendo as costas retas e o núcleo engajado, dobre os quadris e abaixe os halteres em direção ao chão, permitindo uma ligeira flexão dos joelhos. Abaixe os halteres até sentir um alongamento nos isquiotibiais, depois contraia os glúteos e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0432.gif', 'hasaneyldrm', '0432'),
  ('b1d7a80a-0000-4000-8000-000000000433'::uuid, null, 'pulôver com halteres e braço reto', 'isolation', ARRAY['pectorals', 'latissimus dorsi']::text[], ARRAY['latissimus dorsi', 'triceps']::text[], 'dumbbell', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés firmemente plantados no chão. Segure um haltere com as duas mãos e estenda os braços acima do peito. Mantendo os braços retos, abaixe lentamente o haltere atrás da cabeça em um movimento em arco. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0433.gif', 'hasaneyldrm', '0433'),
  ('b1d7a80a-0000-4000-8000-000000000434'::uuid, null, 'levantamento terra com halteres com perna reta', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Mantendo as costas retas e o núcleo engajado, dobre os quadris e abaixe os halteres em direção ao chão, permitindo que o tronco se incline para a frente. Continue abaixando os halteres até sentir um alongamento nos isquiotibiais, mantendo os joelhos ligeiramente flexionados. Faça uma pausa por um momento na parte inferior e, em seguida, envolva os glúteos e isquiotibiais para levantar o tronco de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0434.gif', 'hasaneyldrm', '0434'),
  ('b1d7a80a-0000-4000-8000-000000002808'::uuid, null, 'levantamento de sumô com halteres', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'core']::text[], 'dumbbell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros e os dedos apontados para fora. Segure um haltere com as duas mãos na frente do corpo e os braços estendidos. Dobre os joelhos e abaixe os quadris até uma posição de agachamento, mantendo as costas retas. Abaixe o haltere entre as pernas, mantendo os braços retos. Passe pelos calcanhares e estenda os quadris para a frente, puxando o haltere para cima e na frente do corpo. Contraia os glúteos no início do movimento e, em seguida, abaixe o haltere entre as pernas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2808.gif', 'hasaneyldrm', '2808'),
  ('b1d7a80a-0000-4000-8000-000000002803'::uuid, null, 'Agachamento apoiado com halteres', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão ao lado do corpo. Mantendo o peito para cima e o núcleo engajado, abaixe lentamente o corpo dobrando os joelhos e empurrando os quadris para trás. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2803.gif', 'hasaneyldrm', '2803'),
  ('b1d7a80a-0000-4000-8000-000000000436'::uuid, null, 'halteres tate press', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco plano com um haltere em cada mão, com as palmas voltadas uma para a outra. Levante os halteres até a altura dos ombros e gire os pulsos de modo que as palmas das mãos fiquem voltadas para longe de você. Pressione os halteres para cima até que os braços estejam totalmente estendidos e, em seguida, abaixe-os novamente até a altura dos ombros. Gire os pulsos de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0436.gif', 'hasaneyldrm', '0436'),
  ('b1d7a80a-0000-4000-8000-000000001742'::uuid, null, 'retrocesso de tríceps com halteres com postura de cegonha', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere na mão direita. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Traga o cotovelo direito para o lado, mantendo-o dobrado em um ângulo de 90 graus. Estenda o braço direito para trás, apertando o tríceps. Faça uma pausa por um momento e abaixe lentamente o haltere de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1742.gif', 'hasaneyldrm', '1742'),
  ('b1d7a80a-0000-4000-8000-000000001743'::uuid, null, 'supino com torção com halteres', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure um haltere em cada mão com uma pegada pronada, com as palmas voltadas para longe de você. Estenda os braços sobre o peito, mantendo uma ligeira flexão nos cotovelos. Abaixe os halteres em direção ao peito, mantendo os cotovelos próximos ao corpo. Ao abaixar os halteres, gire os pulsos de modo que as palmas das mãos fiquem voltadas para você na parte inferior do movimento. Faça uma pausa na parte inferior e, em seguida, inverta o movimento pressionando os halteres de volta à posição inicial. Ao pressionar os halteres para cima, gire os pulsos de volta à posição inicial, com as palmas voltadas para longe de você. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1743.gif', 'hasaneyldrm', '1743'),
  ('b1d7a80a-0000-4000-8000-000000000437'::uuid, null, 'remada vertical com halteres', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Deixe os halteres pendurados na frente das coxas, com os braços totalmente estendidos. Mantendo as costas retas e o núcleo engajado, expire e levante os halteres em direção ao queixo, conduzindo com os cotovelos. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0437.gif', 'hasaneyldrm', '0437'),
  ('b1d7a80a-0000-4000-8000-000000001765'::uuid, null, 'remada vertical com halteres (ponto de vista traseiro)', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com uma pegada pronada. Deixe os halteres pendurados na frente das coxas, com os braços totalmente estendidos e as palmas voltadas para o corpo. Mantendo as costas retas e o núcleo engajado, expire e levante os halteres em direção ao queixo, conduzindo com os cotovelos. Continue levantando até que os halteres estejam na altura dos ombros, com os cotovelos apontando para os lados. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1765.gif', 'hasaneyldrm', '1765'),
  ('b1d7a80a-0000-4000-8000-000000000864'::uuid, null, 'rotação externa do ombro vertical com halteres', 'isolation', ARRAY['delts', 'rotator cuff']::text[], ARRAY['rotator cuff', 'trapezius']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão com as palmas voltadas para o corpo. Levante os braços para os lados até ficarem paralelos ao chão, mantendo os cotovelos ligeiramente dobrados. Gire os braços externamente, trazendo os halteres em direção à cabeça enquanto mantém os cotovelos na mesma posição. Faça uma pausa no topo e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0864.gif', 'hasaneyldrm', '0864'),
  ('b1d7a80a-0000-4000-8000-000000005201'::uuid, null, 'rosca direta de bíceps com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para a frente. Mantenha os braços próximos ao corpo e os cotovelos dobrados. Lentamente, enrole os halteres em direção aos ombros, mantendo os pulsos retos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/5201.gif', 'hasaneyldrm', '5201'),
  ('b1d7a80a-0000-4000-8000-000000000438'::uuid, null, 'haltere w-press', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'dumbbell', false, 'Sente-se em um banco com um haltere em cada mão, com as palmas voltadas para frente. Levante os halteres até a altura dos ombros, cotovelos dobrados e palmas das mãos voltadas para frente. Pressione os halteres para cima até que seus braços estejam totalmente estendidos acima da cabeça. Abaixe os halteres de volta à altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0438.gif', 'hasaneyldrm', '0438'),
  ('b1d7a80a-0000-4000-8000-000000000439'::uuid, null, 'rosca Zottman com halteres', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para o corpo. Mantenha os cotovelos próximos ao tronco e gire as palmas das mãos para frente. Enrole os halteres até os ombros, mantendo os braços parados. No início do movimento, gire os pulsos de forma que as palmas fiquem voltadas para longe do corpo. Abaixe lentamente os halteres de volta à posição inicial, girando as palmas das mãos de volta para o corpo. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0439.gif', 'hasaneyldrm', '0439'),
  ('b1d7a80a-0000-4000-8000-000000002294'::uuid, null, 'haltere zottman pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'dumbbell', false, 'Sente-se em um banco de pregador com um haltere em cada mão, as palmas voltadas para cima e os cotovelos apoiados na almofada. Enrole os halteres em direção aos ombros, mantendo os braços parados e as palmas das mãos voltadas para cima. No topo do cacho, gire os pulsos de forma que as palmas fiquem voltadas para baixo. Abaixe lentamente os halteres de volta à posição inicial, girando os pulsos de volta à posição inicial enquanto faz isso. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2294.gif', 'hasaneyldrm', '2294'),
  ('b1d7a80a-0000-4000-8000-000000002189'::uuid, null, 'extensão de tríceps sentado com halteres', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um haltere com as duas mãos com uma pegada pronada e levante-o acima da cabeça. Dobre os cotovelos e abaixe o haltere atrás da cabeça, mantendo os braços próximos às orelhas. Estenda os braços e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2189.gif', 'hasaneyldrm', '2189'),
  ('b1d7a80a-0000-4000-8000-000000001167'::uuid, null, 'alongamento dinâmico de tórax (masculino)', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Estenda os braços para os lados, paralelos ao chão. Lentamente, traga os braços para a frente, cruzando-os na frente do corpo. Sinta o alongamento dos músculos do peito. Mantenha o alongamento por 10 a 30 segundos. Retorne à posição inicial e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1167.gif', 'hasaneyldrm', '1167'),
  ('b1d7a80a-0000-4000-8000-000000003287'::uuid, null, 'cotovelos inclinados', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se na beira de um banco ou cadeira com as mãos segurando a borda próxima aos quadris. Deslize os quadris para a frente do banco e estique as pernas, mantendo os calcanhares no chão. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas próximas ao banco. Faça uma pausa por um momento na parte inferior e, em seguida, empurre as mãos para esticar os braços e levantar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3287.gif', 'hasaneyldrm', '3287'),
  ('b1d7a80a-0000-4000-8000-000000001772'::uuid, null, 'elevação de cotovelo - flexão reversa', 'push_h', ARRAY['upper back', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece deitando-se de bruços no chão, com as pernas estendidas e as mãos colocadas diretamente sob os ombros. Envolva o núcleo e pressione as palmas das mãos para levantar a parte superior do corpo do chão, mantendo os cotovelos próximos ao corpo. Faça uma pausa no topo por um momento, contraindo os músculos da parte superior das costas. Abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1772.gif', 'hasaneyldrm', '1772'),
  ('b1d7a80a-0000-4000-8000-000000000443'::uuid, null, 'cotovelo no joelho', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Comece deitando-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolva os abdominais e levante a parte superior do corpo do chão, aproximando o cotovelo direito do joelho esquerdo. Ao mesmo tempo, leve o joelho esquerdo em direção ao cotovelo direito, criando um movimento de torção. Faça uma pausa no topo, depois abaixe lentamente a parte superior do corpo e estenda as pernas de volta à posição inicial. Repita o movimento, desta vez trazendo o cotovelo esquerdo em direção ao joelho direito e o joelho direito em direção ao cotovelo esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0443.gif', 'hasaneyldrm', '0443'),
  ('b1d7a80a-0000-4000-8000-000000003292'::uuid, null, 'elevador', 'isolation', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'trapezius']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Coloque as mãos nos quadris ou cruze-as na frente do peito. Mantendo as costas retas, incline-se lentamente para a frente na cintura, abaixando a parte superior do corpo em direção ao chão. Faça uma pausa por um momento na parte inferior e, em seguida, levante lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3292.gif', 'hasaneyldrm', '3292'),
  ('b1d7a80a-0000-4000-8000-000000001332'::uuid, null, 'bola de exercícios braços alternados', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'machine', true, 'Sente-se na bola de estabilidade com os pés apoiados no chão e as costas retas. Segure um haltere em cada mão com as palmas voltadas para dentro e os braços estendidos ao lado do corpo. Envolva seu núcleo e levante lentamente um braço em direção ao ombro, mantendo o cotovelo ligeiramente dobrado. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o braço de volta à posição inicial. Repita o movimento com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/1332.gif', 'hasaneyldrm', '1332'),
  ('b1d7a80a-0000-4000-8000-000000001333'::uuid, null, 'extensão de costas com bola de exercício com braços estendidos', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e deite-se de bruços sobre ela, com os quadris apoiados na bola e os pés apoiados na parede para estabilidade. Estenda os braços à sua frente, com as palmas voltadas para baixo. Envolva o núcleo e levante lentamente a parte superior do corpo da bola, mantendo as costas retas e o pescoço alinhado com a coluna. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1333.gif', 'hasaneyldrm', '1333'),
  ('b1d7a80a-0000-4000-8000-000000001334'::uuid, null, 'exercício extensão de costas com bola com as mãos atrás da cabeça', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e deite-se de bruços sobre ela, com os quadris apoiados na bola. Posicione os pés contra uma parede ou outra superfície estável para apoio. Cruze os braços atrás da cabeça, com as mãos tocando a nuca. Envolva o núcleo e levante lentamente a parte superior do corpo da bola, estendendo as costas até que o corpo forme uma linha reta da cabeça aos quadris. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1334.gif', 'hasaneyldrm', '1334'),
  ('b1d7a80a-0000-4000-8000-000000001335'::uuid, null, 'exercício extensão de costas com bola com os joelhos fora do chão', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e deite-se de bruços sobre ela, com os quadris apoiados na bola e os pés apoiados na parede para estabilidade. Posicione as mãos atrás da cabeça ou cruzadas sobre o peito. Envolva o núcleo e levante lentamente a parte superior do corpo da bola, estendendo as costas até que o corpo forme uma linha reta da cabeça aos calcanhares. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1335.gif', 'hasaneyldrm', '1335'),
  ('b1d7a80a-0000-4000-8000-000000001336'::uuid, null, 'extensão de costas da bola de exercícios com rotação', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Comece deitando-se de bruços na bola de estabilidade, com os quadris apoiados na bola e os pés firmemente plantados no chão. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva o núcleo e levante lentamente a parte superior do corpo da bola, estendendo as costas até que o corpo forme uma linha reta da cabeça aos calcanhares. Faça uma pausa por um momento no topo e gire lentamente o tronco para o lado, mantendo os quadris e as pernas estáveis. Volte ao centro e repita a rotação para o outro lado. Abaixe a parte superior do corpo de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/1336.gif', 'hasaneyldrm', '1336'),
  ('b1d7a80a-0000-4000-8000-000000001744'::uuid, null, 'exercício de mergulho com bola', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Coloque as mãos na bola ao lado dos quadris, os dedos apontando para frente. Envolva o tríceps e empurre as mãos para levantar o corpo da bola, esticando os braços. Abaixe o corpo dobrando os cotovelos, mantendo-os próximos ao corpo. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1744.gif', 'hasaneyldrm', '1744'),
  ('b1d7a80a-0000-4000-8000-000000001559'::uuid, null, 'alongamento dos flexores do quadril com bola de exercícios', 'isolation', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e ajoelhe-se na frente dela. Coloque o pé direito em cima da bola de estabilidade, com o joelho dobrado em um ângulo de 90 graus. Estenda a perna esquerda atrás de você, mantendo-a reta. Incline-se para a frente, empurrando os quadris em direção à bola de estabilidade, até sentir um alongamento no flexor direito do quadril. Mantenha o alongamento por 20 a 30 segundos, depois troque de lado e repita.', '/exercise-media/bstrainer/1559.gif', 'hasaneyldrm', '1559'),
  ('b1d7a80a-0000-4000-8000-000000001338'::uuid, null, 'abraço de bola de exercício', 'isolation', ARRAY['spine', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e as costas retas. Segure a bola de estabilidade com as duas mãos, abraçando-a perto do peito. Envolva os músculos centrais e incline-se lentamente para trás, mantendo as costas retas e os pés plantados no chão. Continue inclinando-se para trás até sentir um alongamento nos músculos das costas. Mantenha a posição por alguns segundos e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1338.gif', 'hasaneyldrm', '1338'),
  ('b1d7a80a-0000-4000-8000-000000001339'::uuid, null, 'bola de exercício alongamento posterior', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos e estenda o braço acima da cabeça. Incline-se lentamente para o lado oposto, sentindo um alongamento no músculo posterior. Mantenha o alongamento por 20 a 30 segundos e depois retorne à posição inicial. Repita do outro lado.', '/exercise-media/bstrainer/1339.gif', 'hasaneyldrm', '1339'),
  ('b1d7a80a-0000-4000-8000-000000001341'::uuid, null, 'alongamento da região lombar com bola de exercícios (pirâmide)', 'isolation', ARRAY['lats', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Caminhe lentamente para a frente, rolando a bola pelas costas até que a parte inferior das costas esteja apoiada na bola. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva o núcleo e abaixe lentamente a parte superior do corpo em direção ao chão, permitindo que a parte inferior das costas se estique sobre a bola. Mantenha o alongamento por alguns segundos e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1341.gif', 'hasaneyldrm', '1341'),
  ('b1d7a80a-0000-4000-8000-000000001342'::uuid, null, 'bola de exercício deitado de lado alongamento lateral', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Deite-se de lado com as pernas estendidas e a cabeça apoiada na bola de estabilidade. Coloque o braço superior na bola para estabilidade. Alcance o braço superior acima da cabeça e permita que o tronco gire ligeiramente. Sinta o alongamento dos músculos posteriores na lateral do corpo. Mantenha o alongamento por 20 a 30 segundos, depois troque de lado e repita.', '/exercise-media/bstrainer/1342.gif', 'hasaneyldrm', '1342'),
  ('b1d7a80a-0000-4000-8000-000000001382'::uuid, null, 'bola de exercício na parede panturrilha', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'dumbbell', false, 'Fique de costas contra a parede e coloque uma bola de exercícios entre a parte inferior das costas e a parede. Posicione os pés na largura dos ombros, com os dedos apontando para a frente. Segure um haltere em cada mão, com os braços estendidos ao lado do corpo. Levante os calcanhares do chão, colocando o peso do corpo na planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1382.gif', 'hasaneyldrm', '1382'),
  ('b1d7a80a-0000-4000-8000-000000003241'::uuid, null, 'bola de exercício na parede panturrilha (bola de tênis entre tornozelos)', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'dumbbell', false, 'Fique de frente para uma parede com os pés afastados na largura dos ombros. Coloque uma bola de exercícios entre a parede e a parte inferior das costas. Segure um haltere em cada mão, com os braços estendidos ao lado do corpo. Coloque uma bola de tênis entre os tornozelos. Levante os calcanhares do chão, colocando o corpo na ponta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3241.gif', 'hasaneyldrm', '3241'),
  ('b1d7a80a-0000-4000-8000-000000003240'::uuid, null, 'bola de exercício na parede panturrilha (bola de tênis entre os joelhos)', 'isolation', ARRAY['calves', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings']::text[], 'dumbbell', false, 'Fique de costas contra a parede e coloque uma bola de exercícios entre a parte inferior das costas e a parede. Posicione os pés na largura dos ombros e ligeiramente à sua frente. Segure um haltere em cada mão, com os braços estendidos ao lado do corpo. Coloque uma bola de tênis entre os joelhos. Levante os calcanhares do chão, colocando o corpo na ponta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3240.gif', 'hasaneyldrm', '3240'),
  ('b1d7a80a-0000-4000-8000-000000001416'::uuid, null, 'bola de exercícios rotação da parte inferior do corpo em decúbito dorsal', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'core']::text[], 'machine', true, 'Deite-se de bruços na bola de estabilidade, com os quadris apoiados na bola e as pernas estendidas para trás. Coloque as mãos no chão à sua frente para obter apoio. Envolva os glúteos e os músculos centrais para estabilizar o corpo. Levante lentamente uma perna do chão, mantendo-a reta e paralela ao chão. Gire a perna para fora, longe do corpo, enquanto mantém os quadris e a parte superior do corpo estáveis. Faça uma pausa no final da rotação e retorne lentamente a perna à posição inicial. Repita a rotação com a outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/1416.gif', 'hasaneyldrm', '1416'),
  ('b1d7a80a-0000-4000-8000-000000001417'::uuid, null, 'bola de exercícios chute diagonal unipodal flexão dos isquiotibiais', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'calves']::text[], 'machine', true, 'Comece deitando-se de costas com as pernas estendidas e os calcanhares apoiados em cima da bola de estabilidade. Coloque os braços ao lado do corpo para estabilidade. Envolva os glúteos e os músculos centrais para levantar os quadris do chão, criando uma linha reta dos ombros aos calcanhares. Dobre o joelho direito e leve-o em direção ao peito, mantendo a perna esquerda estendida e o pé flexionado. Chute a perna direita diagonalmente ao longo do corpo, estendendo-a totalmente e envolvendo os isquiotibiais. Retorne lentamente a perna direita à posição inicial, mantendo o controle e a estabilidade. Repita o movimento com a perna esquerda, alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1417.gif', 'hasaneyldrm', '1417'),
  ('b1d7a80a-0000-4000-8000-000000001296'::uuid, null, 'bola de exercício pike push up', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'core']::text[], 'machine', false, 'Comece em uma posição de flexão com as mãos no chão e as canelas apoiadas na bola de estabilidade. Envolva seu núcleo e levante os quadris em direção ao teto, rolando a bola em direção às mãos. Mantenha as pernas retas e o corpo em posição de lança, formando um V invertido. Dobre os cotovelos e abaixe a parte superior do corpo em direção ao chão, mantendo a cabeça alinhada com as mãos. Empurre com as mãos e estenda os braços para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1296.gif', 'hasaneyldrm', '1296'),
  ('b1d7a80a-0000-4000-8000-000000001343'::uuid, null, 'bola de exercícios elevação da perna em decúbito ventral', 'isolation', ARRAY['spine', 'abdominals']::text[], ARRAY['abdominals', 'glutes']::text[], 'machine', true, 'Deite-se de bruços em um tapete com as pernas estendidas e os dedos dos pés apoiados em cima da bola de estabilidade. Coloque as mãos no chão, afastadas na largura dos ombros, e envolva os músculos centrais. Mantendo as pernas retas, levante-as lentamente do chão, usando a parte inferior das costas e os glúteos para levantá-las o mais alto possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1343.gif', 'hasaneyldrm', '1343'),
  ('b1d7a80a-0000-4000-8000-000000001560'::uuid, null, 'alongamento de isquiotibiais sentado com bola', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'lower back']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Role lentamente a bola para a frente, afastando os pés até que a parte superior das costas esteja apoiada na bola e as pernas estendidas à sua frente. Coloque as mãos nos quadris para apoio. Envolva o núcleo e abaixe lentamente a parte superior do corpo em direção ao chão, mantendo as costas retas e o peito levantado. Pare quando sentir um alongamento nos isquiotibiais e mantenha a posição por 20 a 30 segundos. Retorne lentamente à posição inicial empurrando os calcanhares e usando os isquiotibiais para se levantar. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1560.gif', 'hasaneyldrm', '1560'),
  ('b1d7a80a-0000-4000-8000-000000001745'::uuid, null, 'exercício de alongamento de tríceps sentado com bola', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e as costas retas. Segure um haltere com uma das mãos e estenda o braço acima da cabeça. Dobre o cotovelo e abaixe o haltere atrás da cabeça, mantendo o braço próximo à orelha. Mantenha o alongamento por alguns segundos e depois retorne à posição inicial. Repita com o outro braço.', '/exercise-media/bstrainer/1745.gif', 'hasaneyldrm', '1745'),
  ('b1d7a80a-0000-4000-8000-000000001746'::uuid, null, 'bola de exercício extensão de tríceps supino', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Sente-se em uma bola de exercícios com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure um haltere com as duas mãos e estenda os braços em direção ao teto. Abaixe lentamente o haltere atrás da cabeça, mantendo os cotovelos próximos às orelhas. Faça uma pausa e levante o haltere de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1746.gif', 'hasaneyldrm', '1746'),
  ('b1d7a80a-0000-4000-8000-000000001747'::uuid, null, 'ez bar imprensa francesa na bola de exercícios', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Sente-se em uma bola de exercícios e segure uma barra EZ com uma pegada pronada. Estenda os braços para cima, mantendo os cotovelos próximos à cabeça. Abaixe lentamente a barra atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1747.gif', 'hasaneyldrm', '1747'),
  ('b1d7a80a-0000-4000-8000-000000003010'::uuid, null, 'pulôver ez bar deitado com braços dobrados', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'machine', false, 'Deite-se em um banco com a cabeça apoiada em uma das extremidades e os pés no chão. Segure a barra EZ com uma pegada pronada (palmas voltadas para você) e as mãos na largura dos ombros. Estenda os braços acima do peito, mantendo uma ligeira flexão nos cotovelos. Abaixe a barra em um movimento de arco atrás da cabeça, mantendo a leve flexão dos cotovelos. Faça uma pausa por um momento e, em seguida, retorne a barra à posição inicial invertendo o movimento do arco. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3010.gif', 'hasaneyldrm', '3010'),
  ('b1d7a80a-0000-4000-8000-000000001748'::uuid, null, 'barra ez deitada extensão de tríceps com pegada fechada atrás da cabeça', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Deite-se em um banco com os pés apoiados no chão e a cabeça na ponta do banco. Segure a barra ez com força, com as palmas voltadas para cima, e estenda os braços sobre o peito. Mantendo os braços parados, abaixe lentamente a barra atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1748.gif', 'hasaneyldrm', '1748'),
  ('b1d7a80a-0000-4000-8000-000000001344'::uuid, null, 'barra ez empunhadura reversa dobrada sobre a linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra ez com uma pegada supinada, com as palmas voltadas para cima e as mãos na largura dos ombros. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito para cima, até que o tronco fique quase paralelo ao chão. Puxe a barra ez em direção à parte inferior do peito, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra ez de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1344.gif', 'hasaneyldrm', '1344'),
  ('b1d7a80a-0000-4000-8000-000000001682'::uuid, null, 'ez bar sentado perto aderência concentração curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Sente-se em um banco com os pés apoiados no chão e segure uma barra EZ com uma pegada por baixo. Descanse o cotovelo na parte interna da coxa, logo acima do joelho. Enrole a barra em direção ao ombro enquanto mantém o braço parado. Contraia o bíceps no início do movimento e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1682.gif', 'hasaneyldrm', '1682'),
  ('b1d7a80a-0000-4000-8000-000000001749'::uuid, null, 'ez bar em pé imprensa francesa', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra ez com uma pegada pronada. Levante a barra acima da cabeça, estendendo totalmente os braços. Mantendo os braços próximos à cabeça, abaixe lentamente a barra atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1749.gif', 'hasaneyldrm', '1749'),
  ('b1d7a80a-0000-4000-8000-000000000445'::uuid, null, 'ez barbell anti-gravidade', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'machine', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e segurando a barra ez com uma pegada pronada. Levante a barra até a altura dos ombros, mantendo os cotovelos levemente flexionados e as palmas das mãos voltadas para a frente. Pressione a barra acima da cabeça, estendendo totalmente os braços. Abaixe a barra de volta à altura dos ombros e repita o número desejado de repetições.', '/exercise-media/bstrainer/0445.gif', 'hasaneyldrm', '0445'),
  ('b1d7a80a-0000-4000-8000-000000001627'::uuid, null, 'ez barbell close grip pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Sente-se em um banco de pregador e coloque os braços na almofada, segurando a barra ez com uma pegada por baixo. Descanse o tríceps na almofada e estenda totalmente os braços, mantendo as costas retas. Enrole lentamente a barra em direção aos ombros, contraindo os bíceps. Faça uma pausa no topo, apertando o bíceps. Abaixe a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1627.gif', 'hasaneyldrm', '1627'),
  ('b1d7a80a-0000-4000-8000-000000000446'::uuid, null, 'ez barbell close-grip curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo, com as mãos afastadas na largura dos ombros. Mantenha os cotovelos próximos ao tronco e os braços parados durante todo o movimento. Enrole a barra em direção aos ombros, contraindo os bíceps. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0446.gif', 'hasaneyldrm', '0446'),
  ('b1d7a80a-0000-4000-8000-000000000447'::uuid, null, 'ez rosca direta', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo, com as palmas voltadas para cima. Mantenha os cotovelos próximos ao tronco e os braços parados durante todo o movimento. Expire enquanto enrola a barra em direção aos ombros, contraindo os bíceps. Faça uma pausa por um momento no topo e inspire enquanto abaixa lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0447.gif', 'hasaneyldrm', '0447'),
  ('b1d7a80a-0000-4000-8000-000000000448'::uuid, null, 'ez barbell declínio close grip face press', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os pés. Segure a barra ez com força, com as palmas voltadas uma para a outra. Estenda os braços acima do peito, mantendo os cotovelos próximos ao corpo. Abaixe a barra em direção à testa dobrando os cotovelos. Faça uma pausa por um momento e, em seguida, pressione a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0448.gif', 'hasaneyldrm', '0448'),
  ('b1d7a80a-0000-4000-8000-000000002186'::uuid, null, 'ez barra declínio extensão de tríceps', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Deite-se em um banco inclinado com a cabeça mais baixa que os pés e os pés protegidos. Segure a barra ez com uma pegada pronada, com as mãos na largura dos ombros. Estenda totalmente os braços, mantendo os cotovelos próximos à cabeça. Abaixe a barra lentamente em direção à testa, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2186.gif', 'hasaneyldrm', '2186'),
  ('b1d7a80a-0000-4000-8000-000000000449'::uuid, null, 'extensão de tríceps inclinada com barra ez', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Configure um banco inclinado em um ângulo de 45 graus. Sente-se no banco com as costas apoiadas na almofada e segure a barra ez com uma pegada pronada. Estenda os braços totalmente acima da cabeça, mantendo os cotovelos próximos à cabeça. Abaixe a barra atrás da cabeça dobrando os cotovelos, mantendo os braços parados. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0449.gif', 'hasaneyldrm', '0449'),
  ('b1d7a80a-0000-4000-8000-000000000450'::uuid, null, 'ez barbell jm supino', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra ez com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Abaixe a barra até o peito, mantendo os cotovelos próximos ao corpo. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0450.gif', 'hasaneyldrm', '0450'),
  ('b1d7a80a-0000-4000-8000-000000000451'::uuid, null, 'ez barra com aderência reversa curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo. Mantenha os cotovelos próximos ao tronco e os braços parados durante todo o exercício. Enrole a barra para cima contraindo o bíceps enquanto expira. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Lentamente, comece a trazer a barra de volta à posição inicial enquanto inspira. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0451.gif', 'hasaneyldrm', '0451'),
  ('b1d7a80a-0000-4000-8000-000000000452'::uuid, null, 'ez barbell aderência reversa pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Sente-se em um banco de pregador com o peito apoiado na almofada e os pés apoiados no chão. Segure a barra ez com uma pegada por baixo, com as mãos na largura dos ombros. Descanse os braços na almofada, permitindo que os antebraços fiquem pendurados. Mantendo os braços parados, expire e enrole a barra em direção aos ombros. Faça uma pausa por um momento no topo, inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0452.gif', 'hasaneyldrm', '0452'),
  ('b1d7a80a-0000-4000-8000-000000001458'::uuid, null, 'ez cachos sentados com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Sente-se em um banco com os pés apoiados no chão e as costas retas. Segure a barra ez com uma pegada supinada, com as palmas voltadas para cima e as mãos na largura dos ombros. Descanse os braços nas coxas, permitindo que a barra ez fique pendurada na sua frente. Mantendo os braços parados, expire e enrole a barra ez para cima, em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra ez de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1458.gif', 'hasaneyldrm', '1458'),
  ('b1d7a80a-0000-4000-8000-000000000453'::uuid, null, 'extensão de tríceps sentado com barra ez', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure a barra ez com uma pegada pronada, com as mãos na largura dos ombros. Levante a barra acima da cabeça, estendendo totalmente os braços. Mantendo os braços parados, abaixe a barra atrás da cabeça dobrando os cotovelos. Faça uma pausa e, em seguida, levante a barra de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0453.gif', 'hasaneyldrm', '0453'),
  ('b1d7a80a-0000-4000-8000-000000000454'::uuid, null, 'ez rosca aranha com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo, com as palmas voltadas para cima. Descanse os braços em um banco de pregador ou em uma bola de estabilidade, permitindo que os cotovelos fiquem pendurados. Mantendo os braços parados, expire e enrole a barra em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0454.gif', 'hasaneyldrm', '0454'),
  ('b1d7a80a-0000-4000-8000-000000001628'::uuid, null, 'ez rosca aranha com barra', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo, com as palmas voltadas para cima. Descanse os braços em um banco de pregador ou em uma bola de estabilidade, permitindo que os cotovelos fiquem pendurados. Mantendo os braços parados, expire e enrole a barra em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1628.gif', 'hasaneyldrm', '1628'),
  ('b1d7a80a-0000-4000-8000-000000002404'::uuid, null, 'rosca bíceps ez-bar (com arm blaster)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo, com as palmas voltadas para cima. Coloque os braços contra o blaster, mantendo-os parados durante todo o exercício. Mantendo os cotovelos próximos ao corpo, expire e enrole a barra em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2404.gif', 'hasaneyldrm', '2404'),
  ('b1d7a80a-0000-4000-8000-000000002432'::uuid, null, 'Supino com pegada fechada ez-bar', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Deite-se em um banco com os pés apoiados no chão e as costas pressionadas contra o banco. Segure a barra ez com força, com as mãos na largura dos ombros e as palmas voltadas para a frente. Levante a barra do rack e segure-a diretamente acima do peito, com os braços totalmente estendidos. Abaixe lentamente a barra em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2432.gif', 'hasaneyldrm', '2432'),
  ('b1d7a80a-0000-4000-8000-000000002741'::uuid, null, 'ez-barbell em pé com grande aderência para bíceps', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure a barra ez com uma pegada por baixo, com as mãos mais afastadas que a largura dos ombros. Mantenha os cotovelos próximos ao tronco e os braços parados durante todo o movimento. Enrole a barra em direção aos ombros, contraindo o bíceps. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2741.gif', 'hasaneyldrm', '2741'),
  ('b1d7a80a-0000-4000-8000-000000002133'::uuid, null, 'agricultores caminham', 'isolation', ARRAY['quads', 'calves']::text[], ARRAY['calves', 'forearms', 'core']::text[], 'dumbbell', false, 'Fique em pé com um haltere em cada mão, com as palmas voltadas para os lados. Mantenha as costas retas e os ombros para trás. Dê passos pequenos e controlados para frente, mantendo uma postura ereta. Continue caminhando pela distância ou tempo desejado. Para finalizar, pare de caminhar e abaixe cuidadosamente os halteres para os lados.', '/exercise-media/bstrainer/2133.gif', 'hasaneyldrm', '2133'),
  ('b1d7a80a-0000-4000-8000-000000000455'::uuid, null, 'cachos de dedo', 'isolation', ARRAY['forearms', 'wrist flexors']::text[], ARRAY['wrist flexors', 'grip muscles']::text[], 'barbell', false, 'Sente-se em um banco com os pés apoiados no chão e segure uma barra com uma pegada por baixo, com as palmas voltadas para cima. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados na borda. Enrole lentamente os dedos em direção às palmas, apertando a barra com força. Segure a contração por um momento e depois solte lentamente os dedos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0455.gif', 'hasaneyldrm', '0455'),
  ('b1d7a80a-0000-4000-8000-000000003303'::uuid, null, 'bandeira', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'shoulders']::text[], 'bodyweight', false, 'Comece segurando um poste vertical com as duas mãos, as palmas voltadas uma para a outra e os braços totalmente estendidos. Envolva seu núcleo e levante as pernas do chão, mantendo-as retas. Usando a força do núcleo e da parte superior do corpo, levante as pernas até que fiquem paralelas ao chão. Mantenha essa posição o máximo que puder, mantendo a linha reta do corpo. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3303.gif', 'hasaneyldrm', '3303'),
  ('b1d7a80a-0000-4000-8000-000000000456'::uuid, null, 'perna flexionada sentar (joelho flexionado)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Ao mesmo tempo, levante as pernas do chão, dobrando os joelhos e aproximando-os do peito. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo e as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0456.gif', 'hasaneyldrm', '0456'),
  ('b1d7a80a-0000-4000-8000-000000000457'::uuid, null, 'perna flexionada sentar (braço esticado)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'quadriceps']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços esticados acima da cabeça. Envolvendo os abdominais, levante a parte superior do corpo do chão e, ao mesmo tempo, levante as pernas em direção ao peito. Estenda as mãos na direção dos dedos dos pés enquanto levanta a parte superior do corpo e as pernas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo e as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0457.gif', 'hasaneyldrm', '0457'),
  ('b1d7a80a-0000-4000-8000-000000000458'::uuid, null, 'mosca de chão (com barra)', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'barbell', false, 'Deite-se de costas no chão, com os joelhos dobrados e os pés apoiados no chão. Segure uma barra com uma pegada pronada, com os braços estendidos sobre o peito. Abaixe lentamente a barra para os lados, mantendo uma ligeira flexão nos cotovelos. Abaixe a barra até que os braços fiquem paralelos ao chão, sentindo um alongamento no peito. Faça uma pausa por um momento e contraia os músculos do peito para trazer a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0458.gif', 'hasaneyldrm', '0458'),
  ('b1d7a80a-0000-4000-8000-000000000459'::uuid, null, 'chutes agitados', 'isolation', ARRAY['glutes', 'hip flexors']::text[], ARRAY['hip flexors', 'lower abs']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e as mãos ao lado do corpo. Envolva seu núcleo e levante as pernas do chão cerca de 15 centímetros. Mantendo as pernas retas, alterne levantando uma perna ligeiramente mais alta que a outra. Continue este movimento vibrante pelo número desejado de repetições.', '/exercise-media/bstrainer/0459.gif', 'hasaneyldrm', '0459'),
  ('b1d7a80a-0000-4000-8000-000000001472'::uuid, null, 'salto para frente', 'isolation', ARRAY['quads', 'calves']::text[], ARRAY['calves', 'hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada. Balance os braços para trás para ganhar impulso. Salte para frente de forma explosiva, estendendo os quadris, joelhos e tornozelos. Pouse suavemente na ponta dos pés e imediatamente dê o próximo salto. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1472.gif', 'hasaneyldrm', '1472'),
  ('b1d7a80a-0000-4000-8000-000000003470'::uuid, null, 'estocada para frente (masculino)', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos quadris e as mãos nos quadris. Dê um grande passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Dobre o joelho direito cerca de 90 graus, mantendo o joelho alinhado com o tornozelo. Empurre com o pé direito e retorne à posição inicial. Repita com a perna esquerda, alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3470.gif', 'hasaneyldrm', '3470'),
  ('b1d7a80a-0000-4000-8000-000000003194'::uuid, null, 'agachamento frankenstein', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra na frente do corpo com os braços esticados. Mantendo as costas retas, abaixe o corpo dobrando os joelhos e os quadris, como se estivesse sentado em uma cadeira. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3194.gif', 'hasaneyldrm', '3194'),
  ('b1d7a80a-0000-4000-8000-000000002429'::uuid, null, 'crise de sapo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2429.gif', 'hasaneyldrm', '2429'),
  ('b1d7a80a-0000-4000-8000-000000003301'::uuid, null, 'planche de sapo', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos afastadas na largura dos ombros e os pés juntos. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas retas. Ao abaixar o corpo, levante os pés do chão e traga os joelhos em direção ao peito. Mantenha essa posição por alguns segundos, depois estenda as pernas para fora e volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3301.gif', 'hasaneyldrm', '3301'),
  ('b1d7a80a-0000-4000-8000-000000003296'::uuid, null, 'alavanca frontal', 'core', ARRAY['abs', 'lats']::text[], ARRAY['lats', 'shoulders', 'forearms']::text[], 'bodyweight', false, 'Comece pendurando-se em uma barra suspensa com uma pegada pronada, com as mãos afastadas na largura dos ombros. Envolva seu núcleo e puxe as omoplatas para baixo e para trás. Dobre os joelhos e coloque-os em direção ao peito. Simultaneamente, levante as pernas e estenda-as à sua frente, mantendo o corpo paralelo ao chão. Mantenha esta posição o máximo que puder, visando uma posição totalmente frontal da alavanca. Para soltar, abaixe lentamente as pernas e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3296.gif', 'hasaneyldrm', '3296'),
  ('b1d7a80a-0000-4000-8000-000000003295'::uuid, null, 'repetições da alavanca dianteira', 'isolation', ARRAY['upper back', 'core']::text[], ARRAY['core', 'shoulders']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com uma pegada pronada, com as palmas voltadas para longe de você. Envolva seu núcleo e puxe as omoplatas para baixo e para trás. Mantendo o corpo reto, levante as pernas até que fiquem paralelas ao chão. Mantenha essa posição o máximo que puder, mirando por 10 a 20 segundos. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3295.gif', 'hasaneyldrm', '3295'),
  ('b1d7a80a-0000-4000-8000-000000000464'::uuid, null, 'prancha frontal com torção', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta da cabeça aos pés. Envolva seu núcleo e glúteos para manter uma posição estável. Gire o tronco para a direita, levantando o braço direito e estendendo-o em direção ao teto. Mantenha os quadris e as pernas estáveis ​​enquanto gira. Segure por um momento e depois retorne à posição inicial. Repita a torção no lado esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0464.gif', 'hasaneyldrm', '0464'),
  ('b1d7a80a-0000-4000-8000-000000003315'::uuid, null, 'maltês completo', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os braços estendidos para os lados. Incline-se lentamente para a frente, mantendo os braços esticados, até que a parte superior do corpo fique paralela ao chão. Envolva seu núcleo e mantenha esta posição por alguns segundos. Retorne à posição inicial empurrando os pés e levantando-se. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3315.gif', 'hasaneyldrm', '3315'),
  ('b1d7a80a-0000-4000-8000-000000003299'::uuid, null, 'planche completo', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos afastadas na largura dos ombros e os dedos apontando para a frente. Envolva seu núcleo e mova lentamente seu peso para a frente, levantando os pés do chão. Continue deslocando o peso para a frente até que o corpo fique paralelo ao chão, equilibrando-se nas mãos. Mantenha essa posição o máximo que puder, mantendo a linha reta do corpo. Abaixe lentamente os pés de volta ao chão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3299.gif', 'hasaneyldrm', '3299'),
  ('b1d7a80a-0000-4000-8000-000000003327'::uuid, null, 'flexão de prancha completa', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas do que a largura dos ombros. Envolva seu núcleo e abaixe o corpo em direção ao chão, mantendo os cotovelos próximos aos lados. Ao se abaixar, incline o corpo para a frente e levante os pés do chão, equilibrando-se nas mãos. Continue abaixando o corpo até que o peito fique logo acima do solo. Empurre as mãos e estenda os braços para levantar o corpo de volta à posição inicial. Mantenha uma linha reta da cabeça aos calcanhares durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3327.gif', 'hasaneyldrm', '3327'),
  ('b1d7a80a-0000-4000-8000-000000000466'::uuid, null, 'gironda esterno queixo', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'bodyweight', false, 'Fique de frente para uma barra alta com os pés afastados na largura dos ombros. Estenda a mão e agarre a barra com uma pegada pronada, um pouco mais larga que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo reto. Envolva os dorsais e os bíceps para puxar o peito em direção à barra, liderando com o esterno. Faça uma pausa por um momento no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0466.gif', 'hasaneyldrm', '0466'),
  ('b1d7a80a-0000-4000-8000-000000003561'::uuid, null, 'marcha ponte de glúteos', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Envolva os glúteos e levante os quadris do chão, formando uma linha reta dos joelhos até os ombros. Mantendo os quadris elevados, levante um pé do chão e leve o joelho em direção ao peito. Abaixe o pé de volta ao chão e repita o movimento com a outra perna. Continue alternando as pernas em movimento de marcha, mantendo a posição da ponte. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3561.gif', 'hasaneyldrm', '3561'),
  ('b1d7a80a-0000-4000-8000-000000003523'::uuid, null, 'ponte de glúteo duas pernas no banco (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'core']::text[], 'bodyweight', false, 'Sente-se na beira de um banco, com as costas apoiadas e os pés apoiados no chão. Coloque as mãos no banco ao lado dos quadris para obter apoio. Envolva os glúteos e isquiotibiais e, em seguida, levante os quadris do banco até que o corpo forme uma linha reta dos joelhos até os ombros. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3523.gif', 'hasaneyldrm', '3523'),
  ('b1d7a80a-0000-4000-8000-000000003193'::uuid, null, 'aumento de presunto glúteo', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'lower back']::text[], 'bodyweight', false, 'Ajuste a máquina de elevação de presunto glúteo para se ajustar ao seu corpo. Posicione-se de bruços na máquina com os tornozelos protegidos. Coloque as mãos no peito ou cruze-as sobre o peito. Envolva os isquiotibiais e os glúteos para levantar a parte superior do corpo em direção ao teto. Continue levantando até que seu corpo esteja em linha reta, da cabeça aos calcanhares. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3193.gif', 'hasaneyldrm', '3193'),
  ('b1d7a80a-0000-4000-8000-000000000467'::uuid, null, 'queixo de gorila', 'core', ARRAY['abs', 'forearms']::text[], ARRAY['forearms', 'biceps']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure uma barra pull-up com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e as palmas voltadas para você. Envolva seu núcleo e puxe seu corpo em direção à barra, trazendo o queixo acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0467.gif', 'hasaneyldrm', '0467'),
  ('b1d7a80a-0000-4000-8000-000000000469'::uuid, null, 'dor na virilha', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'inner thighs']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante as pernas do chão, aproximando os joelhos do peito. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0469.gif', 'hasaneyldrm', '0469'),
  ('b1d7a80a-0000-4000-8000-000000001383'::uuid, null, 'hackear aumento de panturrilha', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste a máquina de trenó para um peso confortável. Fique na máquina de trenó com os dedos dos pés na plataforma e os calcanhares pendurados. Segure nas alças para estabilidade. Levante os calcanhares o mais alto possível, empurrando a planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1383.gif', 'hasaneyldrm', '1383'),
  ('b1d7a80a-0000-4000-8000-000000001384'::uuid, null, 'hackear elevação de panturrilha com uma perna', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', true, 'Ajuste a máquina de trenó para um peso apropriado. Fique na máquina de trenó com um pé, mantendo o outro pé fora do chão. Segure nas alças para estabilidade. Levante o calcanhar o mais alto possível, apoiando o corpo na planta do pé. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita pelo número desejado de repetições. Troque as pernas e repita o exercício.', '/exercise-media/bstrainer/1384.gif', 'hasaneyldrm', '1384'),
  ('b1d7a80a-0000-4000-8000-000000003221'::uuid, null, 'flexões de meio joelho (masculino)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo como se estivesse sentado em uma cadeira. Mantenha o peito erguido e o peso nos calcanhares. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3221.gif', 'hasaneyldrm', '3221'),
  ('b1d7a80a-0000-4000-8000-000000003202'::uuid, null, 'meio abdominal (masculino)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3202.gif', 'hasaneyldrm', '3202'),
  ('b1d7a80a-0000-4000-8000-000000001511'::uuid, null, 'alongamento dos isquiotibiais', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dê um passo à frente com o pé direito e transfira o peso para a perna direita. Mantendo as costas retas, incline-se lentamente para a frente na altura dos quadris, alcançando o pé direito com as duas mãos. Mantenha o alongamento por 20 a 30 segundos e depois retorne à posição inicial. Repita do outro lado.', '/exercise-media/bstrainer/1511.gif', 'hasaneyldrm', '1511'),
  ('b1d7a80a-0000-4000-8000-000000002139'::uuid, null, 'bicicleta de mãos', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e a posição do guiador para um nível confortável. Sente-se no ergômetro com as costas retas e os pés nos pedais. Segure as alças com as mãos e posicione os braços em um ângulo de 90 graus. Comece a pedalar com as mãos, empurrando e puxando as alças em um movimento controlado. Continue pedalando pela duração ou número de repetições desejado.', '/exercise-media/bstrainer/2139.gif', 'hasaneyldrm', '2139'),
  ('b1d7a80a-0000-4000-8000-000000003218'::uuid, null, 'mãos entrelaçadas toque circular na ponta dos pés (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e as mãos cruzadas na frente do peito. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Abaixe as mãos em direção aos dedos dos pés em movimentos circulares, alcançando o máximo que puder sem esforço. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3218.gif', 'hasaneyldrm', '3218'),
  ('b1d7a80a-0000-4000-8000-000000003215'::uuid, null, 'mãos invertidas entrelaçadas toque circular na ponta dos pés (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos para os lados. Incline-se para a frente na cintura, mantendo as costas retas e os joelhos ligeiramente flexionados. Abaixe as mãos e junte-as atrás das pernas. Levante lentamente as mãos para cima e sobre a cabeça em movimentos circulares, mantendo as pernas retas. Continue o movimento circular até que suas mãos toquem os dedos dos pés. Inverta o movimento e traga as mãos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3215.gif', 'hasaneyldrm', '3215'),
  ('b1d7a80a-0000-4000-8000-000000003302'::uuid, null, 'parada de mão', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'bodyweight', false, 'Encontre um espaço aberto com espaço suficiente para fazer parada de mão. Coloque as mãos no chão na largura dos ombros, os dedos apontando para a frente. Levante as pernas em direção à parede, usando o núcleo e os ombros para manter o equilíbrio. Uma vez na posição de parada de mão, envolva o tríceps para suportar o peso do corpo. Segure o pino enquanto puder manter o equilíbrio. Para descer, abaixe lentamente as pernas de volta ao chão. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3302.gif', 'hasaneyldrm', '3302'),
  ('b1d7a80a-0000-4000-8000-000000000471'::uuid, null, 'flexão de mão', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'chest', 'core']::text[], 'bodyweight', false, 'Encontre uma parede e fique de costas para ela, ficando a alguns metros de distância. Coloque as mãos no chão na largura dos ombros e chute os pés contra a parede, ficando em posição de pino. Dobre os cotovelos e abaixe a cabeça em direção ao chão, mantendo o corpo em linha reta. Empurre com as mãos e estenda os braços para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0471.gif', 'hasaneyldrm', '0471'),
  ('b1d7a80a-0000-4000-8000-000000001764'::uuid, null, 'elevação do quadril com perna pendurada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva o núcleo e levante as pernas flexionando os quadris e os joelhos até que as coxas fiquem paralelas ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1764.gif', 'hasaneyldrm', '1764'),
  ('b1d7a80a-0000-4000-8000-000000000472'::uuid, null, 'elevação de perna pendurada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva seu núcleo e levante as pernas à sua frente, mantendo-as retas. Continue levantando até que suas pernas fiquem paralelas ao chão ou o mais alto que você puder chegar confortavelmente. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0472.gif', 'hasaneyldrm', '0472'),
  ('b1d7a80a-0000-4000-8000-000000001761'::uuid, null, 'elevação oblíqua do joelho pendurada', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva o núcleo e levante os joelhos em direção ao peito, torcendo o tronco para o lado ao fazer isso. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita do outro lado, girando o tronco na direção oposta. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1761.gif', 'hasaneyldrm', '1761'),
  ('b1d7a80a-0000-4000-8000-000000000473'::uuid, null, 'lúcio pendurado', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'shoulders']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva seu núcleo e levante as pernas em direção à barra, mantendo-as retas. Continue levantando até que seu corpo forme um formato de ''V'', com as pernas paralelas ao chão. Mantenha a posição por um momento e depois abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0473.gif', 'hasaneyldrm', '0473'),
  ('b1d7a80a-0000-4000-8000-000000000474'::uuid, null, 'elevação de quadril com perna reta pendurada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva seu núcleo e levante as pernas à sua frente até que fiquem paralelas ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0474.gif', 'hasaneyldrm', '0474'),
  ('b1d7a80a-0000-4000-8000-000000000475'::uuid, null, 'elevação da perna esticada pendurada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva seu núcleo e levante as pernas à sua frente, mantendo-as retas. Continue levantando até que suas pernas fiquem paralelas ao chão ou o mais alto que você puder chegar confortavelmente. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0475.gif', 'hasaneyldrm', '0475'),
  ('b1d7a80a-0000-4000-8000-000000000476'::uuid, null, 'elevação do quadril com perna reta e torcida', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as pernas esticadas. Envolva seu núcleo e levante as pernas em direção ao peito, mantendo-as retas. Quando as pernas estiverem paralelas ao chão, gire os quadris para um lado, trazendo as pernas para esse lado. Faça uma pausa por um momento e depois retorne à posição inicial. Repita o movimento, mas desta vez gire os quadris para o lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0476.gif', 'hasaneyldrm', '0476'),
  ('b1d7a80a-0000-4000-8000-000000003636'::uuid, null, 'joelho alto contra a parede', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'bodyweight', false, 'Fique de frente para uma parede com os pés afastados na largura do quadril. Coloque as mãos na parede para apoio. Envolva o núcleo e levante o joelho direito em direção ao peito, enquanto mantém o pé esquerdo no chão. Troque rapidamente as pernas, trazendo o joelho esquerdo em direção ao peito e abaixando o pé direito. Continue alternando as pernas em movimento de corrida, levantando os joelhos o mais alto possível. Mantenha um ritmo rápido e mantenha a parte superior do corpo estável durante todo o exercício. Repita pela duração desejada ou número de repetições.', '/exercise-media/bstrainer/3636.gif', 'hasaneyldrm', '3636'),
  ('b1d7a80a-0000-4000-8000-000000000484'::uuid, null, 'elevação do quadril (joelho flexionado)', 'core', ARRAY['abs', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos ao lado do corpo, com as palmas voltadas para baixo. Envolva o núcleo e os glúteos e, em seguida, levante os quadris do chão até que o corpo forme uma linha reta dos joelhos até os ombros. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0484.gif', 'hasaneyldrm', '0484'),
  ('b1d7a80a-0000-4000-8000-000000001418'::uuid, null, 'abraço forte no peito', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada. Ao agachar-se, levante os joelhos em direção ao peito e abrace-os com os braços. Mantenha esta posição por um momento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1418.gif', 'hasaneyldrm', '1418'),
  ('b1d7a80a-0000-4000-8000-000000003234'::uuid, null, 'mosca alta com halteres', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders']::text[], 'dumbbell', false, 'Deite-se em um banco com um haltere em cada mão, com as palmas voltadas uma para a outra. Estenda os braços sobre o peito, com uma ligeira flexão nos cotovelos. Mantendo uma ligeira flexão nos cotovelos, abaixe os halteres para os lados em um amplo arco até sentir um alongamento no peito. Faça uma pausa, depois inverta o movimento e traga os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3234.gif', 'hasaneyldrm', '3234'),
  ('b1d7a80a-0000-4000-8000-000000000489'::uuid, null, 'hiperextensão', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Ajuste o banco de hiperextensão de modo que a parte superior das coxas fique apoiada na almofada e os pés fiquem seguros. Cruze os braços sobre o peito ou coloque as mãos atrás da cabeça. Abaixe a parte superior do corpo em direção ao chão, mantendo as costas retas. Faça uma pausa por um momento na parte inferior e, em seguida, levante a parte superior do corpo até que fique alinhado com as pernas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0489.gif', 'hasaneyldrm', '0489'),
  ('b1d7a80a-0000-4000-8000-000000000488'::uuid, null, 'hiperextensão (no banco)', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Ajuste o banco de hiperextensão para que seus quadris repousem confortavelmente na almofada e seus pés fiquem seguros. Cruze os braços sobre o peito ou coloque as mãos atrás da cabeça. Abaixe lentamente a parte superior do corpo em direção ao chão, mantendo as costas retas. Faça uma pausa por um momento na parte inferior e, em seguida, levante a parte superior do corpo até que fique alinhado com as pernas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0488.gif', 'hasaneyldrm', '0488'),
  ('b1d7a80a-0000-4000-8000-000000003289'::uuid, null, 'mergulhos impossíveis', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Posicione-se entre duas barras paralelas com os braços totalmente estendidos e o corpo suspenso no ar. Dobre os joelhos e cruze os tornozelos. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3289.gif', 'hasaneyldrm', '3289'),
  ('b1d7a80a-0000-4000-8000-000000001471'::uuid, null, 'lagarta', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'hamstrings']::text[], 'bodyweight', false, 'Comece em pé, com os pés afastados na largura do quadril. Incline-se para a frente na cintura e coloque as mãos no chão à sua frente. Ande com as mãos para a frente até ficar em uma posição de prancha alta, com o corpo em linha reta da cabeça aos pés. Faça uma pausa por um momento e depois volte as mãos para os pés, mantendo as pernas o mais retas possível. Assim que suas mãos alcançarem os pés, volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1471.gif', 'hasaneyldrm', '1471'),
  ('b1d7a80a-0000-4000-8000-000000003698'::uuid, null, 'lagarta v. 2', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'hamstrings']::text[], 'bodyweight', false, 'Comece em pé, com os pés afastados na largura do quadril. Incline-se para a frente na cintura e coloque as mãos no chão à sua frente. Ande com as mãos para a frente até ficar em uma posição de prancha alta, com o corpo em linha reta da cabeça aos pés. Mantendo as pernas retas, caminhe com os pés em direção às mãos, elevando os quadris em direção ao teto. Continue caminhando com as mãos para frente, repetindo o movimento pelo número desejado de repetições.', '/exercise-media/bstrainer/3698.gif', 'hasaneyldrm', '3698'),
  ('b1d7a80a-0000-4000-8000-000000000490'::uuid, null, 'flexão inclinada com pegada fechada', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Coloque as mãos em uma superfície elevada, como um banco ou degrau, ligeiramente mais larga que a largura dos ombros. Estenda as pernas atrás de você, apoiando-se na planta dos pés, com o corpo formando uma linha reta da cabeça aos calcanhares. Abaixe o peito em direção à superfície elevada dobrando os cotovelos, mantendo-os próximos ao corpo. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0490.gif', 'hasaneyldrm', '0490'),
  ('b1d7a80a-0000-4000-8000-000000000491'::uuid, null, 'perna inclinada elevação do quadril (perna esticada)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se em um banco inclinado com as costas apoiadas no banco e as pernas estendidas à sua frente. Coloque as mãos nas laterais do banco para apoio. Envolvendo os abdominais, levante as pernas do banco, elevando-as o mais alto que puder, mantendo-as retas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0491.gif', 'hasaneyldrm', '0491'),
  ('b1d7a80a-0000-4000-8000-000000000492'::uuid, null, 'inclinação push up salto em profundidade', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Encontre uma superfície elevada, como um banco ou degrau, e coloque as mãos na borda na largura dos ombros. Dê um passo para trás, mantendo o corpo em linha reta da cabeça aos calcanhares. Abaixe o peito em direção à borda da superfície, dobrando os cotovelos e mantendo o corpo alinhado. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Salte da borda da superfície, pousando suavemente com os joelhos ligeiramente flexionados. Repita a flexão e o salto em profundidade pelo número desejado de repetições.', '/exercise-media/bstrainer/0492.gif', 'hasaneyldrm', '0492'),
  ('b1d7a80a-0000-4000-8000-000000000493'::uuid, null, 'flexão inclinada', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Coloque as mãos em uma superfície elevada, como um banco ou degrau, ligeiramente mais larga que a largura dos ombros. Estenda as pernas atrás de você, apoiando-se na planta dos pés, criando uma linha reta da cabeça aos calcanhares. Abaixe o peito em direção à superfície elevada dobrando os cotovelos, mantendo o corpo em linha reta. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0493.gif', 'hasaneyldrm', '0493'),
  ('b1d7a80a-0000-4000-8000-000000003785'::uuid, null, 'flexão inclinada (na caixa)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Coloque as mãos na borda de uma caixa ou superfície elevada, ligeiramente mais afastadas que a largura dos ombros. Estenda as pernas atrás de você, apoiando-se na planta dos pés, criando uma linha reta da cabeça aos calcanhares. Abaixe o peito em direção à caixa dobrando os cotovelos, mantendo o corpo em linha reta. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3785.gif', 'hasaneyldrm', '3785'),
  ('b1d7a80a-0000-4000-8000-000000000494'::uuid, null, 'flexão de aderência reversa inclinada', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Coloque as mãos na borda de um banco ou superfície elevada, ligeiramente mais afastadas que a largura dos ombros. Estenda as pernas atrás de você, apoiando-se na planta dos pés, criando uma linha reta da cabeça aos calcanhares. Abaixe o peito em direção ao banco dobrando os cotovelos, mantendo-os próximos ao corpo. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0494.gif', 'hasaneyldrm', '0494'),
  ('b1d7a80a-0000-4000-8000-000000003011'::uuid, null, 'inclinar a escápula push up', 'isolation', ARRAY['serratus anterior', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Configure um banco inclinado em um ângulo de 45 graus. Coloque as mãos no banco um pouco mais afastadas que a largura dos ombros. Posicione os pés no chão, afastados na largura do quadril. Abaixe o peito em direção ao banco, mantendo os cotovelos dobrados. Ao abaixar, retraia as omoplatas, apertando as escápulas. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3011.gif', 'hasaneyldrm', '3011'),
  ('b1d7a80a-0000-4000-8000-000000000495'::uuid, null, 'abdominais inclinados e torcidos', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Configure um banco inclinado em um ângulo de 45 graus. Deite-se no banco com os pés presos sob as almofadas dos pés. Coloque as mãos atrás da cabeça ou sobre o peito. Envolva os abdominais e levante a parte superior do corpo do banco, curvando-se para a frente. Ao se enrolar, gire o tronco para um lado, trazendo o cotovelo em direção ao joelho oposto. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita o movimento, desta vez girando o tronco para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0495.gif', 'hasaneyldrm', '0495'),
  ('b1d7a80a-0000-4000-8000-000000001564'::uuid, null, 'flexor intermediário do quadril e alongamento do quadríceps', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros. Segure-se em um objeto estável para suporte. Dobre o joelho direito e leve o pé direito em direção aos glúteos, agarrando a corda com a mão direita. Puxe lentamente o pé direito em direção aos glúteos, sentindo um alongamento no quadríceps direito. Mantenha o alongamento por 20 a 30 segundos. Solte o alongamento e repita no lado esquerdo.', '/exercise-media/bstrainer/1564.gif', 'hasaneyldrm', '1564'),
  ('b1d7a80a-0000-4000-8000-000000000496'::uuid, null, 'flexão de perna inversa (apoio de banco)', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'calves']::text[], 'bodyweight', false, 'Deite-se de bruços em um banco com os quadris na borda e as pernas estendidas para trás. Segure-se no banco para obter apoio. Mantendo a parte superior do corpo imóvel, dobre os joelhos e enrole as pernas em direção aos glúteos. Faça uma pausa no topo e, em seguida, estenda lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0496.gif', 'hasaneyldrm', '0496'),
  ('b1d7a80a-0000-4000-8000-000000002400'::uuid, null, 'flexão de perna inversa (em máquina de cabo pull-up)', 'pull_v', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'calves']::text[], 'bodyweight', false, 'Ajuste a máquina de cabos para que as tiras dos tornozelos fiquem na posição mais baixa. Deite-se de bruços no banco com as pernas estendidas e as tiras dos tornozelos presas aos pés. Segure-se nas alças do banco para obter estabilidade. Dobre os joelhos e enrole as pernas em direção aos glúteos, apertando os isquiotibiais. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2400.gif', 'hasaneyldrm', '2400'),
  ('b1d7a80a-0000-4000-8000-000000000499'::uuid, null, 'linha invertida', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Configure uma barra na altura da cintura ou use um treinador de suspensão. Fique de frente para a barra ou treinador de suspensão, com os pés afastados na largura dos ombros. Segure a barra ou as alças com uma pegada pronada, um pouco mais larga que a largura dos ombros. Incline-se para trás, mantendo o corpo reto e os calcanhares no chão. Puxe o peito em direção à barra ou às alças, apertando as omoplatas. Faça uma pausa no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0499.gif', 'hasaneyldrm', '0499'),
  ('b1d7a80a-0000-4000-8000-000000002300'::uuid, null, 'fileira invertida joelhos dobrados', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Monte uma barra na altura da cintura e deite-se embaixo dela. Segure a barra com uma pegada pronada, um pouco mais larga que a largura dos ombros. Posicione o corpo de forma que os calcanhares fiquem no chão e o corpo reto. Puxe o peito em direção à barra, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2300.gif', 'hasaneyldrm', '2300'),
  ('b1d7a80a-0000-4000-8000-000000002298'::uuid, null, 'remada invertida no banco', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Monte um banco a uma altura que permita que seu corpo fique pendurado livremente embaixo dele. Deite-se de bruços no chão com a cabeça voltada para o banco. Estenda a mão e agarre o banco com uma pegada pronada, um pouco mais larga que a largura dos ombros. Posicione o corpo de forma que os calcanhares fiquem no chão e os braços totalmente estendidos. Envolva seu núcleo e aperte as omoplatas enquanto puxa o peito em direção ao banco. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2298.gif', 'hasaneyldrm', '2298'),
  ('b1d7a80a-0000-4000-8000-000000000497'::uuid, null, 'linha invertida v. 2', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Configure uma barra na altura da cintura em uma máquina Smith ou use um treinador de suspensão. Fique de frente para a barra ou treinador de suspensão e agarre-o com uma pegada pronada, com as mãos afastadas na largura dos ombros. Ande com os pés para a frente, inclinando-se para trás até que o corpo fique ligeiramente inclinado. Mantenha o corpo reto e puxe o peito em direção à barra ou às alças, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0497.gif', 'hasaneyldrm', '0497'),
  ('b1d7a80a-0000-4000-8000-000000000498'::uuid, null, 'fileira invertida com alças', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Configure um treinador de suspensão ou tiras na altura do peito. Fique de frente para o ponto de ancoragem e segure as alças com uma pegada pronada. Ande com os pés para a frente, inclinando-se para trás até que o corpo fique inclinado. Mantenha seu corpo reto e envolva seu núcleo. Puxe o peito em direção às alças, apertando as omoplatas. Faça uma pausa no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0498.gif', 'hasaneyldrm', '0498'),
  ('b1d7a80a-0000-4000-8000-000000001419'::uuid, null, 'trecho em cruz de ferro', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', false, 'Deite-se de costas com os braços estendidos para os lados. Levante as pernas em direção ao teto, mantendo-as retas. Abaixe lentamente as pernas para o lado, com o objetivo de tocar o chão com os pés. Mantenha o alongamento por alguns segundos e depois retorne as pernas à posição inicial. Repita o alongamento do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1419.gif', 'hasaneyldrm', '1419'),
  ('b1d7a80a-0000-4000-8000-000000001297'::uuid, null, 'compressão torácica isométrica', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Estenda os braços à sua frente, paralelos ao chão, com as palmas voltadas uma para a outra. Contraia os músculos do peito o máximo que puder, enquanto mantém os braços retos. Mantenha essa posição por alguns segundos, concentrando-se na contração dos músculos do peito. Solte o aperto e relaxe os músculos do peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1297.gif', 'hasaneyldrm', '1297'),
  ('b1d7a80a-0000-4000-8000-000000000500'::uuid, null, 'limpadores isométricos', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'core']::text[], 'bodyweight', false, 'Comece deitando-se de costas em uma esteira ou banco. Estenda os braços para os lados, perpendiculares ao corpo. Envolva seu núcleo e levante ambas as pernas do chão, mantendo-as juntas e retas. Abaixe lentamente as pernas para o lado, tentando tocar o chão com os pés, mantendo o controle. Faça uma pausa por um momento e use o núcleo para levantar as pernas de volta à posição inicial. Repita o movimento, desta vez abaixando as pernas para o lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0500.gif', 'hasaneyldrm', '0500'),
  ('b1d7a80a-0000-4000-8000-000000000501'::uuid, null, 'jack burpee', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'triceps', 'core']::text[], 'bodyweight', false, 'Comece em pé, com os pés afastados na largura dos ombros. Abaixe o corpo até uma posição agachada, colocando as mãos no chão à sua frente. Jogue os pés para trás, aterrissando em uma posição de flexão. Faça uma flexão, abaixando o peito até o chão e depois empurrando de volta para cima. Salte com os pés para a frente, aterrissando em uma posição agachada. Salte de forma explosiva, alcançando os braços acima da cabeça. Pouse suavemente e imediatamente abaixe as costas para a posição de agachamento para iniciar a próxima repetição.', '/exercise-media/bstrainer/0501.gif', 'hasaneyldrm', '0501'),
  ('b1d7a80a-0000-4000-8000-000000003224'::uuid, null, 'jack jump (masculino)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés juntos e os braços ao lado do corpo. Salte, afastando os pés e levantando os braços acima da cabeça. Ao pousar, volte rapidamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3224.gif', 'hasaneyldrm', '3224'),
  ('b1d7a80a-0000-4000-8000-000000000507'::uuid, null, 'abdominais canivetes', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços acima da cabeça. Envolva o núcleo e levante as pernas e a parte superior do corpo simultaneamente, alcançando as mãos na direção dos dedos dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas e a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0507.gif', 'hasaneyldrm', '0507'),
  ('b1d7a80a-0000-4000-8000-000000000508'::uuid, null, 'janda abdominais', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0508.gif', 'hasaneyldrm', '0508'),
  ('b1d7a80a-0000-4000-8000-000000002612'::uuid, null, 'pular corda', 'isolation', ARRAY['cardiovascular system', 'calves']::text[], ARRAY['calves', 'quadriceps', 'hamstrings', 'glutes']::text[], 'machine', false, 'Segure as alças da corda de pular com as mãos, com as palmas voltadas para dentro. Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Passe a corda sobre a cabeça e pule sobre ela quando ela chegar aos seus pés. Pouse suavemente na ponta dos pés e repita o salto enquanto a corda volta a girar. Continue saltando pela duração ou número de repetições desejado.', '/exercise-media/bstrainer/2612.gif', 'hasaneyldrm', '2612'),
  ('b1d7a80a-0000-4000-8000-000000000514'::uuid, null, 'agachamento com salto', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Salte explosivamente do chão, estendendo os quadris, joelhos e tornozelos. Enquanto estiver no ar, traga rapidamente os braços para a frente para manter o equilíbrio. Pouse suavemente na planta dos pés e passe imediatamente para a próxima repetição. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0514.gif', 'hasaneyldrm', '0514'),
  ('b1d7a80a-0000-4000-8000-000000000513'::uuid, null, 'agachamento com salto v. 2', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Salte explosivamente, estendendo totalmente os quadris e joelhos. Pouse suavemente na planta dos pés e abaixe imediatamente o corpo de volta à posição de agachamento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0513.gif', 'hasaneyldrm', '0513'),
  ('b1d7a80a-0000-4000-8000-000000000517'::uuid, null, 'moinho de vento avançado com kettlebell', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'shoulders']::text[], 'kettlebell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando ligeiramente para fora. Segure um kettlebell com a mão direita, com o braço estendido acima da cabeça e a palma voltada para a frente. Gire o pé esquerdo ligeiramente para a direita e transfira o peso para a perna esquerda. Dobre o joelho esquerdo e dobre o quadril, abaixando o tronco para o lado esquerdo. Mantenha o braço direito estendido acima da cabeça e os olhos no kettlebell. Ao abaixar o tronco, deixe a perna direita esticar e o pé direito girar levemente. Abaixe o tronco até sentir um alongamento no tendão esquerdo e o braço direito apontar para o chão. Faça uma pausa por um momento, depois envolva o núcleo e empurre o calcanhar esquerdo para retornar à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0517.gif', 'hasaneyldrm', '0517'),
  ('b1d7a80a-0000-4000-8000-000000000518'::uuid, null, 'kettlebell alternado pendurado limpo', 'isolation', ARRAY['forearms', 'shoulders']::text[], ARRAY['shoulders', 'traps', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão com uma pegada pronada. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Deixe os kettlebells pendurados na frente do corpo com os braços totalmente estendidos. Em um movimento fluido, estenda os quadris de forma explosiva, encolha os ombros e puxe os kettlebells em direção aos ombros. À medida que os kettlebells atingem a altura dos ombros, gire os pulsos e segure os kettlebells na posição de rack, com as palmas voltadas para dentro e os kettlebells apoiados na parte externa dos antebraços. Abaixe os kettlebells de volta à posição inicial e repita o movimento com o braço oposto. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0518.gif', 'hasaneyldrm', '0518'),
  ('b1d7a80a-0000-4000-8000-000000000520'::uuid, null, 'pressão alternada com kettlebell', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão na altura dos ombros. Pressione um kettlebell acima da cabeça, estendendo totalmente o braço. Abaixe o kettlebell de volta à altura dos ombros. Repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0520.gif', 'hasaneyldrm', '0520'),
  ('b1d7a80a-0000-4000-8000-000000000519'::uuid, null, 'supino alternado com kettlebell no chão', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'kettlebell', true, 'Comece deitando-se de costas no chão, com os joelhos dobrados e os pés apoiados no chão. Segure um kettlebell em cada mão, com as palmas voltadas para os pés e os braços estendidos em direção ao teto. Abaixe um kettlebell em direção ao ombro enquanto mantém o outro kettlebell estendido para cima. Pressione o kettlebell abaixado de volta à posição inicial enquanto abaixa simultaneamente o outro kettlebell em direção ao ombro. Continue alternando o movimento de pressão com cada kettlebell para o número desejado de repetições.', '/exercise-media/bstrainer/0519.gif', 'hasaneyldrm', '0519'),
  ('b1d7a80a-0000-4000-8000-000000000521'::uuid, null, 'kettlebell alternando linha renegada', 'pull_h', ARRAY['upper back', 'core']::text[], ARRAY['core', 'shoulders']::text[], 'kettlebell', true, 'Comece em uma posição de prancha alta, com as mãos segurando os kettlebells e os pés afastados na largura do quadril. Envolva seu núcleo e mantenha seu corpo em linha reta da cabeça aos calcanhares. Puxe um kettlebell em direção ao peito, mantendo o cotovelo próximo ao corpo. Abaixe o kettlebell de volta à posição inicial e repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0521.gif', 'hasaneyldrm', '0521'),
  ('b1d7a80a-0000-4000-8000-000000000522'::uuid, null, 'remada alternada com kettlebell', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure um kettlebell em cada mão com as palmas voltadas para o corpo. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Puxe um kettlebell em direção ao peito, mantendo o cotovelo próximo ao corpo e apertando as omoplatas. Abaixe o kettlebell de volta à posição inicial e repita com o outro braço. Continue alternando os braços pelo número desejado de repetições.', '/exercise-media/bstrainer/0522.gif', 'hasaneyldrm', '0522'),
  ('b1d7a80a-0000-4000-8000-000000000523'::uuid, null, 'kettlebell arnold press', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão na altura dos ombros, com as palmas voltadas para você. Envolva seu núcleo e pressione os kettlebells acima da cabeça, girando as palmas das mãos para a frente enquanto estende os braços. Faça uma pausa no início do movimento e abaixe lentamente os kettlebells de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0523.gif', 'hasaneyldrm', '0523'),
  ('b1d7a80a-0000-4000-8000-000000000524'::uuid, null, 'supino dobrado com kettlebell', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'obliques']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na mão direita. Dobre ligeiramente os joelhos e pressione o kettlebell acima da cabeça com o braço direito, mantendo o cotovelo travado. Gire o tronco para a esquerda, transferindo o peso para o pé esquerdo. Dobre o joelho esquerdo e abaixe o tronco em direção ao chão, mantendo o braço direito estendido acima da cabeça. Ao abaixar, mantenha os olhos no kettlebell e no peito levantado. Assim que a mão esquerda tocar o chão, empurre o pé esquerdo e estique a perna esquerda, empurrando os quadris para a frente. Ao impulsionar os quadris para a frente, use o núcleo e o braço direito para pressionar o kettlebell de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0524.gif', 'hasaneyldrm', '0524'),
  ('b1d7a80a-0000-4000-8000-000000000525'::uuid, null, 'kettlebell desce limpo da posição pendurada', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos com uma pegada pronada. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Deixe o kettlebell pendurado entre as pernas, com o braço totalmente estendido. Em um movimento fluido, estenda explosivamente os quadris e os joelhos enquanto puxa o kettlebell em direção ao ombro. Quando o kettlebell atingir a altura dos ombros, gire o pulso de forma que a parte inferior do kettlebell fique voltada para cima. Pegue o kettlebell na altura dos ombros, com o cotovelo dobrado e a palma da mão voltada para cima. Abaixe o kettlebell de volta à posição inicial invertendo o movimento. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0525.gif', 'hasaneyldrm', '0525'),
  ('b1d7a80a-0000-4000-8000-000000000526'::uuid, null, 'kettlebell duplo alternado pendurado limpo', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão com uma pegada pronada. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Deixe os kettlebells pendurados na frente do seu corpo. Em um movimento fluido, estenda explosivamente os quadris e os joelhos enquanto encolhe os ombros. À medida que os kettlebells sobem, puxe-os em direção aos ombros, mantendo os cotovelos elevados e para os lados. Pegue os kettlebells na altura dos ombros, com as palmas voltadas para dentro e os cotovelos apontando para frente. Abaixe os kettlebells de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0526.gif', 'hasaneyldrm', '0526'),
  ('b1d7a80a-0000-4000-8000-000000000527'::uuid, null, 'kettlebell duplo empurrão', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão na altura dos ombros. Dobre ligeiramente os joelhos e envolva o núcleo. Pressione os kettlebells acima da cabeça, estendendo totalmente os braços. Dobre os joelhos e faça um agachamento parcial rapidamente. Estenda explosivamente os quadris e joelhos, levando os kettlebells acima da cabeça. Trave os braços e segure os kettlebells acima da cabeça com os joelhos ligeiramente flexionados. Fique em pé e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0527.gif', 'hasaneyldrm', '0527'),
  ('b1d7a80a-0000-4000-8000-000000000528'::uuid, null, 'pressão dupla com kettlebell', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão na altura dos ombros. Dobre ligeiramente os joelhos e envolva o núcleo. Inicie o movimento estendendo explosivamente os quadris, joelhos e tornozelos, conduzindo os kettlebells acima da cabeça. Quando os kettlebells chegarem ao topo, pressione-os totalmente acima da cabeça, travando os braços. Abaixe os kettlebells de volta à posição inicial dobrando os cotovelos e trazendo-os de volta à altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0528.gif', 'hasaneyldrm', '0528'),
  ('b1d7a80a-0000-4000-8000-000000000529'::uuid, null, 'arrebatamento duplo com kettlebell', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'forearms', 'core']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão com o braço estendido na frente das coxas. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Em um movimento explosivo, estenda os quadris, joelhos e tornozelos e, simultaneamente, puxe os kettlebells em direção aos ombros. À medida que os kettlebells atingem o nível dos ombros, gire os pulsos e dê um soco nos kettlebells acima da cabeça, estendendo totalmente os braços. Abaixe os kettlebells de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0529.gif', 'hasaneyldrm', '0529'),
  ('b1d7a80a-0000-4000-8000-000000000530'::uuid, null, 'moinho de vento duplo com kettlebell', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'hamstrings']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na mão direita. Estenda o braço direito acima da cabeça, mantendo os olhos no kettlebell. Gire o pé esquerdo 45 graus para a esquerda e o pé direito 90 graus para a direita. Dobre a cintura para a esquerda, mantendo o braço direito estendido acima da cabeça. Abaixe o kettlebell em direção ao chão, alcançando o pé esquerdo. Faça uma pausa por um momento, depois envolva o núcleo e empurre o pé direito para retornar à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0530.gif', 'hasaneyldrm', '0530'),
  ('b1d7a80a-0000-4000-8000-000000000531'::uuid, null, 'kettlebell de alcance estendido com um braço no chão', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'kettlebell', true, 'Comece deitando-se de costas no chão, com os joelhos dobrados e os pés apoiados no chão. Segure um kettlebell com uma das mãos, com a palma voltada para os pés. Estenda o braço em direção ao teto, mantendo o cotovelo travado e o pulso reto. Abaixe lentamente o kettlebell de volta à posição inicial, mantendo o controle durante todo o movimento. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0531.gif', 'hasaneyldrm', '0531'),
  ('b1d7a80a-0000-4000-8000-000000000532'::uuid, null, 'kettlebell figura 8', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'forearms']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Passe o kettlebell entre as pernas, trocando de mãos conforme ele chega à parte de trás das pernas. À medida que o kettlebell avança, passe-o para a outra mão entre as pernas. Continue passando o kettlebell entre as pernas em um movimento de figura 8. Mantenha um ritmo constante e envolva seu núcleo durante todo o exercício. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0532.gif', 'hasaneyldrm', '0532'),
  ('b1d7a80a-0000-4000-8000-000000000533'::uuid, null, 'Agachamento frontal com kettlebell', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Segure o kettlebell com as duas mãos na frente do peito, próximo ao corpo. Envolva o núcleo e mantenha o peito erguido enquanto abaixa os quadris para baixo e para trás, como se estivesse sentado em uma cadeira. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Passe pelos calcanhares para se levantar, apertando os glúteos na parte superior. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0533.gif', 'hasaneyldrm', '0533'),
  ('b1d7a80a-0000-4000-8000-000000000534'::uuid, null, 'Agachamento com taça com kettlebell', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell próximo ao peito com as duas mãos. Mantendo o peito para cima e o núcleo engajado, abaixe o corpo até uma posição agachada, dobrando os joelhos e os quadris. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0534.gif', 'hasaneyldrm', '0534'),
  ('b1d7a80a-0000-4000-8000-000000000535'::uuid, null, 'kettlebell pendurado limpo', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'quadriceps', 'calves']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na frente das coxas. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Abaixe o kettlebell em direção ao chão, permitindo que ele balance entre as pernas. Estenda rapidamente os quadris e os joelhos, usando o impulso para balançar o kettlebell até a altura dos ombros. Quando o kettlebell atingir a altura dos ombros, gire os pulsos e segure o kettlebell na posição de suporte, com o cotovelo dobrado para dentro e o kettlebell apoiado no antebraço. Abaixe o kettlebell de volta à posição inicial entre as pernas e repita o número desejado de repetições.', '/exercise-media/bstrainer/0535.gif', 'hasaneyldrm', '0535'),
  ('b1d7a80a-0000-4000-8000-000000000536'::uuid, null, 'passagem de estocada com kettlebell', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na frente do peito com as duas mãos. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Ao avançar, passe o kettlebell sob a coxa direita e transfira-o para a mão esquerda. Empurre com o pé direito para retornar à posição inicial, ao mesmo tempo que passa o kettlebell de volta para a mão direita. Repita a estocada no lado oposto, passando o kettlebell sob a coxa esquerda. Continue alternando estocadas e passando o kettlebell entre as mãos pelo número desejado de repetições.', '/exercise-media/bstrainer/0536.gif', 'hasaneyldrm', '0536'),
  ('b1d7a80a-0000-4000-8000-000000000537'::uuid, null, 'kettlebell com um braço limpo e empurrão', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos com uma pegada pronada. Dobre ligeiramente os joelhos e dobre os quadris, abaixando o kettlebell entre as pernas. Estenda explosivamente os quadris, joelhos e tornozelos, usando o impulso para balançar o kettlebell até a altura dos ombros. Quando o kettlebell atingir a altura dos ombros, gire o pulso e dê um soco na mão para cima, travando o braço acima da cabeça. Abaixe o kettlebell de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0537.gif', 'hasaneyldrm', '0537'),
  ('b1d7a80a-0000-4000-8000-000000001298'::uuid, null, 'kettlebell supino com um braço', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'kettlebell', true, 'Deite-se de costas no chão, com os joelhos dobrados e os pés apoiados no chão. Segure o kettlebell com uma das mãos, com a palma voltada para os pés e o braço estendido em direção ao teto. Abaixe lentamente o kettlebell em direção ao peito, dobrando o cotovelo, mantendo o braço próximo ao corpo. Faça uma pausa por um momento quando o kettlebell estiver logo acima do peito e, em seguida, empurre-o de volta à posição inicial, estendendo o cotovelo. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1298.gif', 'hasaneyldrm', '1298'),
  ('b1d7a80a-0000-4000-8000-000000000538'::uuid, null, 'kettlebell empurrão com um braço', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos na altura dos ombros. Dobre ligeiramente os joelhos e envolva o núcleo. Pressione o kettlebell acima da cabeça em linha reta, estendendo totalmente o braço. Ao pressionar o kettlebell acima da cabeça, abaixe simultaneamente os joelhos e endireite-os rapidamente para gerar impulso. Quando o kettlebell atingir seu ponto mais alto, desça rapidamente por baixo dele, dobrando os joelhos e os quadris. Pegue o kettlebell com uma ligeira flexão nos joelhos e quadris e com o braço totalmente estendido acima da cabeça. Fique em pé, estendendo totalmente os joelhos e quadris, e estabilize o kettlebell acima da cabeça. Abaixe o kettlebell de volta à posição inicial dobrando os joelhos e quadris e repita o número desejado de repetições.', '/exercise-media/bstrainer/0538.gif', 'hasaneyldrm', '0538'),
  ('b1d7a80a-0000-4000-8000-000000000539'::uuid, null, 'kettlebell pressão militar de um braço para o lado', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos na altura dos ombros. Envolva seu núcleo e mantenha as costas retas. Pressione o kettlebell acima da cabeça, estendendo totalmente o braço. Faça uma pausa no topo e abaixe lentamente o kettlebell de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0539.gif', 'hasaneyldrm', '0539'),
  ('b1d7a80a-0000-4000-8000-000000000540'::uuid, null, 'kettlebell push press com um braço', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos na altura dos ombros. Dobre ligeiramente os joelhos e envolva o núcleo. Pressione o kettlebell acima da cabeça, estendendo o braço e estendendo totalmente as pernas. Abaixe o kettlebell de volta à posição inicial dobrando os joelhos e trazendo o kettlebell de volta ao ombro. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0540.gif', 'hasaneyldrm', '0540'),
  ('b1d7a80a-0000-4000-8000-000000000541'::uuid, null, 'remada com kettlebell com um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos com uma pegada pronada. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Puxe o kettlebell em direção ao peito, mantendo o cotovelo próximo ao corpo e apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o kettlebell de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de lado e repita com o outro braço.', '/exercise-media/bstrainer/0541.gif', 'hasaneyldrm', '0541'),
  ('b1d7a80a-0000-4000-8000-000000000542'::uuid, null, 'arranco de um braço com kettlebell', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'forearms', 'core']::text[], 'kettlebell', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos entre as pernas. Dobre ligeiramente os joelhos e dobre os quadris, abaixando o kettlebell em direção ao chão. Estenda explosivamente os quadris e joelhos, usando o impulso para balançar o kettlebell em direção ao ombro. Quando o kettlebell atingir a altura dos ombros, gire a mão e dê um soco acima da cabeça, estendendo totalmente o braço. Abaixe o kettlebell entre as pernas e repita o número desejado de repetições.', '/exercise-media/bstrainer/0542.gif', 'hasaneyldrm', '0542'),
  ('b1d7a80a-0000-4000-8000-000000000543'::uuid, null, 'pernas de ceia de pirata com kettlebell', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'forearms']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em uma das mãos. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Levante o kettlebell até a altura dos ombros, mantendo o cotovelo próximo ao corpo. Estenda o braço totalmente acima da cabeça, endireitando o cotovelo. Abaixe o kettlebell até a altura dos ombros e retorne à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0543.gif', 'hasaneyldrm', '0543'),
  ('b1d7a80a-0000-4000-8000-000000000544'::uuid, null, 'agachamento com pistola kettlebell', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na frente do peito com as duas mãos. Levante o pé esquerdo do chão e estenda-o para frente, mantendo-o paralelo ao chão. Abaixe lentamente o corpo até uma posição de agachamento, mantendo o pé direito apoiado no chão e a perna esquerda estendida. Faça uma pausa por um momento na parte inferior do agachamento e, em seguida, empurre o calcanhar direito para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0544.gif', 'hasaneyldrm', '0544'),
  ('b1d7a80a-0000-4000-8000-000000000545'::uuid, null, 'flexão plyo com kettlebell', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'kettlebell', false, 'Comece em uma posição de prancha alta com as mãos nos kettlebells, afastadas na largura dos ombros. Abaixe o peito em direção ao chão, mantendo os cotovelos próximos ao corpo. Empurre as mãos de forma explosiva, levantando-as dos kettlebells e estendendo totalmente os braços. Pouse suavemente de volta nos kettlebells e abaixe imediatamente o peito para a próxima repetição. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0545.gif', 'hasaneyldrm', '0545'),
  ('b1d7a80a-0000-4000-8000-000000000546'::uuid, null, 'imprensa sentada com kettlebell', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um kettlebell em cada mão na altura dos ombros, com as palmas voltadas para frente. Pressione os kettlebells acima da cabeça, estendendo totalmente os braços. Abaixe os kettlebells de volta à altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0546.gif', 'hasaneyldrm', '0546'),
  ('b1d7a80a-0000-4000-8000-000000001438'::uuid, null, 'kettlebell sentado na imprensa militar de dois braços', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'kettlebell', false, 'Sente-se em um banco com as costas retas e os pés apoiados no chão. Segure um kettlebell em cada mão na altura dos ombros, com as palmas voltadas para a frente. Pressione os kettlebells acima da cabeça, estendendo totalmente os braços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os kettlebells de volta ao nível dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1438.gif', 'hasaneyldrm', '1438'),
  ('b1d7a80a-0000-4000-8000-000000000547'::uuid, null, 'gangorra com kettlebell', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão na altura dos ombros. Pressione um kettlebell acima da cabeça enquanto mantém o outro na altura dos ombros. Abaixe o kettlebell pressionado de volta à altura dos ombros enquanto pressiona simultaneamente o outro kettlebell acima da cabeça. Continue alternando o movimento de pressão, criando um movimento semelhante a uma gangorra. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0547.gif', 'hasaneyldrm', '0547'),
  ('b1d7a80a-0000-4000-8000-000000000548'::uuid, null, 'kettlebell sumô pull alto', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders', 'glutes', 'hamstrings']::text[], 'kettlebell', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando para fora. Segure um kettlebell com as duas mãos na frente do corpo e os braços estendidos para baixo. Dobre os joelhos e abaixe os quadris até uma posição de agachamento, mantendo as costas retas. Passe pelos calcanhares e estenda explosivamente os quadris e joelhos, puxando o kettlebell em direção ao queixo. Ao puxar o kettlebell para cima, mantenha os cotovelos altos e afastados e aperte as omoplatas. Abaixe o kettlebell de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0548.gif', 'hasaneyldrm', '0548'),
  ('b1d7a80a-0000-4000-8000-000000000549'::uuid, null, 'balanço do kettlebell', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'core']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos apontados ligeiramente para fora. Segure o kettlebell com as duas mãos na frente do corpo, com os braços estendidos. Dobre ligeiramente os joelhos e dobre os quadris, empurrando a bunda para trás. Balance o kettlebell para trás entre as pernas, mantendo os braços retos e as costas retas. Leve os quadris para a frente e balance o kettlebell até a altura dos ombros, usando o impulso gerado pelos quadris. Permita que o kettlebell balance para trás entre as pernas e repita o movimento pelo número desejado de repetições.', '/exercise-media/bstrainer/0549.gif', 'hasaneyldrm', '0549'),
  ('b1d7a80a-0000-4000-8000-000000000550'::uuid, null, 'propulsor de kettlebell', 'isolation', ARRAY['delts', 'quadriceps']::text[], ARRAY['quadriceps', 'glutes', 'core']::text[], 'kettlebell', false, 'Comece ficando em pé com os pés afastados na largura dos ombros, segurando um kettlebell na frente do peito com as duas mãos, com as palmas voltadas uma para a outra. Abaixe-se em uma posição de agachamento dobrando os joelhos e empurrando os quadris para trás, mantendo o peito para cima e as costas retas. Ao chegar ao final do agachamento, mova explosivamente os calcanhares para se levantar, pressionando simultaneamente o kettlebell acima da cabeça. Trave os braços no topo do movimento, estendendo totalmente os cotovelos. Abaixe o kettlebell de volta à posição inicial invertendo o movimento, dobrando os cotovelos e baixando o peso de volta ao peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0550.gif', 'hasaneyldrm', '0550'),
  ('b1d7a80a-0000-4000-8000-000000000551'::uuid, null, 'Levantamento turco com kettlebell (estilo agachamento)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'core']::text[], 'kettlebell', false, 'Comece deitado de costas com as pernas estendidas e o kettlebell na mão direita, com o braço totalmente estendido acima do ombro. Dobre o joelho direito e coloque o pé direito no chão, mantendo a perna esquerda estendida. Pressionando o pé direito, levante os quadris do chão, ficando na posição de ponte. Deslize a perna esquerda por baixo do corpo, dobrando o joelho esquerdo e colocando o pé esquerdo no chão. Gire o tronco para a esquerda, colocando a mão esquerda no chão para se apoiar. Pressionando o pé direito e a mão esquerda, levante o tronco do chão, ficando ajoelhado. Ajoelhado, levante-se, mantendo o kettlebell estendido acima da cabeça. Inverta o movimento para retornar à posição inicial. Repita o exercício do outro lado, começando com o kettlebell na mão esquerda.', '/exercise-media/bstrainer/0551.gif', 'hasaneyldrm', '0551'),
  ('b1d7a80a-0000-4000-8000-000000000552'::uuid, null, 'limpeza de dois braços com kettlebell', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'forearms']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na frente das coxas com as duas mãos, as palmas voltadas para você. Dobre ligeiramente os joelhos e dobre os quadris, abaixando o kettlebell em direção ao chão. Estenda explosivamente os quadris e joelhos, usando o impulso para puxar o kettlebell em direção aos ombros. Quando o kettlebell atingir a altura dos ombros, gire os pulsos e segure o kettlebell na posição de rack, com os cotovelos dobrados e o kettlebell apoiado na parte de trás do antebraço. Abaixe o kettlebell de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0552.gif', 'hasaneyldrm', '0552'),
  ('b1d7a80a-0000-4000-8000-000000000553'::uuid, null, 'kettlebell imprensa militar de dois braços', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell em cada mão na altura dos ombros, com as palmas voltadas para a frente. Envolva seu núcleo e pressione os kettlebells acima da cabeça, estendendo totalmente os braços. Faça uma pausa no topo e abaixe lentamente os kettlebells de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0553.gif', 'hasaneyldrm', '0553'),
  ('b1d7a80a-0000-4000-8000-000000001345'::uuid, null, 'remada com dois braços com kettlebell', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure um kettlebell em cada mão com as palmas voltadas para o corpo. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o núcleo engajado. Puxe os kettlebells em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os kettlebells de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1345.gif', 'hasaneyldrm', '1345'),
  ('b1d7a80a-0000-4000-8000-000000000554'::uuid, null, 'moinho de vento com kettlebell', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'shoulders']::text[], 'kettlebell', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um kettlebell na mão direita acima da cabeça. Gire o pé esquerdo cerca de 45 graus para fora e mantenha o pé direito apontando para a frente. Dobre o tronco para o lado esquerdo, mantendo o braço direito estendido acima da cabeça e os olhos no kettlebell. Abaixe o tronco o máximo que puder, mantendo o braço direito esticado e o braço esquerdo estendido para o lado. Faça uma pausa por um momento e depois retorne à posição inicial empurrando o pé direito e envolvendo os oblíquos. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0554.gif', 'hasaneyldrm', '0554'),
  ('b1d7a80a-0000-4000-8000-000000000555'::uuid, null, 'expulsar, sentar', 'isolation', ARRAY['hamstrings', 'quadriceps']::text[], ARRAY['quadriceps', 'glutes']::text[], 'bodyweight', false, 'Sente-se na beira de um banco ou cadeira com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Incline-se ligeiramente para trás e coloque as mãos na borda do banco ou cadeira para se apoiar. Envolvendo os isquiotibiais, levante os pés do chão e estenda as pernas à sua frente. Faça uma pausa no topo, depois dobre lentamente os joelhos e traga os pés de volta ao corpo. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0555.gif', 'hasaneyldrm', '0555'),
  ('b1d7a80a-0000-4000-8000-000000000558'::uuid, null, 'aumentando os músculos', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Comece pendurado em uma barra pull-up com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Envolva seu núcleo e use um movimento oscilante para gerar impulso. Ao balançar para frente, puxe o peito em direção à barra, usando os dorsais e os bíceps para iniciar o movimento. Continue o movimento ascendente até que seu peito alcance a barra e, em seguida, faça a transição para uma posição de mergulho empurrando a barra para baixo e estendendo os braços. Abaixe-se de volta à posição inicial dobrando os braços e controlando a descida. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0558.gif', 'hasaneyldrm', '0558'),
  ('b1d7a80a-0000-4000-8000-000000003640'::uuid, null, 'flexão de toque no joelho', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante as omoplatas do chão e estenda a mão direita em direção ao joelho esquerdo. Volte à posição inicial e repita, desta vez estendendo a mão esquerda em direção ao joelho direito. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3640.gif', 'hasaneyldrm', '3640'),
  ('b1d7a80a-0000-4000-8000-000000001420'::uuid, null, 'agachamento com salto ajoelhado', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'barbell', false, 'Comece ajoelhando-se no chão com os pés afastados na largura dos quadris e os dedos dos pés apontando para a frente. Segure uma barra na parte superior das costas, apoiando-a nos ombros. Envolva o núcleo e os glúteos e, em seguida, salte explosivamente no ar, estendendo os quadris e os joelhos. Ao pular, empurre os dedos dos pés e estenda totalmente os tornozelos, joelhos e quadris. Pouse suavemente de volta ao chão, dobrando os joelhos para absorver o impacto. Vá imediatamente para a próxima repetição, repetindo o movimento de agachamento com salto.', '/exercise-media/bstrainer/1420.gif', 'hasaneyldrm', '1420'),
  ('b1d7a80a-0000-4000-8000-000000001346'::uuid, null, 'alongamento lateral ajoelhado', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'bodyweight', false, 'Ajoelhe-se no chão com os joelhos afastados na largura do quadril e os dedos dos pés apontando para trás. Estenda os braços acima da cabeça e entrelace os dedos. Mantendo as costas retas, incline-se lentamente para o lado direito, sentindo um alongamento no músculo posterior esquerdo. Mantenha o alongamento por 20 a 30 segundos e depois retorne à posição inicial. Repita o alongamento no lado esquerdo, inclinando-se para a esquerda e sentindo um alongamento no músculo posterior direito. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1346.gif', 'hasaneyldrm', '1346'),
  ('b1d7a80a-0000-4000-8000-000000003239'::uuid, null, 'prancha ajoelhada tap ombro (masculino)', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'bodyweight', false, 'Comece ajoelhado com as mãos no chão, na largura dos ombros. Estenda as pernas atrás de você, apoiando-se na ponta dos pés, e levante o corpo até a posição de prancha. Mantendo o núcleo engajado e os quadris estáveis, levante uma mão do chão e bata no ombro oposto. Retorne a mão ao chão e repita com a outra mão. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3239.gif', 'hasaneyldrm', '3239'),
  ('b1d7a80a-0000-4000-8000-000000003211'::uuid, null, 'flexão de joelhos (masculino)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece ajoelhando-se no chão com as mãos afastadas na largura dos ombros e os dedos apontando para a frente. Estenda as pernas atrás de você, apoiando-se na planta dos pés, de modo que seu corpo forme uma linha reta da cabeça aos calcanhares. Envolva o núcleo e abaixe o corpo em direção ao chão, dobrando os cotovelos, mantendo-os próximos ao corpo. Continue abaixando até que seu peito esteja logo acima do chão e, em seguida, empurre de volta à posição inicial, esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3211.gif', 'hasaneyldrm', '3211'),
  ('b1d7a80a-0000-4000-8000-000000003288'::uuid, null, 'molhos coreanos', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Posicione-se entre duas barras paralelas com os braços estendidos e apoiando o peso do corpo. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3288.gif', 'hasaneyldrm', '3288'),
  ('b1d7a80a-0000-4000-8000-000000003418'::uuid, null, 'l-pull-up', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra pull-up com uma pegada pronada, um pouco mais larga que a largura dos ombros. Pendure-se com os braços totalmente estendidos e o corpo reto. Envolva os dorsais e os bíceps para puxar o corpo em direção à barra, mantendo os cotovelos próximos ao corpo. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3418.gif', 'hasaneyldrm', '3418'),
  ('b1d7a80a-0000-4000-8000-000000003419'::uuid, null, 'eu-sento no chão', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Coloque as mãos no chão ao lado dos quadris, os dedos apontando para frente. Envolva seu núcleo e levante as pernas do chão, mantendo-as retas. Tente deixar as pernas paralelas ao chão, formando um ''L'' com o corpo. Mantenha esta posição o máximo que puder. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3419.gif', 'hasaneyldrm', '3419'),
  ('b1d7a80a-0000-4000-8000-000000000562'::uuid, null, 'mina terrestre 180', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'quadriceps']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra com as duas mãos na frente do peito. Dobre ligeiramente os joelhos e gire o tronco para a direita, balançando a barra em direção ao quadril direito. Ao chegar ao final do movimento, inverta rapidamente o movimento e gire o tronco para a esquerda, balançando a barra para cima e através do corpo em direção ao ombro esquerdo. Continue esse movimento de torção, alternando os lados, pelo número desejado de repetições.', '/exercise-media/bstrainer/0562.gif', 'hasaneyldrm', '0562'),
  ('b1d7a80a-0000-4000-8000-000000003237'::uuid, null, 'elevação lateral de minas terrestres', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'upper back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, apoiando-a na frente dos ombros. Mantendo o núcleo engajado e as costas retas, levante a barra e afaste-a do corpo, elevando-a até a altura dos ombros. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3237.gif', 'hasaneyldrm', '3237'),
  ('b1d7a80a-0000-4000-8000-000000003300'::uuid, null, 'prancha magra', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos afastadas na largura dos ombros e o corpo reto. Envolva seu núcleo e mova lentamente o peso para a frente, passando os ombros pelas mãos. Mantenha os cotovelos ligeiramente dobrados e o corpo reto enquanto se inclina para a frente. Mantenha esta posição por alguns segundos e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3300.gif', 'hasaneyldrm', '3300'),
  ('b1d7a80a-0000-4000-8000-000000002271'::uuid, null, 'gancho esquerdo. boxe', 'isolation', ARRAY['delts', 'biceps']::text[], ARRAY['biceps', 'triceps', 'forearms']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Mantenha a mão esquerda levantada para proteger o rosto e a mão direita perto do queixo. Gire os quadris e gire o pé esquerdo enquanto estende o braço esquerdo para a frente em um movimento de soco. Torça o tronco e envolva os músculos centrais para gerar força no soco. Leve o braço de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/2271.gif', 'hasaneyldrm', '2271'),
  ('b1d7a80a-0000-4000-8000-000000000570'::uuid, null, 'puxada de perna em banco plano', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Sente-se em um banco plano com as pernas estendidas à sua frente. Coloque as mãos no banco ao lado dos quadris para obter apoio. Envolva os abdominais e levante as pernas do chão, aproximando os joelhos do peito. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0570.gif', 'hasaneyldrm', '0570'),
  ('b1d7a80a-0000-4000-8000-000000001576'::uuid, null, 'alongamento dos isquiotibiais da perna para cima', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas. Dobre um joelho e leve-o em direção ao peito, segurando a coxa ou a canela. Estique a perna o máximo possível, mantendo-a elevada. Mantenha o alongamento por 20 a 30 segundos. Repita com a outra perna.', '/exercise-media/bstrainer/1576.gif', 'hasaneyldrm', '1576'),
  ('b1d7a80a-0000-4000-8000-000000002287'::uuid, null, 'leg press alternado com alavanca', 'squat', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', true, 'Ajuste o assento e a plataforma dos pés da máquina de alavanca na posição desejada. Sente-se na máquina com as costas apoiadas no encosto e os pés na plataforma para pés. Coloque as mãos nas alças ou nas laterais da máquina para obter estabilidade. Empurre um pé contra a plataforma, estendendo a perna até que fique quase totalmente reta. Faça uma pausa, depois dobre lentamente a perna e retorne à posição inicial. Repita com a outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/2287.gif', 'hasaneyldrm', '2287'),
  ('b1d7a80a-0000-4000-8000-000000000571'::uuid, null, 'alavanca alternada empunhadura estreita fileira sentada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', true, 'Ajuste a altura do assento e a posição da plataforma para garantir o alinhamento adequado. Sente-se na máquina com as costas retas e os pés apoiados na plataforma. Segure as alças com uma pegada estreita, com as palmas voltadas uma para a outra. Mantenha o peito para cima e os ombros para trás durante todo o exercício. Puxe uma alça em direção ao tronco enquanto mantém a outra alça parada. Aperte as omoplatas no final do movimento. Retorne lentamente a alça à posição inicial e repita com o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0571.gif', 'hasaneyldrm', '0571'),
  ('b1d7a80a-0000-4000-8000-000000000572'::uuid, null, 'barra fixa assistida por alavanca', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a máquina de alavancagem para o nível de resistência desejado. Fique na plataforma dos pés e segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Pendure-se com os braços totalmente estendidos, mantendo o corpo reto. Envolva os músculos das costas e puxe o corpo em direção às alças, conduzindo com o peito. Continue puxando até que o queixo fique acima das alças. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0572.gif', 'hasaneyldrm', '0572'),
  ('b1d7a80a-0000-4000-8000-000000000573'::uuid, null, 'extensão traseira da alavanca', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Ajuste a máquina de acordo com o tamanho do seu corpo e amplitude de movimento. Sente-se na máquina com as costas apoiadas na almofada e os pés protegidos. Coloque as mãos nas alças ou barras de apoio. Envolva seu núcleo e incline-se lentamente para a frente, permitindo que suas costas se arredondem ligeiramente. Pare por um momento na posição inferior, sentindo um alongamento na parte inferior das costas. Usando os músculos das costas, levante lentamente o tronco de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0573.gif', 'hasaneyldrm', '0573'),
  ('b1d7a80a-0000-4000-8000-000000000574'::uuid, null, 'alavanca dobrada sobre a linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Incline-se para a frente na altura dos quadris, mantendo as costas retas e o peito erguido. Puxe a barra em direção à parte inferior do peito, apertando as omoplatas. Faça uma pausa no topo e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0574.gif', 'hasaneyldrm', '0574'),
  ('b1d7a80a-0000-4000-8000-000000003200'::uuid, null, 'linha curvada por alavanca com barra em V', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se de frente para a máquina. Segure a barra em V com uma pegada pronada, mantendo as costas retas e os joelhos levemente flexionados. Puxe a barra em V em direção ao abdômen, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente o peso de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3200.gif', 'hasaneyldrm', '3200'),
  ('b1d7a80a-0000-4000-8000-000000000575'::uuid, null, 'rosca direta de bíceps com alavanca', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com uma pegada supinada, com as palmas voltadas para cima, e mantenha os cotovelos próximos ao corpo. Expire e levante as alças, contraindo o bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente as alças de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0575.gif', 'hasaneyldrm', '0575'),
  ('b1d7a80a-0000-4000-8000-000000002289'::uuid, null, 'alavanca de panturrilha', 'push_h', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Ajuste o assento da máquina de alavancagem para que seus ombros fiquem alinhados com a almofada da alavanca. Coloque os dedos dos pés na almofada da alavanca, com os calcanhares pendurados na borda. Segure as alças ou suportes laterais para estabilidade. Empurre a alavanca para baixo estendendo os tornozelos e contraindo os músculos da panturrilha. Faça uma pausa por um momento na parte inferior do movimento. Retorne lentamente à posição inicial, permitindo que os calcanhares voltem a subir. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2289.gif', 'hasaneyldrm', '2289'),
  ('b1d7a80a-0000-4000-8000-000000000577'::uuid, null, 'alavanca de pressão no peito', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com força e posicione os cotovelos em um ângulo de 90 graus. Empurre as alças para frente até que os braços estejam totalmente estendidos, expirando durante o movimento. Faça uma breve pausa no final do movimento e, em seguida, retorne lentamente à posição inicial, inspirando ao fazer isso. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0577.gif', 'hasaneyldrm', '0577'),
  ('b1d7a80a-0000-4000-8000-000000000576'::uuid, null, 'alavanca de pressão no peito', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com força e posicione os cotovelos em um ângulo de 90 graus. Empurre as alças para frente até que os braços estejam totalmente estendidos, expirando durante o movimento. Faça uma breve pausa no final do movimento e, em seguida, retorne lentamente à posição inicial, inspirando ao fazer isso. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0576.gif', 'hasaneyldrm', '0576'),
  ('b1d7a80a-0000-4000-8000-000000000578'::uuid, null, 'levantamento terra por alavanca', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'machine', false, 'Ajuste a altura do assento e a plataforma dos pés na posição desejada. Sente-se na máquina com as costas apoiadas na almofada e os pés apoiados na plataforma para os pés. Segure as alças ou as laterais do assento para obter estabilidade. Envolva os glúteos e isquiotibiais e empurre os calcanhares para levantar o peso. Mantenha as costas retas e evite curvar os ombros. Estenda totalmente os quadris no topo do movimento, apertando os glúteos. Abaixe o peso de maneira controlada, mantendo a tensão nos glúteos e isquiotibiais. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0578.gif', 'hasaneyldrm', '0578'),
  ('b1d7a80a-0000-4000-8000-000000001300'::uuid, null, 'declínio da alavanca, pressão no peito', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e o encosto da máquina de alavanca para uma posição confortável. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados no chão. Segure as alças com uma pegada pronada e posicione as mãos um pouco mais afastadas do que a largura dos ombros. Empurre as alças para frente e para longe do corpo até que os braços estejam totalmente estendidos. Abaixe lentamente as alças em direção ao peito, mantendo os cotovelos ligeiramente dobrados. Faça uma pausa na parte inferior e empurre as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1300.gif', 'hasaneyldrm', '1300'),
  ('b1d7a80a-0000-4000-8000-000000001253'::uuid, null, 'alavanca de elevação de panturrilha de burro', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste a máquina de alavancagem para a altura adequada ao seu corpo. Posicione-se de frente para a máquina, com os dedos dos pés na plataforma dos pés e os calcanhares pendurados na borda. Coloque as mãos nas alças ou nas barras de suporte para estabilidade. Envolva as panturrilhas e levante os calcanhares o mais alto possível, usando a planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1253.gif', 'hasaneyldrm', '1253'),
  ('b1d7a80a-0000-4000-8000-000000000579'::uuid, null, 'alavanca frontal suspensa', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os joelhos sob as almofadas e os pés apoiados no chão. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Sente-se ereto com o peito levantado e os ombros para trás, mantendo um leve arco na parte inferior das costas. Envolva os dorsais e puxe as alças para baixo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0579.gif', 'hasaneyldrm', '0579'),
  ('b1d7a80a-0000-4000-8000-000000000580'::uuid, null, 'encolher de ombros sem aperto de alavanca', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina de alavanca. Segure as alças com as palmas voltadas para dentro e os braços totalmente estendidos. Mantendo as costas retas, expire e eleve os ombros o mais alto possível. Mantenha a contração por um breve momento, depois inspire e abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0580.gif', 'hasaneyldrm', '0580'),
  ('b1d7a80a-0000-4000-8000-000000001439'::uuid, null, 'encolher de ombros sem aperto de alavanca v. 2', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças ou barras com uma pegada pronada, mantendo os braços retos. Mantendo as costas retas, levante os ombros em direção às orelhas o mais alto possível. Mantenha a contração por um momento e depois abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1439.gif', 'hasaneyldrm', '1439'),
  ('b1d7a80a-0000-4000-8000-000000002288'::uuid, null, 'mãos de pinça de alavanca', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'machine', false, 'Ajuste a altura do assento e segure as alças da máquina de alavanca. Mantenha as costas retas e os pés apoiados no chão. Expire e aperte as alças, contraindo os antebraços. Mantenha a contração por um segundo, depois solte lentamente e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2288.gif', 'hasaneyldrm', '2288'),
  ('b1d7a80a-0000-4000-8000-000000001615'::uuid, null, 'alavanca martelo aperto pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina de alavanca. Coloque os braços na almofada do pregador, garantindo que seu peito esteja pressionado contra ela. Segure as alças com um punho de martelo (palmas voltadas uma para a outra). Mantendo os braços parados, expire e enrole as alças em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1615.gif', 'hasaneyldrm', '1615'),
  ('b1d7a80a-0000-4000-8000-000000000581'::uuid, null, 'alavanca linha alta', 'pull_v', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'rear deltoids']::text[], 'machine', false, 'Ajuste a altura do assento e a plataforma dos pés para uma posição confortável. Sente-se na máquina com o peito apoiado na almofada e os pés apoiados na plataforma. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e envolva seu núcleo. Puxe as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0581.gif', 'hasaneyldrm', '0581'),
  ('b1d7a80a-0000-4000-8000-000000002286'::uuid, null, 'alavanca de extensão de quadril v. 2', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Ajuste a máquina ao seu corpo e sente-se nela com as costas apoiadas no encosto. Coloque os pés nos apoios para os pés e segure as alças para obter estabilidade. Envolva os glúteos e isquiotibiais e empurre os apoios para os pés para estender os quadris e levantar as pernas para trás. Faça uma pausa no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2286.gif', 'hasaneyldrm', '2286'),
  ('b1d7a80a-0000-4000-8000-000000002611'::uuid, null, 'alavanca horizontal one leg press', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', true, 'Ajuste o assento da máquina de forma que seus joelhos fiquem em um ângulo de 90 graus quando seus pés estiverem na plataforma. Sente-se na máquina com as costas apoiadas no encosto e os pés afastados na largura dos ombros na plataforma. Coloque as mãos nas alças ou nas laterais da máquina para obter estabilidade. Afaste a plataforma do corpo estendendo a perna, mantendo as costas apoiadas no encosto. Faça uma pausa por um momento na posição totalmente estendida e, em seguida, dobre lentamente a perna para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/2611.gif', 'hasaneyldrm', '2611'),
  ('b1d7a80a-0000-4000-8000-000000001299'::uuid, null, 'alavanca inclinada no peito', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Ajuste o assento e o encosto da máquina de alavanca para uma posição confortável. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados no chão. Segure as alças com uma pegada pronada e posicione as mãos um pouco mais afastadas do que a largura dos ombros. Empurre as alças para frente e para longe do corpo até que os braços estejam totalmente estendidos. Faça uma pausa por um momento, depois dobre lentamente os cotovelos e abaixe as alças em direção ao peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1299.gif', 'hasaneyldrm', '1299'),
  ('b1d7a80a-0000-4000-8000-000000001479'::uuid, null, 'alavanca inclinada no peito v. 2', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e o ângulo do encosto na máquina de alavanca para uma posição confortável. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados no chão. Segure as alças com uma pegada pronada e posicione as mãos um pouco mais afastadas do que a largura dos ombros. Empurre as alças para frente e para longe do corpo até que os braços estejam totalmente estendidos, mas sem travar os cotovelos. Faça uma pausa por um momento na posição totalmente estendida e, em seguida, dobre lentamente os cotovelos e abaixe as alças em direção ao peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1479.gif', 'hasaneyldrm', '1479'),
  ('b1d7a80a-0000-4000-8000-000000000582'::uuid, null, 'flexão de perna ajoelhada com alavanca', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes']::text[], 'machine', false, 'Ajuste a máquina ao seu corpo e selecione o peso desejado. Ajoelhe-se na máquina voltado para baixo, com os joelhos apoiados na almofada e os pés presos sob as almofadas dos pés. Segure as alças ou as laterais da máquina para estabilidade. Mantendo a parte superior do corpo parada, expire e enrole as pernas em direção aos glúteos, flexionando os joelhos. Faça uma pausa por um momento no início do movimento, apertando os isquiotibiais. Inspire e abaixe lentamente as pernas de volta à posição inicial, estendendo totalmente os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0582.gif', 'hasaneyldrm', '0582'),
  ('b1d7a80a-0000-4000-8000-000000000583'::uuid, null, 'alavanca ajoelhada torção', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os joelhos apoiados nas almofadas e a parte superior do corpo voltada para a frente. Segure as alças ou as laterais da máquina para estabilidade. Mantendo o núcleo engajado, gire o tronco para o lado o máximo que for confortável possível. Faça uma pausa por um momento e depois retorne lentamente à posição inicial. Repita a torção para o lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0583.gif', 'hasaneyldrm', '0583'),
  ('b1d7a80a-0000-4000-8000-000000000584'::uuid, null, 'elevação lateral da alavanca', 'isolation', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'upper back']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com força e mantenha os braços retos. Expire e levante os braços para os lados até ficarem paralelos ao chão. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0584.gif', 'hasaneyldrm', '0584'),
  ('b1d7a80a-0000-4000-8000-000000000585'::uuid, null, 'extensão da perna da alavanca', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Ajuste a altura do assento e o encosto da máquina de acordo com o seu corpo. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados no apoio para os pés. Segure as alças ou barras laterais para estabilidade. Estenda as pernas para a frente esticando os joelhos, levantando o peso. Faça uma pausa por um momento no topo e depois abaixe lentamente o peso de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0585.gif', 'hasaneyldrm', '0585'),
  ('b1d7a80a-0000-4000-8000-000000000586'::uuid, null, 'flexão de perna deitada com alavanca', 'isolation', ARRAY['hamstrings', 'calves']::text[], ARRAY['calves']::text[], 'machine', false, 'Ajuste a máquina ao seu corpo e selecione o peso desejado. Deite-se de bruços na máquina com as pernas esticadas e os calcanhares apoiados na alavanca acolchoada. Segure as alças ou as laterais da máquina para estabilidade. Mantendo a parte superior do corpo parada, expire e levante as pernas o máximo possível, sem levantar os quadris da almofada. Mantenha a posição contraída por uma breve pausa enquanto aperta os isquiotibiais. Inspire e abaixe lentamente a alavanca de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0586.gif', 'hasaneyldrm', '0586'),
  ('b1d7a80a-0000-4000-8000-000000003195'::uuid, null, 'alavanca deitada flexão de duas pernas', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes']::text[], 'machine', true, 'Ajuste a máquina ao seu corpo e sente-se nela com as costas apoiadas no encosto. Coloque as pernas na alavanca, logo acima dos tornozelos. Segure as alças nas laterais da máquina para apoiá-la. Mantendo a parte superior do corpo imóvel, expire e enrole as pernas em direção aos glúteos. Faça uma pausa no topo, inspire e abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3195.gif', 'hasaneyldrm', '3195'),
  ('b1d7a80a-0000-4000-8000-000000000587'::uuid, null, 'prensa militar de alavanca', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper chest']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas no encosto. Segure as alças com uma pegada pronada e posicione as mãos um pouco mais afastadas do que a largura dos ombros. Empurre as alças para cima até que os braços estejam totalmente estendidos, mas não trave os cotovelos. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0587.gif', 'hasaneyldrm', '0587'),
  ('b1d7a80a-0000-4000-8000-000000000588'::uuid, null, 'alavanca punho estreito fileira sentada', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e os apoios para os pés para garantir a forma adequada. Sente-se na máquina com os pés apoiados nos apoios para os pés e os joelhos ligeiramente dobrados. Segure as alças com uma pegada estreita, com as palmas voltadas uma para a outra. Mantenha as costas retas e incline-se ligeiramente para a frente. Puxe as alças em direção ao tronco, apertando as omoplatas. Faça uma pausa por um momento no auge do movimento. Solte lentamente as alças e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0588.gif', 'hasaneyldrm', '0588'),
  ('b1d7a80a-0000-4000-8000-000000000589'::uuid, null, 'alavanca um braço dobrado sobre a linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'barbell', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure uma barra com uma pegada pronada. Incline-se para a frente na altura dos quadris, mantendo as costas retas e a cabeça erguida. Deixe a barra pendurada na sua frente com os braços totalmente estendidos. Puxe a barra em direção ao peito, mantendo os cotovelos próximos ao corpo. Aperte as omoplatas no início do movimento. Abaixe a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0589.gif', 'hasaneyldrm', '0589'),
  ('b1d7a80a-0000-4000-8000-000000001356'::uuid, null, 'alavanca um braço linha alta lateral', 'pull_v', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'machine', true, 'Ajuste a altura do assento e posicione-se de frente para a máquina. Segure a alça com uma mão e mantenha as costas retas. Puxe a alça em direção ao corpo, mantendo o cotovelo próximo ao corpo. Contraia os músculos das costas no início do movimento. Solte lentamente a alça de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1356.gif', 'hasaneyldrm', '1356'),
  ('b1d7a80a-0000-4000-8000-000000001347'::uuid, null, 'alavanca pulldown lateral amplo com um braço', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'machine', true, 'Ajuste a altura do assento e posicione-se na máquina com o peito apoiado na almofada e os pés apoiados no chão. Segure a alça com uma pegada pronada e estenda totalmente o braço, mantendo uma ligeira flexão no cotovelo. Puxe a alça para baixo e através do corpo em direção ao quadril oposto, apertando o músculo posterior na parte inferior do movimento. Retorne lentamente a alça à posição inicial, estendendo totalmente o braço. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1347.gif', 'hasaneyldrm', '1347'),
  ('b1d7a80a-0000-4000-8000-000000000590'::uuid, null, 'alavanca de pressão de ombro com um braço', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', true, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure a alavanca com uma mão e posicione o cotovelo em um ângulo de 90 graus. Pressione a alavanca para cima até que seu braço esteja totalmente estendido acima da cabeça. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a alavanca de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/0590.gif', 'hasaneyldrm', '0590'),
  ('b1d7a80a-0000-4000-8000-000000000591'::uuid, null, 'alavanca overhand tríceps dip', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Ajuste a máquina na altura apropriada e fixe seu corpo na posição. Segure as alças com força e posicione o corpo de forma que os braços fiquem totalmente estendidos. Abaixe o corpo dobrando os cotovelos, mantendo os braços próximos ao corpo. Continue abaixando até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, volte à posição inicial estendendo os cotovelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0591.gif', 'hasaneyldrm', '0591'),
  ('b1d7a80a-0000-4000-8000-000000000592'::uuid, null, 'alavanca pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina de alavanca. Coloque os braços na almofada e segure as alças com uma pegada por baixo. Mantenha as costas retas e os cotovelos posicionados na almofada. Expire e enrole os antebraços em direção aos braços, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0592.gif', 'hasaneyldrm', '0592'),
  ('b1d7a80a-0000-4000-8000-000000001614'::uuid, null, 'alavanca pregador curl v. 2', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os braços apoiados na almofada e o peito contra o suporte. Segure as alças com uma pegada por baixo, um pouco mais afastada que a largura dos ombros. Mantenha os braços parados e expire enquanto enrola as alças em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire enquanto abaixa lentamente as alças de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1614.gif', 'hasaneyldrm', '1614'),
  ('b1d7a80a-0000-4000-8000-000000002285'::uuid, null, 'pulôver de alavanca', 'isolation', ARRAY['lats', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste o assento e as alças da máquina de alavanca para uma posição confortável. Sente-se na máquina com as costas apoiadas na almofada e segure as alças com força. Mantenha os braços ligeiramente flexionados e o núcleo engajado. Puxe lentamente as alças em direção ao peito, apertando os dorsais. Faça uma pausa por um momento no pico da contração e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2285.gif', 'hasaneyldrm', '2285'),
  ('b1d7a80a-0000-4000-8000-000000002736'::uuid, null, 'alavanca reversa punho pulldown lateral', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os joelhos sob as almofadas e os pés apoiados no chão. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Sente-se ereto, com o peito para fora e os ombros para trás, mantendo um leve arco na parte inferior das costas. Puxe as alças para baixo em direção ao peito, conduzindo com os cotovelos e apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2736.gif', 'hasaneyldrm', '2736'),
  ('b1d7a80a-0000-4000-8000-000000001616'::uuid, null, 'alavanca de aperto reverso pregador curl', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina de alavanca. Segure as alças com uma pegada supinada, com as palmas voltadas para cima. Descanse os braços na almofada do pregador, garantindo que os cotovelos estejam totalmente estendidos. Mantendo os braços parados, expire e enrole as alças em direção aos ombros. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente as alças de volta à posição inicial, estendendo totalmente os cotovelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1616.gif', 'hasaneyldrm', '1616'),
  ('b1d7a80a-0000-4000-8000-000000001348'::uuid, null, 'alavanca reverso punho linha vertical', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e a posição da plataforma para garantir o alinhamento adequado. Sente-se na máquina com o peito apoiado na almofada e os pés apoiados na plataforma. Segure as alças com uma pegada supinada, com as palmas voltadas para cima. Mantenha as costas retas e envolva seu núcleo. Puxe as alças em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1348.gif', 'hasaneyldrm', '1348'),
  ('b1d7a80a-0000-4000-8000-000000000593'::uuid, null, 'alavanca de hiperextensão reversa', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'machine', false, 'Ajuste a máquina de alavanca para se ajustar ao seu corpo e prenda os pés nas almofadas. Deite-se de bruços na máquina, com a parte superior do corpo pendurada na borda e os quadris apoiados na almofada. Cruze os braços sobre o peito ou coloque-os atrás da cabeça. Envolva os glúteos e isquiotibiais para levantar as pernas até que fiquem paralelas ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0593.gif', 'hasaneyldrm', '0593'),
  ('b1d7a80a-0000-4000-8000-000000001349'::uuid, null, 'linha de barra em t reversa de alavanca', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e a posição da plataforma na máquina de alavancagem. Sente-se na máquina com o peito apoiado na almofada e os pés apoiados na plataforma. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e envolva seu núcleo. Puxe as alças em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1349.gif', 'hasaneyldrm', '1349'),
  ('b1d7a80a-0000-4000-8000-000000002315'::uuid, null, 'panturrilha rotativa de alavanca', 'isolation', ARRAY['calves', 'soleus']::text[], ARRAY['soleus', 'ankle stabilizers']::text[], 'machine', false, 'Ajuste a altura do assento de forma que os joelhos fiquem ligeiramente flexionados e os pés apoiados na plataforma. Coloque os dedos dos pés na plataforma, com os calcanhares pendurados na borda. Segure as alças ou as laterais da máquina para estabilidade. Empurre a planta dos pés, levantando os calcanhares o mais alto possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2315.gif', 'hasaneyldrm', '2315'),
  ('b1d7a80a-0000-4000-8000-000000002335'::uuid, null, 'prensa de panturrilha sentada com alavanca', 'push_h', ARRAY['calves', 'soleus']::text[], ARRAY['soleus', 'hamstrings']::text[], 'machine', false, 'Ajuste o assento da máquina para que seus ombros fiquem alinhados com a almofada da alavanca. Coloque os dedos dos pés na parte inferior da plataforma e posicione os joelhos sob a alavanca. Segure as alças nas laterais do assento para estabilidade. Pressione a alavanca para baixo estendendo os tornozelos e levantando os calcanhares o mais alto possível. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2335.gif', 'hasaneyldrm', '2335'),
  ('b1d7a80a-0000-4000-8000-000000000594'::uuid, null, 'panturrilha sentada por alavanca', 'isolation', ARRAY['calves', 'soleus']::text[], ARRAY['soleus', 'ankle stabilizers']::text[], 'machine', false, 'Ajuste a altura do assento de forma que os joelhos fiquem ligeiramente flexionados e os pés apoiados na plataforma. Coloque os dedos dos pés na plataforma com os calcanhares pendurados na borda. Segure as alças ou as laterais do assento para obter estabilidade. Empurre a planta dos pés para levantar os calcanhares o mais alto possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0594.gif', 'hasaneyldrm', '0594'),
  ('b1d7a80a-0000-4000-8000-000000001452'::uuid, null, 'crunch sentado por alavanca', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'machine', false, 'Sente-se na máquina de alavanca com as costas apoiadas na almofada e os pés apoiados no chão. Segure as alças ou coloque as mãos nas almofadas laterais para apoio. Envolva seus abdominais e incline-se lentamente para trás, permitindo que a almofada se mova com você. Quando a parte superior do corpo estiver em um ângulo de 45 graus, contraia os abdominais e contraia-se para a frente, trazendo o peito em direção aos joelhos. Faça uma pausa por um momento no topo, depois solte lentamente e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1452.gif', 'hasaneyldrm', '1452'),
  ('b1d7a80a-0000-4000-8000-000000000595'::uuid, null, 'crunch sentado por alavanca (almofada no peito)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'machine', false, 'Ajuste a altura do assento e a posição da almofada torácica de acordo com o seu conforto. Sente-se na máquina com as costas apoiadas na almofada do peito e os pés apoiados no chão. Segure as alças ou barras laterais para estabilidade. Envolva os abdominais e incline-se lentamente para trás, permitindo que a almofada torácica se mova com você. Faça uma pausa na contração máxima, sentindo a tensão no abdômen. Volte lentamente à posição inicial, contraindo os abdominais e levantando-se novamente. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0595.gif', 'hasaneyldrm', '0595'),
  ('b1d7a80a-0000-4000-8000-000000003760'::uuid, null, 'crunch sentado por alavanca v. 2', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'machine', false, 'Sente-se na máquina de alavanca com as costas apoiadas na almofada e os pés presos sob as almofadas. Coloque as mãos nas alças ou nas laterais do assento para apoio. Envolva seus abdominais e lentamente avance, trazendo o peito em direção aos joelhos. Faça uma pausa no início do movimento, contraindo o abdômen. Retorne lentamente à posição inicial, permitindo que suas costas se curvem ligeiramente. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3760.gif', 'hasaneyldrm', '3760'),
  ('b1d7a80a-0000-4000-8000-000000001451'::uuid, null, 'mergulho assentado por alavanca', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento para que seus pés fiquem apoiados no chão e os joelhos formem um ângulo de 90 graus. Segure as alças da máquina de alavancagem com as palmas voltadas para baixo e os braços totalmente estendidos. Abaixe lentamente o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1451.gif', 'hasaneyldrm', '1451'),
  ('b1d7a80a-0000-4000-8000-000000000596'::uuid, null, 'mosca com assento de alavanca', 'push_h', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'trapezius']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com uma pegada pronada e mantenha os cotovelos levemente flexionados. Expire e empurre as alças para frente, juntando-as na frente do peito. Faça uma pausa por um momento, contraindo os músculos do peito. Inspire e retorne lentamente à posição inicial, permitindo que os músculos do peito se alonguem. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0596.gif', 'hasaneyldrm', '0596'),
  ('b1d7a80a-0000-4000-8000-000000003759'::uuid, null, 'alavanca sentada bom dia', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'machine', false, 'Ajuste a altura do assento para que os quadris fiquem ligeiramente mais altos que os joelhos. Sente-se na máquina com as costas apoiadas na almofada e os pés apoiados nos apoios para os pés. Segure as alças ou as laterais do assento para obter estabilidade. Mantendo as costas retas, incline-se lentamente para a frente a partir dos quadris até que a parte superior do corpo fique paralela ao chão. Faça uma pausa por um momento e depois retorne lentamente à posição inicial, empurrando os glúteos e isquiotibiais. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3759.gif', 'hasaneyldrm', '3759'),
  ('b1d7a80a-0000-4000-8000-000000000597'::uuid, null, 'abdução do quadril em alavanca', 'isolation', ARRAY['abductors', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Ajuste a altura do assento para que os joelhos fiquem em um ângulo de 90 graus. Sente-se na máquina com as costas apoiadas no encosto e os pés nos apoios para os pés. Coloque as mãos nas alças laterais para estabilidade. Envolva os abdutores e afaste lentamente as pernas, longe da linha média do corpo. Faça uma pausa no final do movimento e, lentamente, junte as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0597.gif', 'hasaneyldrm', '0597'),
  ('b1d7a80a-0000-4000-8000-000000000598'::uuid, null, 'adução de quadril em posição de alavanca', 'isolation', ARRAY['adductors', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas no encosto. Coloque os pés nos apoios para os pés e segure as alças para obter estabilidade. Envolva os músculos adutores e junte lentamente as pernas, apertando a parte interna das coxas. Faça uma pausa por um momento no pico da contração e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0598.gif', 'hasaneyldrm', '0598'),
  ('b1d7a80a-0000-4000-8000-000000000599'::uuid, null, 'flexão de perna sentada por alavanca', 'isolation', ARRAY['hamstrings', 'calves']::text[], ARRAY['calves']::text[], 'machine', false, 'Ajuste a máquina ao seu corpo e sente-se nela com as costas apoiadas no encosto. Coloque a parte inferior das pernas sob a alavanca acolchoada, logo acima dos tornozelos. Segure as alças nas laterais da máquina para apoiá-la. Mantendo a parte superior das pernas estacionária, expire e enrole as pernas o máximo possível. Mantenha a posição contraída por uma breve pausa enquanto aperta os isquiotibiais. Inspire e abaixe lentamente a alavanca de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0599.gif', 'hasaneyldrm', '0599'),
  ('b1d7a80a-0000-4000-8000-000000000600'::uuid, null, 'flexão de elevação de perna sentada por alavanca', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Sente-se na máquina de alavanca com as costas apoiadas no encosto e os pés nos apoios para os pés. Segure as alças ou barras laterais para estabilidade. Envolva os abdominais e levante lentamente as pernas em direção ao peito, curvando o tronco para a frente ao mesmo tempo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas e o tronco de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0600.gif', 'hasaneyldrm', '0600'),
  ('b1d7a80a-0000-4000-8000-000000000602'::uuid, null, 'mosca reversa com assento de alavanca', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com o peito apoiado na almofada e os pés apoiados no chão. Segure as alças com força e mantenha os braços ligeiramente flexionados. Expire e aperte as omoplatas enquanto puxa as alças para trás e para fora, longe do corpo. Faça uma pausa por um momento no pico da contração, depois inspire e retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0602.gif', 'hasaneyldrm', '0602'),
  ('b1d7a80a-0000-4000-8000-000000000601'::uuid, null, 'mosca reversa com sede em alavanca (empunhadura paralela)', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com o peito apoiado na almofada e os pés apoiados no chão. Segure as alças com uma pegada paralela, com as palmas voltadas uma para a outra, e mantenha os braços levemente flexionados. Expire e aperte as omoplatas enquanto puxa as alças para trás e para fora, longe do corpo. Faça uma pausa por um momento no pico da contração, depois inspire e retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0601.gif', 'hasaneyldrm', '0601'),
  ('b1d7a80a-0000-4000-8000-000000001350'::uuid, null, 'fileira sentada por alavanca', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e os apoios para os pés para uma posição confortável. Sente-se na máquina com o peito apoiado na almofada e os pés nos apoios para os pés. Segure as alças com uma pegada pronada, na largura dos ombros. Mantenha as costas retas e o núcleo engajado. Puxe as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no auge do movimento. Solte lentamente as alças e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1350.gif', 'hasaneyldrm', '1350'),
  ('b1d7a80a-0000-4000-8000-000000001385'::uuid, null, 'agachamento sentado com alavanca para panturrilha na máquina de leg press', 'squat', ARRAY['calves', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste o assento da máquina de leg press de modo que seus joelhos fiquem ligeiramente flexionados quando os pés estiverem na plataforma. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados na plataforma, afastados na largura dos ombros. Coloque os dedos dos pés e a planta dos pés na plataforma, mantendo os calcanhares afastados da borda. Solte as alças de segurança e empurre a plataforma para longe de você, estendendo os joelhos. Quando os joelhos estiverem totalmente estendidos, abaixe lentamente os calcanhares flexionando as panturrilhas. Faça uma pausa por um momento na parte inferior e, em seguida, empurre a plataforma para cima estendendo as panturrilhas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1385.gif', 'hasaneyldrm', '1385'),
  ('b1d7a80a-0000-4000-8000-000000000603'::uuid, null, 'alavanca de pressão de ombro', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas no encosto. Segure as alças com uma pegada pronada e posicione as mãos na altura dos ombros. Empurre as alças para cima até que os braços estejam totalmente estendidos, mas não trave os cotovelos. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0603.gif', 'hasaneyldrm', '0603'),
  ('b1d7a80a-0000-4000-8000-000000000869'::uuid, null, 'alavanca de pressão de ombro v. 2', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'machine', false, 'Ajuste a altura do assento e o encosto da máquina de alavanca para uma posição confortável. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados no chão. Segure as alças da máquina com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Empurre as alças para cima e para frente até que seus braços estejam totalmente estendidos, mas não travados. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0869.gif', 'hasaneyldrm', '0869'),
  ('b1d7a80a-0000-4000-8000-000000002318'::uuid, null, 'alavanca de pressão de ombro v. 3', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'chest']::text[], 'machine', false, 'Ajuste a altura do assento e o encosto da máquina de alavanca para uma posição confortável. Sente-se na máquina com as costas apoiadas no encosto e os pés apoiados no chão. Segure as alças da máquina com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Empurre as alças para cima e para frente até que seus braços estejam totalmente estendidos, mas não travados. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2318.gif', 'hasaneyldrm', '2318'),
  ('b1d7a80a-0000-4000-8000-000000000604'::uuid, null, 'encolher de ombros', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina de alavanca com as costas apoiadas na almofada. Segure as alças com força e mantenha os braços retos. Mantendo as costas retas, levante os ombros em direção às orelhas o mais alto possível. Mantenha a contração por um momento e depois abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0604.gif', 'hasaneyldrm', '0604'),
  ('b1d7a80a-0000-4000-8000-000000000605'::uuid, null, 'elevação de panturrilha em pé com alavanca', 'isolation', ARRAY['calves', 'soleus']::text[], ARRAY['soleus', 'ankle stabilizers']::text[], 'machine', false, 'Ajuste a máquina à sua altura e fique em pé com os pés afastados na largura dos ombros. Coloque os ombros sob as almofadas e segure nas alças para obter estabilidade. Levante os calcanhares o mais alto possível, estendendo os tornozelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0605.gif', 'hasaneyldrm', '0605'),
  ('b1d7a80a-0000-4000-8000-000000003758'::uuid, null, 'pressão torácica em pé com alavanca', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os pés apoiados no chão. Segure as alças com força e posicione as mãos na altura do peito. Empurre as alças para frente até que os braços estejam totalmente estendidos, mantendo os cotovelos levemente flexionados. Faça uma pausa e, em seguida, traga lentamente as alças em direção ao peito, mantendo o controle durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3758.gif', 'hasaneyldrm', '3758'),
  ('b1d7a80a-0000-4000-8000-000000000606'::uuid, null, 'alavanca t barra linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e a posição da plataforma para garantir o alinhamento adequado. Sente-se na máquina com o peito apoiado na almofada e os pés apoiados na plataforma. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e envolva seu núcleo. Puxe as alças em direção ao tronco, apertando as omoplatas. Faça uma pausa por um momento no pico da contração e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0606.gif', 'hasaneyldrm', '0606'),
  ('b1d7a80a-0000-4000-8000-000000001351'::uuid, null, 'linha de punho reverso da barra em t da alavanca', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com o peito apoiado na almofada e os pés apoiados no chão. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e envolva seu núcleo. Puxe as alças em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1351.gif', 'hasaneyldrm', '1351'),
  ('b1d7a80a-0000-4000-8000-000000000607'::uuid, null, 'extensão de tríceps por alavanca', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com força e estenda totalmente os braços à sua frente. Mantendo os braços parados, abaixe lentamente as alças em direção à testa, dobrando os cotovelos. Faça uma pausa na parte inferior e empurre as alças de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0607.gif', 'hasaneyldrm', '0607'),
  ('b1d7a80a-0000-4000-8000-000000001313'::uuid, null, 'linha unilateral de alavanca', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se de frente para a máquina. Segure as alças com força e mantenha as costas retas. Puxe as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no auge do movimento e, em seguida, solte lentamente e estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1313.gif', 'hasaneyldrm', '1313'),
  ('b1d7a80a-0000-4000-8000-000000000609'::uuid, null, 'ponte de Londres', 'isolation', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'biceps', 'forearms']::text[], 'machine', false, 'Prenda a corda em um ponto de ancoragem alto. Fique de costas para o ponto de ancoragem, com os pés afastados na largura dos ombros. Segure a corda com uma pegada pronada, com as palmas voltadas para baixo. Incline-se ligeiramente para a frente, mantendo as costas retas e o núcleo engajado. Puxe a corda em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0609.gif', 'hasaneyldrm', '0609'),
  ('b1d7a80a-0000-4000-8000-000000003013'::uuid, null, 'ponte de glúteos baixa no chão', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'core']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque os braços ao lado do corpo, com as palmas voltadas para baixo. Envolva os glúteos e o núcleo e, em seguida, levante os quadris do chão até que o corpo forme uma linha reta dos joelhos até os ombros. Faça uma pausa na parte superior, apertando os glúteos. Abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3013.gif', 'hasaneyldrm', '3013'),
  ('b1d7a80a-0000-4000-8000-000000001352'::uuid, null, 'curvatura lombar', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Deite-se de bruços com as pernas estendidas e os braços ao lado do corpo. Envolva os glúteos e isquiotibiais e levante lentamente a parte superior do corpo do chão, curvando as costas para cima. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1352.gif', 'hasaneyldrm', '1352'),
  ('b1d7a80a-0000-4000-8000-000000003582'::uuid, null, 'estocada com salto', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura dos ombros. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Empurre com o pé direito e pule no ar, mudando a posição dos pés no ar. Aterrisse suavemente com o pé esquerdo à frente e abaixe imediatamente o corpo em uma posição de estocada. Continue alternando entre estocadas e saltos pelo número desejado de repetições.', '/exercise-media/bstrainer/3582.gif', 'hasaneyldrm', '3582'),
  ('b1d7a80a-0000-4000-8000-000000001688'::uuid, null, 'estocada com torção', 'core', ARRAY['abs', 'quadriceps']::text[], ARRAY['quadriceps', 'glutes', 'hamstrings']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura dos ombros. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Ao avançar, gire o tronco para a direita, aproximando o cotovelo esquerdo do joelho direito. Faça uma pausa por um momento e depois retorne à posição inicial. Repita do outro lado, dando um passo à frente com o pé esquerdo e girando o tronco para a esquerda. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1688.gif', 'hasaneyldrm', '1688'),
  ('b1d7a80a-0000-4000-8000-000000000613'::uuid, null, 'alongamento de quadríceps deitado (lateral)', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas esticadas. Dobre a perna de cima e segure o tornozelo ou pé com a mão. Puxe suavemente o tornozelo ou o pé em direção aos glúteos até sentir um alongamento nos quadríceps. Mantenha o alongamento por 20 a 30 segundos. Solte o alongamento e repita do outro lado.', '/exercise-media/bstrainer/0613.gif', 'hasaneyldrm', '0613'),
  ('b1d7a80a-0000-4000-8000-000000002312'::uuid, null, 'deitado cotovelo no joelho', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolva os abdominais e levante a parte superior do corpo do chão, aproximando o cotovelo direito do joelho esquerdo. Ao mesmo tempo, estenda a perna direita e levante-a do chão. Faça uma pausa por um momento e depois retorne à posição inicial. Repita o movimento, desta vez aproximando o cotovelo esquerdo do joelho direito e estendendo a perna esquerda. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/2312.gif', 'hasaneyldrm', '2312'),
  ('b1d7a80a-0000-4000-8000-000000000620'::uuid, null, 'banco plano com elevação de perna deitada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se em um banco plano com as costas pressionadas contra ele. Coloque as mãos sob os glúteos para obter apoio. Mantenha as pernas retas e juntas e levante-as em direção ao teto. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0620.gif', 'hasaneyldrm', '0620'),
  ('b1d7a80a-0000-4000-8000-000000000865'::uuid, null, 'elevação perna-quadril deitado', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Coloque as mãos sob os glúteos para obter apoio. Envolva seu núcleo e levante as pernas do chão, elevando-as em direção ao teto. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0865.gif', 'hasaneyldrm', '0865'),
  ('b1d7a80a-0000-4000-8000-000000001301'::uuid, null, 'prensa torácica interna da máquina', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com as costas apoiadas na almofada. Segure as alças com força e posicione os cotovelos em um ângulo de 90 graus. Empurre as alças para frente até que os braços estejam totalmente estendidos, expirando durante o movimento. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial, inspirando ao fazer isso. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1301.gif', 'hasaneyldrm', '1301'),
  ('b1d7a80a-0000-4000-8000-000000000624'::uuid, null, 'marcha sentar (parede)', 'isolation', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique de costas contra a parede e com os pés afastados na largura do quadril. Deslize lentamente as costas pela parede até que os joelhos fiquem dobrados em um ângulo de 90 graus. Levante o pé direito do chão e leve o joelho em direção ao peito. Abaixe o pé direito e levante o pé esquerdo do chão, trazendo o joelho em direção ao peito. Continue alternando entre levantar o pé direito e esquerdo pelo número desejado de repetições.', '/exercise-media/bstrainer/0624.gif', 'hasaneyldrm', '0624'),
  ('b1d7a80a-0000-4000-8000-000000001353'::uuid, null, 'recepção de bola medicinal e lançamento para cima', 'pull_h', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma bola medicinal com as duas mãos na altura do peito. Dobre ligeiramente os joelhos e envolva o núcleo. Abaixe o corpo até uma posição de agachamento, mantendo as costas retas e o peito erguido. Estenda explosivamente os quadris e as pernas, ao mesmo tempo que joga a bola medicinal acima da cabeça. Solte a bola no início do movimento e pegue-a na descida. Abaixe o corpo de volta à posição de agachamento e repita o número desejado de repetições.', '/exercise-media/bstrainer/1353.gif', 'hasaneyldrm', '1353'),
  ('b1d7a80a-0000-4000-8000-000000001302'::uuid, null, 'passe de peito com bola medicinal', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando a bola medicinal na altura do peito. Estenda os braços para a frente, empurrando a bola medicinal para longe do peito com força. Ao soltar a bola, prossiga com os braços e o tronco, transferindo o peso do pé de trás para o pé da frente. Pegue a bola quando ela rebater na parede ou no parceiro e repita imediatamente o movimento. Continue pelo número desejado de repetições.', '/exercise-media/bstrainer/1302.gif', 'hasaneyldrm', '1302'),
  ('b1d7a80a-0000-4000-8000-000000001303'::uuid, null, 'impulso no peito com bola medicinal a partir da postura de 3 pontos', 'isolation', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Comece em uma postura de 3 pontos com uma mão na bola medicinal e a outra no chão. Estenda as pernas e posicione o corpo em linha reta. Abaixe o peito em direção ao chão, mantendo as costas retas. Empurre a bola medicinal para longe do corpo, estendendo totalmente o braço. Retorne à posição inicial e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1303.gif', 'hasaneyldrm', '1303'),
  ('b1d7a80a-0000-4000-8000-000000001304'::uuid, null, 'peito de bola medicinal empurrar resposta múltipla', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma bola medicinal na altura do peito. Estenda os braços para a frente, afastando a bola medicinal do peito. Faça uma pausa por um momento e, lentamente, traga a bola medicinal de volta ao peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1304.gif', 'hasaneyldrm', '1304'),
  ('b1d7a80a-0000-4000-8000-000000001305'::uuid, null, 'resposta única de empurrão no peito com bola medicinal', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando a bola medicinal na altura do peito. Estenda os braços para a frente, afastando a bola medicinal do peito. Faça uma pausa por um momento e, lentamente, traga a bola medicinal de volta ao peito. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1305.gif', 'hasaneyldrm', '1305'),
  ('b1d7a80a-0000-4000-8000-000000001312'::uuid, null, 'empurrão no peito com bola medicinal com liberação de corrida', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma bola medicinal na altura do peito. Dê um passo à frente com o pé direito e simultaneamente empurre a bola medicinal para frente, estendendo totalmente os braços. Ao empurrar a bola para frente, solte-a e deixe-a rolar para frente. Corra rapidamente para frente e pegue a bola antes que ela caia no chão. Depois de pegar a bola, traga-a de volta ao peito e repita o movimento com o pé esquerdo à frente. Continue alternando as pernas e repetindo o exercício pelo número desejado de repetições.', '/exercise-media/bstrainer/1312.gif', 'hasaneyldrm', '1312'),
  ('b1d7a80a-0000-4000-8000-000000001701'::uuid, null, 'bola medicinal close grip push up', 'isolation', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Comece em uma posição de prancha alta com as mãos na bola medicinal, na largura dos ombros. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Empurre de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1701.gif', 'hasaneyldrm', '1701'),
  ('b1d7a80a-0000-4000-8000-000000001354'::uuid, null, 'bola medicinal batida acima da cabeça', 'push_v', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando uma bola medicinal com as duas mãos acima da cabeça. Envolva seu núcleo e mantenha as costas retas. Dobre ligeiramente os joelhos e bata com força a bola medicinal no chão à sua frente. Ao bater a bola, use todo o corpo para gerar força, incluindo ombros e núcleo. Pegue a bola no salto e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1354.gif', 'hasaneyldrm', '1354'),
  ('b1d7a80a-0000-4000-8000-000000001750'::uuid, null, 'arremesso de peito supino com bola medicinal', 'pull_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Deite-se de costas em um banco com os joelhos dobrados e os pés apoiados no chão. Segure a bola medicinal com as duas mãos, estendendo os braços acima do peito. Abaixe a bola medicinal em direção ao peito, mantendo os cotovelos próximos ao corpo. Empurre a bola medicinal de forma explosiva para cima, estendendo totalmente os braços e jogando a bola o mais alto possível. Pegue a bola medicinal e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1750.gif', 'hasaneyldrm', '1750'),
  ('b1d7a80a-0000-4000-8000-000000000627'::uuid, null, 'pegada mista, queixo para cima', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra de pull-up com uma pegada por baixo (palmas voltadas para você) e com as mãos um pouco mais afastadas que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e os pés fora do chão. Envolva os músculos das costas e puxe o corpo em direção à barra, liderando com o peito. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial com controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0627.gif', 'hasaneyldrm', '0627'),
  ('b1d7a80a-0000-4000-8000-000000003217'::uuid, null, 'flexão hindu modificada (masculino)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas do que a largura dos ombros e os pés afastados na largura dos quadris. Abaixe o corpo em direção ao chão, dobrando os cotovelos e mantendo o núcleo engajado. Ao abaixar o corpo, mude o peso para trás e levante os quadris em direção ao teto, criando um formato de V invertido com o corpo. Continue abaixando o corpo até que o peito fique logo acima do chão e depois inverta o movimento, empurrando os quadris para baixo e estendendo os braços para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3217.gif', 'hasaneyldrm', '3217'),
  ('b1d7a80a-0000-4000-8000-000000001421'::uuid, null, 'flexão modificada para antebraços', 'isolation', ARRAY['forearms', 'triceps']::text[], ARRAY['triceps', 'chest', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos diretamente sob os ombros e o corpo em linha reta. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Quando os cotovelos estiverem em um ângulo de 90 graus, abaixe os antebraços até o chão, mantendo os cotovelos diretamente sob os ombros. Faça uma pausa por um momento e empurre as palmas das mãos para levantar os antebraços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1421.gif', 'hasaneyldrm', '1421'),
  ('b1d7a80a-0000-4000-8000-000000000628'::uuid, null, 'passeio de monstro', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', false, 'Coloque uma faixa de resistência em volta dos tornozelos. Fique em pé com os pés afastados na largura dos ombros e dobre levemente os joelhos. Dê um passo para o lado com o pé direito, mantendo a tensão na faixa de resistência. Siga com o pé esquerdo, dando um passo para o lado para retornar à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0628.gif', 'hasaneyldrm', '0628'),
  ('b1d7a80a-0000-4000-8000-000000000630'::uuid, null, 'alpinista', 'isolation', ARRAY['cardiovascular system', 'core']::text[], ARRAY['core', 'shoulders', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta. Envolva seu núcleo e traga o joelho direito em direção ao peito, depois mude rapidamente e traga o joelho esquerdo em direção ao peito. Continue alternando as pernas em um movimento de corrida, mantendo os quadris baixos e o núcleo engajado. Mantenha um ritmo constante e respire uniformemente durante todo o exercício. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0630.gif', 'hasaneyldrm', '0630'),
  ('b1d7a80a-0000-4000-8000-000000000631'::uuid, null, 'aumentar os músculos', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'triceps', 'shoulders', 'chest']::text[], 'bodyweight', false, 'Comece pendurado em uma barra suspensa com as palmas voltadas para você e os braços totalmente estendidos. Envolva seu núcleo e puxe seu corpo em direção à barra, liderando com o peito. Ao chegar ao topo do movimento, faça a transição da pegada de modo que as palmas das mãos fiquem voltadas para você. Continue se levantando até que seu peito esteja acima da barra e seus braços estejam totalmente flexionados. Inverta o movimento abaixando-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0631.gif', 'hasaneyldrm', '0631'),
  ('b1d7a80a-0000-4000-8000-000000001401'::uuid, null, 'muscle-up (na barra vertical)', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'triceps', 'forearms']::text[], 'bodyweight', false, 'Comece pendurado em uma barra vertical com as palmas voltadas para você e os braços totalmente estendidos. Envolva seu núcleo e puxe seu corpo em direção à barra, liderando com o peito. Ao se levantar, incline-se ligeiramente para trás e traga os cotovelos para os lados. Continue puxando até que o peito alcance a barra e os cotovelos estejam totalmente flexionados. Faça uma pausa por um momento no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1401.gif', 'hasaneyldrm', '1401'),
  ('b1d7a80a-0000-4000-8000-000000002328'::uuid, null, 'flexão estreita na bola de exercícios', 'pull_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e posicione-se em posição de flexão com as mãos na bola, ligeiramente mais estreitas que a largura dos ombros. Envolva seu núcleo e mantenha seu corpo em linha reta da cabeça aos pés. Abaixe o peito em direção à bola dobrando os cotovelos, mantendo-os próximos ao corpo. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2328.gif', 'hasaneyldrm', '2328'),
  ('b1d7a80a-0000-4000-8000-000000001403'::uuid, null, 'alongamento lateral do pescoço', 'isolation', ARRAY['levator scapulae', 'trapezius']::text[], ARRAY['trapezius', 'sternocleidomastoid']::text[], 'bodyweight', false, 'Fique em pé ou sente-se ereto com os ombros relaxados. Incline a cabeça para o lado, aproximando a orelha do ombro. Mantenha o alongamento por 15 a 30 segundos. Repita do outro lado. Execute 2-4 séries de cada lado.', '/exercise-media/bstrainer/1403.gif', 'hasaneyldrm', '1403'),
  ('b1d7a80a-0000-4000-8000-000000000634'::uuid, null, 'crise negativa', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0634.gif', 'hasaneyldrm', '0634'),
  ('b1d7a80a-0000-4000-8000-000000001495'::uuid, null, 'crunch oblíquo v. 2', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva os abdominais e levante as omoplatas do chão, girando o tronco para o lado. Faça uma pausa por um momento e depois abaixe as omoplatas de volta à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1495.gif', 'hasaneyldrm', '1495'),
  ('b1d7a80a-0000-4000-8000-000000000635'::uuid, null, 'flexões oblíquas no chão', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva os abdominais e levante as omoplatas do chão, girando o tronco para o lado. Faça uma pausa por um momento e depois abaixe as omoplatas de volta ao chão. Repita do outro lado, alternando os lados a cada repetição.', '/exercise-media/bstrainer/0635.gif', 'hasaneyldrm', '0635'),
  ('b1d7a80a-0000-4000-8000-000000000636'::uuid, null, 'rosca martelo com barra olímpica', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé, com os pés afastados na largura dos ombros e segure uma barra olímpica com uma pegada pronada. Deixe a barra pendurada com o braço estendido na frente das coxas, com as palmas voltadas para o corpo. Mantendo os braços parados, expire e enrole os pesos enquanto contrai os bíceps. Continue a levantar a barra até que os bíceps estejam totalmente contraídos e a barra esteja na altura dos ombros. Mantenha a posição contraída por uma breve pausa enquanto aperta o bíceps. Inspire e lentamente comece a abaixar a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0636.gif', 'hasaneyldrm', '0636'),
  ('b1d7a80a-0000-4000-8000-000000000637'::uuid, null, 'extensão olímpica de tríceps com barra', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e segurando a barra com uma pegada pronada. Levante a barra acima da cabeça, estendendo totalmente os braços. Mantendo os braços próximos à cabeça, abaixe lentamente a barra atrás da cabeça, dobrando os cotovelos. Faça uma pausa por um momento e depois estenda os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0637.gif', 'hasaneyldrm', '0637'),
  ('b1d7a80a-0000-4000-8000-000000001355'::uuid, null, 'um braço contra a parede', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'bodyweight', true, 'Fique de frente para uma parede com os pés afastados na largura dos ombros. Estenda um braço à sua frente e coloque a palma da mão contra a parede. Envolva o núcleo e incline o corpo para a frente, mantendo o braço reto e as costas retas. Empurre lentamente contra a parede com a palma da mão, ativando os músculos posteriores. Mantenha a posição por alguns segundos, depois solte e repita com o outro braço.', '/exercise-media/bstrainer/1355.gif', 'hasaneyldrm', '1355'),
  ('b1d7a80a-0000-4000-8000-000000000638'::uuid, null, 'barra fixa com um braço para cima', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', true, 'Fique de frente para uma barra suspensa com os pés afastados na largura dos ombros. Estenda a mão e agarre a barra com uma pegada por baixo, com uma mão segurando a barra e a outra segurando seu pulso para se apoiar. Pendure-se na barra com o braço totalmente estendido, mantendo o corpo reto e o núcleo engajado. Suba em direção à barra dobrando o cotovelo e contraindo os músculos das costas. Continue puxando até que o queixo esteja acima da barra e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de braço e repita.', '/exercise-media/bstrainer/0638.gif', 'hasaneyldrm', '0638'),
  ('b1d7a80a-0000-4000-8000-000000000639'::uuid, null, 'mergulho de um braço', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', true, 'Fique de costas para um banco ou cadeira, com os pés afastados na largura dos ombros. Coloque uma das mãos no banco ou cadeira atrás de você, os dedos apontando para o seu corpo. Estenda as pernas à sua frente, mantendo os calcanhares no chão. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas próximas ao banco ou cadeira. Faça uma pausa na parte inferior e, em seguida, empurre as palmas das mãos para esticar os braços e retornar à posição inicial. Repita pelo número desejado de repetições, depois troque de lado e repita com o outro braço.', '/exercise-media/bstrainer/0639.gif', 'hasaneyldrm', '0639'),
  ('b1d7a80a-0000-4000-8000-000000000640'::uuid, null, 'one arm slam (com medicine ball)', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'back']::text[], 'machine', true, 'Fique em pé com os pés afastados na largura dos ombros, segurando a bola medicinal com uma das mãos na frente da cintura. Dobre ligeiramente os joelhos e envolva o núcleo. Levante a bola medicinal acima da cabeça, estendendo totalmente o braço. Bata a bola medicinal com força no chão, usando o núcleo e os ombros para gerar energia. Pegue a bola medicinal no salto e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0640.gif', 'hasaneyldrm', '0640'),
  ('b1d7a80a-0000-4000-8000-000000001773'::uuid, null, 'fileira de toalha de um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros, os joelhos ligeiramente flexionados e segure uma toalha com uma das mãos. Incline-se para a frente na cintura, mantendo as costas retas e o núcleo engajado. Estenda totalmente o braço, deixando a toalha pendurada na sua frente. Puxe a toalha em direção ao peito, apertando as omoplatas. Faça uma pausa na parte superior e, em seguida, abaixe lentamente a toalha de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de braço.', '/exercise-media/bstrainer/1773.gif', 'hasaneyldrm', '1773'),
  ('b1d7a80a-0000-4000-8000-000000001386'::uuid, null, 'criação de panturrilha de burro com uma perna', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros e os dedos apontando para a frente. Coloque as mãos em uma superfície estável para apoio, como uma parede ou uma barra. Levante uma perna do chão, mantendo o joelho ligeiramente dobrado. Levante o calcanhar o mais alto possível, usando os músculos da panturrilha. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/1386.gif', 'hasaneyldrm', '1386'),
  ('b1d7a80a-0000-4000-8000-000000001387'::uuid, null, 'elevação de panturrilha com uma perna no chão', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura do quadril e coloque as mãos em uma parede ou objeto resistente para manter o equilíbrio. Levante um pé do chão e equilibre-se no outro pé. Levante lentamente o calcanhar do chão, levantando o corpo sobre a planta do pé. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1387.gif', 'hasaneyldrm', '1387'),
  ('b1d7a80a-0000-4000-8000-000000001476'::uuid, null, 'agachamento unilateral', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros. Estenda uma perna para frente, mantendo-a fora do chão. Dobre a perna de apoio e abaixe o corpo como se estivesse sentado em uma cadeira. Mantenha o peito erguido e as costas retas. Empurre o calcanhar para retornar à posição inicial. Repita com a outra perna.', '/exercise-media/bstrainer/1476.gif', 'hasaneyldrm', '1476'),
  ('b1d7a80a-0000-4000-8000-000000000641'::uuid, null, 'otis up', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'machine', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0641.gif', 'hasaneyldrm', '0641'),
  ('b1d7a80a-0000-4000-8000-000000000642'::uuid, null, 'flexão de chute de perna externa', 'push_h', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo as costas retas e o núcleo engajado. Ao empurrar para cima, chute uma perna para o lado, estendendo-a totalmente e envolvendo os glúteos. Retorne a perna à posição inicial e repita a flexão, alternando as pernas a cada repetição. Continue alternando chutes nas pernas e flexões para o número desejado de repetições.', '/exercise-media/bstrainer/0642.gif', 'hasaneyldrm', '0642'),
  ('b1d7a80a-0000-4000-8000-000000000643'::uuid, null, 'alongamento de tríceps acima da cabeça', 'push_v', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'bodyweight', false, 'Fique em pé ou sente-se ereto com os pés afastados na largura dos ombros. Estenda um braço acima da cabeça, dobrando o cotovelo de modo que sua mão alcance a omoplata oposta. Com a outra mão, puxe suavemente o cotovelo do braço estendido em direção ao lado oposto da cabeça, sentindo um alongamento no tríceps. Mantenha o alongamento por 15 a 30 segundos e depois solte. Repita do outro lado.', '/exercise-media/bstrainer/0643.gif', 'hasaneyldrm', '0643'),
  ('b1d7a80a-0000-4000-8000-000000003147'::uuid, null, 'inclinação pélvica', 'core', ARRAY['abs', 'lower back']::text[], ARRAY['lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos ao lado do corpo. Envolva os abdominais e incline a pélvis para cima, pressionando a parte inferior das costas no chão. Mantenha essa posição por alguns segundos, concentrando-se na contração do abdômen. Libere a inclinação e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3147.gif', 'hasaneyldrm', '3147'),
  ('b1d7a80a-0000-4000-8000-000000001422'::uuid, null, 'inclinação pélvica na ponte', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'core']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque os braços ao lado do corpo com as palmas voltadas para baixo. Envolva seus glúteos e músculos centrais. Incline a pélvis para cima, levantando os quadris do chão. Mantenha a posição da ponte por alguns segundos. Abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1422.gif', 'hasaneyldrm', '1422'),
  ('b1d7a80a-0000-4000-8000-000000001388'::uuid, null, 'alongamento fibular', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'machine', false, 'Sente-se no chão com as pernas estendidas à sua frente. Passe a corda em volta da planta do pé e segure as pontas da corda com as mãos. Puxe suavemente a corda em sua direção, flexionando o pé e alongando os músculos da panturrilha. Mantenha o alongamento por 15 a 30 segundos. Libere a tensão da corda e repita o alongamento na outra perna. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1388.gif', 'hasaneyldrm', '1388'),
  ('b1d7a80a-0000-4000-8000-000000003662'::uuid, null, 'flexão de pique para cobra', 'push_h', ARRAY['glutes', 'core']::text[], ARRAY['core', 'shoulders', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Envolva seu núcleo e levante os quadris em direção ao teto, formando um V invertido com seu corpo. Abaixe a parte superior do corpo em direção ao chão, dobrando os cotovelos, mantendo-os próximos ao corpo. Ao abaixar, mova o peso para a frente e faça a transição para a postura da cobra, esticando os braços e levantando o peito. Inverta o movimento dobrando os cotovelos e abaixando o peito em direção ao chão. Empurre com as mãos para retornar à posição do V invertido. Continue o movimento abaixando os quadris em direção ao chão, retornando à posição inicial da flexão. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3662.gif', 'hasaneyldrm', '3662'),
  ('b1d7a80a-0000-4000-8000-000000001306'::uuid, null, 'flexão plyo para cima', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta com as mãos ligeiramente mais afastadas que a largura dos ombros. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo o corpo em linha reta. Empurre-se explosivamente do chão, usando os músculos do peito para impulsionar a parte superior do corpo do chão. Pouse suavemente com as mãos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1306.gif', 'hasaneyldrm', '1306'),
  ('b1d7a80a-0000-4000-8000-000000001687'::uuid, null, 'passo posterior para alcance acima da cabeça', 'core', ARRAY['abs', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'quadriceps', 'shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura do quadril e os braços ao lado do corpo. Dê um passo para trás com o pé direito, pousando na planta do pé. Dobre o joelho esquerdo e abaixe o corpo em uma posição de estocada. Ao descer para a estocada, estenda simultaneamente os braços acima da cabeça. Faça uma pausa por um momento na parte inferior da estocada e, em seguida, retorne à posição inicial empurrando o calcanhar esquerdo e trazendo o pé direito para a frente. Repita o movimento do outro lado, recuando com o pé esquerdo e dobrando o joelho direito. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1687.gif', 'hasaneyldrm', '1687'),
  ('b1d7a80a-0000-4000-8000-000000001389'::uuid, null, 'alongamento tibial posterior', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'machine', false, 'Sente-se no chão com as pernas estendidas à sua frente. Passe a corda em volta da planta do pé e segure as pontas da corda com as mãos. Puxe suavemente a corda em sua direção, flexionando o pé e alongando os músculos da panturrilha. Mantenha o alongamento por 20 a 30 segundos. Libere a tensão da corda e relaxe o pé. Repita o alongamento na outra perna.', '/exercise-media/bstrainer/1389.gif', 'hasaneyldrm', '1389'),
  ('b1d7a80a-0000-4000-8000-000000003119'::uuid, null, 'agachamento penico', 'core', ARRAY['abs', 'quadriceps']::text[], ARRAY['quadriceps', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros, os dedos apontando ligeiramente para fora. Abaixe o corpo dobrando os joelhos e empurrando os quadris para trás, como se estivesse sentado em uma cadeira. Mantenha o peito para cima e as costas retas durante todo o movimento. Abaixe-se até que as coxas fiquem paralelas ao chão ou o mais baixo possível. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3119.gif', 'hasaneyldrm', '3119'),
  ('b1d7a80a-0000-4000-8000-000000003132'::uuid, null, 'agachamento penico com apoio', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros, os dedos apontando ligeiramente para fora. Segure-se em um suporte estável, como uma cadeira ou parede, para manter o equilíbrio. Abaixe o corpo até uma posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Mantenha o peito para cima e as costas retas durante todo o movimento. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3132.gif', 'hasaneyldrm', '3132'),
  ('b1d7a80a-0000-4000-8000-000000000648'::uuid, null, 'energia limpa', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'quadriceps', 'calves']::text[], 'barbell', false, 'Comece com a barra no chão à sua frente, com os pés afastados na largura dos ombros. Abaixe-se e segure a barra com uma pegada pronada, um pouco mais larga que a largura dos ombros. Mantenha as costas retas e o peito erguido enquanto levanta a barra do chão, estendendo os quadris e os joelhos. Quando a barra atingir o meio da coxa, puxe-a explosivamente para cima, encolhendo os ombros e puxando os cotovelos para cima e para os lados. Quando a barra atingir seu ponto mais alto, desça rapidamente por baixo dela, girando os cotovelos e pegando a barra nos ombros em uma posição de agachamento frontal. Fique em pé com a barra, estendendo totalmente os quadris e joelhos. Abaixe a barra de volta à posição inicial, mantendo o controle do peso durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0648.gif', 'hasaneyldrm', '0648'),
  ('b1d7a80a-0000-4000-8000-000000003665'::uuid, null, 'prancha de power point', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'glutes']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta da cabeça aos pés. Envolva seu núcleo e contraia os glúteos para manter uma posição estável. Abaixe o corpo sobre os antebraços, um braço de cada vez, mantendo uma linha reta da cabeça aos pés. Mantenha essa posição pelo tempo desejado, mantendo o núcleo e os glúteos engajados. Para retornar à posição inicial, empurre os antebraços e levante o corpo de volta para uma posição de prancha alta. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3665.gif', 'hasaneyldrm', '3665'),
  ('b1d7a80a-0000-4000-8000-000000003203'::uuid, null, 'meio abdominal de prisioneiro (masculino)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3203.gif', 'hasaneyldrm', '3203'),
  ('b1d7a80a-0000-4000-8000-000000001707'::uuid, null, 'torção propensa na bola de estabilidade', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Comece deitado de bruços sobre uma bola de estabilidade, com os pés afastados na largura dos ombros e os dedos dos pés tocando o chão. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva os músculos centrais e levante lentamente a parte superior do corpo da bola, mantendo as costas retas. Gire o tronco para um lado, aproximando o ombro do quadril. Mantenha os quadris e as pernas estáveis ​​durante todo o movimento. Faça uma pausa por um momento e depois retorne à posição inicial. Repita a rotação para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/1707.gif', 'hasaneyldrm', '1707'),
  ('b1d7a80a-0000-4000-8000-000000000651'::uuid, null, 'barra fixa (aperto neutro)', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com pegada neutra (palmas voltadas uma para a outra) e os braços totalmente estendidos. Envolva seu núcleo e aperte as omoplatas. Puxe o corpo em direção à barra, dobrando os cotovelos e descendo em direção aos quadris. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial com controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0651.gif', 'hasaneyldrm', '0651'),
  ('b1d7a80a-0000-4000-8000-000000000650'::uuid, null, 'pull-in (na bola de estabilidade)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Comece sentando-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Coloque as mãos nas laterais da bola de estabilidade para obter apoio. Envolva os abdominais e role lentamente os quadris para a frente, trazendo os joelhos em direção ao peito. Faça uma pausa por um momento no início do movimento e, em seguida, estenda lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0650.gif', 'hasaneyldrm', '0650'),
  ('b1d7a80a-0000-4000-8000-000000000652'::uuid, null, 'barra fixa', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com as palmas das mãos voltadas para você e os braços totalmente estendidos. Envolva seu núcleo e aperte as omoplatas. Puxe o corpo em direção à barra dobrando os cotovelos e trazendo o peito em direção à barra. Faça uma pausa no início do movimento e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0652.gif', 'hasaneyldrm', '0652'),
  ('b1d7a80a-0000-4000-8000-000000001689'::uuid, null, 'empurrar e puxar peso corporal', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'deltoids']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos um pouco mais afastadas que a largura dos ombros e o corpo em linha reta. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo o corpo reto. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Na posição de flexão, puxe o peito em direção ao chão dobrando os cotovelos, mantendo o corpo reto. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1689.gif', 'hasaneyldrm', '1689'),
  ('b1d7a80a-0000-4000-8000-000000003638'::uuid, null, 'pressione para executar', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos afastadas na largura dos ombros e o corpo em linha reta. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo o corpo reto. Empurre as mãos para estender os braços e retornar à posição inicial. Traga rapidamente um joelho em direção ao peito e, em seguida, troque rapidamente e traga o outro joelho em direção ao peito. Continue alternando os joelhos o mais rápido que puder, mantendo a boa forma. Continue pela duração ou número de repetições desejado.', '/exercise-media/bstrainer/3638.gif', 'hasaneyldrm', '3638'),
  ('b1d7a80a-0000-4000-8000-000000001307'::uuid, null, 'empurrar para cima na bola bosu', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'machine', false, 'Coloque a bola bosu no chão com o lado plano voltado para cima. Posicione-se em posição de flexão com as mãos nas bordas externas da bola bosu. Envolva seu núcleo e abaixe o corpo em direção à bola bosu, dobrando os cotovelos. Empurre-se de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1307.gif', 'hasaneyldrm', '1307'),
  ('b1d7a80a-0000-4000-8000-000000000662'::uuid, null, 'flexão', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'deltoids', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Envolva o núcleo e abaixe o corpo em direção ao chão, dobrando os cotovelos, mantendo o corpo em linha reta. Faça uma pausa por um momento quando seu peito estiver logo acima do solo e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0662.gif', 'hasaneyldrm', '0662'),
  ('b1d7a80a-0000-4000-8000-000000000653'::uuid, null, 'flexão (bola bosu)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'machine', false, 'Coloque a bola bosu no chão com o lado plano voltado para cima. Posicione-se em posição de flexão com as mãos nas bordas externas da bola bosu. Envolva seu núcleo e abaixe o corpo em direção à bola bosu, dobrando os cotovelos. Empurre-se de volta à posição inicial, estendendo os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0653.gif', 'hasaneyldrm', '0653'),
  ('b1d7a80a-0000-4000-8000-000000000655'::uuid, null, 'flexão (na bola de estabilidade)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e posicione-se voltado para baixo com as mãos na bola, afastadas na largura dos ombros. Estenda as pernas para trás, equilibrando-se na ponta dos pés. Envolva o núcleo e abaixe o peito em direção à bola, dobrando os cotovelos, mantendo o corpo em linha reta. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0655.gif', 'hasaneyldrm', '0655'),
  ('b1d7a80a-0000-4000-8000-000000000656'::uuid, null, 'flexão (na bola de estabilidade)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'machine', false, 'Coloque a bola de estabilidade no chão e posicione-se voltado para baixo com as mãos na bola, afastadas na largura dos ombros. Estenda as pernas para trás, equilibrando-se na ponta dos pés. Envolva o núcleo e abaixe o peito em direção à bola, dobrando os cotovelos, mantendo o corpo em linha reta. Faça uma pausa por um momento na parte inferior e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0656.gif', 'hasaneyldrm', '0656'),
  ('b1d7a80a-0000-4000-8000-000000000659'::uuid, null, 'flexão (parede)', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'deltoids']::text[], 'bodyweight', false, 'Fique de frente para uma parede, a cerca de um braço de distância. Coloque as mãos na parede na altura dos ombros, ligeiramente mais afastadas do que a largura dos ombros. Dê um passo para trás alguns metros, mantendo o corpo reto e os pés afastados na largura do quadril. Dobre os cotovelos e abaixe o peito em direção à parede, mantendo o corpo em linha reta. Empurre de volta à posição inicial, esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0659.gif', 'hasaneyldrm', '0659'),
  ('b1d7a80a-0000-4000-8000-000000000658'::uuid, null, 'flexão (parede) v. 2', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Fique de frente para uma parede, a cerca de um braço de distância. Coloque as mãos na parede na altura dos ombros, ligeiramente mais afastadas do que a largura dos ombros. Dê um passo para trás com os pés, mantendo-os afastados na largura dos quadris. Envolva seu núcleo e mantenha seu corpo em linha reta da cabeça aos calcanhares. Dobre os cotovelos e abaixe o peito em direção à parede, mantendo o corpo reto. Faça uma pausa por um momento e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0658.gif', 'hasaneyldrm', '0658'),
  ('b1d7a80a-0000-4000-8000-000000000660'::uuid, null, 'push-up close-grip com halteres', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'dumbbell', false, 'Comece em uma posição de flexão com as mãos juntas, diretamente sob os ombros. Segure um haltere em cada mão, apoiando-os no chão. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0660.gif', 'hasaneyldrm', '0660'),
  ('b1d7a80a-0000-4000-8000-000000000661'::uuid, null, 'flexão de perna interna', 'push_h', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo as costas retas e o núcleo engajado. Ao empurrar para cima, levante uma perna do chão e chute-a para o lado, mantendo-a reta. Abaixe a perna novamente e repita a flexão, depois mude para a outra perna. Continue alternando chutes nas pernas com cada repetição de flexão.', '/exercise-media/bstrainer/0661.gif', 'hasaneyldrm', '0661'),
  ('b1d7a80a-0000-4000-8000-000000000663'::uuid, null, 'bola medicinal para flexões', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'machine', false, 'Comece em uma posição de prancha alta com as mãos na bola medicinal, na largura dos ombros. Envolva o núcleo e abaixe o corpo em direção ao chão, dobrando os cotovelos, mantendo as costas retas. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0663.gif', 'hasaneyldrm', '0663'),
  ('b1d7a80a-0000-4000-8000-000000001467'::uuid, null, 'flexão de braços', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha com os antebraços no chão e os cotovelos diretamente abaixo dos ombros. Envolva seu núcleo e mantenha seu corpo em linha reta da cabeça aos pés. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1467.gif', 'hasaneyldrm', '1467'),
  ('b1d7a80a-0000-4000-8000-000000003145'::uuid, null, 'flexão mais', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas do que a largura dos ombros e o corpo em linha reta da cabeça aos calcanhares. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Quando o peito estiver logo acima do solo, empurre as mãos para estender os braços e levantar a parte superior do corpo. No início do movimento, prolongue as omoplatas empurrando a parte superior das costas em direção ao teto. Faça uma pausa por um momento e depois inverta o movimento retraindo as omoplatas e abaixando o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3145.gif', 'hasaneyldrm', '3145'),
  ('b1d7a80a-0000-4000-8000-000000000664'::uuid, null, 'flexão para prancha lateral', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos afastadas na largura dos ombros e o corpo em linha reta. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo o núcleo engajado. Empurre de volta para a posição inicial. Transfira o peso para a mão esquerda e gire o corpo para a direita, levantando o braço direito em direção ao teto. Mantenha a posição da prancha lateral por alguns segundos e depois retorne à posição inicial. Repita a flexão e a prancha lateral no lado oposto. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0664.gif', 'hasaneyldrm', '0664'),
  ('b1d7a80a-0000-4000-8000-000000003533'::uuid, null, 'quádruplos', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Abaixe o corpo dobrando os joelhos e empurrando os quadris para trás, como se estivesse sentado em uma cadeira. Mantenha o peito erguido e as costas retas. Abaixe-se até que as coxas fiquem paralelas ao chão. Empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3533.gif', 'hasaneyldrm', '3533'),
  ('b1d7a80a-0000-4000-8000-000000003201'::uuid, null, 'quarto de abdominais', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3201.gif', 'hasaneyldrm', '3201'),
  ('b1d7a80a-0000-4000-8000-000000003552'::uuid, null, 'pés rápidos v. 2', 'isolation', ARRAY['quads', 'calves']::text[], ARRAY['calves', 'hamstrings']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços ao lado do corpo. Comece movendo rapidamente os pés para cima e para baixo, como se estivesse correndo sem sair do lugar. Mantenha seus movimentos rápidos e leves, concentrando-se em permanecer na planta dos pés. Continue pela duração ou número de repetições desejado.', '/exercise-media/bstrainer/3552.gif', 'hasaneyldrm', '3552'),
  ('b1d7a80a-0000-4000-8000-000000000666'::uuid, null, 'levantar flexão de braço único', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', true, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Estenda um braço para o lado, paralelo ao chão. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo as costas retas e o núcleo engajado. Empurre de volta à posição inicial, usando os músculos do peito para levantar o corpo. Repita com o outro braço estendido.', '/exercise-media/bstrainer/0666.gif', 'hasaneyldrm', '0666'),
  ('b1d7a80a-0000-4000-8000-000000000668'::uuid, null, 'ponte de declínio traseiro', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'bodyweight', false, 'Deite-se de costas com os pés apoiados no chão e os joelhos dobrados. Coloque os braços ao lado do corpo com as palmas voltadas para baixo. Envolva os glúteos e isquiotibiais e levante os quadris do chão até que o corpo forme uma linha reta dos joelhos até os ombros. Mantenha essa posição por alguns segundos e depois abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0668.gif', 'hasaneyldrm', '0668'),
  ('b1d7a80a-0000-4000-8000-000000000669'::uuid, null, 'alongamento do deltóide posterior', 'isolation', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Estenda o braço direito sobre o peito, colocando a mão esquerda no cotovelo direito. Puxe suavemente o braço direito em direção ao ombro esquerdo, sentindo um alongamento no ombro direito. Mantenha o alongamento por 15 a 30 segundos e depois solte. Repita do outro lado.', '/exercise-media/bstrainer/0669.gif', 'hasaneyldrm', '0669'),
  ('b1d7a80a-0000-4000-8000-000000000670'::uuid, null, 'pull-up traseiro', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra pull-up com uma pegada pronada, um pouco mais larga que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo reto. Envolva os músculos das costas e puxe o corpo em direção à barra, mantendo os cotovelos próximos ao corpo. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0670.gif', 'hasaneyldrm', '0670'),
  ('b1d7a80a-0000-4000-8000-000000001582'::uuid, null, 'pose do dedão do pé reclinado com corda', 'isolation', ARRAY['hamstrings', 'calves']::text[], ARRAY['calves', 'glutes']::text[], 'machine', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Passe a corda em volta da planta do pé direito e segure as pontas da corda com as mãos. Levante lentamente a perna direita em direção ao peito, mantendo o joelho reto e o pé flexionado. Mantenha o alongamento por alguns segundos e, em seguida, abaixe lentamente a perna de volta à posição inicial. Repita com a perna esquerda. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/1582.gif', 'hasaneyldrm', '1582'),
  ('b1d7a80a-0000-4000-8000-000000003236'::uuid, null, 'banda de resistência impulsos de quadril sobre os joelhos (feminino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'machine', false, 'Comece ajoelhando-se no chão com os joelhos afastados na largura dos quadris e os pés flexionados. Enrole a faixa de resistência em volta das coxas, logo acima dos joelhos. Coloque as mãos nos quadris ou estenda-as à sua frente para manter o equilíbrio. Envolva seus glúteos e músculos centrais. Empurre os quadris para a frente e contraia os glúteos enquanto levanta os joelhos do chão, estendendo os quadris até que as coxas fiquem paralelas ao chão. Mantenha a posição por um momento e depois abaixe lentamente os joelhos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3236.gif', 'hasaneyldrm', '3236'),
  ('b1d7a80a-0000-4000-8000-000000003007'::uuid, null, 'extensão de perna com faixa de resistência', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Prenda a faixa de resistência a um ponto de ancoragem resistente e prenda-a ao redor do tornozelo. Fique de frente para o ponto de ancoragem com os pés afastados na largura dos ombros. Mantendo o núcleo engajado e a parte superior do corpo estável, estenda a perna à sua frente. Faça uma pausa por um momento no topo e, em seguida, retorne lentamente a perna à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/3007.gif', 'hasaneyldrm', '3007'),
  ('b1d7a80a-0000-4000-8000-000000003123'::uuid, null, 'faixa de resistência rosca bíceps sentada', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Sente-se em uma cadeira ou banco com as costas retas e os pés apoiados no chão. Segure a faixa de resistência com uma pegada supinada, com as palmas voltadas para cima e os braços estendidos ao lado do corpo. Mantendo os braços parados, expire e enrole a faixa de resistência em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a faixa de resistência de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3123.gif', 'hasaneyldrm', '3123'),
  ('b1d7a80a-0000-4000-8000-000000003124'::uuid, null, 'faixa de resistência para prensa torácica sentada', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Sente-se em uma cadeira ou banco com as costas retas e os pés apoiados no chão. Segure as alças da faixa de resistência em cada mão, com as palmas voltadas para baixo e os cotovelos dobrados em um ângulo de 90 graus. Estenda os braços para a frente, afastando a faixa de resistência do peito. Faça uma pausa no final do movimento e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3124.gif', 'hasaneyldrm', '3124'),
  ('b1d7a80a-0000-4000-8000-000000003006'::uuid, null, 'faixa de resistência abdução de quadril sentado', 'isolation', ARRAY['abductors', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Sente-se em uma cadeira ou banco com as costas retas e os pés apoiados no chão. Enrole a faixa de resistência em volta das coxas, logo acima dos joelhos. Coloque as mãos nas laterais da cadeira ou banco para se apoiar. Envolva os abdutores (músculos externos da coxa) e afaste lentamente os joelhos, contra a resistência da faixa. Faça uma pausa no final do movimento e, lentamente, junte os joelhos novamente. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3006.gif', 'hasaneyldrm', '3006'),
  ('b1d7a80a-0000-4000-8000-000000003122'::uuid, null, 'faixa de resistência para ombros sentados', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Sente-se em uma cadeira ou banco com as costas retas e os pés apoiados no chão. Segure a faixa de resistência com as duas mãos, com as palmas voltadas para a frente, e leve-a até a altura dos ombros. Pressione a faixa acima da cabeça, estendendo totalmente os braços. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a faixa até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3122.gif', 'hasaneyldrm', '3122'),
  ('b1d7a80a-0000-4000-8000-000000003144'::uuid, null, 'faixa de resistência sentado na fileira de trás', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'machine', false, 'Sente-se no chão com as pernas estendidas e passe a faixa de resistência em volta dos pés. Segure as pontas da faixa de resistência com as mãos, com as palmas voltadas uma para a outra. Mantenha as costas retas e incline-se ligeiramente para trás, envolvendo o núcleo. Puxe a faixa de resistência em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no topo, depois libere lentamente a tensão e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3144.gif', 'hasaneyldrm', '3144'),
  ('b1d7a80a-0000-4000-8000-000000000872'::uuid, null, 'crise reversa', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os braços estendidos ao longo do corpo. Dobre os joelhos e levante os pés do chão, deixando as coxas perpendiculares ao chão. Contraia o abdômen e levante os quadris do chão, aproximando os joelhos do peito. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0872.gif', 'hasaneyldrm', '0872'),
  ('b1d7a80a-0000-4000-8000-000000000672'::uuid, null, 'mergulho reverso', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Posicione-se entre duas barras paralelas com os braços totalmente estendidos e o corpo reto. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0672.gif', 'hasaneyldrm', '0672'),
  ('b1d7a80a-0000-4000-8000-000000000673'::uuid, null, 'máquina de aderência reversa lat pulldown', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os joelhos sob as almofadas e os pés apoiados no chão. Segure as alças com uma pegada por baixo, um pouco mais afastada que a largura dos ombros. Sente-se ereto, com o peito para fora e os ombros para trás, mantendo um leve arco na parte inferior das costas. Puxe as alças para baixo em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento na parte inferior do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0673.gif', 'hasaneyldrm', '0673'),
  ('b1d7a80a-0000-4000-8000-000000000674'::uuid, null, 'pull-up com pegada reversa', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra pull-up com uma pegada por baixo, com as mãos na largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo reto. Envolva os músculos das costas e puxe o corpo em direção à barra, liderando com o peito. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0674.gif', 'hasaneyldrm', '0674'),
  ('b1d7a80a-0000-4000-8000-000000000675'::uuid, null, 'hiperextensão reversa (na bola de estabilidade)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'machine', false, 'Deite-se de bruços sobre uma bola de estabilidade, com os quadris apoiados na bola e as pernas estendidas para trás. Coloque as mãos no chão à sua frente para obter estabilidade. Envolvendo os glúteos e isquiotibiais, levante as pernas em direção ao teto o mais alto que puder. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0675.gif', 'hasaneyldrm', '0675'),
  ('b1d7a80a-0000-4000-8000-000000001423'::uuid, null, 'hiper reverso em bancada plana', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'bodyweight', false, 'Deite-se de bruços em um banco plano, com os quadris na borda e as pernas penduradas para fora do banco. Segure-se no banco para estabilidade. Mantendo as pernas retas, levante-as em direção ao teto o mais alto que puder. Contraia os glúteos no início do movimento. Abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1423.gif', 'hasaneyldrm', '1423'),
  ('b1d7a80a-0000-4000-8000-000000003663'::uuid, null, 'prancha reversa com elevação de perna', 'core', ARRAY['abs', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'shoulders']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente e as mãos apoiadas no chão atrás de você, os dedos apontando para os pés. Pressione as mãos e levante os quadris do chão, ficando em uma posição reversa de prancha. Envolva seu núcleo e levante uma perna do chão, estendendo-a em direção ao teto. Segure por um momento e depois abaixe a perna novamente. Repita com a outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/3663.gif', 'hasaneyldrm', '3663'),
  ('b1d7a80a-0000-4000-8000-000000000677'::uuid, null, 'quedas do anel', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Comece pendurando-se nas argolas com os braços totalmente estendidos e o corpo reto. Abaixe o corpo dobrando os cotovelos até que os ombros fiquem abaixo dos cotovelos. Empurre-se de volta à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0677.gif', 'hasaneyldrm', '0677'),
  ('b1d7a80a-0000-4000-8000-000000002571'::uuid, null, 'trecho de sapo balançando', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', false, 'Comece ajoelhando-se no chão com os joelhos afastados na largura do quadril. Coloque as mãos no chão à sua frente para obter apoio. Incline-se lentamente para a frente, transferindo o peso para as mãos e estendendo as pernas para trás. Mantenha as costas retas e envolva os glúteos enquanto empurra os quadris para trás e para cima em direção ao teto. Mantenha essa posição por alguns segundos, sentindo um alongamento nos glúteos. Retorne lentamente à posição inicial dobrando os joelhos e abaixando os quadris. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2571.gif', 'hasaneyldrm', '2571'),
  ('b1d7a80a-0000-4000-8000-000000000678'::uuid, null, 'pull-up pull-up rochoso', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Fique na frente de uma barra suspensa com os pés afastados na largura dos ombros. Estenda a mão e agarre a barra com uma pegada pronada, um pouco mais larga que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo reto. Envolva os músculos das costas e puxe o corpo em direção à barra, liderando com o peito. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0678.gif', 'hasaneyldrm', '0678'),
  ('b1d7a80a-0000-4000-8000-000000002208'::uuid, null, 'alongamento de rolo para trás', 'isolation', ARRAY['spine', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Comece sentando no chão com as pernas estendidas à sua frente. Coloque o rolo perpendicular ao corpo, logo abaixo dos glúteos. Role lentamente o corpo para trás, permitindo que o rolo suba pelas costas. Continue rolando até que o rolo alcance a parte superior das costas. Faça uma pausa por um momento e depois volte lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2208.gif', 'hasaneyldrm', '2208'),
  ('b1d7a80a-0000-4000-8000-000000002204'::uuid, null, 'serra de rolo', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'core']::text[], 'machine', false, 'Comece em uma posição de prancha com os antebraços no rolo e o corpo em linha reta. Envolva seu núcleo e role lentamente o rolo para frente, estendendo seu corpo o máximo que puder enquanto mantém o controle. Faça uma pausa por um momento no ponto mais distante e, em seguida, role lentamente o rolo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2204.gif', 'hasaneyldrm', '2204'),
  ('b1d7a80a-0000-4000-8000-000000002205'::uuid, null, 'alongamento lateral do quadril com rolo', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'machine', false, 'Comece ajoelhando-se no chão com o rolo posicionado sob os quadris. Coloque as mãos no rolo para apoio. Role lentamente o rolo para frente, estendendo os quadris e alongando os glúteos. Mantenha o alongamento por alguns segundos e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2205.gif', 'hasaneyldrm', '2205'),
  ('b1d7a80a-0000-4000-8000-000000002202'::uuid, null, 'alongamento de quadril com rolo', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'machine', false, 'Comece sentando no chão com as pernas estendidas à sua frente. Coloque o rolo sob os glúteos, logo acima dos joelhos. Incline-se para trás e coloque as mãos no chão atrás de você para se apoiar. Envolva os glúteos e role lentamente o rolo para frente, dobrando os joelhos e trazendo-os em direção ao peito. Faça uma pausa no final do movimento, sentindo um alongamento nos glúteos. Role lentamente o rolo de volta à posição inicial, estendendo as pernas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2202.gif', 'hasaneyldrm', '2202'),
  ('b1d7a80a-0000-4000-8000-000000002206'::uuid, null, 'trituração reversa do rolo', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Deite-se de costas com os braços estendidos acima da cabeça e as pernas esticadas à sua frente. Coloque o rolo entre os pés e segure-o com os dedos dos pés. Envolvendo os abdominais, levante as pernas do chão e dobre os joelhos em direção ao peito, rolando o rolo em direção ao corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial, rolando o rolo para longe do corpo. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2206.gif', 'hasaneyldrm', '2206'),
  ('b1d7a80a-0000-4000-8000-000000002203'::uuid, null, 'retrator depressor e flexor de ombro sentado com rolo', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'machine', false, 'Sente-se em uma superfície plana com as pernas estendidas à sua frente. Segure o rolo com as duas mãos, com as palmas voltadas para baixo, e coloque-o nas coxas. Incline-se ligeiramente para a frente e role o rolo para longe do corpo, estendendo os braços à sua frente. Faça uma pausa e, em seguida, role lentamente o rolo de volta em direção ao corpo, dobrando os braços e trazendo o rolo de volta às coxas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2203.gif', 'hasaneyldrm', '2203'),
  ('b1d7a80a-0000-4000-8000-000000002209'::uuid, null, 'retrator depressor e flexor de ombro de perna única sentado em rolo', 'isolation', ARRAY['pectorals', 'deltoids']::text[], ARRAY['deltoids', 'triceps']::text[], 'machine', true, 'Sente-se em uma superfície plana com as pernas estendidas à sua frente. Segure o rolo com as duas mãos, com as palmas voltadas para baixo, e coloque-o nas coxas. Incline-se ligeiramente para trás e envolva os músculos centrais. Levante o rolo até a altura dos ombros, mantendo os braços retos. Abaixe lentamente o rolo de volta às coxas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2209.gif', 'hasaneyldrm', '2209'),
  ('b1d7a80a-0000-4000-8000-000000002207'::uuid, null, 'trecho lateral do rolo', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure o rolo com as duas mãos na frente do corpo. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Estenda os braços para a frente e role o rolo em direção aos pés, sentindo um alongamento nas costas. Mantenha o alongamento por alguns segundos e, em seguida, role lentamente o rolo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2207.gif', 'hasaneyldrm', '2207'),
  ('b1d7a80a-0000-4000-8000-000000000680'::uuid, null, 'escalada em corda', 'isolation', ARRAY['upper back', 'forearms']::text[], ARRAY['forearms', 'biceps', 'shoulders']::text[], 'machine', false, 'Fique de frente para a corda com os pés afastados na largura dos ombros. Segure a corda com as duas mãos, com as palmas voltadas para você. Dobre ligeiramente os joelhos e envolva o núcleo. Comece a subir pela corda alternando movimentos de mão sobre mão. Use as pernas para auxiliar no movimento ascendente. Continue subindo até chegar à altura desejada ou ao topo da corda. Para descer, inverta o movimento mão-a-mão enquanto controla a descida. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0680.gif', 'hasaneyldrm', '0680'),
  ('b1d7a80a-0000-4000-8000-000000000685'::uuid, null, 'correr', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura do quadril. Envolva seu núcleo e mantenha a parte superior do corpo relaxada. Comece a correr sem sair do lugar, levantando os joelhos em direção ao peito e pousando suavemente na planta dos pés. Mantenha um ritmo constante e continue correndo pela duração ou distância desejada. Lembre-se de respirar profundamente e manter uma boa postura durante todo o exercício.', '/exercise-media/bstrainer/0685.gif', 'hasaneyldrm', '0685'),
  ('b1d7a80a-0000-4000-8000-000000000684'::uuid, null, 'executar (equipamento)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura do quadril. Envolva seu núcleo e mantenha a parte superior do corpo relaxada. Comece a correr sem sair do lugar, levantando os joelhos em direção ao peito e pousando suavemente na planta dos pés. Mantenha um ritmo constante e continue correndo pela duração ou distância desejada. Lembre-se de respirar profundamente e manter uma boa postura durante todo o exercício.', '/exercise-media/bstrainer/0684.gif', 'hasaneyldrm', '0684'),
  ('b1d7a80a-0000-4000-8000-000000001585'::uuid, null, 'alongamento dos corredores', 'isolation', ARRAY['hamstrings', 'calves']::text[], ARRAY['calves', 'quadriceps']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura do quadril. Dê um passo à frente com o pé direito, mantendo o pé esquerdo plantado. Dobre o joelho direito e abaixe o corpo, mantendo a perna esquerda esticada. Coloque as mãos na coxa direita para apoio. Mantenha o alongamento por 20 a 30 segundos, depois troque de lado e repita.', '/exercise-media/bstrainer/1585.gif', 'hasaneyldrm', '1585'),
  ('b1d7a80a-0000-4000-8000-000000000687'::uuid, null, 'torção russa', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Sente-se no chão com os joelhos dobrados e os pés apoiados no chão. Incline-se ligeiramente para trás, mantendo as costas retas e o núcleo engajado. Mantenha as mãos juntas na frente do peito ou segure um peso, se desejar. Levante os pés do chão, equilibrando-se nos ísquios. Gire o tronco para a direita, trazendo as mãos ou o peso para o lado direito do corpo. Faça uma pausa por um momento e depois gire o tronco para a esquerda, trazendo as mãos ou o peso para o lado esquerdo do corpo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0687.gif', 'hasaneyldrm', '0687'),
  ('b1d7a80a-0000-4000-8000-000000003012'::uuid, null, 'escápula mergulha', 'push_h', ARRAY['traps', 'rhomboids']::text[], ARRAY['rhomboids', 'deltoids']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os braços estendidos à sua frente. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Abaixe o corpo dobrando os cotovelos e retraindo as omoplatas, como se estivesse tentando apertar um lápis entre elas. Faça uma pausa por um momento na parte inferior e, em seguida, empurre as mãos para estender os cotovelos e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3012.gif', 'hasaneyldrm', '3012'),
  ('b1d7a80a-0000-4000-8000-000000003021'::uuid, null, 'flexão de escápula', 'push_h', ARRAY['serratus anterior', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta. Abaixe o peito em direção ao chão, mantendo os cotovelos próximos ao corpo. Ao abaixar, aperte as omoplatas e empurre o peito para a frente. Faça uma pausa por um momento na parte inferior e depois empurre de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3021.gif', 'hasaneyldrm', '3021'),
  ('b1d7a80a-0000-4000-8000-000000000688'::uuid, null, 'flexão escapular', 'pull_v', ARRAY['traps', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'bodyweight', false, 'Comece pendurado em uma barra suspensa com as palmas voltadas para você e os braços totalmente estendidos. Retraia as omoplatas puxando-as para baixo e para trás. Envolva os músculos das costas e puxe o corpo em direção à barra, concentrando-se em apertar as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0688.gif', 'hasaneyldrm', '0688'),
  ('b1d7a80a-0000-4000-8000-000000003219'::uuid, null, 'saltos de tesoura (masculino)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Salte do chão e cruze simultaneamente a perna direita na frente da perna esquerda. Ao pousar, troque rapidamente de perna, cruzando a perna esquerda na frente da direita. Continue alternando as pernas e saltando o mais rápido possível. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3219.gif', 'hasaneyldrm', '3219'),
  ('b1d7a80a-0000-4000-8000-000000001390'::uuid, null, 'alongamento de panturrilha sentado (masculino)', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Sente-se na beirada de uma cadeira ou banco com os pés apoiados no chão. Estenda uma perna esticada à sua frente, mantendo o calcanhar no chão. Incline-se ligeiramente para a frente, sentindo um alongamento no músculo da panturrilha. Mantenha o alongamento por 20 a 30 segundos. Troque as pernas e repita o alongamento.', '/exercise-media/bstrainer/1390.gif', 'hasaneyldrm', '1390'),
  ('b1d7a80a-0000-4000-8000-000000001424'::uuid, null, 'alongamento de glúteo sentado', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Dobre o joelho direito e cruze o tornozelo direito sobre a coxa esquerda. Coloque a mão direita no chão atrás de você para apoio. Com a mão esquerda, pressione suavemente o joelho direito para aprofundar o alongamento. Mantenha o alongamento por 30 segundos a 1 minuto. Troque de lado e repita.', '/exercise-media/bstrainer/1424.gif', 'hasaneyldrm', '1424'),
  ('b1d7a80a-0000-4000-8000-000000000689'::uuid, null, 'elevação de perna sentada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Sente-se em um banco plano com as costas retas e os pés apoiados no chão. Coloque as mãos nas laterais do banco para apoio. Mantendo as pernas retas, levante-as lentamente à sua frente até que fiquem paralelas ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0689.gif', 'hasaneyldrm', '0689'),
  ('b1d7a80a-0000-4000-8000-000000000690'::uuid, null, 'alongamento lombar sentado', 'isolation', ARRAY['lats', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Sente-se na beirada de uma cadeira com os pés apoiados no chão. Coloque as mãos nas coxas ou nas laterais da cadeira para se apoiar. Incline-se lentamente para a frente a partir dos quadris, mantendo as costas retas. Sinta o alongamento na parte inferior das costas e segure por 20 a 30 segundos. Retorne lentamente à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/0690.gif', 'hasaneyldrm', '0690'),
  ('b1d7a80a-0000-4000-8000-000000002567'::uuid, null, 'alongamento do piriforme sentado', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Dobre o joelho direito e coloque o pé direito na parte externa do joelho esquerdo. Coloque o cotovelo esquerdo na parte externa do joelho direito e gire suavemente o tronco para a direita. Mantenha o alongamento por 20 a 30 segundos, depois troque de lado e repita.', '/exercise-media/bstrainer/2567.gif', 'hasaneyldrm', '2567'),
  ('b1d7a80a-0000-4000-8000-000000000691'::uuid, null, 'crunch lateral sentado (parede)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'bodyweight', false, 'Sente-se no chão com as costas apoiadas na parede e as pernas estendidas à sua frente. Dobre os joelhos e coloque os pés apoiados no chão, afastados na largura dos quadris. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolva os abdominais e incline-se para o lado, aproximando o cotovelo do quadril. Faça uma pausa por um momento e depois retorne à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0691.gif', 'hasaneyldrm', '0691'),
  ('b1d7a80a-0000-4000-8000-000000001587'::uuid, null, 'sequência de pose sentada de grande angular', 'isolation', ARRAY['hamstrings', 'quadriceps']::text[], ARRAY['quadriceps', 'calves']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas em um ângulo amplo. Flexione os pés e envolva o quadríceps. Coloque as mãos no chão atrás de você para apoio. Mantendo as costas retas, incline-se para a frente a partir dos quadris. Continue inclinando-se para a frente até sentir um alongamento nos tendões da coxa. Mantenha esta posição por algumas respirações. Solte lentamente o alongamento e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1587.gif', 'hasaneyldrm', '1587'),
  ('b1d7a80a-0000-4000-8000-000000000697'::uuid, null, 'flexão de perna inversa autoassistida', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'calves']::text[], 'bodyweight', false, 'Deite-se de costas em uma esteira ou banco com as pernas estendidas. Coloque as mãos ao lado do corpo ou sob os glúteos para obter apoio. Dobre os joelhos e levante os pés do chão, aproximando as coxas do peito. Faça uma pausa no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0697.gif', 'hasaneyldrm', '0697'),
  ('b1d7a80a-0000-4000-8000-000000001766'::uuid, null, 'flexão de perna inversa autoassistida', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'calves']::text[], 'bodyweight', false, 'Deite-se de bruços em uma máquina de flexão de pernas, com as pernas estendidas e os tornozelos enganchados sob a alavanca acolchoada. Coloque as mãos nas alças laterais da máquina para apoio. Mantendo a parte superior do corpo parada, expire e levante as pernas o máximo possível. Mantenha a posição contraída por uma breve pausa enquanto aperta os isquiotibiais. Abaixe lentamente as pernas de volta à posição inicial enquanto inspira. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1766.gif', 'hasaneyldrm', '1766'),
  ('b1d7a80a-0000-4000-8000-000000000696'::uuid, null, 'flexão de perna inversa autoassistida (no chão)', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'calves']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Dobre os joelhos e coloque os pés apoiados no chão, afastados na largura do quadril. Levante os quadris do chão, envolvendo os glúteos e isquiotibiais. Enrole lentamente as pernas em direção aos glúteos, mantendo os quadris levantados. Faça uma pausa no topo e, em seguida, estenda lentamente as pernas de volta à posição inicial. Abaixe os quadris de volta ao chão. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0696.gif', 'hasaneyldrm', '0696'),
  ('b1d7a80a-0000-4000-8000-000000003222'::uuid, null, 'salto semi-agachamento (masculino)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre os joelhos e abaixe o corpo até uma posição agachada. Salte explosivamente, estendendo os quadris e joelhos enquanto balança os braços para ganhar impulso. Pouse suavemente na planta dos pés e passe imediatamente para a próxima repetição. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3222.gif', 'hasaneyldrm', '3222'),
  ('b1d7a80a-0000-4000-8000-000000003656'::uuid, null, 'corrida com passadas curtas', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Encontre um espaço aberto ou uma esteira para realizar o exercício. Fique em pé com os pés afastados na largura do quadril. Comece a correr sem sair do lugar, levantando os joelhos e balançando os braços. Após alguns segundos, comece a dar passos curtos para frente, mantendo um ritmo rápido. Continue correndo com passadas curtas pela duração ou distância desejada.', '/exercise-media/bstrainer/3656.gif', 'hasaneyldrm', '3656'),
  ('b1d7a80a-0000-4000-8000-000000001763'::uuid, null, 'pull-up com pegada de ombro', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra pull-up com uma pegada na largura dos ombros, com as palmas voltadas para você. Pendure-se livremente com os braços totalmente estendidos. Envolva os músculos das costas e puxe o corpo em direção à barra até que o queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1763.gif', 'hasaneyldrm', '1763'),
  ('b1d7a80a-0000-4000-8000-000000003699'::uuid, null, 'tapinha no ombro', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos diretamente sob os ombros e o corpo em linha reta. Envolva seu núcleo e levante a mão direita do chão, estendendo a mão para tocar no ombro esquerdo. Coloque a mão direita de volta no chão e repita com a mão esquerda batendo no ombro direito. Continue alternando toques nos ombros enquanto mantém os quadris e o tronco estáveis. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3699.gif', 'hasaneyldrm', '3699'),
  ('b1d7a80a-0000-4000-8000-000000000699'::uuid, null, 'flexão de ombro', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas do que a largura dos ombros e o corpo em linha reta da cabeça aos calcanhares. Abaixe o corpo em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Ao empurrar para cima, levante a mão direita do chão e bata no ombro esquerdo. Retorne a mão direita ao chão e repita a flexão, desta vez levantando a mão esquerda e batendo no ombro direito. Continue alternando toques nos ombros com cada repetição de flexão. Mantenha um núcleo estável e evite rotação excessiva do quadril durante o exercício. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0699.gif', 'hasaneyldrm', '0699'),
  ('b1d7a80a-0000-4000-8000-000000001774'::uuid, null, 'ponte lateral abdução do quadril', 'isolation', ARRAY['abductors', 'glutes']::text[], ARRAY['glutes', 'obliques']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas estendidas e empilhadas uma sobre a outra. Apoie-se no antebraço, mantendo o cotovelo diretamente abaixo do ombro. Envolva o núcleo e levante os quadris do chão, criando uma linha reta da cabeça aos pés. Enquanto mantém o núcleo engajado, levante a perna de cima o mais alto possível, sem girar os quadris. Faça uma pausa por um momento no topo e depois abaixe a perna novamente. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1774.gif', 'hasaneyldrm', '1774'),
  ('b1d7a80a-0000-4000-8000-000000000705'::uuid, null, 'ponte lateral v. 2', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'glutes']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas estendidas e empilhadas uma sobre a outra. Coloque o antebraço no chão, diretamente abaixo do ombro, com o cotovelo dobrado em um ângulo de 90 graus. Envolva o núcleo e levante os quadris do chão, criando uma linha reta da cabeça aos pés. Mantenha esta posição pelo tempo desejado. Abaixe os quadris de volta à posição inicial. Repita do outro lado.', '/exercise-media/bstrainer/0705.gif', 'hasaneyldrm', '0705'),
  ('b1d7a80a-0000-4000-8000-000000000709'::uuid, null, 'lado do quadril (nas barras paralelas)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Fique entre duas barras paralelas com os pés afastados na largura dos ombros. Coloque as mãos nas barras e levante o corpo do chão, apoiando o peso nos braços. Envolva os abdominais e levante lentamente as pernas para o lado, mantendo-as retas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0709.gif', 'hasaneyldrm', '0709'),
  ('b1d7a80a-0000-4000-8000-000000000710'::uuid, null, 'abdução lateral do quadril', 'isolation', ARRAY['abductors', 'glutes']::text[], ARRAY['glutes', 'quadriceps']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e as mãos nos quadris. Mude o peso para uma perna e levante a perna oposta para o lado, mantendo-a reta. Faça uma pausa no topo e, em seguida, abaixe lentamente a perna de volta à posição inicial. Repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0710.gif', 'hasaneyldrm', '0710'),
  ('b1d7a80a-0000-4000-8000-000000001358'::uuid, null, 'alongamento lateral no chão', 'isolation', ARRAY['lats', 'obliques']::text[], ARRAY['obliques', 'glutes']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas esticadas e o braço inferior estendido acima da cabeça. Dobre o joelho de cima e coloque o pé no chão, na frente da perna de baixo. Passe o braço superior acima da cabeça e agarre-se a algo estável, como uma parede ou um móvel. Levante lentamente a perna de baixo do chão, mantendo-a reta, até sentir um alongamento na lateral do corpo. Mantenha o alongamento por 20 a 30 segundos e, em seguida, abaixe lentamente a perna. Repita do outro lado.', '/exercise-media/bstrainer/1358.gif', 'hasaneyldrm', '1358'),
  ('b1d7a80a-0000-4000-8000-000000003667'::uuid, null, 'adução de quadril deitado de lado (masculino)', 'isolation', ARRAY['adductors', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas esticadas e empilhadas uma sobre a outra. Coloque o braço inferior sob a cabeça para obter apoio. Envolva os adutores e levante a perna de cima o mais alto possível, sem girar os quadris ou inclinar-se para trás. Faça uma pausa no topo e, em seguida, abaixe lentamente a perna de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/3667.gif', 'hasaneyldrm', '3667'),
  ('b1d7a80a-0000-4000-8000-000000001775'::uuid, null, 'prancha lateral adução de quadril', 'isolation', ARRAY['adductors', 'obliques']::text[], ARRAY['obliques', 'glutes']::text[], 'bodyweight', false, 'Comece deitando-se de lado com as pernas estendidas e empilhadas uma sobre a outra. Apoie-se no antebraço, mantendo o cotovelo diretamente abaixo do ombro. Envolva o núcleo e levante os quadris do chão, criando uma linha reta da cabeça aos pés. Mantendo a posição da prancha lateral, levante a perna de cima em direção ao teto, mantendo-a reta. Abaixe lentamente a perna de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1775.gif', 'hasaneyldrm', '1775'),
  ('b1d7a80a-0000-4000-8000-000000000716'::uuid, null, 'alongamento lateral do pescoço', 'isolation', ARRAY['levator scapulae', 'trapezius']::text[], ARRAY['trapezius', 'sternocleidomastoid']::text[], 'bodyweight', false, 'Fique em pé ou sente-se ereto com os ombros relaxados. Incline a cabeça para a direita, aproximando a orelha direita do ombro direito. Coloque a mão direita no lado esquerdo da cabeça e aplique pressão suavemente para aumentar o alongamento. Mantenha o alongamento por 15 a 30 segundos. Repita do outro lado, inclinando a cabeça para a esquerda e aplicando pressão com a mão esquerda. Repita o alongamento 2 a 3 vezes de cada lado.', '/exercise-media/bstrainer/0716.gif', 'hasaneyldrm', '0716'),
  ('b1d7a80a-0000-4000-8000-000000000717'::uuid, null, 'flexão lateral', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'chest', 'core']::text[], 'bodyweight', false, 'Comece deitando-se de lado com as pernas estendidas e empilhadas uma sobre a outra. Coloque a mão de baixo no chão, diretamente sob o ombro, com os dedos apontando para a frente. Pressione a mão de baixo para levantar o corpo do chão, mantendo as pernas retas e o núcleo engajado. Estenda o braço superior em direção ao teto, criando uma linha reta da cabeça aos calcanhares. Abaixe o corpo de volta à posição inicial com controle. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0717.gif', 'hasaneyldrm', '0717'),
  ('b1d7a80a-0000-4000-8000-000000000721'::uuid, null, 'alongamento lateral do pulso', 'isolation', ARRAY['forearms', 'wrists']::text[], ARRAY['wrists', 'hands']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos à sua frente. Estenda o braço direito para o lado, paralelo ao chão, com a palma da mão voltada para baixo. Com a mão esquerda, segure a mão direita e puxe-a suavemente em direção ao corpo, sentindo um estiramento no antebraço direito. Mantenha o alongamento por 15 a 30 segundos e depois solte. Repita do outro lado.', '/exercise-media/bstrainer/0721.gif', 'hasaneyldrm', '0721'),
  ('b1d7a80a-0000-4000-8000-000000000720'::uuid, null, 'queixo lateral', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure uma barra pull-up com uma pegada pronada, com as mãos ligeiramente mais afastadas que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo relaxado. Levante-se dobrando os cotovelos e trazendo o queixo em direção à barra, enquanto mantém o corpo reto. Quando o queixo estiver acima da barra, abaixe-se de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0720.gif', 'hasaneyldrm', '0720'),
  ('b1d7a80a-0000-4000-8000-000000003213'::uuid, null, 'toque lateral do dedo do pé (masculino)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos para os lados. Dobre a cintura para a direita, estendendo a mão direita em direção ao pé direito, mantendo a mão esquerda estendida para o lado. Retorne à posição inicial e dobre a cintura para a esquerda, estendendo a mão esquerda em direção ao pé esquerdo, mantendo a mão direita estendida para o lado. Repita o movimento de flexão lateral para o número desejado de repetições.', '/exercise-media/bstrainer/3213.gif', 'hasaneyldrm', '3213'),
  ('b1d7a80a-0000-4000-8000-000000000725'::uuid, null, 'flexão de braço único', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', true, 'Comece em uma posição de flexão com as mãos afastadas na largura dos ombros e uma mão ligeiramente mais larga que a outra. Envolva o núcleo e abaixe o corpo em direção ao chão, dobrando os cotovelos, mantendo as costas retas. Ao se abaixar, mude o peso para um lado e levante o braço oposto do chão, estendendo-o para o lado. Empurre o peito e o tríceps para levantar o corpo de volta à posição inicial e, ao mesmo tempo, abaixe o braço estendido de volta ao chão. Repita o movimento, alternando o braço estendido a cada repetição.', '/exercise-media/bstrainer/0725.gif', 'hasaneyldrm', '0725'),
  ('b1d7a80a-0000-4000-8000-000000003645'::uuid, null, 'ponte unipodal com perna estendida', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'bodyweight', true, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Estenda uma perna esticada à sua frente. Envolva os glúteos e levante os quadris do chão, formando uma linha reta dos joelhos até os ombros. Segure por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/3645.gif', 'hasaneyldrm', '3645'),
  ('b1d7a80a-0000-4000-8000-000000000727'::uuid, null, 'Elevação de panturrilha unipodal (com halteres)', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'dumbbell', true, 'Fique em pé com os pés afastados na largura do quadril e segure um haltere em uma das mãos. Levante um pé do chão e equilibre-se no outro pé. Levante lentamente o calcanhar o mais alto possível, usando os músculos da panturrilha. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar. Repita o número desejado de repetições e depois mude para a outra perna.', '/exercise-media/bstrainer/0727.gif', 'hasaneyldrm', '0727'),
  ('b1d7a80a-0000-4000-8000-000000000730'::uuid, null, 'corrediça de plataforma de perna única', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'quadriceps']::text[], 'bodyweight', true, 'Comece apoiando um pé em uma plataforma ou prancha deslizante. Dobre ligeiramente o joelho e deslize o pé na plataforma para trás, estendendo a perna. Mantenha seu núcleo engajado e mantenha uma postura reta durante todo o movimento. Retorne lentamente à posição inicial deslizando o pé de volta à posição inicial. Repita o movimento pelo número desejado de repetições e depois troque de perna.', '/exercise-media/bstrainer/0730.gif', 'hasaneyldrm', '0730'),
  ('b1d7a80a-0000-4000-8000-000000001759'::uuid, null, 'agachamento unipodal (pistola) masculino', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos à sua frente. Levante o pé direito do chão e estenda-o para a frente. Abaixe lentamente o corpo dobrando o joelho esquerdo e empurrando os quadris para trás. Mantenha o peito para cima e as costas retas enquanto se abaixa. Abaixe até que a coxa esquerda fique paralela ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre o calcanhar esquerdo para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/1759.gif', 'hasaneyldrm', '1759'),
  ('b1d7a80a-0000-4000-8000-000000001489'::uuid, null, 'agachamento maricas', 'squat', ARRAY['quads', 'calves']::text[], ARRAY['calves', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos dos pés apontando ligeiramente para fora. Segure-se em um objeto estável para manter o equilíbrio, se necessário. Abaixe lentamente o corpo dobrando os joelhos e inclinando-se para trás, mantendo o tronco ereto. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais longe que você puder ir confortavelmente. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1489.gif', 'hasaneyldrm', '1489'),
  ('b1d7a80a-0000-4000-8000-000000000735'::uuid, null, 'abdominais v. 2', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante lentamente a parte superior do corpo do chão, curvando-se para a frente até que o tronco fique em um ângulo de 45 graus. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0735.gif', 'hasaneyldrm', '0735'),
  ('b1d7a80a-0000-4000-8000-000000003679'::uuid, null, 'abdominais com os braços no peito', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Cruze os braços sobre o peito. Envolvendo os abdominais, levante a parte superior do corpo do chão em direção aos joelhos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3679.gif', 'hasaneyldrm', '3679'),
  ('b1d7a80a-0000-4000-8000-000000003361'::uuid, null, 'saltos de skatista', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e salte para a direita, pousando com o pé direito. Ao pousar, balance a perna esquerda atrás da direita e bata no chão com os dedos do pé esquerdo. Salte imediatamente para a esquerda, pousando com o pé esquerdo. Ao pousar, balance a perna direita atrás da esquerda e bata no chão com os dedos do pé direito. Continue alternando os lados, pulando e batendo no chão com cada perna. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3361.gif', 'hasaneyldrm', '3361'),
  ('b1d7a80a-0000-4000-8000-000000002142'::uuid, null, 'esquiergômetro', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'forearms']::text[], 'machine', false, 'Ajuste a altura do assento e os apoios para os pés para uma posição confortável. Segure as alças com uma pegada pronada, com as palmas voltadas para baixo. Sente-se ereto com os pés apoiados nos apoios para os pés. Estenda os braços à sua frente, mantendo os cotovelos ligeiramente dobrados. Envolva o tríceps e empurre as alças em direção às coxas. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2142.gif', 'hasaneyldrm', '2142'),
  ('b1d7a80a-0000-4000-8000-000000003671'::uuid, null, 'etapa de esqui', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e mantenha as costas retas. Salte para a direita, pousando com o pé direito enquanto balança a perna esquerda atrás da direita. Salte imediatamente para a esquerda, pousando com o pé esquerdo enquanto balança a perna direita atrás da esquerda. Continue alternando saltos de um lado para o outro, imitando um movimento de esqui. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3671.gif', 'hasaneyldrm', '3671'),
  ('b1d7a80a-0000-4000-8000-000000003304'::uuid, null, 'esfola o gato', 'isolation', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'bodyweight', false, 'Comece pendurado em uma barra com os braços totalmente estendidos e o corpo relaxado. Envolva seu núcleo e levante as pernas, trazendo os joelhos em direção ao peito. Continue a levantar as pernas acima da cabeça, permitindo que o corpo passe pelos braços. Quando as pernas estiverem totalmente estendidas sobre a cabeça, comece a baixá-las de volta à posição inicial. Ao abaixar as pernas, deixe seu corpo passar pelos braços até que você fique pendurado com os braços totalmente estendidos novamente. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3304.gif', 'hasaneyldrm', '3304'),
  ('b1d7a80a-0000-4000-8000-000000001425'::uuid, null, 'trenó 45 graus one leg press', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', true, 'Ajuste a máquina trenó em um ângulo de 45 graus. Sente-se na máquina de trenó com as costas apoiadas na almofada e os pés na plataforma. Coloque um pé na plataforma e estenda a perna, empurrando o trenó para longe de você. Dobre lentamente o joelho e abaixe o trenó de volta à posição inicial. Repita com a outra perna. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/1425.gif', 'hasaneyldrm', '1425'),
  ('b1d7a80a-0000-4000-8000-000000000738'::uuid, null, 'prensa de panturrilha trenó 45°', 'push_h', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Ajuste a máquina trenó em um ângulo de 45 graus. Coloque os pés na plataforma do trenó com os dedos apontando para a frente. Empurre a plataforma do trenó para longe de você, estendendo os tornozelos e panturrilhas. Faça uma pausa no topo e abaixe lentamente a plataforma do trenó de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0738.gif', 'hasaneyldrm', '0738'),
  ('b1d7a80a-0000-4000-8000-000000000739'::uuid, null, 'trenó 45° leg press', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste o assento e a plataforma da máquina trenó para uma posição confortável. Sente-se na máquina de trenó com as costas apoiadas no encosto e os pés afastados na largura dos ombros na plataforma. Segure as alças nas laterais do assento para estabilidade. Empurre a plataforma para longe do corpo, estendendo as pernas, mantendo os calcanhares na plataforma. Continue empurrando até que as pernas estejam quase totalmente estendidas, mas sem travar os joelhos. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente a plataforma de volta ao corpo, dobrando os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0739.gif', 'hasaneyldrm', '0739'),
  ('b1d7a80a-0000-4000-8000-000000001464'::uuid, null, 'trenó 45 ° leg press (ponto de vista traseiro)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste o assento da máquina de trenó de forma que os joelhos fiquem em um ângulo de 45 graus. Sente-se na máquina de trenó com as costas apoiadas no encosto e os pés afastados na largura dos ombros na plataforma. Segure as alças nas laterais do assento para estabilidade. Empurre a plataforma para longe do corpo, estendendo as pernas, mantendo os calcanhares na plataforma. Faça uma pausa por um momento na posição totalmente estendida. Dobre lentamente os joelhos e abaixe a plataforma em direção ao corpo, controlando o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1464.gif', 'hasaneyldrm', '1464'),
  ('b1d7a80a-0000-4000-8000-000000001463'::uuid, null, 'trenó leg press 45° (ponto de vista lateral)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste o assento da máquina de trenó de modo que seus joelhos fiquem em um ângulo de 90 graus quando seus pés estiverem na plataforma. Sente-se na máquina de trenó com as costas apoiadas no encosto e os pés afastados na largura dos ombros na plataforma. Segure as alças nas laterais do assento para estabilidade. Empurre a plataforma para estender as pernas, endireitando-as completamente. Faça uma pausa no topo e, em seguida, dobre lentamente os joelhos para abaixar a plataforma de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1463.gif', 'hasaneyldrm', '1463'),
  ('b1d7a80a-0000-4000-8000-000000000740'::uuid, null, 'trenó 45 ° leg wide press', 'push_h', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a máquina trenó em um ângulo de 45 graus. Sente-se na máquina de trenó com as costas apoiadas na almofada e os pés na plataforma para os pés. Posicione os pés mais afastados do que a largura dos ombros. Empurre a plataforma dos pés para estender as pernas e endireitar os joelhos. Faça uma pausa no final do movimento e, em seguida, dobre lentamente os joelhos para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0740.gif', 'hasaneyldrm', '0740'),
  ('b1d7a80a-0000-4000-8000-000000001391'::uuid, null, 'panturrilha trenó no leg press', 'squat', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps']::text[], 'machine', false, 'Ajuste o assento da máquina de leg press de modo que os joelhos fiquem ligeiramente flexionados quando os pés estiverem no trenó. Coloque os pés na largura dos ombros no trenó, com os dedos dos pés apontando para a frente. Solte as alças de segurança e empurre o trenó para longe de você, estendendo os joelhos e tornozelos. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente o trenó dobrando os joelhos e tornozelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1391.gif', 'hasaneyldrm', '1391'),
  ('b1d7a80a-0000-4000-8000-000000000741'::uuid, null, 'agachamento hack mais próximo do trenó', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste o trenó para um peso confortável e posicione-se com as costas apoiadas na almofada. Coloque os pés na largura dos ombros na plataforma, com os dedos ligeiramente apontados para fora. Segure as alças nas laterais da máquina para estabilidade. Envolva o núcleo e abaixe lentamente o corpo, dobrando os joelhos e quadris, mantendo as costas retas. Continue abaixando até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para estender as pernas e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0741.gif', 'hasaneyldrm', '0741'),
  ('b1d7a80a-0000-4000-8000-000000000742'::uuid, null, 'elevação da panturrilha em ângulo para frente em trenó', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste o trenó para um peso confortável e posicione-se na máquina com os dedos dos pés na plataforma e os calcanhares pendurados. Coloque as mãos nas alças ou nas laterais da máquina para apoiá-la. Envolva as panturrilhas e levante lentamente os calcanhares o mais alto possível, empurrando a resistência do trenó. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0742.gif', 'hasaneyldrm', '0742'),
  ('b1d7a80a-0000-4000-8000-000000000743'::uuid, null, 'agachamento com trenó', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a máquina de trenó para uma posição confortável para sua altura. Fique em pé com os pés afastados na largura dos ombros na plataforma, os dedos dos pés ligeiramente apontados para fora. Segure nas alças ou barras para estabilidade. Abaixe o corpo dobrando os joelhos e quadris, mantendo as costas retas e o peito para cima. Continue abaixando até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento e empurre os calcanhares para levantar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0743.gif', 'hasaneyldrm', '0743'),
  ('b1d7a80a-0000-4000-8000-000000002334'::uuid, null, 'prensa de panturrilha deitada em trenó', 'push_h', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste a máquina de trenó para um peso confortável. Sente-se na máquina de trenó com as costas apoiadas na almofada e os pés na plataforma. Coloque os dedos dos pés e a planta dos pés na borda da plataforma, com os calcanhares pendurados. Afaste a plataforma de você estendendo os tornozelos, mantendo os joelhos ligeiramente flexionados. Continue empurrando até que suas panturrilhas estejam totalmente contraídas. Segure a contração por um momento e depois abaixe lentamente a plataforma de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2334.gif', 'hasaneyldrm', '2334'),
  ('b1d7a80a-0000-4000-8000-000000000744'::uuid, null, 'trenó deitado agachado', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a máquina de trenó para um peso confortável. Deite-se de costas na máquina de trenó com os pés na plataforma. Posicione os pés na largura dos ombros e ligeiramente inclinados para fora. Segure as alças da máquina de trenó para estabilidade. Envolva seus glúteos e músculos centrais. Empurre os calcanhares e estenda as pernas para levantar o trenó. Abaixe o trenó dobrando os joelhos e quadris. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0744.gif', 'hasaneyldrm', '0744'),
  ('b1d7a80a-0000-4000-8000-000000001392'::uuid, null, 'trenó one leg panturrilha no leg press', 'squat', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', true, 'Ajuste o assento da máquina de leg press de modo que os joelhos fiquem ligeiramente flexionados quando os pés estiverem no trenó. Sente-se na máquina com as costas apoiadas no encosto e os pés no trenó, afastados na largura dos ombros. Coloque os dedos dos pés e a planta dos pés no trenó, mantendo os calcanhares afastados. Empurre o trenó para frente estendendo os tornozelos, mantendo os joelhos ligeiramente flexionados. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o trenó flexionando os tornozelos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1392.gif', 'hasaneyldrm', '1392'),
  ('b1d7a80a-0000-4000-8000-000000001496'::uuid, null, 'marreta', 'core', ARRAY['abs', 'forearms']::text[], ARRAY['forearms', 'shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a marreta com as duas mãos. Envolva seu núcleo e mantenha as costas retas. Balance a marreta em direção ao chão, usando a força do núcleo e da parte superior do corpo. Ao descer, gire os quadris e transfira a força para o martelo. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1496.gif', 'hasaneyldrm', '1496'),
  ('b1d7a80a-0000-4000-8000-000000000746'::uuid, null, 'Smith dá de ombros', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha os braços retos e deixe a barra pendurada na frente das coxas. Levante os ombros em direção às orelhas, apertando as armadilhas na parte superior. Segure por um momento e depois abaixe os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0746.gif', 'hasaneyldrm', '0746'),
  ('b1d7a80a-0000-4000-8000-000000000747'::uuid, null, 'smith atrás do pescoço', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Ajuste a altura do assento da ferreiro para que a barra fique na altura dos ombros. Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do rack e dê um passo para trás, mantendo uma postura estável. Abaixe a barra até a nuca, mantendo os cotovelos apontando para a frente. Pressione a barra acima da cabeça até que os braços estejam totalmente estendidos. Faça uma pausa no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0747.gif', 'hasaneyldrm', '0747'),
  ('b1d7a80a-0000-4000-8000-000000000748'::uuid, null, 'supino smith', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura da barra da ferreiro ao nível do peito. Deite-se no banco com os pés firmemente plantados no chão. Segure a barra com uma pegada pronada um pouco mais larga que a largura dos ombros. Desencaixe a barra e abaixe-a em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0748.gif', 'hasaneyldrm', '0748'),
  ('b1d7a80a-0000-4000-8000-000000000749'::uuid, null, 'Smith joelho dobrado, bom dia', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'lower back']::text[], 'machine', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os dedos apontando para a frente. Coloque a barra na parte superior das costas, apoiando-a nas armadilhas. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Abaixe o tronco até ficar paralelo ao chão, sentindo um alongamento nos isquiotibiais. Envolva os glúteos e isquiotibiais para levantar o tronco de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0749.gif', 'hasaneyldrm', '0749'),
  ('b1d7a80a-0000-4000-8000-000000001359'::uuid, null, 'Smith curvado sobre a linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Configure a máquina de ferreiro com a barra na altura do quadril. Fique de frente para a barra com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Puxe a barra em direção à parte inferior do peito, apertando as omoplatas. Faça uma pausa no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1359.gif', 'hasaneyldrm', '1359'),
  ('b1d7a80a-0000-4000-8000-000000000750'::uuid, null, 'agachamento com cadeira smith', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a altura da barra da ferreiro para uma posição confortável. Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Coloque a barra na parte superior das costas, apoiando-a nas armadilhas. Envolva o núcleo e mantenha o peito erguido enquanto abaixa lentamente o corpo, dobrando os joelhos e os quadris. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0750.gif', 'hasaneyldrm', '0750'),
  ('b1d7a80a-0000-4000-8000-000000000751'::uuid, null, 'supino com pegada fechada smith', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se no banco com os pés apoiados no chão. Segure a barra com uma pegada fechada, um pouco mais estreita que a largura dos ombros. Abaixe a barra em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0751.gif', 'hasaneyldrm', '0751'),
  ('b1d7a80a-0000-4000-8000-000000000752'::uuid, null, 'levantamento terra de Smith', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'lower back']::text[], 'machine', false, 'Configure a máquina de ferreiro com a barra na altura do quadril. Fique em pé com os pés afastados na largura dos ombros, os dedos apontando ligeiramente para fora. Dobre os quadris e os joelhos, mantendo as costas retas e o peito para cima, e segure a barra com uma pegada pronada um pouco mais larga que a largura dos ombros. Envolva o núcleo e levante a barra estendendo os quadris e os joelhos, mantendo a barra próxima ao corpo. Fique em pé, estendendo totalmente os quadris e joelhos. Abaixe a barra dobrando os quadris e os joelhos, mantendo o controle e as costas retas. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0752.gif', 'hasaneyldrm', '0752'),
  ('b1d7a80a-0000-4000-8000-000000000753'::uuid, null, 'Smith recusa supino', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste o banco de declínio no ângulo desejado. Deite-se no banco com os pés presos sob as almofadas dos pés. Segure a barra com uma pegada pronada um pouco mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0753.gif', 'hasaneyldrm', '0753'),
  ('b1d7a80a-0000-4000-8000-000000000754'::uuid, null, 'smith recusa pressão reversa', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a máquina Smith para uma posição de declínio. Deite-se no banco com os pés presos sob as almofadas dos pés. Segure a barra com uma pegada invertida, com as mãos ligeiramente mais afastadas que a largura dos ombros. Desembale a barra e abaixe-a em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0754.gif', 'hasaneyldrm', '0754'),
  ('b1d7a80a-0000-4000-8000-000000001433'::uuid, null, 'agachamento frontal smith (pega limpa)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[], 'machine', false, 'Configure a máquina Smith com a barra na altura dos ombros. Fique de frente para a barra com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Dê um passo para trás e posicione a barra nos ombros da frente, apoiando-a na clavícula e nos deltóides. Mantenha o peito erguido, as costas retas e o núcleo engajado. Abaixe o corpo dobrando os joelhos e quadris, como se estivesse sentado em uma cadeira. Continue abaixando até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1433.gif', 'hasaneyldrm', '1433'),
  ('b1d7a80a-0000-4000-8000-000000003281'::uuid, null, 'agachamento completo smith', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Configure a máquina Smith com a barra na altura dos ombros. Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Passe por baixo da barra e posicione-a na parte superior das costas, apoiando-se nas armadilhas. Segure a barra com as mãos um pouco mais afastadas que a largura dos ombros. Desenrole a barra e dê um passo para trás, mantendo uma postura estável. Mantendo o peito para cima e o núcleo engajado, inicie o agachamento empurrando os quadris para trás e dobrando os joelhos. Abaixe o corpo até que as coxas fiquem paralelas ao chão ou o mais baixo que sua flexibilidade permitir. Faça uma pausa por um momento na parte inferior e, em seguida, passe pelos calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3281.gif', 'hasaneyldrm', '3281'),
  ('b1d7a80a-0000-4000-8000-000000000755'::uuid, null, 'agachamento hack smith', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a barra na máquina de ferreiro para uma altura adequada ao seu corpo. Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente apontados para fora. Posicione-se sob a barra, apoiando-a nas armadilhas superiores e nos ombros. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Envolva seu núcleo e mantenha o peito erguido enquanto desmonta a barra. Dê um passo para trás e posicione os pés um pouco mais afastados do que a largura dos ombros. Dobre os joelhos e abaixe o corpo, mantendo o peito para cima e as costas retas. Continue descendo até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0755.gif', 'hasaneyldrm', '0755'),
  ('b1d7a80a-0000-4000-8000-000000000756'::uuid, null, 'elevação de quadril Smith', 'core', ARRAY['abs', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Posicione-se na máquina de ferreiro com as costas apoiadas na almofada e os pés afastados na largura dos ombros. Coloque as mãos na barra, ligeiramente mais afastadas que a largura dos ombros. Envolva o núcleo e os glúteos e, em seguida, empurre os calcanhares para levantar os quadris do chão. Continue levantando até que seu corpo forme uma linha reta dos joelhos até os ombros. Segure por um momento na parte superior e, em seguida, abaixe lentamente os quadris de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0756.gif', 'hasaneyldrm', '0756'),
  ('b1d7a80a-0000-4000-8000-000000000757'::uuid, null, 'supino inclinado smith', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Ajuste o banco para uma inclinação de 30-45 graus. Sente-se no banco com as costas apoiadas na almofada e os pés firmemente no chão. Segure a barra com uma pegada pronada um pouco mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção à parte superior do peito, mantendo os cotovelos levemente dobrados. Faça uma pausa por um momento na parte inferior e, em seguida, empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0757.gif', 'hasaneyldrm', '0757'),
  ('b1d7a80a-0000-4000-8000-000000000758'::uuid, null, 'smith inclinação reversa-grip press', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste o assento da ferreiro para um ângulo de inclinação confortável. Sente-se na máquina com as costas apoiadas na almofada e os pés apoiados no chão. Segure a barra com uma pegada pronada ligeiramente mais larga que a largura dos ombros. Desencaixe a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento quando a barra estiver logo acima do peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0758.gif', 'hasaneyldrm', '0758'),
  ('b1d7a80a-0000-4000-8000-000000000759'::uuid, null, 'elevação de ombro inclinada smith', 'isolation', ARRAY['serratus anterior', 'deltoids']::text[], ARRAY['deltoids', 'trapezius']::text[], 'machine', false, 'Ajuste a máquina Smith para uma posição inclinada. Fique de frente para a máquina com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e o núcleo engajado. Levante a barra em direção ao teto, guiando-a com os cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0759.gif', 'hasaneyldrm', '0759'),
  ('b1d7a80a-0000-4000-8000-000000000760'::uuid, null, 'leg press smith', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste o assento e a plataforma da ferreiro para uma posição confortável. Sente-se na máquina com as costas apoiadas no encosto e os pés afastados na largura dos ombros na plataforma. Segure as alças ou laterais da máquina para estabilidade. Empurre a plataforma para longe de você, estendendo as pernas, mantendo as costas apoiadas no encosto. Faça uma pausa por um momento na posição totalmente estendida. Dobre lentamente os joelhos e abaixe a plataforma em sua direção, retornando à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0760.gif', 'hasaneyldrm', '0760'),
  ('b1d7a80a-0000-4000-8000-000000001434'::uuid, null, 'agachamento com barra baixa smith', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Configure a máquina Smith com a barra a uma altura que permita apoiá-la confortavelmente na parte superior das costas. Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Passe por baixo da barra e posicione-a na parte superior das costas, apoiando-a nas armadilhas. Segure a barra com as mãos um pouco mais afastadas que a largura dos ombros. Desencaixe a barra esticando as pernas e afastando-se do suporte. Respire fundo e prepare seu núcleo. Inicie o agachamento empurrando os quadris para trás e dobrando os joelhos. Abaixe o corpo até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Mantenha o peito para cima e as costas retas durante todo o movimento. Passe pelos calcanhares para se levantar, estendendo os quadris e os joelhos. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1434.gif', 'hasaneyldrm', '1434'),
  ('b1d7a80a-0000-4000-8000-000000001683'::uuid, null, 'rosca bíceps smith machine', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Ajuste a altura da barra da ferreiro para que fique na altura da cintura. Fique de frente para a máquina de ferreiro com os pés afastados na largura dos ombros. Segure a barra com uma pegada por baixo, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha os cotovelos próximos aos lados e os braços parados. Expire e levante a barra em direção aos ombros, contraindo os bíceps. Faça uma pausa no início do movimento, apertando o bíceps. Inspire e abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1683.gif', 'hasaneyldrm', '1683'),
  ('b1d7a80a-0000-4000-8000-000000001625'::uuid, null, 'máquina smith declínio supino fechado', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Ajuste a bancada da ferreiro para uma posição declinada. Deite-se no banco com os pés firmemente plantados no chão. Segure a barra com uma pegada fechada, um pouco mais estreita que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento quando a barra estiver logo acima do seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1625.gif', 'hasaneyldrm', '1625'),
  ('b1d7a80a-0000-4000-8000-000000001752'::uuid, null, 'extensão de tríceps inclinada da máquina smith', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Ajuste o assento da ferreiro de forma que a barra fique na altura dos ombros. Sente-se no banco com as costas apoiadas na almofada e os pés apoiados no chão. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Estenda totalmente os braços, levantando a barra do rack e segurando-a diretamente acima do peito. Abaixe a barra lentamente em direção à testa, mantendo os cotovelos próximos à cabeça. Faça uma pausa na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1752.gif', 'hasaneyldrm', '1752'),
  ('b1d7a80a-0000-4000-8000-000000001626'::uuid, null, 'máquina smith declínio reverso supino de aperto próximo', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a máquina Smith para uma posição de declínio. Deite-se no banco com os pés presos sob as almofadas dos pés. Segure a barra com uma pegada fechada, um pouco mais estreita que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa por um momento na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1626.gif', 'hasaneyldrm', '1626'),
  ('b1d7a80a-0000-4000-8000-000000000761'::uuid, null, 'linha estreita de Smith', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'rear deltoids']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com os pés apoiados no chão. Segure as alças com uma pegada pronada, ligeiramente mais estreita que a largura dos ombros. Mantenha as costas retas e o peito erguido enquanto puxa as alças em direção ao corpo, apertando as omoplatas. Faça uma pausa por um momento no pico do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0761.gif', 'hasaneyldrm', '0761'),
  ('b1d7a80a-0000-4000-8000-000000001360'::uuid, null, 'smith remada com um braço', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', true, 'Ajuste a altura da barra da ferreiro ao nível da cintura. Fique de frente para a máquina de ferreiro com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Segure a barra com uma mão usando uma pegada pronada, com a palma voltada para baixo. Mantenha o cotovelo próximo ao corpo e puxe a barra em direção à cintura, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições e depois mude para o outro braço.', '/exercise-media/bstrainer/1360.gif', 'hasaneyldrm', '1360'),
  ('b1d7a80a-0000-4000-8000-000000001393'::uuid, null, 'Smith levantamento de panturrilha com uma perna no chão', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', true, 'Posicione-se no chão sob a barra da ferreiro, de costas para a máquina. Coloque as pontas dos pés em uma superfície elevada, como uma placa de peso ou bloco. Posicione a barra da ferreiro na parte inferior das pernas, logo acima dos tornozelos. Segure a barra com as mãos para obter estabilidade. Levante os calcanhares do chão estendendo os tornozelos, levantando o corpo. Faça uma pausa no início do movimento e abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1393.gif', 'hasaneyldrm', '1393'),
  ('b1d7a80a-0000-4000-8000-000000000762'::uuid, null, 'remada deltóide traseira smith', 'pull_h', ARRAY['delts', 'trapezius']::text[], ARRAY['trapezius', 'rhomboids', 'biceps']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na máquina com o peito apoiado na almofada e os pés apoiados no chão. Segure as alças com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Mantenha as costas retas e o núcleo engajado enquanto puxa as alças em direção ao peito, apertando as omoplatas. Faça uma pausa por um momento no início do movimento e, em seguida, solte lentamente as alças de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0762.gif', 'hasaneyldrm', '0762'),
  ('b1d7a80a-0000-4000-8000-000000000763'::uuid, null, 'smith elevação reversa de panturrilha', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Ajuste a barra da ferreiro a uma altura logo abaixo dos ombros. Fique de frente para a barra com os pés afastados na largura do quadril e os dedos apontando para a frente. Coloque as pontas dos pés na borda de um degrau ou plataforma, com os calcanhares pendurados. Segure-se na barra para obter apoio, mantendo as costas retas e o núcleo engajado. Levante os calcanhares o mais alto possível, colocando o peso do corpo na planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0763.gif', 'hasaneyldrm', '0763'),
  ('b1d7a80a-0000-4000-8000-000000001394'::uuid, null, 'smith elevação reversa de panturrilha', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', false, 'Ajuste a barra da ferreiro a uma altura logo abaixo dos ombros. Fique de frente para a barra com os pés afastados na largura do quadril e os dedos apontando para a frente. Coloque as pontas dos pés na borda de um degrau ou plataforma, com os calcanhares pendurados. Segure-se na barra para obter apoio. Levante os calcanhares o mais alto possível, colocando o corpo na ponta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1394.gif', 'hasaneyldrm', '1394'),
  ('b1d7a80a-0000-4000-8000-000000001361'::uuid, null, 'smith punho reverso curvado sobre a linha', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Configure a máquina de ferreiro com a barra na altura do quadril. Fique de frente para a barra com os pés afastados na largura dos ombros. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Segure a barra com uma pegada por baixo, com as mãos na largura dos ombros. Puxe a barra em direção à parte inferior do peito, apertando as omoplatas. Faça uma pausa no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1361.gif', 'hasaneyldrm', '1361'),
  ('b1d7a80a-0000-4000-8000-000000000764'::uuid, null, 'prensa de aperto reverso smith', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a altura da barra da ferreiro ao nível do peito. Fique de frente para a barra com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Dê um passo para trás e posicione-se com uma ligeira flexão dos joelhos. Mantenha o peito erguido e o núcleo engajado durante todo o exercício. Abaixe a barra em direção ao peito, mantendo os cotovelos dobrados. Faça uma pausa na parte inferior e empurre a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0764.gif', 'hasaneyldrm', '0764'),
  ('b1d7a80a-0000-4000-8000-000000001395'::uuid, null, 'Smith sentado com uma perna levantada na panturrilha', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings']::text[], 'machine', true, 'Sente-se na máquina com as costas apoiadas na almofada e os pés no apoio para os pés. Coloque uma perna no apoio para os pés e mantenha a outra perna fora do apoio para os pés. Usando os músculos da panturrilha, levante o calcanhar o mais alto possível. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o calcanhar de volta à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/1395.gif', 'hasaneyldrm', '1395'),
  ('b1d7a80a-0000-4000-8000-000000000765'::uuid, null, 'smith sentado no ombro', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Ajuste a altura do assento para que as alças fiquem na altura dos ombros. Sente-se na máquina com as costas apoiadas na almofada e os pés apoiados no chão. Segure as alças com força e levante-as dos suportes, estendendo totalmente os braços. Abaixe as alças até a altura dos ombros, mantendo os cotovelos levemente flexionados. Pressione as alças acima da cabeça até que seus braços estejam totalmente estendidos. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente as alças até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0765.gif', 'hasaneyldrm', '0765'),
  ('b1d7a80a-0000-4000-8000-000000001426'::uuid, null, 'curvatura de pulso sentada de Smith', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'brachialis']::text[], 'machine', false, 'Sente-se em um banco em frente a uma máquina Smith com os pés apoiados no chão. Segure a barra com uma pegada supinada, com as mãos afastadas na largura dos ombros. Descanse os antebraços nas coxas, permitindo que os pulsos fiquem pendurados. Enrole lentamente os pulsos para cima, trazendo a barra em direção aos antebraços. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1426.gif', 'hasaneyldrm', '1426'),
  ('b1d7a80a-0000-4000-8000-000000000766'::uuid, null, 'press de ombro smith', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Ajuste a altura do assento e posicione-se na ferreiro com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do suporte e posicione-a na altura dos ombros, com os cotovelos dobrados e as palmas das mãos voltadas para a frente. Pressione a barra para cima até que seus braços estejam totalmente estendidos acima da cabeça. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra até a altura dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0766.gif', 'hasaneyldrm', '0766'),
  ('b1d7a80a-0000-4000-8000-000000000767'::uuid, null, 'Smith dá de ombros', 'isolation', ARRAY['traps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha os braços retos e os ombros relaxados. Levante os ombros em direção às orelhas, apertando as armadilhas na parte superior. Segure por um momento e, em seguida, abaixe lentamente os ombros de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0767.gif', 'hasaneyldrm', '0767'),
  ('b1d7a80a-0000-4000-8000-000000000768'::uuid, null, 'agachamento dividido com uma perna smith', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', true, 'Fique na frente da máquina de ferreiro com os pés afastados na largura dos ombros. Coloque um pé atrás de você em um banco ou degrau, com os dedos apontando para frente. Segure a barra da máquina de ferreiro para obter estabilidade. Dobre o joelho da frente e abaixe o corpo em uma posição de estocada, mantendo as costas retas. Faça uma pausa por um momento na parte inferior e, em seguida, empurre o calcanhar dianteiro para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0768.gif', 'hasaneyldrm', '0768'),
  ('b1d7a80a-0000-4000-8000-000000000769'::uuid, null, 'estocada de sprint de Smith', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Configure a máquina Smith com a barra na altura do quadril. Fique de costas para a máquina, com os pés afastados na largura dos ombros. Dê um passo para trás com o pé direito e coloque-o na barra, apoiando a parte superior do pé na barra. Dobre o joelho esquerdo e abaixe o corpo em uma posição de estocada, mantendo as costas retas. Empurre o calcanhar esquerdo para retornar à posição inicial. Repita do outro lado, recuando com o pé esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0769.gif', 'hasaneyldrm', '0769'),
  ('b1d7a80a-0000-4000-8000-000000000770'::uuid, null, 'agachamento smith', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Configure a máquina Smith com a barra na altura apropriada para o seu agachamento. Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Posicione-se sob a barra, apoiando-a nas armadilhas superiores e nos ombros. Segure a barra com uma pegada larga, um pouco mais larga que a largura dos ombros. Envolva seu núcleo e desenrole a barra, recuando para liberar o suporte. Mantendo o peito para cima e as costas retas, inicie o agachamento dobrando os quadris e os joelhos. Abaixe o corpo até que as coxas fiquem paralelas ao chão ou ligeiramente abaixo. Faça uma pausa por um momento na parte inferior e, em seguida, passe pelos calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0770.gif', 'hasaneyldrm', '0770'),
  ('b1d7a80a-0000-4000-8000-000000000771'::uuid, null, 'Smith em pé para trás, curvatura do pulso', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'machine', false, 'Fique de frente para a máquina de ferreiro com os pés afastados na largura dos ombros. Segure a barra com uma pegada pronada, com as mãos na largura dos ombros. Mantenha as costas retas e os cotovelos próximos ao corpo. Enrole lentamente os pulsos para cima, trazendo a barra em direção ao corpo. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0771.gif', 'hasaneyldrm', '0771'),
  ('b1d7a80a-0000-4000-8000-000000000772'::uuid, null, 'Smith em pé atrás da cabeça da imprensa militar', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Ajuste a altura do assento da ferreiro para que a barra fique na altura dos ombros. Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do rack e dê um passo para trás, mantendo uma postura estável. Posicione a barra atrás da cabeça, apoiada nas armadilhas superiores. Mantenha seu núcleo engajado e seu peito levantado durante todo o exercício. Pressione a barra acima da cabeça, estendendo os braços e esticando-os totalmente. Faça uma breve pausa no início do movimento e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0772.gif', 'hasaneyldrm', '0772'),
  ('b1d7a80a-0000-4000-8000-000000000773'::uuid, null, 'Smith levantando perna em pé', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Ajuste a barra da ferreiro a uma altura que permita que você fique com os pés apoiados no chão e os ombros sob a barra. Posicione-se sob a barra com os pés afastados na largura dos ombros e os dedos dos pés apontando para a frente. Coloque as mãos na barra para estabilidade. Envolva as panturrilhas e levante lentamente os calcanhares do chão, levantando o corpo na ponta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0773.gif', 'hasaneyldrm', '0773'),
  ('b1d7a80a-0000-4000-8000-000000000774'::uuid, null, 'imprensa militar em pé de Smith', 'push_v', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Levante a barra do rack e abaixe-a até a altura dos ombros, com as palmas das mãos voltadas para a frente. Pressione a barra para cima até que seus braços estejam totalmente estendidos acima da cabeça. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta ao nível dos ombros. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0774.gif', 'hasaneyldrm', '0774'),
  ('b1d7a80a-0000-4000-8000-000000003142'::uuid, null, 'agachamento sumô smith', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Configure a máquina Smith com a barra na altura do quadril. Fique em pé com os pés mais afastados do que a largura dos ombros, com os dedos apontando para fora. Posicione-se sob a barra, apoiando-a na parte superior das costas e nos ombros. Envolva o núcleo e mantenha o peito levantado enquanto abaixa o corpo até uma posição agachada, empurrando os quadris para trás e dobrando os joelhos. Abaixe-se até que as coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3142.gif', 'hasaneyldrm', '3142'),
  ('b1d7a80a-0000-4000-8000-000000001396'::uuid, null, 'aumento do dedo do pé do ferreiro', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'shins']::text[], 'machine', false, 'Ajuste a barra da ferreiro a uma altura que permita que você fique confortavelmente em pé com os pés apoiados no chão. Posicione-se sob a barra com os ombros diretamente abaixo dela e os pés afastados na largura dos ombros. Coloque as pontas dos pés em uma plataforma elevada ou placas de peso, com os calcanhares pendurados na borda. Segure a barra com uma pegada pronada, ligeiramente mais larga que a largura dos ombros. Envolva seu núcleo e mantenha as costas retas durante todo o exercício. Levante lentamente os calcanhares o mais alto possível, colocando o peso do corpo na planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1396.gif', 'hasaneyldrm', '1396'),
  ('b1d7a80a-0000-4000-8000-000000000775'::uuid, null, 'smith fileira vertical', 'pull_h', ARRAY['delts', 'traps']::text[], ARRAY['traps', 'biceps']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, de frente para a máquina de ferreiro. Segure a barra com uma pegada pronada, com as mãos um pouco mais afastadas que a largura dos ombros. Mantenha as costas retas e o núcleo engajado. Puxe a barra em direção ao queixo, conduzindo com os cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0775.gif', 'hasaneyldrm', '0775'),
  ('b1d7a80a-0000-4000-8000-000000001308'::uuid, null, 'supino smith com pegada larga', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste a bancada para uma posição confortável na máquina de ferreiro. Deite-se no banco com os pés apoiados no chão. Segure a barra com uma pegada larga, um pouco mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos para os lados. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1308.gif', 'hasaneyldrm', '1308'),
  ('b1d7a80a-0000-4000-8000-000000001309'::uuid, null, 'smith ampla aderência declínio supino', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Ajuste o banco de declínio no ângulo desejado. Deite-se no banco com os pés presos sob as almofadas dos pés. Segure a barra com uma pegada larga, um pouco mais larga que a largura dos ombros. Desembale a barra e abaixe-a lentamente em direção ao peito, mantendo os cotovelos apontados para fora. Faça uma pausa por um momento quando a barra tocar seu peito. Empurre a barra de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1309.gif', 'hasaneyldrm', '1309'),
  ('b1d7a80a-0000-4000-8000-000000000776'::uuid, null, 'arrebatar puxar', 'isolation', ARRAY['quads', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes', 'calves']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e a barra no chão à sua frente. Dobre os joelhos e dobre os quadris para abaixar até a posição de agachamento, segurando a barra com uma pegada pronada. Mantenha as costas retas e o peito erguido enquanto passa pelos calcanhares para levantar a barra do chão, estendendo os quadris e os joelhos. Quando a barra atingir o nível do quadril, puxe-a explosivamente para cima, encolhendo os ombros e puxando os cotovelos para cima e para os lados. Quando a barra atingir seu ponto mais alto, desça rapidamente por baixo dela, colocando-se em uma posição de agachamento profundo. Pegue a barra acima da cabeça com os braços totalmente estendidos e os joelhos dobrados. Levante-se estendendo os quadris e os joelhos, mantendo a barra acima da cabeça. Abaixe a barra de volta à posição inicial, invertendo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0776.gif', 'hasaneyldrm', '0776'),
  ('b1d7a80a-0000-4000-8000-000000000777'::uuid, null, 'lançador de feitiços', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'dumbbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em uma das mãos. Dobre ligeiramente os joelhos e incline-se para a frente na cintura, mantendo as costas retas. Estenda o braço com o haltere em direção ao pé oposto, girando o tronco ao fazer isso. Volte à posição inicial e repita do outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0777.gif', 'hasaneyldrm', '0777'),
  ('b1d7a80a-0000-4000-8000-000000001362'::uuid, null, 'esfinge', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Deite-se de bruços no chão, com os antebraços apoiados no chão e os cotovelos diretamente sob os ombros. Envolva seu núcleo e levante o peito do chão, mantendo os antebraços e os dedos dos pés no chão. Mantenha essa posição por alguns segundos, certificando-se de manter o pescoço em uma posição neutra. Abaixe lentamente o peito de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1362.gif', 'hasaneyldrm', '1362'),
  ('b1d7a80a-0000-4000-8000-000000000778'::uuid, null, 'aranha crawl push up', 'isolation', ARRAY['glutes', 'core']::text[], ARRAY['core', 'chest', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Traga o joelho direito em direção ao cotovelo direito, mantendo-o fora do chão. Ao trazer o joelho direito para trás, abaixe simultaneamente o corpo em direção ao chão, dobrando os cotovelos. Empurre de volta à posição inicial e repita com o joelho esquerdo em direção ao cotovelo esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0778.gif', 'hasaneyldrm', '0778'),
  ('b1d7a80a-0000-4000-8000-000000001363'::uuid, null, 'alongamento da coluna', 'isolation', ARRAY['spine', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Coloque as mãos no chão atrás de você, os dedos apontando para o seu corpo. Envolva seu núcleo e incline-se lentamente para trás, mantendo as costas retas. Continue inclinando-se para trás até sentir um alongamento na coluna. Mantenha o alongamento por alguns segundos e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1363.gif', 'hasaneyldrm', '1363'),
  ('b1d7a80a-0000-4000-8000-000000002329'::uuid, null, 'torção da coluna', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Dobre os joelhos e coloque os pés apoiados no chão, afastados na largura do quadril. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolva os abdominais e gire lentamente o tronco para a direita, aproximando o cotovelo direito do joelho esquerdo. Faça uma pausa no final da torção e depois retorne lentamente à posição inicial. Repita a torção para o lado esquerdo, aproximando o cotovelo esquerdo do joelho direito. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/2329.gif', 'hasaneyldrm', '2329'),
  ('b1d7a80a-0000-4000-8000-000000002368'::uuid, null, 'agachamento dividido', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dê um passo à frente com um pé e coloque-o cerca de 60 centímetros à frente do outro pé. Abaixe o corpo dobrando os joelhos e quadris, mantendo as costas retas. Continue abaixando até que a coxa da frente fique paralela ao chão e o joelho de trás paire logo acima do chão. Faça uma pausa por um momento e empurre o calcanhar dianteiro para retornar à posição inicial. Repita pelo número desejado de repetições, depois troque de perna e repita.', '/exercise-media/bstrainer/2368.gif', 'hasaneyldrm', '2368'),
  ('b1d7a80a-0000-4000-8000-000000000786'::uuid, null, 'agachamento idiota', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves', 'core']::text[], 'barbell', false, 'Comece com a barra apoiada nos ombros, com os pés afastados na largura dos ombros. Abaixe o corpo em uma posição agachada, mantendo o peito para cima e os joelhos acompanhando os dedos dos pés. Ao chegar ao final do agachamento, passe explosivamente pelas pernas e empurre a barra acima da cabeça. Quando a barra atingir o pico, caia rapidamente para uma posição dividida, com um pé à frente e outro atrás. Pegue a barra acima da cabeça com os braços totalmente estendidos e o joelho de trás tocando levemente o chão. Levante-se da posição dividida, juntando os pés novamente. Abaixe a barra de volta aos ombros e repita o número desejado de repetições.', '/exercise-media/bstrainer/0786.gif', 'hasaneyldrm', '0786'),
  ('b1d7a80a-0000-4000-8000-000000001705'::uuid, null, 'agachamento na bola bosu', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'machine', false, 'Coloque a bola bosu no chão com o lado plano voltado para cima. Fique em pé com os pés afastados na largura dos ombros e posicione-se em cima da bola bosu. Abaixe o corpo dobrando os joelhos e quadris, como se estivesse sentado em uma cadeira. Mantenha o peito erguido e o peso sobre os calcanhares. Abaixe-se até que as coxas fiquem paralelas ao chão. Faça uma pausa por um momento e empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1705.gif', 'hasaneyldrm', '1705'),
  ('b1d7a80a-0000-4000-8000-000000001685'::uuid, null, 'agachamento para alcance acima da cabeça', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'core']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Abaixe o corpo até uma posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Ao sair do agachamento, estenda os braços acima da cabeça, alcançando o teto. Retorne à posição inicial abaixando os braços e dobrando os joelhos para agachar-se novamente. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1685.gif', 'hasaneyldrm', '1685'),
  ('b1d7a80a-0000-4000-8000-000000001686'::uuid, null, 'agachamento até alcance acima da cabeça com torção', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'core']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos ligeiramente voltados para fora. Abaixe o corpo até a posição de agachamento, dobrando os joelhos e empurrando os quadris para trás. Ao sair do agachamento, levante os braços acima da cabeça e gire o tronco para o lado. Volte à posição inicial e repita o agachamento, desta vez girando o tronco para o lado oposto. Continue alternando os lados com cada repetição de agachamento.', '/exercise-media/bstrainer/1686.gif', 'hasaneyldrm', '1686'),
  ('b1d7a80a-0000-4000-8000-000000002297'::uuid, null, 'crunch de bola de estabilidade (mãos em toda a extensão atrás da cabeça)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'machine', false, 'Sente-se na bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, enrole lentamente a parte superior do corpo para a frente, trazendo o peito em direção aos joelhos. Faça uma pausa por um momento na parte superior e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2297.gif', 'hasaneyldrm', '2297'),
  ('b1d7a80a-0000-4000-8000-000000003291'::uuid, null, 'prensa de estalar', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'bodyweight', false, 'Comece ficando em pé com os pés afastados na largura dos ombros e os braços estendidos acima da cabeça. Dobre ligeiramente os joelhos e envolva o núcleo. Abaixe o corpo até uma posição de agachamento, mantendo os braços estendidos acima da cabeça. Ao agachar-se, pressione os braços em direção ao chão, envolvendo o tríceps. Faça uma pausa por um momento na parte inferior do agachamento e, em seguida, empurre os calcanhares para se levantar e, ao mesmo tempo, levante os braços acima da cabeça. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3291.gif', 'hasaneyldrm', '3291'),
  ('b1d7a80a-0000-4000-8000-000000003669'::uuid, null, 'arqueiro em pé', 'isolation', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders', 'biceps', 'forearms']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Estenda os braços à sua frente, na altura dos ombros, paralelos ao chão. Gire o tronco para a direita, mantendo os braços estendidos e as costas retas. Ao girar, estenda o braço direito para a frente e o braço esquerdo para trás, imitando o movimento de puxar a corda de um arco. Mantenha a posição por um momento e depois retorne à posição inicial. Repita o movimento, desta vez girando o tronco para a esquerda e estendendo o braço esquerdo para frente e o direito para trás. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/3669.gif', 'hasaneyldrm', '3669'),
  ('b1d7a80a-0000-4000-8000-000000000788'::uuid, null, 'em pé atrás do pescoço', 'push_h', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'barbell', false, 'Fique em pé com os pés afastados na largura dos ombros e segure a barra atrás do pescoço com uma pegada pronada. Mantenha as costas retas e o núcleo engajado. Pressione a barra acima da cabeça, estendendo os braços, estendendo totalmente os cotovelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a barra de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0788.gif', 'hasaneyldrm', '0788'),
  ('b1d7a80a-0000-4000-8000-000000001490'::uuid, null, 'panturrilha em pé (em escada)', 'isolation', ARRAY['calves', 'ankles']::text[], ARRAY['ankles', 'feet']::text[], 'bodyweight', false, 'Fique na beira de um degrau ou plataforma robusta com os calcanhares pendurados e os dedos dos pés no degrau. Segure-se em um corrimão ou parede para se equilibrar, se necessário. Levante lentamente os calcanhares o mais alto possível, colocando o peso do corpo na planta dos pés. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1490.gif', 'hasaneyldrm', '1490'),
  ('b1d7a80a-0000-4000-8000-000000001397'::uuid, null, 'bezerros em pé', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos apontando para a frente. Levante os calcanhares do chão o mais alto possível, ficando na ponta dos pés. Mantenha a posição por um momento e depois abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1397.gif', 'hasaneyldrm', '1397'),
  ('b1d7a80a-0000-4000-8000-000000001398'::uuid, null, 'alongamento de panturrilhas em pé', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique de frente para uma parede ou objeto resistente, a cerca de um braço de distância. Coloque as mãos na parede ou objeto na altura dos ombros. Dê um passo para trás com um pé, mantendo o calcanhar apoiado no chão. Dobre ligeiramente o joelho da frente e incline-se para a frente, mantendo a perna de trás esticada. Você deve sentir um alongamento no músculo da panturrilha. Mantenha o alongamento por 20 a 30 segundos. Repita na outra perna.', '/exercise-media/bstrainer/1398.gif', 'hasaneyldrm', '1398'),
  ('b1d7a80a-0000-4000-8000-000000001599'::uuid, null, 'alongamento de isquiotibiais e panturrilhas em pé com cinta', 'isolation', ARRAY['hamstrings', 'calves']::text[], ARRAY['calves']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros. Segure a alça com as duas mãos e coloque-a em volta da planta do pé. Mantenha a perna reta e incline-se lentamente para a frente a partir dos quadris, mantendo as costas retas. Sinta o alongamento dos músculos isquiotibiais e da panturrilha. Mantenha o alongamento por 20 a 30 segundos. Solte o alongamento e repita com a outra perna. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1599.gif', 'hasaneyldrm', '1599'),
  ('b1d7a80a-0000-4000-8000-000000000794'::uuid, null, 'alongamento lateral em pé', 'isolation', ARRAY['lats', 'shoulders']::text[], ARRAY['shoulders', 'obliques']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Estenda os braços para os lados, paralelos ao chão. Incline lentamente a parte superior do corpo para um lado, sentindo um alongamento nas laterais e nos dorsais. Mantenha o alongamento por 15 a 30 segundos. Volte à posição inicial e repita do outro lado. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0794.gif', 'hasaneyldrm', '0794'),
  ('b1d7a80a-0000-4000-8000-000000001364'::uuid, null, 'inclinação pélvica em pé', 'isolation', ARRAY['spine', 'abdominals']::text[], ARRAY['abdominals']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Coloque as mãos nos quadris ou deixe-as penduradas ao lado do corpo. Envolva os músculos centrais e incline a pélvis para a frente, empurrando a parte inferior das costas em direção à parede atrás de você. Mantenha a posição por alguns segundos, depois solte e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1364.gif', 'hasaneyldrm', '1364'),
  ('b1d7a80a-0000-4000-8000-000000000795'::uuid, null, 'flexão de perna única em pé', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes']::text[], 'bodyweight', true, 'Fique em pé com os pés afastados na largura dos quadris e as mãos nos quadris. Transfira o peso para a perna esquerda e levante o pé direito do chão, dobrando o joelho. Enrole lentamente o calcanhar direito em direção aos glúteos, apertando os tendões da coxa. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o pé direito de volta à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0795.gif', 'hasaneyldrm', '0795'),
  ('b1d7a80a-0000-4000-8000-000000000796'::uuid, null, 'rolamento da roda em pé', 'core', ARRAY['abs', 'lower back']::text[], ARRAY['lower back', 'shoulders']::text[], 'machine', false, 'Comece ficando em pé, com os pés afastados na largura dos ombros e o rolo da roda à sua frente. Dobre a cintura e role lentamente a roda para frente, mantendo as costas retas e o núcleo engajado. Continue rolando para frente até sentir um alongamento no abdômen e seu corpo esticar o máximo possível. Faça uma pausa por um momento e, em seguida, gire lentamente a roda em direção ao seu corpo, retornando à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0796.gif', 'hasaneyldrm', '0796'),
  ('b1d7a80a-0000-4000-8000-000000003223'::uuid, null, 'salto estrela (masculino)', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços ao lado do corpo. Dobre ligeiramente os joelhos e salte explosivamente. Ao pular, abra as pernas e estenda os braços para os lados, formando uma estrela com o corpo. Pouse suavemente na planta dos pés com os joelhos ligeiramente dobrados. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3223.gif', 'hasaneyldrm', '3223'),
  ('b1d7a80a-0000-4000-8000-000000002138'::uuid, null, 'corrida de bicicleta ergométrica v. 3', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a altura e a posição do assento para garantir o alinhamento adequado. Coloque os pés nos pedais e prenda-os com as tiras, se disponíveis. Comece a pedalar em um ritmo confortável. Mantenha um ritmo constante e aumente a resistência conforme desejado. Envolva os músculos centrais para manter a estabilidade e a postura adequada. Continue pedalando durante a duração desejada do seu treino. Diminua gradualmente a resistência e desacelere antes de parar completamente. Estique as pernas e relaxe após o treino.', '/exercise-media/bstrainer/2138.gif', 'hasaneyldrm', '2138'),
  ('b1d7a80a-0000-4000-8000-000000000798'::uuid, null, 'caminhada de bicicleta ergométrica', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste a altura e a posição do assento na bicicleta ergométrica para garantir o alinhamento adequado. Coloque os pés nos pedais e prenda-os com as tiras, se disponíveis. Comece a pedalar em um ritmo confortável, mantendo as costas retas e o núcleo engajado. Mantenha um ritmo constante e aumente o nível de resistência, se desejar. Continue pedalando durante a duração desejada do seu treino cardiovascular. Refresque-se reduzindo gradualmente o ritmo e o nível de resistência. Alongue os músculos das pernas após o treino para evitar rigidez e promover a recuperação.', '/exercise-media/bstrainer/0798.gif', 'hasaneyldrm', '0798'),
  ('b1d7a80a-0000-4000-8000-000000003314'::uuid, null, 'straddle maltês', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'bodyweight', false, 'Comece pendurado em um par de argolas com os braços totalmente estendidos e o corpo em linha reta. Afaste bem as pernas, formando uma posição aberta. Envolva seu núcleo e abaixe lentamente o corpo até que os braços fiquem paralelos ao chão. Mantenha essa posição por alguns segundos e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3314.gif', 'hasaneyldrm', '3314'),
  ('b1d7a80a-0000-4000-8000-000000003298'::uuid, null, 'straddle planche', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'triceps', 'chest']::text[], 'bodyweight', false, 'Comece em uma posição de flexão com as mãos na largura dos ombros e os pés bem afastados. Envolva seu núcleo e mova lentamente o peso para a frente, colocando os ombros sobre as mãos. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo os cotovelos próximos ao corpo. Faça uma pausa por um momento na parte inferior e, em seguida, empurre as mãos para esticar os braços e levantar o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3298.gif', 'hasaneyldrm', '3298'),
  ('b1d7a80a-0000-4000-8000-000000001427'::uuid, null, 'abdutor externo do quadril com perna reta', 'isolation', ARRAY['abductors', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'bodyweight', false, 'Deite-se de lado com as pernas esticadas e empilhadas uma sobre a outra. Coloque o braço inferior sob a cabeça para obter apoio. Envolva o núcleo e levante a perna de cima o mais alto possível, sem girar os quadris ou inclinar-se para trás. Faça uma pausa no topo e, em seguida, abaixe lentamente a perna de volta à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/1427.gif', 'hasaneyldrm', '1427'),
  ('b1d7a80a-0000-4000-8000-000000000803'::uuid, null, 'flexão do super-homem', 'push_h', ARRAY['pectorals', 'core']::text[], ARRAY['core', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Envolva o núcleo e abaixe o corpo em direção ao chão, mantendo os cotovelos próximos ao corpo. Ao abaixar o corpo, levante simultaneamente o braço direito e a perna esquerda do chão, estendendo-os para fora. Faça uma pausa por um momento no topo e, em seguida, abaixe o braço e a perna enquanto se empurra de volta à posição inicial. Repita o movimento, desta vez levantando o braço esquerdo e a perna direita. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0803.gif', 'hasaneyldrm', '0803'),
  ('b1d7a80a-0000-4000-8000-000000000805'::uuid, null, 'precipitação abdominal suspensa', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Prenda um suporte de suspensão a um ponto de ancoragem alto e ajuste as tiras na altura da cintura. Fique de costas para o ponto de ancoragem e segure as alças com os braços estendidos à sua frente. Incline-se para a frente na cintura, mantendo o corpo reto e o núcleo engajado. Abaixe o corpo o máximo que puder, mantendo o controle e a tensão nos abdominais. Faça uma pausa por um momento na parte inferior e, em seguida, levante lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0805.gif', 'hasaneyldrm', '0805'),
  ('b1d7a80a-0000-4000-8000-000000000806'::uuid, null, 'flexão suspensa', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders', 'core']::text[], 'bodyweight', false, 'Encontre um treinador de suspensão e ajuste-o para uma altura apropriada. Fique de costas para o ponto de ancoragem e segure as alças com uma pegada pronada. Ande com os pés para a frente, inclinando o corpo para a frente até que seu peso seja sustentado pelo suporte de suspensão. Mantenha o corpo reto da cabeça aos calcanhares, envolva o núcleo e abaixe o peito em direção às alças. Empurre o peito e os braços para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0806.gif', 'hasaneyldrm', '0806'),
  ('b1d7a80a-0000-4000-8000-000000000807'::uuid, null, 'crise reversa suspensa', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva o núcleo e levante os joelhos em direção ao peito, curvando a pélvis em direção à caixa torácica. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os joelhos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0807.gif', 'hasaneyldrm', '0807'),
  ('b1d7a80a-0000-4000-8000-000000000808'::uuid, null, 'linha suspensa', 'pull_h', ARRAY['upper back', 'biceps']::text[], ARRAY['biceps', 'shoulders']::text[], 'bodyweight', false, 'Configure um treinador de suspensão a uma altura apropriada. Fique de frente para o ponto de ancoragem com os pés afastados na largura dos ombros. Segure as alças com uma pegada pronada, com as palmas voltadas uma para a outra. Incline-se para trás, mantendo o corpo reto e os calcanhares no chão. Puxe o peito em direção às alças, apertando as omoplatas. Faça uma pausa no topo e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0808.gif', 'hasaneyldrm', '0808'),
  ('b1d7a80a-0000-4000-8000-000000000809'::uuid, null, 'agachamento dividido suspenso', 'lunge', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique de costas para um treinador de suspensão com os pés afastados na largura dos ombros. Estenda uma perna para a frente e coloque a parte superior do pé na base do suporte de suspensão. Dobre a perna de apoio e abaixe o corpo em uma posição de estocada, mantendo o peito para cima e o joelho alinhado com os dedos dos pés. Empurre o calcanhar para retornar à posição inicial. Repita o número desejado de repetições e depois troque as pernas.', '/exercise-media/bstrainer/0809.gif', 'hasaneyldrm', '0809'),
  ('b1d7a80a-0000-4000-8000-000000003433'::uuid, null, 'nadador chuta v. 2 (masculino)', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'calves']::text[], 'bodyweight', false, 'Deite-se de bruços em uma esteira com os braços estendidos acima da cabeça. Envolva seu núcleo e levante o peito e as pernas do chão simultaneamente. Balance as pernas para cima e para baixo em um movimento vibrante, como se estivesse nadando. Continue chutando pelo número desejado de repetições. Abaixe o peito e as pernas de volta à posição inicial.', '/exercise-media/bstrainer/3433.gif', 'hasaneyldrm', '3433'),
  ('b1d7a80a-0000-4000-8000-000000003318'::uuid, null, 'balanço 360', 'isolation', ARRAY['cardiovascular system', 'shoulders']::text[], ARRAY['shoulders', 'core']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Mantenha os braços esticados à sua frente, paralelos ao chão. Envolva seu núcleo e balance os braços em um movimento circular, girando o tronco enquanto faz isso. Continue o movimento circular, balançando os braços e girando o tronco pelo número desejado de repetições. Lembre-se de respirar durante todo o exercício.', '/exercise-media/bstrainer/3318.gif', 'hasaneyldrm', '3318'),
  ('b1d7a80a-0000-4000-8000-000000001753'::uuid, null, 'três mergulhos na bancada', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se em um banco com as mãos segurando a borda e os dedos apontando para frente. Deslize a bunda para fora do banco, apoiando o peso com as mãos. Dobre os cotovelos e abaixe o corpo até que os braços fiquem paralelos ao chão. Empurre-se de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1753.gif', 'hasaneyldrm', '1753'),
  ('b1d7a80a-0000-4000-8000-000000002459'::uuid, null, 'pneu virando', 'isolation', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'core']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, de frente para o pneu. Dobre os joelhos e dobre os quadris, abaixando-se para uma posição agachada. Abaixe-se e segure a borda inferior do pneu com as duas mãos, os dedos voltados para você. Envolva os glúteos e os músculos das pernas e passe explosivamente pelas pernas para levantar o pneu do chão. Quando o pneu virar, use a força da parte superior do corpo para guiá-lo e manter o controle. Assim que o pneu estiver totalmente virado, dê um passo para trás rapidamente e redefina sua postura. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2459.gif', 'hasaneyldrm', '2459'),
  ('b1d7a80a-0000-4000-8000-000000000811'::uuid, null, 'levantamento terra com barra de armadilha', 'hinge', ARRAY['glutes', 'hamstrings']::text[], ARRAY['hamstrings', 'quadriceps', 'lower back']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e a barra da armadilha no chão à sua frente. Dobre os quadris e os joelhos para se abaixar e segure as alças da barra de armadilha com uma pegada pronada. Mantenha as costas retas e o peito erguido ao começar a levantar a barra do chão, estendendo os quadris e os joelhos. Ao levantar, concentre-se em passar pelos calcanhares e apertar os glúteos no topo do movimento. Abaixe a barra de armadilha de volta ao chão, dobrando os quadris e os joelhos, mantendo as costas retas durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0811.gif', 'hasaneyldrm', '0811'),
  ('b1d7a80a-0000-4000-8000-000000000814'::uuid, null, 'mergulho de tríceps', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se na beira de um banco ou cadeira com as mãos segurando a borda e os dedos apontando para frente. Deslize a bunda para fora do banco, apoiando o peso com as mãos. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas próximas ao banco. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0814.gif', 'hasaneyldrm', '0814'),
  ('b1d7a80a-0000-4000-8000-000000000812'::uuid, null, 'mergulho de tríceps (perna de banco)', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se na beira de um banco com as mãos segurando a borda e os dedos apontando para frente. Ande com os pés para a frente, deslizando a bunda para fora do banco e estique os braços. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas próximas ao banco. Empurre as palmas das mãos para esticar os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0812.gif', 'hasaneyldrm', '0812'),
  ('b1d7a80a-0000-4000-8000-000000000813'::uuid, null, 'mergulho de tríceps (entre bancos)', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se em um banco com as mãos segurando a borda do banco e os dedos apontando para frente. Deslize a bunda para fora do banco, apoiando o peso com as mãos. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo as costas próximas ao banco. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0813.gif', 'hasaneyldrm', '0813'),
  ('b1d7a80a-0000-4000-8000-000000000815'::uuid, null, 'tríceps mergulha no chão', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'bodyweight', false, 'Sente-se na beirada de uma cadeira ou banco com as mãos próximas aos quadris e os dedos apontando para a frente. Deslize a bunda para fora da cadeira com as pernas estendidas à sua frente. Estique os braços, mantendo uma pequena flexão nos cotovelos para manter a tensão nos tríceps e nas articulações dos cotovelos. Dobre lentamente os cotovelos para abaixar o corpo em direção ao chão até que os cotovelos formem um ângulo de 90 graus. Ao chegar ao final do movimento, pressione a cadeira para endireitar os cotovelos, retornando à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0815.gif', 'hasaneyldrm', '0815'),
  ('b1d7a80a-0000-4000-8000-000000000816'::uuid, null, 'desenvolvimento de tríceps', 'push_h', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os joelhos ligeiramente flexionados. Estenda os braços à sua frente, paralelos ao chão. Dobre os cotovelos e abaixe o corpo em direção ao chão, mantendo os braços próximos ao corpo. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0816.gif', 'hasaneyldrm', '0816'),
  ('b1d7a80a-0000-4000-8000-000000000817'::uuid, null, 'alongamento de tríceps', 'isolation', ARRAY['triceps', 'shoulders']::text[], ARRAY['shoulders']::text[], 'bodyweight', false, 'Fique em pé ou sente-se ereto com as costas retas. Estenda um braço acima da cabeça, dobrando-o no cotovelo. Coloque a mão oposta no cotovelo dobrado e puxe-o suavemente em direção à cabeça. Mantenha o alongamento por 15 a 30 segundos, sentindo um alongamento suave no tríceps. Solte o alongamento e repita no outro braço.', '/exercise-media/bstrainer/0817.gif', 'hasaneyldrm', '0817'),
  ('b1d7a80a-0000-4000-8000-000000000871'::uuid, null, 'dobra crocante', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos atrás da cabeça com os cotovelos apontando para fora. Envolvendo os abdominais, levante as omoplatas do chão e traga os joelhos em direção ao peito, curvando simultaneamente a parte superior do corpo em direção aos joelhos. Faça uma pausa por um momento no topo, depois abaixe lentamente as omoplatas e estenda as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0871.gif', 'hasaneyldrm', '0871'),
  ('b1d7a80a-0000-4000-8000-000000000818'::uuid, null, 'alça dupla alça paralela lat pulldown', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[], 'cable', false, 'Ajuste a altura do assento e posicione-se de frente para a máquina de cabos. Segure as alças com uma pegada pronada, com as mãos na largura dos ombros. Sente-se e posicione as coxas sob as almofadas das coxas, mantendo os pés apoiados no chão. Incline-se ligeiramente para trás e mantenha o peito erguido, mantendo a coluna neutra. Puxe as alças para baixo em direção à parte superior do tórax, apertando as omoplatas. Faça uma pausa por um momento no final do movimento, sentindo a contração no seu grande dorsal. Solte lentamente as alças e retorne à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0818.gif', 'hasaneyldrm', '0818'),
  ('b1d7a80a-0000-4000-8000-000000001466'::uuid, null, 'elevação de quadril com torção', 'isolation', ARRAY['glutes', 'obliques']::text[], ARRAY['obliques', 'hamstrings']::text[], 'bodyweight', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Coloque as mãos ao lado do corpo para apoio. Envolva os glúteos e levante os quadris do chão, formando uma linha reta dos joelhos até os ombros. Mantendo os quadris elevados, gire a parte inferior do corpo para o lado direito, trazendo os joelhos em direção ao chão. Volte à posição inicial e repita a torção para o lado esquerdo. Continue alternando torções para o número desejado de repetições.', '/exercise-media/bstrainer/1466.gif', 'hasaneyldrm', '1466'),
  ('b1d7a80a-0000-4000-8000-000000002802'::uuid, null, 'elevação de perna torcida', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Coloque as mãos sob os glúteos para obter apoio. Envolva os abdominais e levante ambas as pernas do chão, mantendo-as retas. Ao levantar as pernas, gire os quadris para o lado, trazendo as pernas em direção ao ombro oposto. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita o movimento, desta vez girando o quadril para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/2802.gif', 'hasaneyldrm', '2802'),
  ('b1d7a80a-0000-4000-8000-000000002801'::uuid, null, 'elevação de perna torcida (feminino)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'bodyweight', false, 'Deite-se de costas com as pernas estendidas e os braços ao lado do corpo. Dobre os joelhos e levante as pernas do chão, aproximando-as do peito. Ao levantar as pernas, gire os quadris para o lado, trazendo os joelhos em direção ao ombro oposto. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita o movimento, desta vez girando o quadril para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/2801.gif', 'hasaneyldrm', '2801'),
  ('b1d7a80a-0000-4000-8000-000000003231'::uuid, null, 'toque com dois dedos (masculino)', 'isolation', ARRAY['spine', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros e os braços estendidos para os lados. Incline-se para a frente na cintura, mantendo as costas retas e os joelhos ligeiramente flexionados. Alcance os dedos dos pés com as duas mãos, mantendo as pernas retas. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3231.gif', 'hasaneyldrm', '3231'),
  ('b1d7a80a-0000-4000-8000-000000001365'::uuid, null, 'alongamento da parte superior das costas', 'isolation', ARRAY['upper back', 'shoulders']::text[], ARRAY['shoulders']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Estenda os braços esticados à sua frente, paralelos ao chão. Entrelace os dedos e gire as palmas para longe do corpo. Levante lentamente os braços acima da cabeça, mantendo-os retos e paralelos um ao outro. Ao levantar os braços, aperte as omoplatas. Mantenha o alongamento por 15 a 30 segundos, depois solte e repita.', '/exercise-media/bstrainer/1365.gif', 'hasaneyldrm', '1365'),
  ('b1d7a80a-0000-4000-8000-000000001366'::uuid, null, 'cachorro voltado para cima', 'isolation', ARRAY['spine', 'shoulders']::text[], ARRAY['shoulders', 'chest']::text[], 'bodyweight', false, 'Deite-se de bruços no chão com as pernas estendidas para trás. Coloque as mãos no chão, próximas às costelas inferiores, com os dedos apontando para frente. Pressione as mãos firmemente no chão e estique os braços, levantando o tronco e as coxas do chão. Role os ombros para trás e para baixo, abrindo o peito e levantando o olhar para o teto. Mantenha essa posição por algumas respirações e depois abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1366.gif', 'hasaneyldrm', '1366'),
  ('b1d7a80a-0000-4000-8000-000000003420'::uuid, null, 'v-sentar no chão', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Sente-se no chão com as pernas estendidas à sua frente. Incline-se ligeiramente para trás e levante as pernas do chão, mantendo-as retas. Simultaneamente, levante a parte superior do corpo do chão e estenda os braços em direção às pernas. Mantenha essa posição por alguns segundos e, em seguida, abaixe lentamente a parte superior do corpo e as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3420.gif', 'hasaneyldrm', '3420'),
  ('b1d7a80a-0000-4000-8000-000000000826'::uuid, null, 'elevação vertical das pernas (nas barras paralelas)', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors']::text[], 'bodyweight', false, 'Pendure-se nas barras paralelas com os braços totalmente estendidos e o corpo reto. Envolva seu núcleo e levante as pernas à sua frente, mantendo-as retas. Continue levantando até que suas pernas fiquem paralelas ao chão ou um pouco mais altas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0826.gif', 'hasaneyldrm', '0826'),
  ('b1d7a80a-0000-4000-8000-000000002141'::uuid, null, 'aparelho elíptico para caminhada', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'machine', false, 'Ajuste o nível de resistência e a inclinação da máquina elíptica para as configurações desejadas. Suba nos pedais da máquina e segure levemente as alças. Comece empurrando para baixo com os pés e puxando as alças em direção ao corpo. Continue esse movimento, alternando entre empurrar e puxar, para simular um movimento de caminhada ou corrida. Mantenha um ritmo constante e mantenha seu núcleo engajado durante todo o exercício. Continue pela duração desejada do seu treino cardiovascular. Diminua gradualmente a intensidade e a velocidade da máquina antes de sair.', '/exercise-media/bstrainer/2141.gif', 'hasaneyldrm', '2141'),
  ('b1d7a80a-0000-4000-8000-000000003655'::uuid, null, 'caminhada com estocada de joelhos altos', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura do quadril. Levante o joelho direito em direção ao peito o mais alto que puder enquanto se equilibra na perna esquerda. Dê um passo à frente com o pé direito e abaixe o corpo em uma posição de estocada, dobrando os joelhos em um ângulo de 90 graus. Empurre com o pé direito e levante o joelho esquerdo em direção ao peito. Dê um passo à frente com o pé esquerdo e abaixe o corpo em uma posição de estocada. Continue alternando as pernas e avançando, mantendo o núcleo engajado e um ritmo constante. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3655.gif', 'hasaneyldrm', '3655'),
  ('b1d7a80a-0000-4000-8000-000000001460'::uuid, null, 'estocada andando', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Fique em pé com os pés afastados na largura dos ombros. Dê um passo à frente com a perna direita, abaixando o corpo para uma posição de estocada. Mantenha o tronco ereto e o joelho da frente alinhado com o tornozelo. Empurre com o pé direito e leve o pé esquerdo para a frente, assumindo uma posição de estocada com a perna esquerda. Continue alternando as pernas e andando para frente, mantendo um ritmo controlado e constante. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1460.gif', 'hasaneyldrm', '1460'),
  ('b1d7a80a-0000-4000-8000-000000003666'::uuid, null, 'caminhada em esteira inclinada', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Ajuste o nível de inclinação da esteira para a intensidade desejada. Fique na esteira com os pés afastados na largura dos ombros. Comece a caminhar em um ritmo confortável, garantindo a manutenção da forma adequada. Envolva os músculos centrais e mantenha as costas retas durante todo o exercício. Continue caminhando na esteira inclinada durante a duração desejada do seu treino cardiovascular. Diminua gradualmente a inclinação e a velocidade da esteira para esfriar antes de parar.', '/exercise-media/bstrainer/3666.gif', 'hasaneyldrm', '3666'),
  ('b1d7a80a-0000-4000-8000-000000002311'::uuid, null, 'andando na esteira', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves']::text[], 'machine', false, 'Ajuste a máquina de stepmill para um nível confortável. Suba na máquina e coloque as mãos nos corrimãos para se apoiar. Comece a caminhar colocando um pé no degrau e depois o outro, alternando entre as pernas. Mantenha uma postura ereta e envolva os músculos centrais. Continue caminhando pela duração ou distância desejada. Aumente gradualmente a intensidade ou velocidade à medida que se sentir mais confortável com o exercício. Lembre-se de esfriar e alongar após concluir o exercício.', '/exercise-media/bstrainer/2311.gif', 'hasaneyldrm', '2311'),
  ('b1d7a80a-0000-4000-8000-000000000830'::uuid, null, 'mergulho de bancada ponderado', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Sente-se em um banco com as mãos segurando a borda e os dedos apontando para frente. Deslize a bunda para fora do banco, apoiando o peso com as mãos. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Empurre-se de volta à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0830.gif', 'hasaneyldrm', '0830'),
  ('b1d7a80a-0000-4000-8000-000000002987'::uuid, null, 'Pegada fechada com peso na barra de apoio na gaiola de imersão', 'push_h', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Fique na frente da gaiola de imersão e agarre as barras paralelas com uma pegada por baixo, com as mãos afastadas na largura dos ombros. Pendure-se nas barras com os braços totalmente estendidos, os pés afastados do chão e o corpo reto. Envolva os músculos das costas e puxe o corpo em direção às barras, mantendo os cotovelos próximos aos lados. Continue puxando até que seu queixo esteja acima das barras e faça uma pausa por um momento. Abaixe lentamente o corpo de volta à posição inicial, estendendo totalmente os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2987.gif', 'hasaneyldrm', '2987'),
  ('b1d7a80a-0000-4000-8000-000000003643'::uuid, null, 'agachamento cossaco ponderado (masculino)', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Fique em pé com os pés mais afastados do que a largura dos ombros e os dedos apontando ligeiramente para fora. Segure um peso na frente do peito com as duas mãos. Mude o peso para um lado e abaixe o corpo dobrando o joelho do lado para o qual você se deslocou, enquanto mantém a outra perna reta. Vá o mais baixo possível, mantendo o equilíbrio e o peito erguido. Empurre o calcanhar da perna dobrada para retornar à posição inicial. Repita do outro lado, alternando entre as pernas.', '/exercise-media/bstrainer/3643.gif', 'hasaneyldrm', '3643'),
  ('b1d7a80a-0000-4000-8000-000000000832'::uuid, null, 'crise ponderada', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques']::text[], 'machine', false, 'Deite-se de costas com os joelhos dobrados e os pés apoiados no chão. Segure uma placa de peso ou haltere no peito. Envolva os abdominais e levante a parte superior do corpo do chão, curvando-se para a frente até que as omoplatas saiam do chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0832.gif', 'hasaneyldrm', '0832'),
  ('b1d7a80a-0000-4000-8000-000000003670'::uuid, null, 'abdominais de declínio ponderado', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'machine', false, 'Deite-se em um banco inclinado com os pés presos sob as almofadas dos pés. Coloque as mãos atrás da cabeça ou sobre o peito. Envolva os abdominais e levante lentamente a parte superior do corpo do banco, curvando-se para a frente até que o tronco fique perpendicular ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3670.gif', 'hasaneyldrm', '3670'),
  ('b1d7a80a-0000-4000-8000-000000000833'::uuid, null, 'cria ponderada de burro', 'isolation', ARRAY['calves', 'hamstrings']::text[], ARRAY['hamstrings', 'glutes']::text[], 'machine', false, 'Fique em uma plataforma elevada com os dedos dos pés na borda e os calcanhares pendurados. Segure-se em um objeto estável para suporte. Levante os calcanhares o mais alto possível, estendendo os tornozelos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os calcanhares de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0833.gif', 'hasaneyldrm', '0833'),
  ('b1d7a80a-0000-4000-8000-000000001310'::uuid, null, 'flexão de queda ponderada', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Comece em uma posição de prancha alta, com as mãos ligeiramente mais afastadas que a largura dos ombros e os pés juntos. Abaixe o peito em direção ao chão, mantendo os cotovelos próximos ao corpo. Quando seu peito estiver logo acima do solo, empurre-se para cima de forma explosiva, levantando as mãos do chão. Ao empurrar para cima, mova rapidamente as mãos para os lados e ligeiramente para a frente, permitindo que seu corpo caia em direção ao chão. Segure-se com as mãos na posição mais ampla e abaixe imediatamente o peito em direção ao chão novamente. Repita o movimento de flexão, caindo e segurando as mãos na posição mais estreita. Continue alternando entre as posições das mãos mais largas e mais estreitas para o número desejado de repetições.', '/exercise-media/bstrainer/1310.gif', 'hasaneyldrm', '1310'),
  ('b1d7a80a-0000-4000-8000-000000002135'::uuid, null, 'prancha frontal ponderada', 'core', ARRAY['abs', 'shoulders']::text[], ARRAY['shoulders', 'lower back']::text[], 'machine', false, 'Comece deitando-se de bruços no chão. Coloque os antebraços no chão, com os cotovelos diretamente sob os ombros. Estenda as pernas para trás, com os dedos dos pés no chão. Envolva seu núcleo e levante o corpo do chão, equilibrando-se nos antebraços e dedos dos pés. Mantenha o corpo em linha reta, da cabeça aos calcanhares. Mantenha esta posição pelo tempo desejado. Abaixe o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2135.gif', 'hasaneyldrm', '2135'),
  ('b1d7a80a-0000-4000-8000-000000000834'::uuid, null, 'elevação frontal ponderada', 'isolation', ARRAY['delts', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um haltere em cada mão com as palmas voltadas para as coxas. Mantendo os braços retos, expire e levante os halteres à sua frente até que fiquem na altura dos ombros. Faça uma pausa por um momento no topo, inspire e abaixe lentamente os halteres de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0834.gif', 'hasaneyldrm', '0834'),
  ('b1d7a80a-0000-4000-8000-000000000866'::uuid, null, 'elevação ponderada de perna e quadril pendurada', 'core', ARRAY['abs', 'hip flexors']::text[], ARRAY['hip flexors', 'lower back']::text[], 'machine', false, 'Pendure-se em uma barra suspensa com os braços totalmente estendidos e as palmas voltadas para longe de você. Envolva seu núcleo e levante as pernas à sua frente, mantendo-as retas. Continue levantando até que suas pernas fiquem paralelas ao chão ou um pouco mais altas. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente as pernas de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0866.gif', 'hasaneyldrm', '0866'),
  ('b1d7a80a-0000-4000-8000-000000000835'::uuid, null, 'hiperextensão ponderada (na bola de estabilidade)', 'isolation', ARRAY['spine', 'glutes']::text[], ARRAY['glutes', 'hamstrings']::text[], 'machine', false, 'Posicione-se de bruços em uma bola de estabilidade, com os quadris apoiados na bola e os pés contra a parede para estabilidade. Coloque as mãos atrás da cabeça ou cruze-as sobre o peito. Envolva o núcleo e levante lentamente a parte superior do corpo da bola, estendendo as costas até que o corpo forme uma linha reta. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente a parte superior do corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0835.gif', 'hasaneyldrm', '0835'),
  ('b1d7a80a-0000-4000-8000-000000003641'::uuid, null, 'degrau ajoelhado com peso e balanço', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'core']::text[], 'machine', false, 'Comece na posição ajoelhada, com os joelhos afastados na largura do quadril e as costas retas. Segure um peso em cada mão, com os braços estendidos à sua frente. Envolva seu núcleo e balance os pesos para cima e acima da cabeça, mantendo os braços retos. Abaixe os pesos de volta à posição inicial e repita o número desejado de repetições.', '/exercise-media/bstrainer/3641.gif', 'hasaneyldrm', '3641'),
  ('b1d7a80a-0000-4000-8000-000000003644'::uuid, null, 'estocada ponderada com balanço', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, segurando um peso em cada mão. Dê um passo à frente com o pé direito, abaixando o corpo para uma posição de estocada. Ao avançar, balance os pesos para frente e para cima, mantendo os braços retos. Empurre com o pé direito e volte à posição inicial, balançando os pesos para baixo. Repita com o pé esquerdo e continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/3644.gif', 'hasaneyldrm', '3644'),
  ('b1d7a80a-0000-4000-8000-000000003286'::uuid, null, 'músculo ponderado para cima', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'triceps', 'shoulders', 'chest']::text[], 'machine', false, 'Comece pendurado em uma barra suspensa com as palmas voltadas para você e as mãos um pouco mais afastadas do que a largura dos ombros. Envolva seu núcleo e puxe seu corpo em direção à barra, liderando com o peito. Ao chegar ao topo do movimento, faça a transição da pegada de modo que as palmas das mãos fiquem voltadas para você. Continue se levantando até que seu peito alcance a barra e faça uma pausa por um momento. Abaixe-se lentamente de volta à posição inicial, mantendo o controle durante todo o movimento. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3286.gif', 'hasaneyldrm', '3286'),
  ('b1d7a80a-0000-4000-8000-000000003312'::uuid, null, 'musculação ponderada (na barra)', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'triceps', 'shoulders', 'forearms']::text[], 'machine', false, 'Comece pendurado em uma barra suspensa com as palmas voltadas para você e as mãos um pouco mais afastadas do que a largura dos ombros. Envolva seu núcleo e puxe as omoplatas para baixo e para trás. Dobre os cotovelos e puxe o peito em direção à barra, mantendo o corpo reto. Assim que seu peito atingir a barra, empurre para baixo com as mãos e leve os cotovelos para trás, levantando o corpo acima da barra. Faça uma pausa no início do movimento e, em seguida, abaixe-se lentamente de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3312.gif', 'hasaneyldrm', '3312'),
  ('b1d7a80a-0000-4000-8000-000000003290'::uuid, null, 'com peso de uma mão, puxe para cima', 'isolation', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Segure a barra pull-up com uma pegada pronada, um pouco mais larga que a largura dos ombros. Pendure-se na barra com o braço totalmente estendido e o corpo reto. Envolva o núcleo e puxe o corpo em direção à barra, dobrando o cotovelo e contraindo os músculos das costas. Continue puxando até que seu queixo fique acima da barra. Abaixe o corpo de volta à posição inicial com controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3290.gif', 'hasaneyldrm', '3290'),
  ('b1d7a80a-0000-4000-8000-000000000840'::uuid, null, 'crunch ponderado acima da cabeça (na bola de estabilidade)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure uma placa de peso ou haltere com as duas mãos e estenda os braços acima da cabeça. Envolva os abdominais e curve lentamente o tronco para a frente, trazendo o peito em direção aos joelhos. Faça uma pausa no topo e, em seguida, abaixe lentamente o tronco de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0840.gif', 'hasaneyldrm', '0840'),
  ('b1d7a80a-0000-4000-8000-000000000841'::uuid, null, 'pull-up ponderado', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'machine', false, 'Segure a barra pull-up com uma pegada pronada, um pouco mais larga que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo reto. Envolva os músculos das costas e puxe o corpo em direção à barra, mantendo os cotovelos próximos ao corpo. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0841.gif', 'hasaneyldrm', '0841'),
  ('b1d7a80a-0000-4000-8000-000000000844'::uuid, null, 'braço redondo ponderado', 'isolation', ARRAY['delts', 'triceps']::text[], ARRAY['triceps', 'upper back']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão. Dobre ligeiramente os joelhos e incline-se para a frente na altura dos quadris, mantendo as costas retas. Levante os braços para os lados, mantendo uma ligeira flexão nos cotovelos. Continue levantando os braços até que fiquem paralelos ao chão. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente os braços de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0844.gif', 'hasaneyldrm', '0844'),
  ('b1d7a80a-0000-4000-8000-000000000846'::uuid, null, 'torção russa ponderada', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Sente-se no chão com os joelhos dobrados e os pés apoiados no chão. Segure um peso ou bola medicinal com as duas mãos na frente do peito. Incline-se ligeiramente para trás, mantendo as costas retas e o núcleo engajado. Gire lentamente o tronco para a direita, trazendo o peso ou bola medicinal em direção ao chão do seu lado direito. Faça uma pausa por um momento e depois gire o tronco para a esquerda, trazendo o peso ou bola medicinal em direção ao chão do seu lado esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0846.gif', 'hasaneyldrm', '0846'),
  ('b1d7a80a-0000-4000-8000-000000000845'::uuid, null, 'torção russa ponderada (pernas para cima)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'hip flexors']::text[], 'machine', false, 'Sente-se no chão com os joelhos dobrados e os pés levantados do chão, mantendo as pernas juntas. Segure o peso com as duas mãos na frente do peito, mantendo os cotovelos levemente flexionados. Incline-se ligeiramente para trás para envolver os músculos centrais. Gire o tronco para a direita, trazendo o peso para o chão do lado direito. Faça uma pausa por um momento e depois gire o tronco para a esquerda, trazendo o peso para o chão do lado esquerdo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0845.gif', 'hasaneyldrm', '0845'),
  ('b1d7a80a-0000-4000-8000-000000002371'::uuid, null, 'torção russa ponderada v. 2', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Sente-se no chão com os joelhos dobrados e os pés apoiados no chão. Segure o peso com as duas mãos na frente do peito. Incline-se ligeiramente para trás para envolver os músculos centrais. Gire o tronco para a direita, trazendo o peso para o lado direito do corpo. Faça uma pausa e depois gire o tronco para a esquerda, trazendo o peso para o lado esquerdo do corpo. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/2371.gif', 'hasaneyldrm', '2371'),
  ('b1d7a80a-0000-4000-8000-000000000847'::uuid, null, 'rosca direta ponderada para bíceps sentado (na bola de estabilidade)', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e as costas retas. Segure uma bola medicinal com um aperto de mão, com as palmas voltadas para cima, e deixe os braços pendurados ao lado do corpo. Mantendo os braços parados, expire e enrole a bola medicinal em direção aos ombros. Faça uma pausa no topo, apertando o bíceps. Inspire e abaixe lentamente a bola medicinal de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0847.gif', 'hasaneyldrm', '0847'),
  ('b1d7a80a-0000-4000-8000-000000000849'::uuid, null, 'torção sentada ponderada (na bola de estabilidade)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés apoiados no chão e os joelhos dobrados em um ângulo de 90 graus. Segure uma placa de peso ou haltere com as duas mãos perto do peito. Envolva o núcleo e gire lentamente o tronco para o lado, mantendo os quadris estáveis. Faça uma pausa no final da rotação e depois retorne lentamente à posição inicial. Repita a rotação para o outro lado. Continue alternando os lados pelo número desejado de repetições.', '/exercise-media/bstrainer/0849.gif', 'hasaneyldrm', '0849'),
  ('b1d7a80a-0000-4000-8000-000000000850'::uuid, null, 'curvatura lateral ponderada (na bola de estabilidade)', 'core', ARRAY['abs', 'obliques']::text[], ARRAY['obliques', 'lower back']::text[], 'machine', false, 'Sente-se em uma bola de estabilidade com os pés afastados na largura dos ombros e apoiados no chão. Segure um peso com uma das mãos e coloque a outra no quadril. Envolva seu núcleo e incline-se lentamente para o lado em direção ao lado pesado, mantendo as costas retas. Faça uma pausa na parte inferior e depois retorne lentamente à posição inicial. Repita pelo número desejado de repetições e depois troque de lado.', '/exercise-media/bstrainer/0850.gif', 'hasaneyldrm', '0850'),
  ('b1d7a80a-0000-4000-8000-000000000851'::uuid, null, 'agachamento maricas ponderado', 'squat', ARRAY['quads', 'glutes']::text[], ARRAY['glutes', 'hamstrings', 'calves']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e os dedos dos pés apontando ligeiramente para fora. Segure um peso na frente do peito com as duas mãos ou coloque uma barra na parte superior das costas. Mantendo o peito para cima e o núcleo engajado, abaixe lentamente o corpo dobrando os joelhos e os quadris. Continue abaixando até que as coxas fiquem paralelas ao chão ou o mais baixo possível. Faça uma pausa por um momento na parte inferior e, em seguida, empurre os calcanhares para retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0851.gif', 'hasaneyldrm', '0851'),
  ('b1d7a80a-0000-4000-8000-000000000852'::uuid, null, 'agachamento ponderado', 'squat', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros, os dedos apontando ligeiramente para fora. Segure um peso na frente do peito ou nos ombros. Envolva o núcleo e mantenha o peito erguido enquanto abaixa os quadris para baixo e para trás, como se estivesse sentado em uma cadeira. Abaixe até que suas coxas fiquem paralelas ao chão ou o mais baixo que você puder confortavelmente. Empurre os calcanhares para se levantar, apertando os glúteos na parte superior. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0852.gif', 'hasaneyldrm', '0852'),
  ('b1d7a80a-0000-4000-8000-000000000853'::uuid, null, 'ondulação em pé ponderada', 'isolation', ARRAY['biceps', 'forearms']::text[], ARRAY['forearms']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um haltere em cada mão, com as palmas voltadas para a frente. Mantenha os cotovelos próximos ao tronco e expire enquanto enrola os pesos até a altura dos ombros. Faça uma pausa por um momento no topo e inspire enquanto abaixa lentamente os pesos de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0853.gif', 'hasaneyldrm', '0853'),
  ('b1d7a80a-0000-4000-8000-000000000854'::uuid, null, 'aperto de mão em pé com peso', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure um peso em cada mão. Estenda os braços esticados à sua frente, com as palmas voltadas uma para a outra. Aperte as mãos o mais forte que puder, envolvendo os antebraços. Segure o aperto por alguns segundos e depois solte. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0854.gif', 'hasaneyldrm', '0854'),
  ('b1d7a80a-0000-4000-8000-000000003313'::uuid, null, 'queda ponderada da barra reta', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'machine', false, 'Posicione-se entre as barras paralelas com os braços totalmente estendidos e o corpo reto. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3313.gif', 'hasaneyldrm', '3313'),
  ('b1d7a80a-0000-4000-8000-000000003642'::uuid, null, 'estocada de alongamento ponderada', 'lunge', ARRAY['glutes', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros. Dê um passo à frente com o pé direito, mantendo as costas retas. Abaixe o corpo dobrando os joelhos até que a coxa direita fique paralela ao chão. Empurre o calcanhar direito para retornar à posição inicial. Repita com a perna esquerda. Continue alternando as pernas pelo número desejado de repetições.', '/exercise-media/bstrainer/3642.gif', 'hasaneyldrm', '3642'),
  ('b1d7a80a-0000-4000-8000-000000000856'::uuid, null, 'prensa ponderada de svend', 'push_h', ARRAY['pectorals', 'shoulders']::text[], ARRAY['shoulders', 'triceps']::text[], 'machine', false, 'Fique em pé com os pés afastados na largura dos ombros e segure uma placa de peso na frente do peito com as duas mãos. Mantenha os cotovelos ligeiramente flexionados e as palmas voltadas uma para a outra. Pressione a placa de peso à sua frente, estendendo totalmente os braços. Faça uma pausa no final do movimento e, em seguida, traga lentamente a placa de peso de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0856.gif', 'hasaneyldrm', '0856'),
  ('b1d7a80a-0000-4000-8000-000000001754'::uuid, null, 'três quedas de bancada ponderadas', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Sente-se na beira de um banco com as mãos segurando a borda e os dedos apontando para frente. Ande com os pés para frente, deslizando a bunda para fora do banco e apoiando o peso com os braços. Abaixe o corpo dobrando os cotovelos, mantendo as costas próximas ao banco. Faça uma pausa na parte inferior e depois volte à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1754.gif', 'hasaneyldrm', '1754'),
  ('b1d7a80a-0000-4000-8000-000000001755'::uuid, null, 'quedas ponderadas de tríceps', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Sente-se na beira de um banco ou cadeira com as mãos segurando a borda próxima aos quadris. Deslize a bunda para fora do banco com as pernas estendidas à sua frente. Mantenha as costas próximas ao banco e os cotovelos levemente flexionados. Abaixe o corpo dobrando os cotovelos até que os braços fiquem paralelos ao chão. Empurre-se de volta à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1755.gif', 'hasaneyldrm', '1755'),
  ('b1d7a80a-0000-4000-8000-000000001767'::uuid, null, 'mergulho ponderado de tríceps em barras paralelas altas', 'push_h', ARRAY['triceps', 'chest']::text[], ARRAY['chest', 'shoulders']::text[], 'machine', false, 'Posicione-se entre duas barras paralelas com as mãos segurando as barras e os braços totalmente estendidos. Dobre os cotovelos e abaixe o corpo até que os braços fiquem paralelos ao chão. Faça uma pausa por um momento e, em seguida, empurre as palmas das mãos para esticar os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1767.gif', 'hasaneyldrm', '1767'),
  ('b1d7a80a-0000-4000-8000-000000000857'::uuid, null, 'rolamento da roda', 'core', ARRAY['abs', 'lower back']::text[], ARRAY['lower back']::text[], 'machine', false, 'Ajoelhe-se no chão e coloque o rolo da roda à sua frente. Coloque as mãos nas alças do rolo da roda e estenda os braços à sua frente. Envolva os músculos centrais e role lentamente a roda para frente, mantendo as costas retas e os abdominais contraídos. Continue rolando para frente até que seu corpo esteja totalmente estendido e seus braços acima da cabeça. Faça uma pausa por um momento e, em seguida, gire lentamente a roda em direção aos joelhos, mantendo o controle e os abdominais engajados. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0857.gif', 'hasaneyldrm', '0857'),
  ('b1d7a80a-0000-4000-8000-000000003637'::uuid, null, 'corrida de roda', 'isolation', ARRAY['cardiovascular system', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Comece na posição de prancha com as mãos no volante e o corpo reto. Envolva seu núcleo e comece a rolar a roda para frente estendendo os braços. Continue rolando até que seu corpo esteja totalmente estendido e seus braços acima da cabeça. Inverta o movimento puxando a roda em direção ao corpo, usando o núcleo e os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/3637.gif', 'hasaneyldrm', '3637'),
  ('b1d7a80a-0000-4000-8000-000000001429'::uuid, null, 'pull-up de grande aderência', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Pendure-se em uma barra suspensa com as palmas voltadas para longe de você e as mãos mais afastadas do que a largura dos ombros. Envolva seu núcleo e aperte as omoplatas. Puxe o corpo em direção à barra até que o queixo fique acima da barra. Abaixe o corpo de volta à posição inicial com controle. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1429.gif', 'hasaneyldrm', '1429'),
  ('b1d7a80a-0000-4000-8000-000000001367'::uuid, null, 'pull-up traseiro de grande aderência', 'pull_v', ARRAY['lats', 'biceps']::text[], ARRAY['biceps', 'forearms']::text[], 'bodyweight', false, 'Segure a barra pull-up com uma pegada ampla, com as mãos um pouco mais afastadas que a largura dos ombros. Pendure-se na barra com os braços totalmente estendidos e o corpo reto. Envolva os músculos das costas e puxe o corpo em direção à barra, liderando com o peito. Continue puxando até que seu queixo fique acima da barra. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o corpo de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1367.gif', 'hasaneyldrm', '1367'),
  ('b1d7a80a-0000-4000-8000-000000001311'::uuid, null, 'flexão de mão larga para cima', 'isolation', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Comece em uma posição de prancha alta com as mãos mais afastadas do que a largura dos ombros. Mantenha seu corpo em linha reta da cabeça aos pés. Abaixe o peito em direção ao chão dobrando os cotovelos, mantendo-os próximos ao corpo. Empurre as palmas das mãos para estender os braços e retornar à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/1311.gif', 'hasaneyldrm', '1311'),
  ('b1d7a80a-0000-4000-8000-000000002363'::uuid, null, 'mergulho no peito com pegada ampla em barras paralelas altas', 'push_h', ARRAY['pectorals', 'triceps']::text[], ARRAY['triceps', 'shoulders']::text[], 'bodyweight', false, 'Posicione-se nas barras paralelas com os braços totalmente estendidos e o corpo suspenso no ar. Incline-se ligeiramente para a frente e abaixe o corpo dobrando os cotovelos até que o peito fique logo acima das barras. Faça uma pausa por um momento e, em seguida, volte à posição inicial esticando os braços. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/2363.gif', 'hasaneyldrm', '2363'),
  ('b1d7a80a-0000-4000-8000-000000000858'::uuid, null, 'corridas de vento', 'core', ARRAY['abs', 'quadriceps']::text[], ARRAY['quadriceps', 'hamstrings', 'calves']::text[], 'bodyweight', false, 'Encontre um espaço aberto ou uma pista para realizar o exercício. Comece ficando em pé com os pés afastados na largura dos ombros. Comece a correr o mais rápido que puder, levantando os braços e levantando os joelhos. Continue correndo por uma distância ou período de tempo específico. Descanse e repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0858.gif', 'hasaneyldrm', '0858'),
  ('b1d7a80a-0000-4000-8000-000000001604'::uuid, null, 'maior trecho do mundo', 'isolation', ARRAY['hamstrings', 'glutes']::text[], ARRAY['glutes', 'quadriceps', 'calves']::text[], 'bodyweight', false, 'Comece em uma posição de estocada com o pé direito para frente e o pé esquerdo para trás. Coloque as mãos no chão de cada lado do pé direito. Abaixe o joelho esquerdo até o chão e estenda a perna direita, mantendo o pé direito apoiado no chão. Gire o tronco para a direita, estendendo o braço direito em direção ao teto. Mantenha esta posição por alguns segundos e depois retorne à posição inicial. Troque de lado e repita o alongamento com o pé esquerdo à frente.', '/exercise-media/bstrainer/1604.gif', 'hasaneyldrm', '1604'),
  ('b1d7a80a-0000-4000-8000-000000001428'::uuid, null, 'círculos no pulso', 'isolation', ARRAY['forearms', 'hands']::text[], ARRAY['hands', 'wrists']::text[], 'bodyweight', false, 'Estenda os braços esticados à sua frente. Faça um punho com as duas mãos. Gire os pulsos em movimentos circulares, mantendo os braços imóveis. Continue os círculos no pulso pelo número desejado de repetições.', '/exercise-media/bstrainer/1428.gif', 'hasaneyldrm', '1428'),
  ('b1d7a80a-0000-4000-8000-000000000859'::uuid, null, 'rolo de pulso', 'isolation', ARRAY['forearms', 'biceps']::text[], ARRAY['biceps', 'triceps']::text[], 'machine', false, 'Prenda um peso na extremidade de uma corda ou barra. Segure a outra ponta da corda ou barra com as duas mãos, com as palmas voltadas para baixo. Fique em pé com os pés afastados na largura dos ombros e os braços totalmente estendidos à sua frente. Role lentamente o peso em direção às mãos, flexionando os pulsos. Faça uma pausa por um momento no topo e, em seguida, abaixe lentamente o peso de volta à posição inicial. Repita pelo número desejado de repetições.', '/exercise-media/bstrainer/0859.gif', 'hasaneyldrm', '0859')
on conflict (source, external_id) where external_id is not null and org_id is null do update set
  name = excluded.name,
  movement_pattern = excluded.movement_pattern,
  primary_muscles = excluded.primary_muscles,
  secondary_muscles = excluded.secondary_muscles,
  load_type = excluded.load_type,
  unilateral = excluded.unilateral;

